  lesson_content = EXCLUDED.lesson_content,
  summary = EXCLUDED.summary,
  display_order = EXCLUDED.display_order,
  manuel_ref = EXCLUDED.manuel_ref;

INSERT INTO public.chapters (id, subject_id, title, description, lesson_content, summary, display_order, manuel_ref) VALUES
  ('75cba66f-2438-53d4-abe1-7872a242c2ca', 'arabic-7eme', 'النّكرة والمعرفة، والمُعرَب والمبنيّ', 'التمييز بين النّكرة والمعرفة وأنواع المعارف الستّة (العلم، الضّمير، اسم الإشارة، الاسم الموصول، المعرّف بأل، المضاف إلى معرفة)، ودور «أل» في التّعريف، والفرق بين الاسم المُعرَب الّذي تتغيّر حركة آخره والاسم المبنيّ الّذي تلزم حركته حالة واحدة، والعلامات الإعرابيّة الأصليّة (الضمّة والفتحة والكسرة) على المُعرَب، وأبرز الأسماء المبنيّة', '# ⚔️ النّكرة والمعرفة والمُعرَب والمبنيّ — مفتاح ضبط الاسم

> 💡 «الاسم إمّا نكرة تنتظر التّعريف، أو معرفة تُشير إلى شيءٍ بعينه؛ وإمّا معربٌ تتلوّن حركتُه بموقعه، أو مبنيٌّ يلزم حركةً واحدة مهما تنقّل.»

## 🏰 النّكرة والمعرفة

- **النّكرة**: اسمٌ يدلّ على شيءٍ **غير معيّن**، شائعٍ بين أفراد جنسه. مثال: _رأيتُ رجلًا_ (أيّ رجل).
- **المعرفة**: اسمٌ يدلّ على شيءٍ **معيّن بذاته**، معروفٍ للسّامع. مثال: _رأيتُ خالدًا_ (رجلٌ بعينه).

> 🗡️ من علامات النّكرة الشّائعة قبولها «أل» فتتعرّف بها (رجلٌ ← الرّجلُ).

## ⚡ أنواع المعارف السّتّة

المعرفة ليست نوعًا واحدًا، بل ستّة أصناف:

| نوع المعرفة          | تعريفه                                         | مثال                     |
| -------------------- | ---------------------------------------------- | ------------------------ |
| **العلم**            | اسمٌ يدلّ على مسمّى معيّن بذاته (شخص، مكان...) | خالدٌ، تونسُ             |
| **الضّمير**          | ما دلّ على متكلّم أو مخاطب أو غائب             | أنا، أنتَ، هو            |
| **اسم الإشارة**      | ما دلّ على مشارٍ إليه بلفظه                    | هذا، تلك، هؤلاء          |
| **الاسم الموصول**    | ما دلّ على معيّن بواسطة جملة بعده (الصّلة)     | الّذي، الّتي، الّذين     |
| **المعرَّف بـ«أل»**  | نكرة دخلت عليها «أل» فأفادت التّعريف           | الرّجلُ، الكتابُ         |
| **المضاف إلى معرفة** | نكرة أُضيفت إلى اسمٍ معرفة فاكتسبت تعريفه      | كتابُ خالدٍ، بيتُ الجارِ |

> ⚠️ لا يكفي أن يكون الاسم مضافًا ليصير معرفةً: **المضاف إلى نكرة يبقى نكرة** (كتابُ تلميذٍ نكرة)؛ وإنّما يتعرّف **بالإضافة إلى معرفة فقط** (كتابُ التّلميذِ، كتابُ خالدٍ).

## 🛡️ التّعريف بـ«أل»

«أل» أداةٌ تدخل على النّكرة فتحوّلها معرفةً: _قلمٌ ← القلمُ_. وهي أشيع أدوات التّعريف وأوسعها استعمالًا؛ تدخل على أسماء الأجناس فتُعرّفها إمّا تعريف جنسٍ (الأسدُ قويٌّ، أيّ جنس الأسود) أو تعريف عهدٍ (شيءٌ معروفٌ سبق ذكره أو حاضرٌ في الذّهن).

> 🗡️ اختبر النّكرة بعرضها على «أل»: إن قبِلتها وتغيّر معناها إلى التّعيين فهي نكرة صالحة للتّعريف بها.

## 🔮 الاسم المُعرَب والاسم المبنيّ

- **المُعرَب**: اسمٌ **تتغيّر حركة آخره** بتغيّر موقعه في الجملة، تبعًا للعامل الدّاخل عليه. معظم الأسماء معربة.
- **المبنيّ**: اسمٌ **تلزم حركة آخره حالةً واحدة** لا تتغيّر مهما تبدّل موقعه في الجملة.

مثالٌ يوضّح الفرق: _جاء الطّالبُ_ / _رأيتُ الطّالبَ_ / _مررتُ بالطّالبِ_ — «الطّالب» **معربٌ** (تغيّرت حركته: ضمّة، فتحة، كسرة). أمّا _جاء هذا_ / _رأيتُ هذا_ / _مررتُ بهذا_ — «هذا» **مبنيٌّ** (بقيت حركته واحدة في كلّ المواقع).

## 🧮 العلامات الإعرابيّة الأصليّة على المُعرَب

الاسم المُعرَب يأخذ إحدى ثلاث حالات، ولكلّ حالة علامتها الأصليّة:

| الحالة     | علامتها الأصليّة | متى تلزم                    | مثال            |
| ---------- | ---------------- | --------------------------- | --------------- |
| **الرّفع** | الضّمّة          | فاعل، مبتدأ، خبر...         | جاءَ الطّالبُ   |
| **النّصب** | الفتحة           | مفعولٌ به، حالٌ...          | رأيتُ الطّالبَ  |
| **الجرّ**  | الكسرة           | بعد حرف جرّ، أو مضافًا إليه | مررتُ بالطّالبِ |

> ⚠️ لا تُعرَب الأسماء بالجزم أبدًا: الجزم علامةٌ خاصّةٌ بالفعل المضارع، لا بالاسم.

## 🧪 أبرز الأسماء المبنيّة

طائفةٌ من الأسماء **لا تتغيّر حركة آخرها** مهما اختلف موقعها، وأهمّها:

| الصّنف               | أمثلة                        | ملاحظة                                             |
| -------------------- | ---------------------------- | -------------------------------------------------- |
| **الضّمائر**         | أنا، أنتَ، هو، نحن، هم       | كلّها مبنيّة بلا استثناء                           |
| **أسماء الإشارة**    | هذا، هذه، ذلك، تلك، هؤلاء    | ما عدا المثنّى منها (هذانِ/هاتانِ)، فهو معربٌ      |
| **الأسماء الموصولة** | الّذي، الّتي، الّذين         | ما عدا المثنّى منها (اللّذانِ/اللّتانِ)، فهو معربٌ |
| **أسماء الاستفهام**  | مَن، ما، متى، أينَ، كيفَ، كم | كلّها مبنيّة رغم دخولها كأدوات سؤال                |

> ⚠️ الخطأ الشّائع عدُّ اسم الاستفهام معربًا لأنّه يبدأ جملةً ويؤدّي وظيفةً نحويّة (مبتدأ، مفعول به...): **الوظيفة النّحويّة لا تُخرجه عن كونه مبنيًّا**؛ فـ«مَن» في «مَن حضرَ؟» مبتدأٌ في محلّ رفعٍ، لكنّها تبقى مبنيّةً على السّكون.

> 🏆 أتقنتَ التّمييز بين النّكرة والمعرفة، وبين المُعرَب والمبنيّ: أنت الآن مستعدٌّ لتحليل الجملة الفعليّة بأركانها كاملة.', '# 📜 ملخّص: النّكرة والمعرفة والمُعرَب والمبنيّ

- **النّكرة والمعرفة**: النّكرة تدلّ على شيءٍ غير معيّن (رجلٌ)، والمعرفة تدلّ على شيءٍ معيّن بذاته (خالدٌ).
- **أنواع المعارف السّتّة**: العلم، الضّمير، اسم الإشارة، الاسم الموصول، المعرَّف بـ«أل»، والمضاف إلى معرفة (المضاف إلى نكرة يبقى نكرة).
- **التّعريف بـ«أل»**: أداةٌ تدخل على النّكرة فتحوّلها معرفةً (قلمٌ ← القلمُ)، تعريف جنسٍ أو تعريف عهدٍ.
- **المُعرَب والمبنيّ**: المُعرَب تتغيّر حركة آخره بتغيّر موقعه (الطّالبُ/الطّالبَ/الطّالبِ)، والمبنيّ تلزم حركته حالةً واحدة (هذا في كلّ موقع).
- **العلامات الأصليّة على المُعرَب**: الضّمّة للرّفع، الفتحة للنّصب، الكسرة للجرّ (الجزم خاصٌّ بالفعل المضارع، لا بالاسم).
- **أبرز الأسماء المبنيّة**: الضّمائر، أسماء الإشارة (عدا مثنّاها)، الأسماء الموصولة (عدا مثنّاها)، وأسماء الاستفهام كلّها — مهما كانت وظيفتها النّحويّة.', 5, NULL)
ON CONFLICT (id) DO UPDATE SET
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  description = EXCLUDED.description,
  lesson_content = EXCLUDED.lesson_content,
  summary = EXCLUDED.summary,
  display_order = EXCLUDED.display_order,
  manuel_ref = EXCLUDED.manuel_ref;

INSERT INTO public.chapters (id, subject_id, title, description, lesson_content, summary, display_order, manuel_ref) VALUES
  ('ed7989a0-b1f3-5c27-ae93-f4da6a81e635', 'arabic-7eme', 'الجملة الفعليّة: الفاعل ونائب الفاعل والمفعول به', 'أشكال الجملة الفعليّة البسيطة الثّلاثة (فعل+فاعل، فعل+فاعل+مفعول به، فعل+فاعل+مفعولان)، والفاعل حكمًا (الرّفع) وصورةً (اسم ظاهر أو ضمير) مع تأنيث الفعل لفاعله المؤنّث، ونائب الفاعل الذي يحلّ محلّ الفاعل المحذوف في الجملة المبنيّة للمجهول، والمفعول به حكمًا (النّصب)، وفق البرنامج الرسمي', '# ⚔️ الجملة الفعليّة: الفاعل ونائب الفاعل والمفعول به — أركان الجملة الفعليّة الثّلاثة

> 💡 «الجملة الفعليّة عمارة: الفعل عمودها، والفاعل أساسها الذي لا يسقط أبدًا، والمفعول به تتمّة تُكمل معناها.»

## 🏰 أشكال الجملة الفعليّة البسيطة

تقوم الجملة الفعليّة البسيطة (ذات النّواة الواحدة) على فعلٍ وما يتعلّق به، وتتّخذ ثلاثة أشكال بحسب تعدية الفعل (تذكّر: اللازم والمتعدّي، الدّرس السّابق):

| الشّكل                    | يقوم على فعل          | مثال                           |
| ------------------------- | --------------------- | ------------------------------ |
| **فعل + فاعل**            | لازم                  | نامَ الطّفلُ                   |
| **فعل + فاعل + مفعول به** | متعدٍّ إلى مفعول واحد | كتبَ التّلميذُ الدّرسَ         |
| **فعل + فاعل + مفعولان**  | متعدٍّ إلى مفعولين    | منحَ المعلّمُ التّلميذَ جائزةً |

> 🗡️ العنصر الثّابت في الأشكال الثّلاثة هو **الفاعل**: لا جملة فعليّة بلا فاعل (أو نائبٍ عنه)، أمّا المفعول به فزائدٌ بحسب تعدية الفعل.

## ⚡ الفاعل: تعريفه وحكمه

**الفاعل** اسمٌ يدلّ على من قام بالفعل أو اتّصف به، ويأتي **بعد الفعل**. حكمه الإعرابيّ ثابتٌ لا يتغيّر: الفاعل **مرفوعٌ دائمًا**، وعلامة رفعه **الضّمّة**. مثال: قرأَ الطّالبُ (الطّالبُ: فاعل مرفوع وعلامة رفعه الضّمّة).

> ⚠️ لا يبدّل موقع الاسم في الكلام وظيفته: الفاعل يُعرَف بدلالته (من قام بالفعل) وبمكانه بعد فعله، لا بترتيبه في الكلام اليوميّ.

## 🛡️ الفاعل اسمًا ظاهرًا أو ضميرًا

يرد الفاعل على صورتين:

- **اسمًا ظاهرًا**: كلمة صريحة تدلّ عليه. مثال: ركضَ الحصانُ (الحصانُ: اسم ظاهر).
- **ضميرًا**: إمّا **متّصل** بالفعل (تُ، نا، تَ، تِ...): كتبتُ الدّرسَ، أو **مستتر** يُفهم من صيغة الفعل دون أن يظهر: يكتبُ (الفاعل ضمير مستتر تقديره «هو»).

> 🗡️ الضّمير المتّصل والضّمير المستتر كلاهما فاعل، وحكمهما الرّفع محلًّا وإن لم تظهر عليهما حركة.

## 🔮 تأنيث الفعل مع الفاعل المؤنّث

إذا كان الفاعل **مؤنّثًا** (اسمًا ظاهرًا أو ضميرًا)، اتّصلت بالفعل الماضي **تاء التّأنيث السّاكنة**. مثال: نجحتْ التّلميذةُ (اتّصلت التّاء لأنّ الفاعل «التّلميذةُ» مؤنّث)؛ ونقارن: نجحَ التّلميذُ (فاعل مذكّر، فلا تاء).

> ⚠️ الخطأ الشّائع: نسيان تاء التّأنيث حين يكون الفاعل مؤنّثًا ولو كان اسم علمٍ لا علامة تأنيث ظاهرة فيه، مثل: حضرتْ سعادُ، لا حضرَ سعادُ.

## 🧪 نائب الفاعل: حين يغيب الفاعل

تذكّر (الدّرس السّابق): إذا **حُذف الفاعل** لغرضٍ ما، بُني الفعل **للمجهول**، وحلّ **المفعول به** محلّه فسُمّي حينئذٍ **نائب فاعل**. وحكمه الإعرابيّ كحكم الفاعل تمامًا في كلّ شيء: فهو **مرفوعٌ** وعلامة رفعه **الضّمّة**، ويعامَل معاملة الفاعل حتّى في اتّصال تاء التّأنيث بالفعل إن كان مؤنّثًا. مثال: كُتِبَ الدّرسُ (الدّرسُ: نائب فاعل مرفوع، بعد أن كان مفعولًا به منصوبًا في: كتبَ التّلميذُ الدّرسَ).

> ⚠️ نائب الفاعل **ليس مفعولًا به** رغم أنّه كان كذلك قبل حذف الفاعل: تغيّر حكمه من النّصب إلى الرّفع حين ناب عن الفاعل المحذوف. ولا يُبنى للمجهول إلّا الفعل **المتعدّي** الذي له مفعول به يقوم مقام الفاعل؛ أمّا الفعل **اللازم** فلا مفعول له يحلّ محلّ الفاعل.

## 🧮 المفعول به: حكمه وعلامة نصبه

**المفعول به** اسمٌ يقع عليه فعل الفاعل، وحكمه الإعرابيّ ثابت: المفعول به **منصوبٌ دائمًا**، وعلامة نصبه **الفتحة**. مثال: شربَ الطّفلُ الحليبَ (الحليبَ: مفعول به منصوب وعلامة نصبه الفتحة). وفي الجملة ذات المفعولين، ينصب الفعل **كلا** المفعولين معًا: منحَ المعلّمُ التّلميذَ جائزةً (التّلميذَ وجائزةً: مفعولان منصوبان).

> 🏆 أتقنتَ أركان الجملة الفعليّة الثّلاثة: الفاعل مرفوعٌ، ونائب الفاعل يقوم مقامه مرفوعًا حين يغيب، والمفعول به منصوبٌ يتمّم المعنى. أنت الآن مستعدٌّ لدخول عالم الجملة الاسميّة ونواسخها في الدّرس القادم.', '# 📜 ملخّص: الجملة الفعليّة: الفاعل ونائب الفاعل والمفعول به

- **أشكال الجملة الفعليّة**: فعل+فاعل (لازم)، فعل+فاعل+مفعول به (متعدٍّ لمفعول واحد)، فعل+فاعل+مفعولان (متعدٍّ لمفعولين).
- **الفاعل**: اسمٌ يدلّ على من قام بالفعل، يأتي بعده، وحكمه الرّفع دائمًا وعلامته الضّمّة.
- **الفاعل اسمًا أو ضميرًا**: يرد اسمًا ظاهرًا (الحصانُ) أو ضميرًا متّصلًا (كتبتُ) أو مستترًا (يكتبُ).
- **تأنيث الفعل**: تتّصل بالفعل الماضي تاء التّأنيث السّاكنة إذا كان الفاعل مؤنّثًا (نجحتْ التّلميذةُ).
- **نائب الفاعل**: يحلّ محلّ الفاعل المحذوف في الجملة المبنيّة للمجهول، وحكمه الرّفع كالفاعل تمامًا، ولا يوجد إلّا مع الفعل المتعدّي (كُتِبَ الدّرسُ).
- **المفعول به**: اسمٌ يقع عليه الفعل، وحكمه النّصب دائمًا وعلامته الفتحة؛ وقد يتعدّد إلى مفعولين.', 6, NULL)
