INSERT INTO public.chapters (id, subject_id, title, description, lesson_content, summary, display_order, manuel_ref) VALUES
  ('77bf962a-cc7b-5251-abaa-dba374b6de38', 'arabic-7eme', 'الفعل المعتلّ: المثال، الأجوف، النّاقص، اللّفيف', 'تعريف الفعل المعتلّ (فعل يحتوي على حرف علّة من أحرفه الأصليّة: ا، و، ي)، وتصنيفه بحسب موقع حرف العلّة: المثال (معتلّ الفاء)، الأجوف (معتلّ العين)، النّاقص (معتلّ اللام)، واللّفيف (حرفا علّة معًا: مفروق أو مقرون)', '# ⚔️ الفعل المعتلّ — حين يتسلّل حرف العلّة إلى الجذر

> 💡 «جذرٌ فيه حرف علّة يغيّر كلّ شيء: تعلّم موقعه فتفكّ شفرة أيّ فعلٍ معتلّ تراه.»

تعلّمتَ في الفصل الثّالث عشر أنّ **الفعل السّالم** أحرفه الأصليّة الثّلاثة سليمة، خالية من حرف العلّة والهمزة والتّضعيف، مثل كَتَبَ وفَهِمَ. أمّا اليوم فستكتشف عائلة الأفعال التي تخالف هذا الشّرط الأوّل: الأفعال **المعتلّة**.

## 🏰 الفعل المعتلّ: تعريف

**الفعل المعتلّ** فعلٌ أحد أحرفه الأصليّة الثّلاثة **حرف علّة**، وأحرف العلّة ثلاثة لا غير: **الألف (ا)، والواو (و)، والياء (ي)**. فإذا خلا الجذر من هذه الأحرف الثّلاثة كان الفعل سالمًا، وإذا وُجد أحدها في جذره كان معتلًّا.

يُصنَّف الفعل المعتلّ بحسب **موقع** حرف العلّة من الأحرف الثّلاثة الأصليّة: **الفاء** (الحرف الأوّل)، أو **العين** (الحرف الثّاني)، أو **اللام** (الحرف الثّالث)، أو موقعين معًا.

> 🗡️ لتصنّف فعلًا معتلًّا، استخرج جذره الثّلاثيّ أوّلًا، ثمّ افحص كلّ حرفٍ من أحرفه الثّلاثة على حدة: هل هو حرف علّة أم صحيح؟

## ⚡ المثال: معتلّ الفاء

**الفعل المثال** فعلٌ حرفه الأصليّ **الأوّل (الفاء)** حرف علّة، وحرفاه الثّاني والثّالث صحيحان.

| الفعل  | جذره  | الحرف المعتلّ |
| ------ | ----- | ------------- |
| وَعَدَ | و ع د | الفاء (و)     |
| يَسَرَ | ي س ر | الفاء (ي)     |
| وَجَدَ | و ج د | الفاء (و)     |
| يَئِسَ | ي أ س | الفاء (ي)     |

## 🛡️ الأجوف: معتلّ العين

**الفعل الأجوف** فعلٌ حرفه الأصليّ **الثّاني (العين)** حرف علّة، وحرفاه الأوّل والثّالث صحيحان. يظهر حرف العلّة في الماضي غالبًا ألفًا ممدودة، وأصله واو أو ياء: _قالَ_ أصله **قَوَلَ** (من القول)، و*باعَ* أصله **بَيَعَ** (من البيع).

| الفعل | جذره  | الحرف المعتلّ |
| ----- | ----- | ------------- |
| قالَ  | ق و ل | العين (و)     |
| باعَ  | ب ي ع | العين (ي)     |
| نامَ  | ن و م | العين (و)     |
| خافَ  | خ و ف | العين (و)     |

> ⚠️ الخطأ الشّائع الظّنّ أنّ الألف الظّاهرة في «قالَ» و«باعَ» هي أحد الأحرف الأصليّة الثّلاثة. في الحقيقة هذه الألف بديلة عن الواو أو الياء الأصليّة (تفصيل تحوّلها يُدرَس لاحقًا)؛ ما يهمّنا هنا فقط أنّ **عين الفعل** معتلّة.

## 🔮 النّاقص: معتلّ اللام

**الفعل النّاقص** فعلٌ حرفه الأصليّ **الثّالث (اللام)** حرف علّة، وحرفاه الأوّل والثّاني صحيحان.

| الفعل | جذره  | الحرف المعتلّ |
| ----- | ----- | ------------- |
| دَعا  | د ع و | اللام (و)     |
| رَمى  | ر م ي | اللام (ي)     |
| سَعى  | س ع ي | اللام (ي)     |
| مَشى  | م ش ي | اللام (ي)     |

> 🗡️ فرّق بين الأجوف والنّاقص بموقع الحرف المعتلّ لا بشكله: في الأجوف يقع **وسط** الفعل (قالَ)، وفي النّاقص يقع في **آخره** (دَعا).

## 🧮 اللّفيف: حرفا علّة معًا

**الفعل اللّفيف** فعلٌ اجتمع في جذره **حرفا علّة**، لا حرف واحد. وله صنفان بحسب موقع الحرفين:

| الصّنف              | الحرفان المعتلاّن | الوصف                         | أمثلة                      |
| ------------------- | ----------------- | ----------------------------- | -------------------------- |
| **اللّفيف المفروق** | الفاء واللام      | يفصل بينهما حرفٌ صحيح (العين) | وَفى (و ف ي)، وَقى (و ق ي) |
| **اللّفيف المقرون** | العين واللام      | متجاوران، لا يفصل بينهما شيء  | رَوى (ر و ي)، طَوى (ط و ي) |

> ⚠️ الخطأ الشّائع تصنيف فعلٍ فيه حرف علّة واحد فقط على أنّه لفيف. اللّفيف يشترط **حرفين** من أحرف العلّة معًا في الجذر نفسه؛ فعلٌ مثل «وَعَدَ» فيه حرف علّة واحد (الفاء)، فهو مثال لا لفيف.

## 🧪 منهج التّصنيف: أربع خطوات

لتصنّف أيّ فعلٍ معتلّ بثقة، اتّبع هذه الخطوات:

1. استخرج **الجذر الثّلاثيّ** للفعل (الفاء، العين، اللام).
2. افحص **كلّ حرفٍ** من الثّلاثة: أهو حرف علّة (ا، و، ي) أم صحيح؟
3. إن وُجد **حرف علّة واحد**، حدّد موقعه: الفاء (مثال)، أو العين (أجوف)، أو اللام (ناقص).
4. إن وُجد **حرفا علّة**، حدّد هل يفصل بينهما حرفٌ صحيح (مفروق) أم هما متجاوران (مقرون).

> 🏆 أتقنتَ الآن تصنيف الفعل المعتلّ إلى مثالٍ وأجوفَ وناقصٍ ولفيف. أنت مستعدّ للفصل القادم: اشتقاق الأفعال والأسماء من الرّباعيّ المجرّد والمزيد.', '# 📜 ملخّص: الفعل المعتلّ — المثال، الأجوف، النّاقص، اللّفيف

- **الفعل المعتلّ**: فعلٌ أحد أحرفه الأصليّة الثّلاثة حرف علّة (ا، و، ي)، ويُصنَّف بحسب موقع هذا الحرف من الجذر: الفاء، أو العين، أو اللام، أو موقعين معًا.
- **المثال**: معتلّ الفاء (الحرف الأوّل)، مثل وَعَدَ ويَسَرَ.
- **الأجوف**: معتلّ العين (الحرف الثّاني)، يظهر ألفًا في الماضي غالبًا وأصله واو أو ياء، مثل قالَ (أصله قَوَلَ) وباعَ (أصله بَيَعَ).
- **النّاقص**: معتلّ اللام (الحرف الثّالث)، مثل دَعا ورَمى.
- **اللّفيف**: حرفا علّة معًا في الجذر، وينقسم إلى **مفروق** (الفاء واللام، يفصل بينهما العين الصّحيح، مثل وَفى) و**مقرون** (العين واللام متجاوران، مثل رَوى).
- **منهج التّصنيف**: استخراج الجذر الثّلاثيّ، ثمّ فحص كلّ حرفٍ منه، فتحديد موقع حرف/حرفَي العلّة لمعرفة الصّنف.', 16, NULL)
ON CONFLICT (id) DO UPDATE SET
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  description = EXCLUDED.description,
  lesson_content = EXCLUDED.lesson_content,
  summary = EXCLUDED.summary,
  display_order = EXCLUDED.display_order,
  manuel_ref = EXCLUDED.manuel_ref;

INSERT INTO public.chapters (id, subject_id, title, description, lesson_content, summary, display_order, manuel_ref) VALUES
  ('8bbdfcf3-9192-5cc9-a7ac-ce67acaca7fa', 'arabic-7eme', 'اشتقاق الأفعال والأسماء من الرّباعيّ المجرّد ؛ المزيد من الأفعال والأسماء', 'الفعل الرّباعيّ المجرّد وتصريفه الأساسي (دَحْرَجَ، زَلْزَلَ)، وأوزان الفعل المزيد الشّائعة أَفْعَلَ وفَعَّلَ وتَفَاعَلَ وأثر الزّيادة على المعنى كالتّعدية، مع خاتمةٍ شاملةٍ تختم باب الصّرف كاملًا', '# ⚔️ اشتقاق الأفعال والأسماء من الرّباعيّ المجرّد؛ المزيد من الأفعال والأسماء — ختام مغامرة الصّرف

> 💡 «أربعة أحرف أصليّة تبني فعلًا رباعيًّا، وحرفٌ واحدٌ زائدٌ يبني فعلًا جديدًا: بابٌ أخير يفتح لك سرّ توليد الأفعال، ويختم رحلتك في علم الصّرف.»

انتهيتَ في الفصول السّابقة من دراسة الفعل الثّلاثيّ المجرّد بأنواعه، وتعرّفتَ كيف يُشتقّ منه المصدر واسم الفاعل واسم المفعول. في هذا الفصل الأخير من باب الصّرف، ستكتشف نوعين جديدين من الأفعال: **الفعل الرّباعيّ المجرّد**، و**الفعل المزيد** الّذي تُزاد حروفٌ على أصله الثّلاثيّ، ثمّ نختم الرّحلة بمراجعةٍ شاملةٍ لكلّ ما تعلّمته في هذا الباب.

## 🏰 الفعل الرّباعيّ المجرّد: أربعة أحرف أصليّة

**الفعل الرّباعيّ المجرّد** فعلٌ أحرفه الأصليّة **أربعة**، وكلّها أصليّة بلا أيّ حرفٍ زائد عليها، على وزن **فَعْلَلَ**. فالفعل _دَحْرَجَ_ (بمعنى: قلَّب الشّيء وأداره) جذره (د ح ر ج) أربعة أحرف، وكلّها أصليّة. ومثله: _وَسْوَسَ_ (و س و س)، _زَلْزَلَ_ (ز ل ز ل)، _بَعْثَرَ_ (ب ع ث ر)، _تَرْجَمَ_ (ت ر ج م).

| الفعل    | جذره    | عدد أحرفه الأصليّة | نوعه         |
| -------- | ------- | ------------------ | ------------ |
| دَحْرَجَ | د ح ر ج | أربعة              | رباعيّ مجرّد |
| زَلْزَلَ | ز ل ز ل | أربعة              | رباعيّ مجرّد |
| بَعْثَرَ | ب ع ث ر | أربعة              | رباعيّ مجرّد |

> ⚠️ الخطأ الشّائع الظّنّ أنّ كلّ فعلٍ من أربعة أحرفَ رباعيٌّ مجرّد. فالعبرة بأصالة الأحرف الأربعة كلّها، لا بعددها فقط؛ فعلٌ مثل _أَخْرَجَ_ من أربعة أحرفَ أيضًا، لكنّ أحدها (الهمزة) زائدٌ على أصلٍ ثلاثيّ (خَرَجَ)، فهو **ثلاثيٌّ مزيد**، لا رباعيّ مجرّد. سترى الفرق بوضوح في الفقرة القادمة.

## ⚡ تصريف الفعل الرّباعيّ المجرّد: الماضي والمضارع المرفوع

يتصرّف الفعل الرّباعيّ المجرّد مع الضّمائر بالطّريقة نفسها الّتي درستَها في الثّلاثيّ، دون أن يتغيّر جذره الرّباعيّ:

| الضّمير | الماضي      | المضارع المرفوع |
| ------- | ----------- | --------------- |
| هو      | دَحْرَجَ    | يُدَحْرِجُ      |
| هي      | دَحْرَجَتْ  | تُدَحْرِجُ      |
| هم      | دَحْرَجُوا  | يُدَحْرِجُونَ   |
| أنتَ    | دَحْرَجْتَ  | تُدَحْرِجُ      |
| أنا     | دَحْرَجْتُ  | أُدَحْرِجُ      |
| نحن     | دَحْرَجْنَا | نُدَحْرِجُ      |

مضارع الفعل الرّباعيّ المجرّد يبدأ بحرف مضارعةٍ **مضمومٍ دائمًا** (يُدَحْرِجُ، لا يَدَحْرِجُ)، وعينه ولامه الأولى **مكسورتان**.

> 🗡️ لتتأكّد من رباعيّة فعلٍ، صرّفه مع «أنا»: إن ظهرت أربعة أحرفَ أصليّة ثابتة (كـ دَحْرَجْتُ)، فهو رباعيّ مجرّد.

## 🛡️ الفعل المزيد: زيادة على الأصل الثّلاثيّ

**الفعل المزيد** فعلٌ زيدَ على أصله الثّلاثيّ حرفٌ واحدٌ أو أكثر، فتغيّر وزنه ومعناه، مع بقاء **جذره الثّلاثيّ الأصليّ** كما هو. من أكثر أوزان المزيد شيوعًا:

| الوزن         | الزّيادة                            | مثال      | الجذر الثّلاثيّ |
| ------------- | ----------------------------------- | --------- | --------------- |
| **أَفْعَلَ**  | همزة في أوّله (حرفٌ واحد)           | أَكْرَمَ  | ك ر م           |
| **فَعَّلَ**   | تضعيف عين الفعل (حرفٌ واحد)         | عَلَّمَ   | ع ل م           |
| **تَفَاعَلَ** | تاء في أوّله وألف بعد الفاء (حرفان) | تَعَاوَنَ | ع و ن           |

فـ*أَكْرَمَ* أصله الثّلاثيّ _كَرُمَ_ زيدت عليه همزةٌ؛ و*عَلَّمَ* أصله _عَلِمَ_ ضُوعفت عينه؛ و*تَعَاوَنَ* أصله (ع و ن) زيدت عليه التّاء والألف معًا.

> ⚠️ الخطأ الشّائع الخلط بين عدد الحروف الزّائدة في كلّ وزن: أَفْعَلَ وفَعَّلَ زيادتهما **حرفٌ واحد** فقط (رغم اختلاف موضعها)، بينما تَفَاعَلَ زيادته **حرفان**. عُدَّ الأحرف الأصليّة أوّلًا (ثلاثةٌ دومًا في المزيد الثّلاثيّ) قبل أن تحكم على عدد الزّوائد.

## 🔮 أثر الزّيادة على المعنى: التّعدية أنموذجًا

زيادة الحرف لا تغيّر شكل الفعل فحسب، بل قد تغيّر **معناه** أيضًا. من أبرز آثارها **التّعدية**: تحويل فعلٍ **لازمٍ** (يكتفي بفاعله) إلى فعلٍ **متعدٍّ** (يحتاج مفعولًا به).

فالفعل _خَرَجَ_ لازمٌ (خَرَجَ الطّفلُ)، فإذا زيدت همزةٌ في أوّله صار _أَخْرَجَ_ متعدّيًا (أَخْرَجَ الطّفلُ الكرةَ). وكذلك _فَرِحَ_ لازمٌ (فَرِحَ الولدُ)، فيصير بزيادة الهمزة _أَفْرَحَ_ متعدّيًا (أَفْرَحَ الخبرُ الولدَ).

> 🗡️ زيادة الهمزة في أوّل الفعل (أَفْعَلَ) من أكثر وسائل التّعدية شيوعًا: فعلٌ لازمٌ يصبح متعدّيًا بمجرّد إلحاق همزةٍ بأوّله.

## 🧮 ختام باب الصّرف: خارطة ما تعلّمته

أنهيتَ الآن باب **علم الصّرف** كاملًا. هذه خارطةٌ توجز محطّاته الخمس:

| المحطّة               | خلاصتها                                                                                                                   |
| --------------------- | ------------------------------------------------------------------------------------------------------------------------- |
| **الجذر**             | الحروف الأصليّة الثّابتة الّتي يدور حولها معنى الكلمة، مجرّدةً من كلّ زيادة                                               |
| **تصريف السّالم**     | تصريف الفعل الثّلاثيّ المجرّد السّالم (الخالي من العلّة والهمزة والتّضعيف) مع الضّمائر في الماضي والمضارع                 |
| **الاشتقاق**          | توليد المصدر واسم الفاعل واسم المفعول والصّفة المشبّهة من الجذر الثّلاثيّ الواحد                                          |
| **المعتلّ**           | الفعل الّذي أحد أحرفه الأصليّة حرف علّة (ألف/واو/ياء)، فيتغيّر تصريفه عن السّالم                                          |
| **الرّباعيّ والمزيد** | الرّباعيّ المجرّد: أربعة أحرفَ أصليّة (دَحْرَجَ)؛ المزيد: زيادة حرفٍ أو أكثر على الثّلاثيّ (أَكْرَمَ، عَلَّمَ، تَعَاوَنَ) |

> ⚠️ الخطأ الشّائع الظّنّ أنّ «الفعل المعتلّ» و«الفعل المزيد» صنفان متنافيان أو مترادفان؛ في الحقيقة هما معيارا تصنيفٍ مختلفان: الأوّل ينظر إلى **نوع الأحرف الأصليّة** (سالمة أم معتلّة)، والثّاني ينظر إلى **وجود زيادةٍ من عدمها** على الأصل، وقد يجتمعان في فعلٍ واحد.

> 🏆 أتقنتَ الآن الفعل الرّباعيّ المجرّد والفعل المزيد بأوزانه الشّائعة، وأثر الزّيادة على المعنى، وختمتَ باب الصّرف كاملًا: من الصّوت إلى الجذر، فالتّصريف، فالاشتقاق، فالمعتلّ، فالرّباعيّ والمزيد. أنت الآن فارسٌ مكتملُ العدّة في علم الصّرف العربيّ!', '# 📜 ملخّص: اشتقاق الأفعال والأسماء من الرّباعيّ المجرّد؛ المزيد من الأفعال والأسماء

- **الفعل الرّباعيّ المجرّد**: فعلٌ أحرفه الأصليّة أربعة كلّها أصليّة بلا زيادة، على وزن فَعْلَلَ، مثل دَحْرَجَ وزَلْزَلَ وبَعْثَرَ؛ يُميَّز عن الثّلاثيّ المزيد الّذي قد يبلغ أربعة أحرفَ أيضًا لكنّ أحدها زائد.
- **تصريف الرّباعيّ المجرّد**: يتصرّف مع الضّمائر كالثّلاثيّ دون تغيّر جذره الرّباعيّ؛ مضارعه يبدأ بحرف مضارعةٍ مضمومٍ دائمًا (يُدَحْرِجُ).
- **الفعل المزيد**: فعلٌ زيدَ على أصله الثّلاثيّ حرفٌ أو أكثر مع بقاء جذره الثّلاثيّ؛ أشهر أوزانه: أَفْعَلَ وفَعَّلَ (زيادة حرفٍ واحد، مثل أَكْرَمَ وعَلَّمَ)، وتَفَاعَلَ (زيادة حرفين، مثل تَعَاوَنَ).
- **أثر الزّيادة على المعنى**: قد تحوّل الفعل اللاّزم إلى متعدٍّ (التّعدية)، مثل خَرَجَ ← أَخْرَجَ، وفَرِحَ ← أَفْرَحَ.
- **ختام باب الصّرف**: خمس محطّاتٍ بنت العلم معًا: الجذر (الحروف الأصليّة الثّابتة) ← تصريف السّالم ← الاشتقاق من الثّلاثيّ ← المعتلّ ← الرّباعيّ والمزيد.', 17, NULL)
ON CONFLICT (id) DO UPDATE SET
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  description = EXCLUDED.description,
  lesson_content = EXCLUDED.lesson_content,
  summary = EXCLUDED.summary,
  display_order = EXCLUDED.display_order,
  manuel_ref = EXCLUDED.manuel_ref;

