INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9cd630e6-7333-59d0-87b8-37bb7901989d', 'f03c4cbb-6000-55f0-891e-f8cf82fc0c79', 'ما الشرطُ الأساسيُّ لتكونَ الكلماتُ جملةً مفيدةً؟', '[{"id":"a","text":"أن تقومَ على إسنادٍ يُخبَرُ فيه عن شيءٍ"},{"id":"b","text":"أن تبدأَ باسمٍ"},{"id":"c","text":"أن تزيدَ على ثلاث كلماتٍ"},{"id":"d","text":"أن تنتهيَ بحرفٍ"}]'::jsonb, 'a', 'الجملةُ المفيدةُ تقومُ على نواةٍ إسناديّةٍ: نُسنِدُ شيئًا (المُسنَد) إلى شيءٍ (المُسنَد إليه). ولا عبرةَ بعددِ الكلمات ولا بنوعِ أوّلِها.', 2)
