  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('81c7a25d-be80-5f80-9354-97a15d249555', 'f03c4cbb-6000-55f0-891e-f8cf82fc0c79', 'في «البحرُ هادئٌ»، ما المُسنَد إليه (ما نتحدّثُ عنه)؟', '[{"id":"a","text":"البحرُ"},{"id":"b","text":"هادئٌ"},{"id":"c","text":"الجملةُ كلُّها"},{"id":"d","text":"لا مُسنَدَ إليه فيها"}]'::jsonb, 'a', 'المُسنَد إليه هو المحدَّثُ عنه، وهنا نتحدّثُ عن «البحرِ» ونُخبِرُ عنه بأنّه «هادئٌ»؛ فـ«البحرُ» هو المُسنَد إليه و«هادئٌ» هو المُسنَد.', 3)
