  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2c7bd3e5-535d-582d-a7c9-a467f8c8a4b3', '1c195d6c-9db3-5cfa-8b5a-06aa517c828b', '«مفاتيحُ السيّارةِ على الطاولةِ» — لماذا نعدُّه كلامًا مفيدًا (جملةً) لا مجرّدَ تركيبٍ؟', '[{"id":"a","text":"لأنّه يزيدُ على ثلاث كلماتٍ"},{"id":"b","text":"لأنّه يبدأُ باسمٍ معرفةٍ"},{"id":"c","text":"لأنّه أخبرَ عن «المفاتيحِ» بأنّها «على الطاولةِ»، فتمّ الإسنادُ"},{"id":"d","text":"لأنّه يحتوي على حرفِ جرٍّ"}]'::jsonb, 'c', 'لو اقتصرنا على «مفاتيحِ السيّارةِ» لكان تركيبًا يُسمّي فقط. لكنّنا أسندنا إليه خبرًا («على الطاولةِ») يُبيّنُ مكانَها، فتمّتِ النواةُ الإسناديّةُ وصارَ جملةً. الخطأُ الشائعُ ربطُ الإفادةِ بعددِ الكلماتِ أو بنوعِ أوّلِها، والعبرةُ بالإسنادِ.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c975e366-9fb0-5e85-8172-0a63aafbf4af', '1c195d6c-9db3-5cfa-8b5a-06aa517c828b', '«شاهدَ الولدُ الأسدَ» و«شاهدَ الأسدُ الولدَ»: علامَ يدلّ اختلافُ المعنى بين الجملتين؟', '[{"id":"a","text":"على أنّ النّحوَ (الترتيبَ والضبطَ) يحدّدُ المعنى: مَن الفاعلُ ومَن المفعولُ"},{"id":"b","text":"على أنّ الكلماتِ مختلفةٌ"},{"id":"c","text":"على أنّ الجملةَ الثانيةَ خطأٌ"},{"id":"d","text":"على أنّ المعنى واحدٌ لا يتغيّرُ"}]'::jsonb, 'a', 'الكلماتُ نفسُها، لكنّ الترتيبَ وضبطَ الأواخرِ بدّلا المعنى: في الأولى الولدُ هو المشاهِدُ، وفي الثانيةِ الأسدُ هو المشاهِدُ. الخطأُ الشائعُ ظنُّ أنّ المعنى واحدٌ ما دامتِ الكلماتُ واحدةً؛ وهنا تظهرُ فائدةُ النّحو في حفظِ المعنى.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e13aca6f-b8bf-530a-a5af-21368c8ca714', '1c195d6c-9db3-5cfa-8b5a-06aa517c828b', '«رجعَ الفلّاحونَ من الحقلِ. كانوا متعبينَ لكنّهم راضونَ.» — ما الذي يجعلُهما نصًّا متماسكًا لا جملتين متباعدتين؟', '[{"id":"a","text":"عددُ الكلماتِ المتساوي"},{"id":"b","text":"وجودُ حرفِ الجرِّ «من»"},{"id":"c","text":"أنّهما تبدآنِ بفعلٍ"},{"id":"d","text":"الضميرُ العائدُ على الفلّاحينَ (كانوا/هم) ووحدةُ الموضوعِ"}]'::jsonb, 'd', 'الضميرُ في «كانوا» و«لكنّهم» يعودُ على «الفلّاحينَ»، فيربطُ الجملةَ الثانيةَ بالأولى في موضوعٍ واحدٍ، فيتحقّقُ التماسكُ. الخطأُ الشائعُ عدُّ كلِّ حرفٍ رابطًا؛ وحرفُ الجرِّ «من» متعلّقٌ داخلَ الجملةِ الأولى لا رابطٌ بينهما.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a857bf9d-04fc-59c5-8e45-abe36ece8e08', '1c195d6c-9db3-5cfa-8b5a-06aa517c828b', 'رتّبِ الجملَ الآتيةَ لتؤلّفَ نصًّا متماسكًا: (1) فغرسَ فيها شجيراتٍ. (2) اشترى جدّي أرضًا صغيرةً. (3) فصارتْ بستانًا جميلًا.', '[{"id":"a","text":"2 ثمّ 1 ثمّ 3"},{"id":"b","text":"1 ثمّ 2 ثمّ 3"},{"id":"c","text":"3 ثمّ 2 ثمّ 1"},{"id":"d","text":"2 ثمّ 3 ثمّ 1"}]'::jsonb, 'a', 'يبدأُ النّصُّ بالحدثِ الأوّلِ (اشترى جدّي أرضًا)، ثمّ ما ترتّبَ عليه بالفاءِ (فغرسَ فيها شجيراتٍ)، ثمّ النتيجةَ (فصارتْ بستانًا): 2 ثمّ 1 ثمّ 3. الخطأُ الشائعُ تقديمُ النتيجةِ (صارتْ بستانًا) على سببِها، فيختلُّ الترتيبُ المنطقيُّ.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('adbf645a-f2d9-5551-ba9f-aa06cce1e83c', '8317ee18-c9fe-5091-aaa3-7b1ecd515f18', 'arabic-7eme', '⭐⭐ تمرين مراجعة (نمط امتحان): الكلمةُ والجملةُ والنّصّ', 2, 70, 15, 'practice', 'admin', 3)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3d15d33b-2ac0-560e-919b-b2a683f4709a', 'adbf645a-f2d9-5551-ba9f-aa06cce1e83c', 'ما نوعُ الكلمة «هل»؟', '[{"id":"a","text":"اسمٌ"},{"id":"b","text":"فعلٌ"},{"id":"c","text":"حرفٌ"},{"id":"d","text":"فعلُ أمرٍ"}]'::jsonb, 'c', '«هل» أداةُ استفهامٍ لا تدلّ على معنًى مستقلٍّ بنفسها، بل تُدخِلُ الاستفهامَ على الجملة، فهي حرفٌ.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('41fefca0-c010-5de3-b17a-2fa22976c866', 'adbf645a-f2d9-5551-ba9f-aa06cce1e83c', 'ما النّصُّ في أبسطِ تعريفٍ له؟', '[{"id":"a","text":"كلمةٌ واحدةٌ طويلةٌ"},{"id":"b","text":"جملٌ مترابطةٌ تدورُ حول موضوعٍ واحدٍ"},{"id":"c","text":"حرفٌ يربطُ بين اسمين"},{"id":"d","text":"فعلٌ وفاعلُه فقط"}]'::jsonb, 'b', 'النّصُّ وحدةٌ متناسقةٌ من جملٍ مفيدةٍ مترابطةٍ تدورُ حول موضوعٍ واحدٍ، لا كلمةٌ واحدةٌ ولا جملةٌ منفردةٌ.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7c05acbe-1908-5ead-80d9-b4f2c47b6e6c', 'adbf645a-f2d9-5551-ba9f-aa06cce1e83c', 'في «الطائرُ يغرّدُ فوقَ الغصنِ»، ما المُسنَد إليه؟', '[{"id":"a","text":"الطائرُ"},{"id":"b","text":"يغرّدُ"},{"id":"c","text":"الغصنِ"},{"id":"d","text":"فوقَ"}]'::jsonb, 'a', 'المُسنَد إليه هو المحدَّثُ عنه؛ ونحن نتحدّثُ عن «الطائرِ» ونُخبِرُ عنه بالتغريدِ. أمّا «فوقَ الغصنِ» فبيانٌ للمكانِ لا مُسنَدٌ إليه.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('115970ec-4671-5b1a-b8ae-3a594b61938d', 'adbf645a-f2d9-5551-ba9f-aa06cce1e83c', 'أيُّ العبارات التالية **ليست** جملةً مفيدةً؟', '[{"id":"a","text":"هطلَ الثلجُ"},{"id":"b","text":"عادَ المسافرُ"},{"id":"c","text":"أزهرَ البستانُ"},{"id":"d","text":"نافذةُ الغرفةِ"}]'::jsonb, 'd', '«نافذةُ الغرفةِ» تركيبٌ إضافيٌّ يُسمّي شيئًا ولا يُخبِرُ عنه، فلا فائدةَ تامّةً فيه. أمّا البواقي فجملٌ أخبرتْ عن مُسنَدٍ إليه بفعلٍ.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0d8e30f2-4812-5d71-a982-1b6cf71e261e', 'adbf645a-f2d9-5551-ba9f-aa06cce1e83c', 'في «قرأتْ ليلى القصّةَ ثمّ لخّصتْها»، ما الرابطُ الذي جعلَ الجملتين نصًّا متماسكًا؟', '[{"id":"a","text":"حرفُ العطفِ «ثمّ» والضميرُ «ـها» العائدُ على القصّةِ"},{"id":"b","text":"كثرةُ الكلماتِ"},{"id":"c","text":"اسمُ العلمِ «ليلى»"},{"id":"d","text":"الفعلُ «قرأَ»"}]'::jsonb, 'a', '«ثمّ» رتّبتِ الحدثين، والضميرُ «ـها» في «لخّصتْها» عادَ على «القصّةِ»، فربطا الجملةَ الثانيةَ بالأولى في موضوعٍ واحدٍ.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('060debe2-02ec-5bcf-ac0e-a733a7cd864e', 'adbf645a-f2d9-5551-ba9f-aa06cce1e83c', 'كلمةُ «البستانُ» — ما الذي ينقصُها لتصيرَ جملةً مفيدةً؟', '[{"id":"a","text":"لا شيءَ، هي جملةٌ"},{"id":"b","text":"حرفُ جرٍّ"},{"id":"c","text":"مُسنَدٌ نُخبِرُ به عنها (كأن نقولَ: البستانُ مثمرٌ)"},{"id":"d","text":"علامةُ تعجّبٍ"}]'::jsonb, 'c', '«البستانُ» مُسنَدٌ إليه بلا مُسنَدٍ، فالنواةُ ناقصةٌ. فإذا أضفنا خبرًا (مثمرٌ) تمّتِ النواةُ الإسناديّةُ وصارتْ جملةً مفيدةً: «البستانُ مثمرٌ».', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('da34863b-34a8-5b7c-8295-a02f3d79d6c2', '8317ee18-c9fe-5091-aaa3-7b1ecd515f18', 'arabic-7eme', '👑 تحدّي النخبة ⭐⭐⭐⭐: من النّحو إلى المعنى', 4, 300, 60, 'challenge', 'admin', 4)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c8dba30d-67d7-5e1c-aa92-45f709b293b2', 'da34863b-34a8-5b7c-8295-a02f3d79d6c2', 'أيُّ العبارات التالية صحيحةٌ؟', '[{"id":"a","text":"كلُّ اجتماعِ كلمتين جملةٌ مفيدةٌ"},{"id":"b","text":"الجملةُ المفيدةُ تقومُ على نواةٍ إسناديّةٍ من مُسنَدٍ ومُسنَدٍ إليه"},{"id":"c","text":"النّصُّ لا يحتاجُ إلى روابطَ بين جملِه"},{"id":"d","text":"الحرفُ يدلّ على معنًى تامٍّ وحدَه"}]'::jsonb, 'b', 'الصحيحُ أنّ الجملةَ المفيدةَ تقومُ على نواةٍ إسناديّةٍ (مُسنَدٌ + مُسنَدٌ إليه). أمّا اجتماعُ كلمتين فقد يكونُ تركيبًا لا جملةً، والنّصُّ يحتاجُ روابطَ ليتماسكَ، والحرفُ لا يدلّ على معنًى تامٍّ وحدَه.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('96003539-bd9e-50a4-b1ad-4799920b32e8', 'da34863b-34a8-5b7c-8295-a02f3d79d6c2', 'قالَ تلميذٌ: «العبارةُ (زهرةُ الحديقةِ) جملةٌ مفيدةٌ لأنّها تتألّفُ من كلمتين وتبدأُ باسمٍ.» أين الخطأُ في استدلالِه؟', '[{"id":"a","text":"لا خطأَ، فهي جملةٌ مفيدةٌ"},{"id":"b","text":"الخطأُ أنّها ثلاثُ كلماتٍ لا كلمتانِ"},{"id":"c","text":"الخطأُ أنّ العددَ والبدءَ باسمٍ لا يصنعانِ جملةً؛ العبرةُ بالإسنادِ، و(زهرةُ الحديقةِ) تركيبٌ إضافيٌّ لا إخبارَ فيه"},{"id":"d","text":"الخطأُ أنّها يجبُ أن تبدأَ بفعلٍ"}]'::jsonb, 'c', '(هذا سؤالُ تصحيحِ خطأٍ، فالجوابُ الصحيحُ هو بيانُ موضعِ الخطأ.) استدلالُه فاسدٌ: لا العددُ (كلمتان) ولا البدءُ باسمٍ يجعلُ الكلامَ جملةً. «زهرةُ الحديقةِ» تركيبٌ إضافيٌّ يُسمّي ولا يُخبِرُ، فلا نواةَ إسناديّةَ فيه. ولا يُشترَطُ البدءُ بفعلٍ.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('eb32fc2e-b305-5b0c-8ca9-0a90bcf45cc4', 'da34863b-34a8-5b7c-8295-a02f3d79d6c2', 'جملةٌ مُسنَدُها إليه «القطارُ» ومُسنَدُها فعلٌ يدلّ على الوصولِ. أيُّ الجملِ يطابقُ هذا الوصفَ؟', '[{"id":"a","text":"انتظرَ المسافرونَ القطارَ"},{"id":"b","text":"وصلَ القطارُ في موعدِه"},{"id":"c","text":"محطّةُ القطارِ بعيدةٌ"},{"id":"d","text":"القطارُ سريعٌ جدًّا"}]'::jsonb, 'b', 'المطلوبُ أن يكونَ «القطارُ» هو المحدَّثَ عنه والمُسنَدُ فعلَ وصولٍ: «وصلَ القطارُ» يطابقُ ذلك. الخطأُ الشائعُ اختيارُ «انتظرَ المسافرونَ القطارَ» حيثُ «القطارَ» مفعولٌ لا مُسنَدٌ إليه؛ وفي «بعيدةٌ» و«سريعٌ» المُسنَدُ اسمٌ لا فعلَ وصولٍ.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3442d2f8-f921-5a5c-b52d-e24c27c52a79', 'da34863b-34a8-5b7c-8295-a02f3d79d6c2', 'في نصّ «رأى الصيّادُ سمكةً كبيرةً. أمسكَ بها بحذرٍ. لكنّها أفلتتْ منه.» — أيُّ التحليلات صحيحٌ؟', '[{"id":"a","text":"جملةٌ واحدةٌ طويلةٌ لا ثلاثُ جملٍ"},{"id":"b","text":"نصٌّ غيرُ متماسكٍ لعدمِ وجودِ روابطَ"},{"id":"c","text":"الجملُ لا نواةَ إسناديّةَ لها"},{"id":"d","text":"ثلاثُ جملٍ مستقلّةٍ بنواها، ربطتْ بينها الضمائرُ (ها/ه) وحرفُ الاستدراكِ «لكنّ» ووحدةُ الموضوعِ، فصارتْ نصًّا"}]'::jsonb, 'd', 'كلُّ جملةٍ مستقلّةٌ بنواتِها الإسناديّةِ، لكنّ الضمائرَ («بها»، «لكنّها»، «منه») وحرفَ «لكنّ» ووحدةَ الموضوعِ (الصيدُ) ربطتْها فصارتْ نصًّا متماسكًا. الخطأُ الشائعُ عدُّها جملةً واحدةً، أو نفيُ الروابطِ رغمَ ظهورِ الضمائرِ.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c5426f86-9083-587f-a3bc-cea97166cf91', 'da34863b-34a8-5b7c-8295-a02f3d79d6c2', 'قيلَ: «أكلَ السمكةَ القطُّ» و«أكلَ السمكةُ القطَّ». كيف يميّزُ النّحوُ المعنى الصحيحَ؟', '[{"id":"a","text":"بضبطِ الأواخرِ: الفاعلُ مرفوعٌ والمفعولُ منصوبٌ، فالمرفوعُ هو الآكلُ والمنصوبُ هو المأكولُ"},{"id":"b","text":"بعددِ الكلماتِ"},{"id":"c","text":"لا فرقَ، المعنى واحدٌ"},{"id":"d","text":"بترتيبِ الحروفِ داخلَ الكلمةِ"}]'::jsonb, 'a', 'النّحوُ يضبطُ الأواخرَ فيُميّزُ المواقعَ: المرفوعُ بالضمّةِ هو الفاعلُ (الآكلُ)، والمنصوبُ بالفتحةِ هو المفعولُ (المأكولُ). ففي «القطُّ» (بالضمِّ) القطُّ آكلٌ، وفي «القطَّ» (بالفتحِ) القطُّ مأكولٌ. الخطأُ الشائعُ ظنُّ المعنى واحدًا؛ وهنا تظهرُ غايةُ النّحو في الإفهامِ.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('65cc2582-4181-539a-8da3-74a35e3cdbeb', 'da34863b-34a8-5b7c-8295-a02f3d79d6c2', 'أيُّ المجموعتين نصٌّ متماسكٌ؟ (1) «طلعتِ الشمسُ. ذابَ الجليدُ فوقَ الجبالِ. جرتِ الجداولُ في الوديانِ.» (2) «طلعتِ الشمسُ. يحبُّ القطُّ الحليبَ. اخترعَ العالِمُ آلةً.»', '[{"id":"a","text":"الثانيةُ، لأنّ جملَها أطولُ"},{"id":"b","text":"كلتاهما متماسكةٌ"},{"id":"c","text":"الأولى، لأنّ جملَها تدورُ حول موضوعٍ واحدٍ (أثرِ طلوعِ الشمسِ) وتترتّبُ ترتيبًا سببيًّا متماسكًا"},{"id":"d","text":"لا فرقَ بينهما"}]'::jsonb, 'c', 'المجموعةُ الأولى نصٌّ متماسكٌ: جملُها تدورُ حول موضوعٍ واحدٍ (أثرِ الشمسِ) وتترتّبُ سببيًّا (طلوعٌ ← ذوبانٌ ← جريانٌ). أمّا الثانيةُ فجملُها مفيدةٌ لكنّها مبعثرةٌ بلا موضوعٍ جامعٍ، فلا تكوّنُ نصًّا. الخطأُ الشائعُ الحكمُ بالتماسكِ لمجرّدِ صحّةِ كلِّ جملةٍ على حدةٍ.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('a8d67854-36f7-5d48-bacd-77b6593e7317', '8317ee18-c9fe-5091-aaa3-7b1ecd515f18', 'arabic-7eme', '📝 تدريب ⭐⭐⭐ شامل: النّواةُ والنّصّ (مراجعة شاملة)', 3, 120, 30, 'boss', 'admin', 5)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('62f8a581-6259-5790-9abd-3bf4ad40fa53', 'a8d67854-36f7-5d48-bacd-77b6593e7317', 'في «الطبيبُ يفحصُ المريضَ»، عيّنِ المُسنَد إليه والمُسنَد على التوالي.', '[{"id":"a","text":"المُسنَد إليه: المريضَ / المُسنَد: يفحصُ"},{"id":"b","text":"المُسنَد إليه: الطبيبُ / المُسنَد: يفحصُ"},{"id":"c","text":"المُسنَد إليه: يفحصُ / المُسنَد: الطبيبُ"},{"id":"d","text":"لا نواةَ إسناديّةَ فيها"}]'::jsonb, 'b', 'المحدَّثُ عنه هو «الطبيبُ» (المُسنَد إليه)، وما أُخبِرَ به عنه هو الفعلُ «يفحصُ» (المُسنَد). أمّا «المريضَ» فمفعولٌ داخلَ الخبرِ لا مُسنَدٌ إليه.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f8167470-1d5d-57ff-bd70-f8a567a6c9e0', 'a8d67854-36f7-5d48-bacd-77b6593e7317', 'أيُّها تركيبٌ (إضافةٌ) وليس جملةً؟', '[{"id":"a","text":"مكتبةُ المدينةِ"},{"id":"b","text":"سافرَ العُمّالُ"},{"id":"c","text":"اخضرّتِ الحقولُ"},{"id":"d","text":"تعبَ الحصّادُ"}]'::jsonb, 'a', '«مكتبةُ المدينةِ» تركيبٌ إضافيٌّ يُسمّي مكتبةً بعينِها ولا يُخبِرُ عنها بشيءٍ، فلا فائدةَ تامّةً فيه. أمّا البواقي فجملٌ أخبرتْ عن مُسنَدٍ إليه بفعلٍ.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4230faa6-145e-5cff-8a1d-70ea762e2f05', 'a8d67854-36f7-5d48-bacd-77b6593e7317', '«النّحوُ يعصمُ اللسانَ من الخطأِ» تعني أنّ غايةَ النّحو:', '[{"id":"a","text":"حفظُ الشعرِ"},{"id":"b","text":"تحقيقُ الفهمِ والإفهامِ بضبطِ الكلامِ"},{"id":"c","text":"كثرةُ الكلماتِ"},{"id":"d","text":"تعلّمُ الحروفِ فقط"}]'::jsonb, 'b', 'عصمةُ اللسانِ من الخطأِ تعني ضبطَ الكلامِ حتّى يستقيمَ المعنى، فيفهمَ الإنسانُ ويُفهِمَ؛ وهذه هي غايةُ النّحو.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('75d21837-b8ae-534b-92c1-b4a45b2c8547', 'a8d67854-36f7-5d48-bacd-77b6593e7317', '«هذه» وحدَها — لماذا لا تُعدُّ جملةً مفيدةً رغمَ أنّها كلمةٌ دالّةٌ؟', '[{"id":"a","text":"لأنّها حرفٌ"},{"id":"b","text":"لأنّها فعلٌ ماضٍ"},{"id":"c","text":"لأنّها اسمُ إشارةٍ لا يُخبِرُ عن شيءٍ؛ فيها طرفٌ واحدٌ لا إسنادَ"},{"id":"d","text":"لأنّها نكرةٌ"}]'::jsonb, 'c', '«هذه» اسمُ إشارةٍ يصلحُ مُسنَدًا إليه، لكنّه بلا مُسنَدٍ يُخبِرُ عنه؛ فالنواةُ ناقصةٌ ولا فائدةَ. الخطأُ الشائعُ عدُّ كلِّ كلمةٍ ذاتِ معنًى جملةً؛ والعبرةُ بتمامِ الإسنادِ لا بدلالةِ الكلمةِ وحدَها.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2b3afa21-9c28-558b-bf62-70a6e66098fc', 'a8d67854-36f7-5d48-bacd-77b6593e7317', 'في نصّ «ذهبتِ الأمُّ إلى السوقِ. اشترتْ خضرًا طازجةً. ثمّ رجعتْ مسرعةً.» ما الروابطُ التي حقّقتِ التماسكَ؟', '[{"id":"a","text":"كثرةُ الأسماءِ"},{"id":"b","text":"حرفُ الجرِّ «إلى» فقط"},{"id":"c","text":"لا روابطَ، الجملُ مستقلّةٌ تمامًا"},{"id":"d","text":"الضميرُ العائدُ على الأمِّ (اشترتْ/رجعتْ) وحرفُ العطفِ «ثمّ» ووحدةُ الموضوعِ"}]'::jsonb, 'd', 'الفاعلُ في «اشترتْ» و«رجعتْ» يعودُ على «الأمِّ»، و«ثمّ» رتّبتِ الأحداثَ، ووحدةُ الموضوعِ (رحلةُ السوقِ) جمعتِ الجملَ، فتماسكَ النّصُّ. الخطأُ الشائعُ عدُّ حرفِ الجرِّ «إلى» رابطًا بين الجملِ، وهو متعلّقٌ داخلَ الجملةِ الأولى.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('21c6623c-602f-5582-86d9-55e0e5ff7b80', 'a8d67854-36f7-5d48-bacd-77b6593e7317', 'أيُّ جملةٍ لا تنتمي إلى نصٍّ موضوعُه «يومٌ في المدرسةِ»؟', '[{"id":"a","text":"نضجَ الموزُ في الغابةِ الاستوائيّةِ"},{"id":"b","text":"دقَّ الجرسُ صباحًا"},{"id":"c","text":"دخلَ التلاميذُ الأقسامَ"},{"id":"d","text":"شرحَ المعلّمُ الدرسَ"}]'::jsonb, 'a', 'النّصُّ وحدةٌ متناسقةٌ تدورُ حول موضوعٍ واحدٍ. جملةُ «نضجَ الموزُ في الغابةِ الاستوائيّةِ» خارجةٌ عن موضوعِ «يومٍ في المدرسةِ»، فتكسِرُ وحدةَ الموضوعِ. أمّا البواقي فتخدمُ الموضوعَ نفسَه.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('aa88417c-7792-570a-8387-a79993a0da42', '8317ee18-c9fe-5091-aaa3-7b1ecd515f18', 'arabic-7eme', '👑 تحدّي النخبة ⭐⭐⭐⭐: قمّةُ الفهم والإفهام', 4, 300, 60, 'challenge', 'admin', 6)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('24a96ea4-79d4-5402-be83-4ae983f8dd55', 'aa88417c-7792-570a-8387-a79993a0da42', 'أيُّها كلمةٌ مفردةٌ (لا جملةٌ ولا نصٌّ)؟', '[{"id":"a","text":"هطلَ"},{"id":"b","text":"هطلَ المطرُ"},{"id":"c","text":"هطلَ المطرُ فجرتِ الأوديةُ فاخضرّتِ السهولُ"},{"id":"d","text":"هطلَ المطرُ ليلًا"}]'::jsonb, 'a', '«هطلَ» كلمةٌ مفردةٌ (فعلٌ) لم تُسنَدْ بعدُ إلى مُسنَدٍ إليه ظاهرٍ. «هطلَ المطرُ» و«هطلَ المطرُ ليلًا» جملتانِ مفيدتانِ، والثالثةُ نصٌّ من جملٍ مترابطةٍ.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d44792f5-fd63-56cd-bd51-3debbe21dc6d', 'aa88417c-7792-570a-8387-a79993a0da42', 'أردنا تحويلَ التركيبِ «مصباحُ الغرفةِ» إلى جملةٍ مفيدةٍ. أيُّ إضافةٍ تحقّقُ ذلك؟', '[{"id":"a","text":"حذفُ كلمةِ «الغرفةِ»"},{"id":"b","text":"إضافةُ مُسنَدٍ نُخبِرُ به، نحو: «مصباحُ الغرفةِ منطفئٌ»"},{"id":"c","text":"إضافةُ حرفِ جرٍّ في أوّلِه: «في مصباحِ الغرفةِ»"},{"id":"d","text":"جعلُه سؤالًا بإضافةِ «هل»: «هل مصباحُ الغرفةِ؟»"}]'::jsonb, 'b', '«مصباحُ الغرفةِ» مُسنَدٌ إليه بلا مُسنَدٍ. بإضافةِ خبرٍ («منطفئٌ») تتمُّ النواةُ الإسناديّةُ فتصيرُ جملةً. الخطأُ الشائعُ ظنُّ «هل» تصنعُ الفائدةَ؛ و«هل مصباحُ الغرفةِ؟» يبقى ناقصَ المُسنَدِ، وإضافةُ حرفِ الجرِّ تزيدُه بُعدًا عن الجملةِ.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8fa2c271-4c30-5bd6-8a45-fb769811980f', 'aa88417c-7792-570a-8387-a79993a0da42', 'زعمَ قارئٌ أنّ ما يلي نصٌّ متماسكٌ: «اشتدَّ البردُ. يفوزُ فريقُ المدينةِ عادةً. لبستُ معطفي الثقيلَ.» ما الحكمُ الصحيحُ؟', '[{"id":"a","text":"نصٌّ متماسكٌ لأنّه ثلاثُ جملٍ"},{"id":"b","text":"ليس كلامًا مفيدًا أصلًا"},{"id":"c","text":"ليس نصًّا متماسكًا: الجملةُ الوسطى خارجةٌ عن الموضوعِ (البردِ)، فاختلّتْ وحدةُ الموضوعِ"},{"id":"d","text":"متماسكٌ لأنّ الجملَ مضبوطةُ الأواخرِ"}]'::jsonb, 'c', 'الجملُ الثلاثُ مفيدةٌ كلٌّ على حدةٍ، لكنّ «يفوزُ فريقُ المدينةِ» خارجةٌ عن موضوعِ البردِ الذي يجمعُ الأولى والثالثةَ، فتنكسِرُ وحدةُ الموضوعِ ويختلُّ التماسكُ. الخطأُ الشائعُ الحكمُ بالتماسكِ لمجرّدِ صحّةِ كلِّ جملةٍ أو ضبطِ أواخرِها.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e6309b55-a724-52af-ba08-e60b4c759424', 'aa88417c-7792-570a-8387-a79993a0da42', 'في نصّ «زرعَ الفلّاحُ القمحَ. سقاهُ حتّى نضجَ. ثمّ حصدَهُ فرِحًا.» — أيُّ العبارات صحيحةٌ تمامًا؟', '[{"id":"a","text":"المُسنَد إليه في الجملة الأولى «القمحَ»، والرابطُ بين الجملِ حرفُ «حتّى» فقط"},{"id":"b","text":"لا نواةَ للجملتين الأخيرتين لأنّهما بلا اسمٍ ظاهرٍ"},{"id":"c","text":"النّصُّ جملةٌ واحدةٌ لا ثلاثُ جملٍ"},{"id":"d","text":"المُسنَد إليه في الجملة الأولى «الفلّاحُ»، والروابطُ: الضميرُ «ه» العائدُ على القمحِ وحرفُ العطفِ «ثمّ» ووحدةُ الموضوعِ"}]'::jsonb, 'd', 'في الجملةِ الأولى المحدَّثُ عنه «الفلّاحُ» (المُسنَد إليه) و«القمحَ» مفعولٌ. والروابطُ: الضميرُ «ه» في «سقاهُ/حصدَهُ» العائدُ على القمحِ، وحرفُ «ثمّ»، ووحدةُ الموضوعِ. الخطأُ الشائعُ عدُّ المفعولِ «القمحَ» مُسنَدًا إليه، أو نفيُ النواةِ عن الجملتين الأخيرتين وإن لم يظهرْ فيهما اسمٌ.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e888fc39-eb4c-5154-a701-46aa16689907', 'aa88417c-7792-570a-8387-a79993a0da42', '«النّحوُ يحفظُ المعنى.» في أيِّ المواقفِ يظهرُ خطرُ إهمالِ النّحو أوضحَ ما يكونُ؟', '[{"id":"a","text":"حين تتشابهُ الكلماتُ في النطقِ"},{"id":"b","text":"حين يجتمعُ في الجملةِ اسمانِ يصلحُ كلٌّ منهما فاعلًا ومفعولًا، فيلتبسُ مَن فعلَ بمن وقعَ عليه الفعلُ لولا ضبطُ الأواخرِ"},{"id":"c","text":"حين تكونُ الجملةُ قصيرةً"},{"id":"d","text":"حين نكتبُ نصًّا طويلًا"}]'::jsonb, 'b', 'يظهرُ خطرُ إهمالِ النّحو حين يصلحُ اسمانِ لأن يكونَ كلٌّ منهما فاعلًا أو مفعولًا (نحو: «ضربَ موسى عيسى»)؛ فلولا ضبطُ الأواخرِ لالتبسَ الفاعلُ بالمفعولِ، وهنا يحفظُ النّحوُ المعنى ويحقّقُ الإفهامَ.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('22b24cbe-d2d7-5428-b05d-1b90793e1d81', 'aa88417c-7792-570a-8387-a79993a0da42', 'أيُّ العبارات التالية صحيحةٌ دون سِواها؟', '[{"id":"a","text":"«كلُّ جملةٍ مفيدةٍ مستقلّةٌ بنواتِها، ومع ذلك ترتبطُ بأخواتِها في النّصّ بروابطَ تحقّقُ الاتّساقَ»"},{"id":"b","text":"«النّصُّ مجموعةُ كلماتٍ مهما كان ترتيبُها»"},{"id":"c","text":"«التركيبُ الإضافيُّ كـ(كتابُ التلميذِ) جملةٌ مفيدةٌ»"},{"id":"d","text":"«غايةُ النّحوِ الزخرفةُ اللفظيّةُ لا الفهمُ والإفهامُ»"}]'::jsonb, 'a', 'الصحيحُ أنّ كلَّ جملةٍ مستقلّةٌ بنواتِها الإسناديّةِ، ومع ذلك ترتبطُ بغيرِها بروابطَ تحقّقُ الاتّساقَ. الباقياتُ خاطئةٌ: النّصُّ يحتاجُ ترتيبًا وروابطَ لا كلماتٍ مبعثرةً، والتركيبُ الإضافيُّ ليس جملةً، وغايةُ النّحو الفهمُ والإفهامُ لا الزخرفةُ.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('beaed189-c1b4-5c78-bbd6-32d2fbd5f4a8', '0bdd292a-4220-5d59-b6fc-70d9b36c8dae', 'arabic-7eme', 'اختبار فهم الدرس ⭐', 1, 20, 5, 'quiz', 'admin', 0)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
