  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2fe4db07-a527-5911-a786-c450372e62d4', 'beaed189-c1b4-5c78-bbd6-32d2fbd5f4a8', '«انتصرَ الفريقُ» جملة:', '[{"id":"a","text":"اسمية، لأنّها تدلّ على معنًى تامّ"},{"id":"b","text":"فعلية، لأنّ نواتها فعل وفاعل"},{"id":"c","text":"اسمية، لأنّها تنتهي باسم"},{"id":"d","text":"فعلية، لأنّ نواتها مبتدأ وخبر"}]'::jsonb, 'b', 'الجملة نواتها «انتصرَ» (فعل) و«الفريقُ» (فاعل)، فهي جملة فعلية. والمسند فيها هو الفعل. أمّا المبتدأ والخبر فهما نواة الجملة الاسمية لا الفعلية.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e07523a3-656d-5843-ba3f-638b766e8ebd', 'beaed189-c1b4-5c78-bbd6-32d2fbd5f4a8', 'المسند إليه في الجملة هو:', '[{"id":"a","text":"المحكوم عليه، أي ما نتحدّث عنه"},{"id":"b","text":"المحكوم به، أي ما نُخبر به"},{"id":"c","text":"المتمّم الذي يُثري المعنى"},{"id":"d","text":"أوّل كلمة في الجملة دائمًا"}]'::jsonb, 'a', 'المسند إليه هو المحكوم عليه، أي ما نتحدّث عنه (الفاعل في الفعلية، والمبتدأ في الاسمية). أمّا المحكوم به الذي نُخبر به فهو المسند.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8fb9af20-a4f9-5dae-bf8c-63cc691f3d63', 'beaed189-c1b4-5c78-bbd6-32d2fbd5f4a8', 'النواة الإسنادية في «قطفَ الفلّاحُ الثمارَ» هي:', '[{"id":"a","text":"الفلّاحُ الثمارَ"},{"id":"b","text":"قطفَ الثمارَ"},{"id":"c","text":"قطفَ الفلّاحُ"},{"id":"d","text":"الثمارَ وحدها"}]'::jsonb, 'c', 'النواة الإسنادية للجملة الفعلية = فعل + فاعل، أي «قطفَ الفلّاحُ». أمّا «الثمارَ» فمفعول به، وهو متمّم يُثري المعنى وليس ركنًا في النواة.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('56e0ee34-dd70-51b3-a39a-6e42b3c89339', 'beaed189-c1b4-5c78-bbd6-32d2fbd5f4a8', 'أيّ الجمل التالية مركّبة (فيها أكثر من نواة)؟', '[{"id":"a","text":"هطلَ المطرُ"},{"id":"b","text":"النخلةُ عاليةٌ"},{"id":"c","text":"طارَ العصفورُ وغرّدَ"},{"id":"d","text":"قرأَ عليٌّ كتابًا مفيدًا"}]'::jsonb, 'c', '«طارَ العصفورُ وغرّدَ» فيها نواتان: (طارَ العصفورُ) و(غرّدَ هو)، فهي مركّبة. أمّا الباقي ففيه نواة واحدة، والجملة «قرأ عليٌّ كتابًا مفيدًا» بسيطة رغم متمّماتها.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('cbc5eda1-de1e-5047-b697-d301e955e844', 'beaed189-c1b4-5c78-bbd6-32d2fbd5f4a8', '«في المساءِ يعودُ الصيّادُ» جملة:', '[{"id":"a","text":"اسمية، لأنّها بدأت باسم مجرور"},{"id":"b","text":"مركّبة، لأنّ فيها ظرفًا ونواة"},{"id":"c","text":"اسمية، لأنّ «المساء» مبتدأ والباقي خبر"},{"id":"d","text":"فعلية، لأنّ نواتها فعل وفاعل: يعودُ الصيّادُ"}]'::jsonb, 'd', 'لا يُعتدّ بالمتقدّم من جارٍّ ومجرور «في المساءِ» في التصنيف؛ العبرة بالنواة، ونواتها «يعودُ الصيّادُ» (فعل + فاعل)، فهي فعلية. والخطأ الشائع أن نظنّها اسمية لأنّها بدأت باسم مجرور.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

