INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a062bf64-8b6a-5d4a-9604-75c832aeeda9', 'b1a24945-4642-5e52-9104-331e7c4627ee', '«سقطتِ الورقةُ» جملة:', '[{"id":"a","text":"فعلية"},{"id":"b","text":"اسمية"},{"id":"c","text":"مركّبة"},{"id":"d","text":"بسيطة اسمية"}]'::jsonb, 'a', 'الجملة بدأت بفعل «سقطتِ» ونواتها فعل وفاعل (سقطتِ الورقةُ)، فهي جملة فعلية بسيطة.', 1)
