INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8ccf1308-aee5-5160-8c69-ff3cb46a7b2a', 'b1a24945-4642-5e52-9104-331e7c4627ee', '«الجوُّ صحوٌ» جملة:', '[{"id":"a","text":"فعلية"},{"id":"b","text":"مركّبة"},{"id":"c","text":"فعلية بسيطة"},{"id":"d","text":"اسمية"}]'::jsonb, 'd', 'الجملة بدأت باسم «الجوُّ» ونواتها مبتدأ وخبر (الجوُّ صحوٌ) ولا فعل فيها، فهي جملة اسمية.', 2)
