INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8ea0abcf-08e9-5a5f-827c-c3ada563e20f', 'b1a24945-4642-5e52-9104-331e7c4627ee', 'المسند في الجملة الفعلية هو:', '[{"id":"a","text":"الفاعل"},{"id":"b","text":"المفعول به"},{"id":"c","text":"الفعل"},{"id":"d","text":"المبتدأ"}]'::jsonb, 'c', 'المسند هو المحكوم به الذي نُخبر به؛ وهو في الجملة الفعلية الفعلُ، وأمّا الفاعل فهو المسند إليه.', 3)
