INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('46232c89-6790-56d5-8ad6-4f8fc40a0da6', 'b1a24945-4642-5e52-9104-331e7c4627ee', 'المسند إليه في الجملة الاسمية هو:', '[{"id":"a","text":"الخبر"},{"id":"b","text":"المبتدأ"},{"id":"c","text":"الفعل"},{"id":"d","text":"الجار والمجرور"}]'::jsonb, 'b', 'المسند إليه هو المحكوم عليه الذي نتحدّث عنه؛ وهو في الجملة الاسمية المبتدأ، وأمّا الخبر فهو المسند.', 4)
