INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7a517d65-2c33-599f-ae54-25c510df6cec', 'b1a24945-4642-5e52-9104-331e7c4627ee', 'الجملة البسيطة هي التي:', '[{"id":"a","text":"فيها نواة إسنادية واحدة"},{"id":"b","text":"فيها أكثر من نواة إسنادية"},{"id":"c","text":"تبدأ باسم دائمًا"},{"id":"d","text":"خلت من الفاعل"}]'::jsonb, 'a', 'الجملة البسيطة تحتوي على نواة إسنادية واحدة؛ فإن زادت النوى صارت مركّبة.', 5)
