INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6496d5b1-45d6-59a2-b359-3e036bd69535', 'b1a24945-4642-5e52-9104-331e7c4627ee', 'في «يلعبُ الأطفالُ الكرةَ»، الكلمة التي تُعدّ متمّمًا (لا ركنًا في النواة) هي:', '[{"id":"a","text":"يلعبُ"},{"id":"b","text":"الأطفالُ"},{"id":"c","text":"الكرةَ"},{"id":"d","text":"يلعبُ الأطفالُ"}]'::jsonb, 'c', 'النواة الإسنادية هي «يلعبُ الأطفالُ» (فعل + فاعل)؛ أمّا «الكرةَ» فمفعول به، وهو متمّم يُثري المعنى ويصحّ حذفُه، وليس من أركان النواة.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
