INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('bf0ef64f-14ab-5acc-816c-df491eaeb9da', '74598b9d-2789-524c-a8ab-16aea41c24d5', 'في «رسمَ التلميذُ لوحةً جميلةً في الحصّةِ»، النواة الإسنادية هي:', '[{"id":"a","text":"رسمَ التلميذُ"},{"id":"b","text":"التلميذُ لوحةً"},{"id":"c","text":"رسمَ لوحةً"},{"id":"d","text":"التلميذُ في الحصّةِ"}]'::jsonb, 'a', 'النواة = فعل + فاعل = «رسمَ التلميذُ». أمّا «لوحةً جميلةً» و«في الحصّةِ» فمتمّمات (مفعول به ونعت وجار ومجرور) تُثري المعنى ولا تدخل في النواة.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f4d4e634-1f46-5339-aa4a-9345b6635150', '74598b9d-2789-524c-a8ab-16aea41c24d5', '«فوقَ الغصنِ يقفُ العصفورُ» جملة:', '[{"id":"a","text":"اسمية، لأنّها بدأت بظرف «فوقَ»"},{"id":"b","text":"مركّبة، لتعدّد الأسماء فيها"},{"id":"c","text":"فعلية، لأنّ نواتها «يقفُ العصفورُ»"},{"id":"d","text":"اسمية، «فوقَ» مبتدأ و«العصفورُ» خبر"}]'::jsonb, 'c', 'لا يُعتدّ بالمتقدّم من ظرفٍ في التصنيف؛ العبرة بالنواة، ونواتها فعل وفاعل «يقفُ العصفورُ»، فهي فعلية. والخطأ الشائع أن نظنّها اسمية لمجرّد أنّها بدأت بظرف، أو أن نعُدّ الظرف مبتدأً.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('60ddc3d4-4c6d-57e9-9a30-ee39f3cffa00', '74598b9d-2789-524c-a8ab-16aea41c24d5', 'كم نواة إسنادية في «أشرقتِ الشمسُ فتفتّحتِ الأزهارُ»؟', '[{"id":"a","text":"نواة واحدة"},{"id":"b","text":"نواتان"},{"id":"c","text":"ثلاث نوى"},{"id":"d","text":"لا نواة فيها"}]'::jsonb, 'b', 'فيها إسنادان: (أشرقتِ الشمسُ) و(تفتّحتِ الأزهارُ)، فهما نواتان؛ ولذلك فالجملة مركّبة. حرف العطف «الفاء» ربط بين النواتين ولا يُعدّ نواةً.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7e23d4de-ed90-5218-a036-ad0b5e6355df', '74598b9d-2789-524c-a8ab-16aea41c24d5', 'أيّ الجمل التالية بسيطة (فيها نواة واحدة)؟', '[{"id":"a","text":"زارَنا الضيفُ وابتسمَ"},{"id":"b","text":"الحديقةُ واسعةٌ وأشجارُها مثمرةٌ"},{"id":"c","text":"نامَ الطفلُ ثمّ استيقظَ"},{"id":"d","text":"اشترى الرجلُ خبزًا طازجًا من الفرنِ"}]'::jsonb, 'd', '«اشترى الرجلُ خبزًا طازجًا من الفرنِ» نواتها واحدة (اشترى الرجلُ) وباقيها متمّمات، فهي بسيطة. أمّا الجمل الأخرى فكلٌّ منها فيه نواتان معطوفتان (زارنا/ابتسم، واسعة/مثمرة، نام/استيقظ)، فهي مركّبة. الخطأ الشائع: عدُّ كثرة الكلمات دليلًا على التركيب، والعبرة إنّما بعدد النوى.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('07d475c9-31c5-5a9b-8a20-b91c4b9097e9', '74598b9d-2789-524c-a8ab-16aea41c24d5', 'في «الكتابُ نافعٌ»، المسند هو:', '[{"id":"a","text":"نافعٌ"},{"id":"b","text":"الكتابُ"},{"id":"c","text":"الكتابُ ونافعٌ معًا"},{"id":"d","text":"لا مسند في الجملة"}]'::jsonb, 'a', 'الجملة اسمية؛ مسندها الخبرُ «نافعٌ» (المحكوم به)، ومسندها إليه المبتدأ «الكتابُ» (المحكوم عليه). فالمسند هو ما نُخبر به عن المبتدأ.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d0a98e4f-765c-539c-85f6-3937a33092e5', '74598b9d-2789-524c-a8ab-16aea41c24d5', 'أيّ كلمة في «عادَ المسافرُ مساءً» يصحّ حذفُها وتبقى الجملةُ تامّةً؟', '[{"id":"a","text":"عادَ"},{"id":"b","text":"المسافرُ"},{"id":"c","text":"مساءً"},{"id":"d","text":"لا يصحّ حذف شيء منها"}]'::jsonb, 'c', '«مساءً» ظرف زمان، وهو متمّم غير ضروري تركيبيًّا؛ يصحّ حذفُه فتبقى «عادَ المسافرُ» جملةً تامّة. أمّا «عادَ» و«المسافرُ» فركنا النواة لا يجوز حذف أحدهما.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('71f1eafc-b2d1-508f-9ec5-59229beff490', '0bdd292a-4220-5d59-b6fc-70d9b36c8dae', 'arabic-7eme', '⭐⭐ تمرين مراجعة (نمط امتحان): صنفا الجملة والمتمّمات', 2, 70, 15, 'practice', 'admin', 3)
ON CONFLICT (id) DO UPDATE SET
