INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7c8d11a5-06bf-5061-af9c-eca229b0d8b1', '71f1eafc-b2d1-508f-9ec5-59229beff490', '«تغرّدُ البلابلُ» جملة:', '[{"id":"a","text":"اسمية"},{"id":"b","text":"مركّبة"},{"id":"c","text":"فعلية"},{"id":"d","text":"بسيطة اسمية"}]'::jsonb, 'c', 'نواتها فعل وفاعل «تغرّدُ البلابلُ»، والمسند فيها الفعل، فهي جملة فعلية بسيطة.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3162846f-f92c-593e-bd5b-6b3f2f878351', '71f1eafc-b2d1-508f-9ec5-59229beff490', '«القمرُ مضيءٌ» جملة:', '[{"id":"a","text":"اسمية"},{"id":"b","text":"فعلية"},{"id":"c","text":"مركّبة"},{"id":"d","text":"فعلية بسيطة"}]'::jsonb, 'a', 'نواتها مبتدأ وخبر «القمرُ مضيءٌ» ولا فعل فيها، فهي جملة اسمية.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
