  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('528016a5-8371-5095-92ec-d8e836fdefa5', '71f1eafc-b2d1-508f-9ec5-59229beff490', 'المسند إليه في «فازَ سميرٌ بالجائزةِ» هو:', '[{"id":"a","text":"فازَ"},{"id":"b","text":"سميرٌ"},{"id":"c","text":"بالجائزةِ"},{"id":"d","text":"الجائزةِ"}]'::jsonb, 'b', 'المسند إليه هو المحكوم عليه؛ وهو هنا الفاعل «سميرٌ». أمّا «فازَ» فمسند، و«بالجائزةِ» جار ومجرور متمّم.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f1bbd8ee-27ab-5f80-a064-210011885b59', '71f1eafc-b2d1-508f-9ec5-59229beff490', 'المتمّم (غير الضروري تركيبيًّا) في «حصدَ الفلّاحُ القمحَ» هو:', '[{"id":"a","text":"حصدَ"},{"id":"b","text":"الفلّاحُ"},{"id":"c","text":"القمحَ"},{"id":"d","text":"لا متمّم في الجملة"}]'::jsonb, 'c', 'النواة «حصدَ الفلّاحُ» (فعل + فاعل)، و«القمحَ» مفعول به، وهو متمّم يُثري المعنى ويصحّ حذفُه فتبقى الجملة تامّة.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('496cacdf-e70b-5052-bf22-4a79e2647b36', '71f1eafc-b2d1-508f-9ec5-59229beff490', 'أيّ الجمل التالية مركّبة؟', '[{"id":"a","text":"ازدحمَ الشارعُ"},{"id":"b","text":"الوردةُ حمراءُ"},{"id":"c","text":"شربَ الولدُ عصيرًا باردًا"},{"id":"d","text":"هبّتِ الريحُ وتمايلتِ الأغصانُ"}]'::jsonb, 'd', '«هبّتِ الريحُ وتمايلتِ الأغصانُ» فيها نواتان معطوفتان، فهي مركّبة. أمّا الباقي ففيه نواة واحدة، والجملة «شربَ الولدُ عصيرًا باردًا» بسيطة رغم متمّميها.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('592fbceb-ebdb-502b-adc0-c5bf1daec5e1', '71f1eafc-b2d1-508f-9ec5-59229beff490', '«في القاعةِ اجتمعَ الطلّابُ» جملة:', '[{"id":"a","text":"اسمية، لأنّها بدأت بجارٍّ ومجرور"},{"id":"b","text":"فعلية، لأنّ نواتها «اجتمعَ الطلّابُ»"},{"id":"c","text":"اسمية، «القاعة» مبتدأ"},{"id":"d","text":"مركّبة، لأنّ فيها ثلاث كلمات"}]'::jsonb, 'b', 'لا يُعتدّ بالجارّ والمجرور المتقدّم «في القاعةِ» في التصنيف؛ العبرة بالنواة، ونواتها فعل وفاعل «اجتمعَ الطلّابُ»، فهي فعلية بسيطة.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('fd7a2043-d9b5-5a40-a657-63c2f1cdb9c8', '0bdd292a-4220-5d59-b6fc-70d9b36c8dae', 'arabic-7eme', '👑 تحدّي النخبة ⭐⭐⭐⭐: دقائق النواة والتركيب', 4, 300, 60, 'challenge', 'admin', 4)
ON CONFLICT (id) DO UPDATE SET
