INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2f8a8f7c-ceac-5a7c-9b80-5ac553e2bd75', 'fd7a2043-d9b5-5a40-a657-63c2f1cdb9c8', 'أيّ العبارات التالية صحيحة؟', '[{"id":"a","text":"المفعول به ركن أساسيّ من النواة الإسنادية"},{"id":"b","text":"الجملة الاسمية لا نواة إسنادية لها"},{"id":"c","text":"المتمّم غير ضروريّ تركيبيًّا لكنّه مفيد معنويًّا"},{"id":"d","text":"الجملة المركّبة فيها نواة إسنادية واحدة"}]'::jsonb, 'c', 'المتمّم (مفعول به، ظرف، جار ومجرور…) يُثري المعنى ولا تقوم عليه بنية الجملة، فيصحّ حذفُه. أمّا الباقي فخطأ: المفعول به متمّم لا ركن، والجملة الاسمية نواتها [مبتدأ + خبر]، والمركّبة فيها أكثر من نواة.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('222feea6-e01d-586d-ade1-f1db75e7061b', 'fd7a2043-d9b5-5a40-a657-63c2f1cdb9c8', 'جملةٌ نواتها [مبتدأ + خبر] وفيها متمّم واحد. أيُّها تطابق الوصف؟', '[{"id":"a","text":"الطريقُ إلى المدرسةِ طويلٌ"},{"id":"b","text":"طلعَ الفجرُ"},{"id":"c","text":"كتبَ سميرٌ رسالةً طويلةً"},{"id":"d","text":"نجحَ الطالبُ وفرِحَ أهلُه"}]'::jsonb, 'a', '«الطريقُ … طويلٌ» نواة اسمية [مبتدأ + خبر]، و«إلى المدرسةِ» جار ومجرور متمّم واحد. «طلعَ الفجرُ» فعلية بلا متمّم، و«كتبَ سميرٌ…» فعلية، و«نجحَ الطالبُ وفرِحَ أهلُه» مركّبة.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f7b5f05d-1492-5671-b45e-99312b5804d9', 'fd7a2043-d9b5-5a40-a657-63c2f1cdb9c8', 'حلّل تلميذٌ الجملة «شاهدَ الجمهورُ المباراةَ» فقال: النواة «شاهدَ الجمهورُ»، والمتمّم «المباراةَ»، والجملة فعلية بسيطة، والمسند إليه «المباراةَ». أين الخطأ؟', '[{"id":"a","text":"النواة ليست «شاهدَ الجمهورُ»"},{"id":"b","text":"«المباراةَ» ليست متمّمًا بل ركنًا"},{"id":"c","text":"الجملة اسمية لا فعلية"},{"id":"d","text":"المسند إليه هو «الجمهورُ» لا «المباراةَ»"}]'::jsonb, 'd', 'التحليل صحيح كلّه إلّا تعيين المسند إليه: المسند إليه هو المحكوم عليه (الفاعل) «الجمهورُ»، لا المفعول به «المباراةَ». (السؤال من نمط «تصحيح الخطأ»، فالجواب الصحيح هو الخطوة الخاطئة.)', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('30a19047-879d-5770-b1cb-9b2082a6e632', 'fd7a2043-d9b5-5a40-a657-63c2f1cdb9c8', '«صباحًا يفتحُ التاجرُ متجرَه، ومساءً يُغلقُه». هذه الجملة:', '[{"id":"a","text":"بسيطة فعلية، لأنّها بدأت بظرف"},{"id":"b","text":"بسيطة اسمية، «صباحًا» مبتدأ"},{"id":"c","text":"مركّبة، لأنّ فيها نواتين فعليّتين"},{"id":"d","text":"مركّبة اسمية، لتقدّم الظرف"}]'::jsonb, 'c', 'فيها إسنادان: (يفتحُ التاجرُ) و(يُغلقُه هو)، فهما نواتان والجملة مركّبة. الظرفان «صباحًا» و«مساءً» متمّمان متقدّمان لا يغيّران العدّ. الخطأ الشائع: الحكم بالبساطة لمجرّد بدء الجملة بظرف.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('36f22f3d-2d49-58c1-8a83-bdc9b2ed2b05', 'fd7a2043-d9b5-5a40-a657-63c2f1cdb9c8', 'الجملتان: (1) «عادَ الغائبُ» و(2) «عادَ الغائبُ وسُرَّ الأهلُ». الفرق بينهما أنّ:', '[{"id":"a","text":"الأولى اسمية والثانية فعلية"},{"id":"b","text":"الأولى بسيطة (نواة واحدة) والثانية مركّبة (نواتان)"},{"id":"c","text":"الأولى مركّبة والثانية بسيطة"},{"id":"d","text":"كلتيهما بسيطة"}]'::jsonb, 'b', 'الأولى فيها نواة واحدة (عادَ الغائبُ) فهي بسيطة، والثانية أُضيفت إليها نواة معطوفة (وسُرَّ الأهلُ) فصارت نواتين، فهي مركّبة. وكلتاهما فعلية، فالتصنيف بسيطة/مركّبة يقوم على عدد النوى لا على الصنف.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e111adfe-18fc-5cc3-84f7-933f116c60ee', 'fd7a2043-d9b5-5a40-a657-63c2f1cdb9c8', 'في «يحترمُ التلاميذُ معلّمَهم»، المسند إليه (المحكوم عليه) هو:', '[{"id":"a","text":"يحترمُ"},{"id":"b","text":"معلّمَهم"},{"id":"c","text":"الاحترامُ"},{"id":"d","text":"التلاميذُ"}]'::jsonb, 'd', 'المسند إليه هو الفاعل «التلاميذُ» (المحكوم عليه). «يحترمُ» مسند (فعل)، و«معلّمَهم» مفعول به متمّم. الخطأ الشائع: جعل المفعول به «معلّمَهم» مسندًا إليه لأنّه اسم ظاهر.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('19acb44a-d779-58a3-93da-d0ad82b7aaff', '0bdd292a-4220-5d59-b6fc-70d9b36c8dae', 'arabic-7eme', '📝 تدريب ⭐⭐⭐: مراجعة شاملة على الجملة البسيطة', 3, 120, 30, 'boss', 'admin', 5)
