INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d72db787-5e15-5f80-b10f-d48515bd6633', '19acb44a-d779-58a3-93da-d0ad82b7aaff', 'المسند في «السماءُ صافيةٌ» هو:', '[{"id":"a","text":"صافيةٌ"},{"id":"b","text":"السماءُ"},{"id":"c","text":"السماءُ وصافيةٌ معًا"},{"id":"d","text":"لا مسند فيها"}]'::jsonb, 'a', 'الجملة اسمية؛ مسندها الخبرُ «صافيةٌ» (المحكوم به)، ومسندها إليه المبتدأ «السماءُ» (المحكوم عليه).', 1)
