  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5aae668f-8c13-592a-93c3-0dee9f3c69ee', '19acb44a-d779-58a3-93da-d0ad82b7aaff', 'النواة الإسنادية في «يزرعُ الفلّاحُ الأشجارَ في الربيعِ» هي:', '[{"id":"a","text":"يزرعُ الأشجارَ"},{"id":"b","text":"الفلّاحُ الأشجارَ"},{"id":"c","text":"يزرعُ الفلّاحُ"},{"id":"d","text":"الأشجارَ في الربيعِ"}]'::jsonb, 'c', 'النواة = فعل + فاعل = «يزرعُ الفلّاحُ». أمّا «الأشجارَ» فمفعول به، و«في الربيعِ» جار ومجرور؛ وكلاهما متمّم لا يدخل في النواة.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('47de4e8b-4eb9-5cb0-b7c5-bf64cc786352', '19acb44a-d779-58a3-93da-d0ad82b7aaff', 'كم نواة إسنادية في «سطعَ البرقُ وقصفَ الرعدُ وانهمرَ المطرُ»؟', '[{"id":"a","text":"نواة واحدة"},{"id":"b","text":"أربع نوى"},{"id":"c","text":"نواتان"},{"id":"d","text":"ثلاث نوى"}]'::jsonb, 'd', 'فيها ثلاثة إسنادات: (سطعَ البرقُ) و(قصفَ الرعدُ) و(انهمرَ المطرُ)، فهي ثلاث نوى، والجملة مركّبة. حروف العطف «الواو» تربط النوى ولا تُعدّ منها.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f5514813-b957-5ec3-92bc-1de6aa5adc1c', '19acb44a-d779-58a3-93da-d0ad82b7aaff', '«تحتَ الجسرِ يجري النهرُ» جملة:', '[{"id":"a","text":"اسمية، لأنّها بدأت بظرف «تحتَ»"},{"id":"b","text":"فعلية، لأنّ نواتها «يجري النهرُ»"},{"id":"c","text":"اسمية، «النهرُ» مبتدأ مؤخّر"},{"id":"d","text":"مركّبة، لتعدّد كلماتها"}]'::jsonb, 'b', 'لا يُعتدّ بالظرف المتقدّم «تحتَ الجسرِ»؛ العبرة بالنواة، ونواتها فعل وفاعل «يجري النهرُ»، فهي فعلية بسيطة.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2e4dea88-4db0-57b5-b473-3cc6d0c0d065', '19acb44a-d779-58a3-93da-d0ad82b7aaff', 'الكلمة التي يصحّ حذفُها من «سافرَ الحاجُّ برًّا» وتبقى الجملة تامّةً:', '[{"id":"a","text":"برًّا"},{"id":"b","text":"سافرَ"},{"id":"c","text":"الحاجُّ"},{"id":"d","text":"لا شيء منها"}]'::jsonb, 'a', '«برًّا» متمّم (حال/تمييز في المعنى) يُثري الخبر ويصحّ حذفُه فتبقى «سافرَ الحاجُّ» جملة تامّة. أمّا «سافرَ» و«الحاجُّ» فركنا النواة لا يُحذف أحدهما.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ba10208f-ebac-5ed9-a2eb-24733d31fd45', '19acb44a-d779-58a3-93da-d0ad82b7aaff', 'أيّ الجمل التالية بسيطة (نواة واحدة)؟', '[{"id":"a","text":"لمعَ النجمُ واختفى"},{"id":"b","text":"الجوُّ حارٌّ والبحرُ مالحٌ"},{"id":"c","text":"دخلَ المعلّمُ ثمّ بدأَ الدرسَ"},{"id":"d","text":"قطعَ الحطّابُ غصنًا يابسًا بفأسِه"}]'::jsonb, 'd', '«قطعَ الحطّابُ غصنًا يابسًا بفأسِه» نواتها واحدة (قطعَ الحطّابُ) وباقيها متمّمات، فهي بسيطة. أمّا الباقي ففي كلٍّ منه نواتان معطوفتان، فهي مركّبة. العبرة بعدد النوى لا بكثرة الكلمات.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('2d2966d4-0d8c-5247-80b8-f340ec649ec4', '0bdd292a-4220-5d59-b6fc-70d9b36c8dae', 'arabic-7eme', '👑 تحدّي النخبة ⭐⭐⭐⭐: سقف الفصل في تحليل الجملة', 4, 300, 60, 'challenge', 'admin', 6)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d63e1d3d-c9f7-564a-b6bc-6dcd4cf197b6', '2d2966d4-0d8c-5247-80b8-f340ec649ec4', 'أيّ العبارات التالية **خاطئة**؟', '[{"id":"a","text":"قد تبدأ الجملة الفعلية بمتمّم متقدّم كالظرف"},{"id":"b","text":"كلُّ جملة فيها أكثر من نواة تُسمّى بسيطة"},{"id":"c","text":"المسند إليه في الجملة الفعلية هو الفاعل"},{"id":"d","text":"الخبر مسندٌ في الجملة الاسمية"}]'::jsonb, 'b', 'العبارة الخاطئة: ما فيه أكثر من نواة يُسمّى مركّبًا لا بسيطًا؛ فالبسيطة نواة واحدة. أمّا الباقي فصحيح: قد يتقدّم المتمّم على النواة، والمسند إليه في الفعلية هو الفاعل، والخبر مسند في الاسمية. (السؤال بصيغة النفي: المطلوب العبارة الخاطئة.)', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6c7302ee-ad0c-527f-900e-ddcbcf567b4f', '2d2966d4-0d8c-5247-80b8-f340ec649ec4', 'جملةٌ فعلية بسيطة فيها متمّمان اثنان. أيُّها تطابق الوصف؟', '[{"id":"a","text":"شربَ الطفلُ الحليبَ صباحًا"},{"id":"b","text":"الحقيبةُ ثقيلةٌ"},{"id":"c","text":"لعبَ الأطفالُ وضحكوا"},{"id":"d","text":"الشمسُ ساطعةٌ والجوُّ دافئٌ"}]'::jsonb, 'a', '«شربَ الطفلُ الحليبَ صباحًا» نواة فعلية واحدة (شربَ الطفلُ) ومعها متمّمان: «الحليبَ» (مفعول به) و«صباحًا» (ظرف). «الحقيبةُ ثقيلةٌ» اسمية بلا متمّمين، و«لعبَ الأطفالُ وضحكوا» و«الشمسُ ساطعةٌ والجوُّ دافئٌ» مركّبتان (نواتان).', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6fcb6612-3ffa-590f-971f-5af16a8d8ccc', '2d2966d4-0d8c-5247-80b8-f340ec649ec4', 'حلّل تلميذٌ «في الملعبِ تدرّبَ اللاعبونَ بجدٍّ» فقال: الجملة اسمية لأنّها بدأت بـ«في الملعبِ»، ونواتها «الملعبِ»، والمتمّم «بجدٍّ». حدّد الخطأ الرئيس:', '[{"id":"a","text":"«بجدٍّ» ليست متمّمًا بل نواة"},{"id":"b","text":"الجملة مركّبة لا بسيطة"},{"id":"c","text":"الجملة فعلية ونواتها «تدرّبَ اللاعبونَ»؛ لا يُعتدّ بالجارّ والمجرور المتقدّم"},{"id":"d","text":"«الملعبِ» مبتدأ صحيح والتحليل سليم"}]'::jsonb, 'c', 'الخطأ الرئيس تصنيفها اسمية وجعل «الملعبِ» نواةً؛ فالجارّ والمجرور «في الملعبِ» متمّم متقدّم لا يُعتدّ به، والنواة فعل وفاعل «تدرّبَ اللاعبونَ»، فالجملة فعلية بسيطة و«بجدٍّ» متمّم فعلًا. (نمط تصحيح الخطأ: الجواب هو الخطوة الخاطئة.)', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7a8ae675-a4c1-59af-a4c1-08a8417b000f', '2d2966d4-0d8c-5247-80b8-f340ec649ec4', 'أيّ التغييرات يحوّل «حضرَ الضيوفُ» من جملة بسيطة إلى مركّبة؟', '[{"id":"a","text":"إضافة مفعول: «حضرَ الضيوفُ الحفلَ»"},{"id":"b","text":"إضافة ظرف: «حضرَ الضيوفُ مساءً»"},{"id":"c","text":"إضافة نعت: «حضرَ الضيوفُ الكرامُ»"},{"id":"d","text":"عطف نواة: «حضرَ الضيوفُ وابتهجَ المضيفُ»"}]'::jsonb, 'd', 'التركيب يقوم على تعدّد النوى؛ فعطف نواة جديدة «وابتهجَ المضيفُ» يجعل الجملة مركّبة (نواتان). أمّا إضافة مفعول أو ظرف أو نعت فمجرّد متمّمات تُبقي النواة واحدة، فتظلّ الجملة بسيطة. الخطأ الشائع: ظنّ أنّ زيادة أيّ كلمة تُركّب الجملة.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e1e7db01-5b84-553a-b7e2-318286a9ac4f', '2d2966d4-0d8c-5247-80b8-f340ec649ec4', 'في «في البيتِ ضيوفٌ»، المسند إليه (المبتدأ) هو:', '[{"id":"a","text":"ضيوفٌ"},{"id":"b","text":"البيتِ"},{"id":"c","text":"في"},{"id":"d","text":"في البيتِ"}]'::jsonb, 'a', 'الجملة اسمية (لا فعل فيها)، والمسند إليه هو المبتدأ «ضيوفٌ» (المحكوم عليه)، وشبه الجملة «في البيتِ» مسند مقدّم يُخبَر به عنه. الخطأ الشائع: عدُّ «البيتِ» مبتدأً لأنّه أوّل اسم ظاهر.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f0a97751-59f3-55df-b344-e06f0886275b', '2d2966d4-0d8c-5247-80b8-f340ec649ec4', '«عندما هطلَ المطرُ، عادَ الفلّاحونَ إلى بيوتِهم». عدد النوى وصنف التركيب:', '[{"id":"a","text":"نواة واحدة، جملة بسيطة"},{"id":"b","text":"نواتان، جملة مركّبة"},{"id":"c","text":"ثلاث نوى، جملة مركّبة"},{"id":"d","text":"نواتان، جملة بسيطة"}]'::jsonb, 'b', 'فيها إسنادان: (هطلَ المطرُ) و(عادَ الفلّاحونَ)، فهما نواتان، فالجملة مركّبة. «إلى بيوتِهم» جار ومجرور متمّم لا نواة. الخطأ الشائع: عدُّ المتمّم «إلى بيوتِهم» نواةً ثالثة.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('b5cd95af-79c9-5ce8-bd84-3ca41d0022ca', 'e25e5f18-2234-57fb-87eb-8a6900f161fe', 'arabic-7eme', 'اختبار فهم الدرس ⭐', 1, 20, 5, 'quiz', 'admin', 0)
