INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3c6a6808-b4ae-5090-9352-bebc577d96c6', 'b5cd95af-79c9-5ce8-bd84-3ca41d0022ca', 'الفعل كلمة تدلّ على:', '[{"id":"a","text":"حدثٍ مقترن بزمن"},{"id":"b","text":"ذاتٍ ثابتة لا زمن لها"},{"id":"c","text":"صفةٍ للاسم فقط"},{"id":"d","text":"رابطٍ بين جملتين"}]'::jsonb, 'a', 'الفعل يدلّ على حدث (عمل أو حالة أو صفة) مقترن بزمن ماضٍ أو حاضر أو مستقبل، بخلاف الاسم الذي يدلّ على ذات لا زمن لها.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2d6b8984-d74d-5cfa-a02a-3224c2510ff6', 'b5cd95af-79c9-5ce8-bd84-3ca41d0022ca', '«فرِحَ الولدُ» — الفعل «فرِحَ» يدلّ على:', '[{"id":"a","text":"عمل ظاهر يقوم به الفاعل"},{"id":"b","text":"حالة يشعر بها الفاعل"},{"id":"c","text":"صفة ثابتة كالطول"},{"id":"d","text":"زمن مستقبل فقط"}]'::jsonb, 'b', '«فرِحَ» انفعال داخليّ يشعر به الفاعل، فهو من الأفعال الدّالّة على حالة، مثل حزِنَ وخافَ.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8c02ca1b-c6fc-5418-b471-7357a1577100', 'b5cd95af-79c9-5ce8-bd84-3ca41d0022ca', 'الفعل اللازم هو الذي:', '[{"id":"a","text":"يحتاج إلى مفعولين دائمًا"},{"id":"b","text":"يُحذف فاعله دائمًا"},{"id":"c","text":"يكتفي بفاعله ولا ينصب مفعولًا به"},{"id":"d","text":"يأتي في زمن الماضي فقط"}]'::jsonb, 'c', 'الفعل اللازم يتمّ معناه بفاعله ولا يحتاج مفعولًا به، مثل: جلسَ الضّيفُ، وسافرَ أخي.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('60e9b033-c9d5-5df8-9d69-1254277c17cc', 'b5cd95af-79c9-5ce8-bd84-3ca41d0022ca', '«كتبَ التّلميذُ الدّرسَ» — الفعل «كتبَ» فعلٌ:', '[{"id":"a","text":"لازم يكتفي بفاعله"},{"id":"b","text":"متعدٍّ إلى مفعول واحد"},{"id":"c","text":"متعدٍّ إلى مفعولين"},{"id":"d","text":"مبنيّ للمجهول"}]'::jsonb, 'b', '«كتبَ» نصب مفعولًا به واحدًا هو «الدّرسَ»، فهو متعدٍّ إلى مفعول واحد.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('48933ab1-cbf7-5e5e-8ee6-d17c119c3818', 'b5cd95af-79c9-5ce8-bd84-3ca41d0022ca', 'المبنيّ للمجهول فعلٌ:', '[{"id":"a","text":"ذُكِر فاعله ومفعوله معًا"},{"id":"b","text":"لا فاعل له ولا مفعول أصلًا"},{"id":"c","text":"يدلّ على المستقبل حتمًا"},{"id":"d","text":"حُذِف فاعله وحلّ المفعول به محلّه"}]'::jsonb, 'd', 'في المبنيّ للمجهول يُحذف الفاعل ويقوم المفعول به مقامه، كقولنا: كُسِرَ الزّجاجُ (دون ذكر الكاسر).', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
