INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b6a653c5-fc2f-5ef0-b94a-b666e225de4b', '104e191a-f9bb-50ab-a9d8-40d0e65ff71e', 'أيّ الكلمات التّالية فعل؟', '[{"id":"a","text":"ذهبَ"},{"id":"b","text":"كتابٌ"},{"id":"c","text":"جميلٌ"},{"id":"d","text":"تحتَ"}]'::jsonb, 'a', '«ذهبَ» تدلّ على حدث في زمن ماضٍ فهي فعل، أمّا «كتابٌ» و«جميلٌ» فاسمان، و«تحتَ» ظرف (اسم).', 1)
