INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3823fd67-3601-5543-bcf3-0fa115dc3cec', '104e191a-f9bb-50ab-a9d8-40d0e65ff71e', '«أخذَ الرّجلُ الحقيبةَ» — الفعل «أخذَ» يدلّ على:', '[{"id":"a","text":"عمل قام به الفاعل"},{"id":"b","text":"حالة شعوريّة"},{"id":"c","text":"صفة ثابتة"},{"id":"d","text":"اسم جامد"}]'::jsonb, 'a', '«أخذَ» فعلٌ ظاهر يُنجزه الفاعل، فهو من الأفعال الدّالّة على عمل، مثل ألقى وركضَ.', 2)
