  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('879d64ca-6ca5-5bd4-a713-92dcb605115d', '104e191a-f9bb-50ab-a9d8-40d0e65ff71e', '«كبُرَ الغلامُ» — الفعل «كبُرَ» يدلّ على:', '[{"id":"a","text":"عمل يقوم به الفاعل"},{"id":"b","text":"حالة يشعر بها الفاعل"},{"id":"c","text":"حرف لا معنى له"},{"id":"d","text":"صفة اتّصف بها الفاعل"}]'::jsonb, 'd', '«كبُرَ» يدلّ على وصفٍ يثبت للفاعل (الكِبَر)، فهو من الأفعال الدّالّة على صفة، مثل حسُنَ وكرُمَ.', 3)
