  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8e9c87df-bfb1-5b1f-ba03-bc27d815c128', '104e191a-f9bb-50ab-a9d8-40d0e65ff71e', 'الفعل الذي يكتفي بفاعله ولا يحتاج مفعولًا به يسمّى:', '[{"id":"a","text":"متعدّيًا"},{"id":"b","text":"لازمًا"},{"id":"c","text":"مجهولًا"},{"id":"d","text":"جامدًا"}]'::jsonb, 'b', 'الفعل اللازم يتمّ معناه بفاعله دون مفعول به، مثل جلسَ ونامَ، بخلاف المتعدّي الذي ينصب مفعولًا به.', 4)
