  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8aeecae4-abd5-5f65-b241-86f2404a3750', '104e191a-f9bb-50ab-a9d8-40d0e65ff71e', 'أيّ الأفعال التّالية متعدٍّ (يحتاج مفعولًا به)؟', '[{"id":"a","text":"جلسَ"},{"id":"b","text":"نامَ"},{"id":"c","text":"وصلَ"},{"id":"d","text":"شربَ"}]'::jsonb, 'd', '«شربَ» يحتاج مفعولًا به يقع عليه الحدث (شربَ الماءَ)، أمّا جلسَ ونامَ ووصلَ فأفعال لازمة تكتفي بفاعلها.', 5)
