INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('396b00e1-1490-5697-bbd4-c4ec66fd7e13', '104e191a-f9bb-50ab-a9d8-40d0e65ff71e', '«كُسِرَ الزّجاجُ» — الفعل «كُسِرَ»:', '[{"id":"a","text":"مبنيّ للمعلوم"},{"id":"b","text":"لازم"},{"id":"c","text":"مبنيّ للمجهول"},{"id":"d","text":"اسم"}]'::jsonb, 'c', '«كُسِرَ» بُني على صيغة فُعِلَ (ضمّ الأوّل وكسر ما قبل الآخر)، فقد حُذِف فاعله وحلّ «الزّجاجُ» محلّه، فهو مبنيّ للمجهول.', 6)
ON CONFLICT (id) DO UPDATE SET
