  ('80531155-bdfe-5cb5-8e44-5418ae9f6606', 'e25e5f18-2234-57fb-87eb-8a6900f161fe', 'arabic-7eme', '⚔️ زعيم الفصل ⭐⭐⭐: اللزوم والتّعدية والبناء للمجهول', 3, 120, 30, 'boss', 'admin', 2)
