INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0dda91c2-89fd-5db7-8e08-fdd11f596862', '80531155-bdfe-5cb5-8e44-5418ae9f6606', '«سافرَ التّاجرُ إلى المدينةِ» — الفعل «سافرَ»:', '[{"id":"a","text":"متعدٍّ لأنّ بعده «المدينةِ»"},{"id":"b","text":"لازم تعدّى بحرف الجرّ"},{"id":"c","text":"متعدٍّ إلى مفعولين"},{"id":"d","text":"مبنيّ للمجهول"}]'::jsonb, 'b', '«سافرَ» فعل لازم يكتفي بفاعله، و«المدينةِ» اسم مجرور بحرف الجرّ «إلى» لا مفعول به. الخطأ الشّائع عدّه متعدّيًا لوجود اسم بعده، والمتعدّي الحقّ ينصب مفعولًا به بلا واسطة.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e2fbdcad-cc7b-5a2b-aa4b-f6aa4e0c48ee', '80531155-bdfe-5cb5-8e44-5418ae9f6606', '«منحَ الأستاذُ التّلميذَ جائزةً» — الفعل «منحَ» فعلٌ:', '[{"id":"a","text":"لازم"},{"id":"b","text":"متعدٍّ إلى مفعول واحد"},{"id":"c","text":"متعدٍّ إلى مفعولين"},{"id":"d","text":"مبنيّ للمجهول"}]'::jsonb, 'c', '«منحَ» نصب مفعولين بعد فاعله هما «التّلميذَ» و«جائزةً»، فهو متعدٍّ إلى مفعولين، مثل أعطى ومنعَ.', 2)
ON CONFLICT (id) DO UPDATE SET
