  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('335257ab-cb1d-5e80-a016-43037d095c6c', '80531155-bdfe-5cb5-8e44-5418ae9f6606', 'صياغة المبنيّ للمجهول من الفعل الماضي «فَهِمَ» هي:', '[{"id":"a","text":"فُهِمَ"},{"id":"b","text":"فَهُمَ"},{"id":"c","text":"فُهُمَ"},{"id":"d","text":"يُفهَم"}]'::jsonb, 'a', 'في الماضي نضمّ الأوّل ونكسر ما قبل الآخر على صيغة فُعِلَ: فَهِمَ ← فُهِمَ. أمّا «يُفهَم» فهو المضارع لا الماضي.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('36a80649-7c41-5921-b93a-549689eb1ff1', '80531155-bdfe-5cb5-8e44-5418ae9f6606', 'تحويل «يَشرَبُ الطّفلُ الحليبَ» إلى المبنيّ للمجهول:', '[{"id":"a","text":"يُشرَبُ الحليبُ"},{"id":"b","text":"يَشرُبُ الحليبُ"},{"id":"c","text":"شُرِبَ الحليبُ"},{"id":"d","text":"يُشرِبُ الحليبُ"}]'::jsonb, 'a', 'في المضارع نضمّ الأوّل ونفتح ما قبل الآخر على صيغة يُفْعَل: يَشرَبُ ← يُشرَبُ، ويحلّ «الحليبُ» محلّ الفاعل المحذوف. الخطأ الشّائع كسر ما قبل الآخر (يُشرِبُ) أو تحويله إلى ماضٍ (شُرِبَ).', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e9737174-7d20-5d17-9c84-ba29c0e984ec', '80531155-bdfe-5cb5-8e44-5418ae9f6606', 'ماذا يحدث حين نبني الفعل المتعدّي للمجهول؟', '[{"id":"a","text":"يُحذف المفعول به من الجملة"},{"id":"b","text":"يتحوّل الفعل إلى اسم"},{"id":"c","text":"يبقى الفاعل ويُحذف المفعول"},{"id":"d","text":"يُحذف الفاعل ويحلّ المفعول به محلّه"}]'::jsonb, 'd', 'البناء للمجهول يحذف الفاعل، فيرتفع المفعول به ليقوم مقامه، كما في: كُسِرَ الزّجاجُ. الخطأ الشّائع ظنّ أنّ المفعول به هو الذي يُحذف.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('14dbe00c-dee3-506d-8bc7-a34b96743aa7', '80531155-bdfe-5cb5-8e44-5418ae9f6606', 'أراد تلميذ بناء الفعل «كَتَبَ» للمجهول فقال «كُتَبَ». أين وجه الصّواب؟', '[{"id":"a","text":"الصّواب ضمّ الأوّل فقط، و«كُتَبَ» صحيحة"},{"id":"b","text":"الصّواب «كَتُبَ» بفتح الأوّل وضمّ ما قبل الآخر"},{"id":"c","text":"الصّواب «كُتِبَ» بضمّ الأوّل وكسر ما قبل الآخر"},{"id":"d","text":"لا خطأ، فـ«كُتَبَ» صياغة صحيحة"}]'::jsonb, 'c', 'لا يكفي ضمّ الأوّل؛ فقاعدة الماضي المجهول ضمّ الأوّل وكسر ما قبل الآخر: كَتَبَ ← كُتِبَ. الخطأ الشّائع هو فتح ما قبل الآخر (كُتَبَ) بدل كسره.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

