INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e191a7f4-647a-5823-b453-4e009a07e8af', '477722a7-e180-5049-a87c-6a01dc8ecd0a', '«حزِنَ المسافرُ» — الفعل «حزِنَ» يدلّ على:', '[{"id":"a","text":"حالة يشعر بها الفاعل"},{"id":"b","text":"عمل يقوم به الفاعل"},{"id":"c","text":"صفة ثابتة"},{"id":"d","text":"زمن مضارع"}]'::jsonb, 'a', '«حزِنَ» انفعال داخليّ يشعر به الفاعل، فهو من الأفعال الدّالّة على حالة، مثل فرِحَ وخافَ.', 1)
