INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e4bf8151-1d33-585b-95f7-dd335035b200', '477722a7-e180-5049-a87c-6a01dc8ecd0a', '«أعطى الجدُّ الحفيدَ هديّةً» — درجة تعدية «أعطى»:', '[{"id":"a","text":"لازم لا ينصب مفعولًا"},{"id":"b","text":"متعدٍّ إلى مفعول واحد"},{"id":"c","text":"مبنيّ للمجهول"},{"id":"d","text":"متعدٍّ إلى مفعولين"}]'::jsonb, 'd', '«أعطى» نصب مفعولين بعد فاعله هما «الحفيدَ» و«هديّةً»، فهو متعدٍّ إلى مفعولين، مثل منحَ ومنعَ.', 3)
