INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('65c1a3fe-ed4d-59a5-8988-e71256f9dc16', '477722a7-e180-5049-a87c-6a01dc8ecd0a', 'ما الفرق بين «الفعل» و«المركّب الفعليّ»؟', '[{"id":"a","text":"لا فرق بينهما"},{"id":"b","text":"الفعل كلمة واحدة، والمركّب الفعليّ الفعل مع متمّماته"},{"id":"c","text":"المركّب الفعليّ كلمة واحدة، والفعل جملة"},{"id":"d","text":"الفعل اسم، والمركّب الفعليّ حرف"}]'::jsonb, 'b', 'الفعل كلمة مفردة تدلّ على الحدث، والمركّب الفعليّ هو الفعل مع فاعله ومتمّماته؛ ففي «قرأَ الطّالبُ كتابًا» الفعل «قرأَ» جزءٌ من المركّب الفعليّ كلّه.', 5)
