INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4e239303-08a6-585c-b3fa-7309afb87a17', 'c3eb28f7-ba07-54d5-a5b3-15a1d95d5d76', 'أيّ العبارات التّالية صحيحة في وصف الفعل «فرِحَ»؟', '[{"id":"a","text":"فعل لازم يدلّ على حالة"},{"id":"b","text":"فعل متعدٍّ إلى مفعولين"},{"id":"c","text":"فعل مبنيّ للمجهول"},{"id":"d","text":"فعل يدلّ على صفة ثابتة كالطول"}]'::jsonb, 'a', '«فرِحَ» يدلّ على انفعال داخليّ (حالة)، وهو لازم يكتفي بفاعله (فرِحَ الولدُ). ليس متعدّيًا ولا مجهولًا، ودلالته على حالةٍ لا على صفةٍ ثابتة.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('06987696-e07f-5719-bbcd-58f2f9a0d367', 'c3eb28f7-ba07-54d5-a5b3-15a1d95d5d76', 'تحويل «منحَ المديرُ الفائزَ جائزةً» إلى المبنيّ للمجهول:', '[{"id":"a","text":"مُنِحَ الفائزُ جائزةً"},{"id":"b","text":"مَنُحَ الفائزُ جائزةً"},{"id":"c","text":"مُنِحَ المديرُ الفائزَ"},{"id":"d","text":"يُمنَح الفائزُ جائزةً"}]'::jsonb, 'a', 'نبني الماضي على صيغة فُعِلَ: مَنَحَ ← مُنِحَ، ونحذف الفاعل «المديرُ»، فيحلّ المفعول الأوّل «الفائزُ» محلّه ويرتفع، ويبقى «جائزةً» منصوبًا. الخطأ الشّائع تحويله إلى مضارع (يُمنَح) أو إبقاء الفاعل.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('573188b4-91fc-5c3f-91fd-0f22f4e3fb0f', 'c3eb28f7-ba07-54d5-a5b3-15a1d95d5d76', 'عند بناء الفعل المتعدّي إلى مفعولين للمجهول، ما الذي يحلّ محلّ الفاعل المحذوف؟', '[{"id":"a","text":"المفعول به الثّاني"},{"id":"b","text":"المفعول به الأوّل"},{"id":"c","text":"حرف الجرّ"},{"id":"d","text":"الفعل نفسه"}]'::jsonb, 'b', 'يحلّ المفعول به الأوّل محلّ الفاعل المحذوف فيرتفع، ويبقى المفعول الثّاني منصوبًا: منحَ المديرُ الفائزَ جائزةً ← مُنِحَ الفائزُ جائزةً.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6610b5a1-6056-5a71-87ec-c1dc29629838', 'c3eb28f7-ba07-54d5-a5b3-15a1d95d5d76', 'بُنِيَ «يَفتَحُ» للمجهول فصار «يُفتَحُ». فمن بنى «يَكتُبُ» فقال «يُكتُبُ» أخطأ؛ فما الصّواب؟', '[{"id":"a","text":"«يُكتُبُ» صحيحة"},{"id":"b","text":"«يَكتَبُ»"},{"id":"c","text":"«يُكتَبُ» بضمّ الأوّل وفتح ما قبل الآخر"},{"id":"d","text":"«كُتِبَ»"}]'::jsonb, 'c', 'قاعدة المضارع المجهول ضمّ الأوّل وفتح ما قبل الآخر على صيغة يُفْعَل: يَكتُبُ ← يُكتَبُ. الخطأ الشّائع إبقاء ضمّة ما قبل الآخر (يُكتُبُ)، و«كُتِبَ» ماضٍ لا مضارع.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4c17f272-e455-5b31-ad23-31435a503a1a', 'c3eb28f7-ba07-54d5-a5b3-15a1d95d5d76', 'في أيّ جملة الفعل متعدٍّ ينصب مفعولًا به بلا واسطة حرف جرّ؟', '[{"id":"a","text":"رغِبَ المتعلّمُ في النّجاحِ"},{"id":"b","text":"أرادَ المتعلّمُ النّجاحَ"},{"id":"c","text":"وصلَ المتعلّمُ إلى القاعةِ"},{"id":"d","text":"جلسَ المتعلّمُ في الصّفِّ"}]'::jsonb, 'b', '«أرادَ» نصب المفعول به «النّجاحَ» مباشرةً فهو متعدٍّ. أمّا رغِبَ ووصلَ فلازمان تعدّيا بحرف جرّ (في، إلى)، وجلسَ لازم. الخطأ الشّائع عدّ ما بعد حرف الجرّ مفعولًا به.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('680ef22c-55e3-5286-a342-8e9a861d7864', 'c3eb28f7-ba07-54d5-a5b3-15a1d95d5d76', '«استقبلَ الأميرُ الضّيوفَ» — الفعل «استقبلَ» من حيث النّوع والتّعدية:', '[{"id":"a","text":"حالة، لازم"},{"id":"b","text":"صفة، لازم"},{"id":"c","text":"عمل، متعدٍّ إلى مفعولين"},{"id":"d","text":"عمل، متعدٍّ إلى مفعول واحد"}]'::jsonb, 'd', '«استقبلَ» عملٌ ظاهر يقوم به الفاعل، ونصب مفعولًا به واحدًا هو «الضّيوفَ»، فهو متعدٍّ إلى مفعول واحد، لا حالة ولا صفة ولا لازم.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

