INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('dab7f97d-ad08-50ec-ae8c-c01e26984a03', 'db8f4f0d-ca16-54f6-a678-c671eb2b0304', '«حسُنَ خُلقُ الرّجلِ» — الفعل «حسُنَ» يدلّ على:', '[{"id":"a","text":"صفة اتّصف بها الفاعل"},{"id":"b","text":"عمل يقوم به الفاعل"},{"id":"c","text":"حالة يشعر بها الفاعل"},{"id":"d","text":"حرف لا معنى له"}]'::jsonb, 'a', '«حسُنَ» يدلّ على وصفٍ يثبت للفاعل (الحُسْن)، فهو من الأفعال الدّالّة على صفة، مثل كبُرَ وكرُمَ.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
