  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0f5598eb-1d19-5315-9dc2-c1508340b64f', 'db8f4f0d-ca16-54f6-a678-c671eb2b0304', 'أيّ الأفعال التّالية متعدٍّ ينصب مفعولًا به؟', '[{"id":"a","text":"قعدَ"},{"id":"b","text":"نصرَ"},{"id":"c","text":"جلسَ"},{"id":"d","text":"نامَ"}]'::jsonb, 'b', '«نصرَ» ينصب مفعولًا به يقع عليه الحدث (نصرَ القائدُ جيشَه)، أمّا قعدَ وجلسَ ونامَ فأفعال لازمة تكتفي بفاعلها.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
