  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8408d12c-268b-5355-829f-40066b8a22dd', 'db8f4f0d-ca16-54f6-a678-c671eb2b0304', '«ظننتُ الجوَّ صحوًا» — الفعل «ظنّ»:', '[{"id":"a","text":"لازم لا ينصب مفعولًا"},{"id":"b","text":"متعدٍّ إلى مفعولين"},{"id":"c","text":"متعدٍّ إلى مفعول واحد"},{"id":"d","text":"مبنيّ للمجهول"}]'::jsonb, 'b', '«ظنّ» نصب مفعولين هما «الجوَّ» و«صحوًا»، فهو متعدٍّ إلى مفعولين، مثل حسِبَ وأعطى.', 3)
