INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('cdce2775-1fcb-553e-ae2c-047e456ac913', 'db8f4f0d-ca16-54f6-a678-c671eb2b0304', 'صياغة المبنيّ للمجهول من الفعل الماضي «شَرَحَ»:', '[{"id":"a","text":"شَرُحَ"},{"id":"b","text":"شُرُحَ"},{"id":"c","text":"شُرِحَ"},{"id":"d","text":"يُشرَح"}]'::jsonb, 'c', 'في الماضي نضمّ الأوّل ونكسر ما قبل الآخر على صيغة فُعِلَ: شَرَحَ ← شُرِحَ. الخطأ الشّائع ضمّ ما قبل الآخر (شُرُحَ)، و«يُشرَح» مضارع لا ماضٍ.', 4)
ON CONFLICT (id) DO UPDATE SET
