  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f27a8baa-13ee-574a-a8f2-425dd5c42fd4', 'db8f4f0d-ca16-54f6-a678-c671eb2b0304', 'تحويل «يَفتَحُ الحارسُ البابَ» إلى المبنيّ للمجهول:', '[{"id":"a","text":"يُفتَحُ البابُ"},{"id":"b","text":"يَفتُحُ البابُ"},{"id":"c","text":"فُتِحَ البابُ"},{"id":"d","text":"يُفتِحُ البابُ"}]'::jsonb, 'a', 'في المضارع نضمّ الأوّل ونفتح ما قبل الآخر على صيغة يُفْعَل: يَفتَحُ ← يُفتَحُ، ويحلّ «البابُ» محلّ الفاعل. الخطأ الشّائع كسر ما قبل الآخر (يُفتِحُ) أو التّحويل إلى ماضٍ (فُتِحَ).', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('18ef8439-a6f3-5b84-85ee-cc4d9919845c', 'db8f4f0d-ca16-54f6-a678-c671eb2b0304', 'عند بناء الفعل للمجهول، ما مصير المفعول به؟', '[{"id":"a","text":"يُحذف من الجملة"},{"id":"b","text":"يبقى منصوبًا كما هو"},{"id":"c","text":"يتحوّل إلى حرف جرّ"},{"id":"d","text":"يرتفع ويقوم مقام الفاعل المحذوف"}]'::jsonb, 'd', 'عند البناء للمجهول يُحذف الفاعل فيرتفع المفعول به ليقوم مقامه: كسرَ اللاعبُ الزّجاجَ ← كُسِرَ الزّجاجُ. الخطأ الشّائع ظنّ أنّ المفعول به يبقى منصوبًا أو يُحذف.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
