INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('eb73e35a-c255-54ae-aee0-ddc3724f7af1', '8f60cd8a-1ef5-5c63-b4a4-71d7f2dd361b', 'أيّ الأفعال التّالية لازمٌ لا ينصب مفعولًا به أبدًا؟', '[{"id":"a","text":"بنى"},{"id":"b","text":"كسا"},{"id":"c","text":"نامَ"},{"id":"d","text":"منحَ"}]'::jsonb, 'c', '«نامَ» يكتفي بفاعله فهو لازم. أمّا بنى (بنى العاملُ البيتَ) وكسا ومنحَ فأفعال متعدّية تنصب مفعولًا به أو مفعولين.', 1)
