INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('df05d4ae-f7b7-5f24-a253-67ab5c31f6ce', '8f60cd8a-1ef5-5c63-b4a4-71d7f2dd361b', '«كرُمَ الرّجلُ» — الفعل «كرُمَ» من حيث النّوع والتّعدية:', '[{"id":"a","text":"عمل، متعدٍّ"},{"id":"b","text":"صفة، لازم"},{"id":"c","text":"حالة، متعدٍّ إلى مفعولين"},{"id":"d","text":"مبنيّ للمجهول"}]'::jsonb, 'b', '«كرُمَ» يدلّ على صفةٍ تثبت للفاعل (الكرم)، وهو لازم يكتفي بفاعله ولا ينصب مفعولًا به، وليس مبنيًّا للمجهول.', 2)
ON CONFLICT (id) DO UPDATE SET
