INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2f326914-0d37-529a-9bde-c4cabc66edc1', '8f60cd8a-1ef5-5c63-b4a4-71d7f2dd361b', '«منعَ الحارسُ الزّائرَ الدّخولَ» فعلٌ متعدٍّ إلى مفعولين. فما صورته عند البناء للمجهول؟', '[{"id":"a","text":"مُنِعَ الزّائرُ الدّخولَ"},{"id":"b","text":"مَنُعَ الزّائرُ الدّخولَ"},{"id":"c","text":"مُنِعَ الحارسُ الزّائرَ"},{"id":"d","text":"يُمنَع الزّائرُ الدّخولَ"}]'::jsonb, 'a', 'نبني الماضي على صيغة فُعِلَ: مَنَعَ ← مُنِعَ، ونحذف الفاعل «الحارسُ»، فيرتفع المفعول الأوّل «الزّائرُ» ويبقى «الدّخولَ» منصوبًا. الخطأ الشّائع تحويله إلى مضارع (يُمنَع) أو إبقاء الفاعل.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
