INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d763adfc-0687-5e38-bbaf-ce5df2c00c32', '8f60cd8a-1ef5-5c63-b4a4-71d7f2dd361b', 'في أيّ جملة الفعل لازمٌ تعدّى بحرف جرّ (وليس متعدّيًا بنفسه)؟', '[{"id":"a","text":"كتبَ الشّاعرُ قصيدةً"},{"id":"b","text":"رغِبَ الشّاعرُ في الشّهرةِ"},{"id":"c","text":"أنشدَ الشّاعرُ قصيدةً"},{"id":"d","text":"ألقى الشّاعرُ خطبةً"}]'::jsonb, 'b', '«رغِبَ» فعل لازم تعدّى إلى «الشّهرةِ» بحرف الجرّ «في»، فالاسم بعده مجرور لا مفعول به. أمّا كتبَ وأنشدَ وألقى فمتعدّية نصبت مفعولها مباشرةً. الخطأ الشّائع عدّ المجرور مفعولًا به.', 4)
ON CONFLICT (id) DO UPDATE SET
