INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('706873a1-c960-54f8-a09a-95da3390b4da', '8f60cd8a-1ef5-5c63-b4a4-71d7f2dd361b', 'أيّ التّحويلات التّالية إلى المبنيّ للمجهول صحيحٌ؟', '[{"id":"a","text":"فَتَحَ ← فَتُحَ"},{"id":"b","text":"يَعلَمُ ← يُعلِم"},{"id":"c","text":"نَصَرَ ← نُصِرَ"},{"id":"d","text":"أَخَذَ ← أُخَذَ"}]'::jsonb, 'c', 'الماضي المجهول على صيغة فُعِلَ (ضمّ الأوّل وكسر ما قبل الآخر): نَصَرَ ← نُصِرَ. والصّواب في البقيّة: فُتِحَ، ويُعلَم (فتح ما قبل الآخر في المضارع)، وأُخِذَ.', 5)
