INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a0a2f1c2-371d-530f-b3fa-ba0eda40627c', '8f60cd8a-1ef5-5c63-b4a4-71d7f2dd361b', 'في جملة «فُهِمَ الدّرسُ»، أيّ وصفٍ يجمع الصّواب كلّه؟', '[{"id":"a","text":"فعل مضارع مبنيّ للمعلوم"},{"id":"b","text":"فعل لازم لا مفعول له أصلًا"},{"id":"c","text":"فعل متعدٍّ إلى مفعولين"},{"id":"d","text":"فعل ماضٍ مبنيّ للمجهول حُذِف فاعله"}]'::jsonb, 'd', '«فُهِمَ» ماضٍ بُني للمجهول على صيغة فُعِلَ، حُذِف فاعله فحلّ المفعول به «الدّرسُ» محلّه. وأصله متعدٍّ إلى مفعول واحد لا مفعولين، وليس لازمًا ولا مضارعًا.', 6)
