INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3df6f035-56df-5d70-bb57-8a38d2e58ad2', '71130d45-e898-5b05-ae42-6f1ff5b262d6', 'أيّ الكلمات التّالية مؤنّثة رغم خلوّها من علامة تأنيث ظاهرة؟', '[{"id":"a","text":"قلمٌ"},{"id":"b","text":"أرضٌ"},{"id":"c","text":"بابٌ"},{"id":"d","text":"كتابٌ"}]'::jsonb, 'b', '«أرضٌ» مؤنّثة رغم خلوّها من علامة تأنيث ظاهرة، وتُعرف بالسّماع، أمّا البقيّة فأسماء مذكّرة.', 2)
