INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d479e5c0-b0cb-57e4-9bdf-d70a9d41dd60', '71130d45-e898-5b05-ae42-6f1ff5b262d6', '«ـــــ مجتهدون في دروسكم» — الضّمير المناسب:', '[{"id":"a","text":"هم"},{"id":"b","text":"نحن"},{"id":"c","text":"أنتنّ"},{"id":"d","text":"أنتم"}]'::jsonb, 'd', '«أنتم» ضمير رفع منفصل لجماعة الذّكور المخاطَبين، يوافق «مجتهدون» جمع مذكّر.', 3)
