INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('59498ba9-b30e-59ac-bf96-f57212a63637', '71130d45-e898-5b05-ae42-6f1ff5b262d6', '«ـــــ ساعةً تدرسُ يوميًّا؟» — الأداة المناسبة:', '[{"id":"a","text":"كم"},{"id":"b","text":"كيف"},{"id":"c","text":"أين"},{"id":"d","text":"متى"}]'::jsonb, 'a', '«كم» يُستعمل للسّؤال عن العدد (عدد السّاعات)، لا «كيف» للحال ولا «أين» للمكان ولا «متى» للزّمان.', 5)
