INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('37ab2f04-8baa-5b30-9c33-ba2c788c0e02', '12dd8be3-ab92-5c7a-8f09-61d1d3451530', 'أيّ الجمل التّالية تحوي اسم إشارة للبعيد؟', '[{"id":"a","text":"هذا كتابي"},{"id":"b","text":"تلك حديقتُنا"},{"id":"c","text":"هؤلاء أصدقائي"},{"id":"d","text":"هذه سيّارتي"}]'::jsonb, 'b', '«تلك» اسم إشارة للمفرد المؤنّث البعيد، بخلاف بقيّة الجمل التي تشير إلى القريب (هذا، هؤلاء، هذه).', 1)
