INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4fd18056-2478-5cbf-8c40-99cf924ba2f5', '12dd8be3-ab92-5c7a-8f09-61d1d3451530', '«جارتي التي سافرت أمس هي معلّمة» — نوع الاسم الموصول ومطابقته:', '[{"id":"a","text":"مفرد مؤنّث، يطابق «جارتي»"},{"id":"b","text":"مثنّى مؤنّث"},{"id":"c","text":"جمع مؤنّث"},{"id":"d","text":"مفرد مذكّر"}]'::jsonb, 'a', 'الاسم الموصول يطابق ما قبله؛ «جارتي» مفردة مؤنّثة، فيُستعمل معها «التي» وهي للمفرد المؤنّث.', 2)
