INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8b1e9a33-75d5-5aa9-a131-3f74d3cb804d', '12dd8be3-ab92-5c7a-8f09-61d1d3451530', '«الرّجلان ـــــ سافرا أمس صديقاي» — الاسم الموصول المناسب لمثنّى مذكّر:', '[{"id":"a","text":"الذي"},{"id":"b","text":"الذين"},{"id":"c","text":"اللذان"},{"id":"d","text":"اللتان"}]'::jsonb, 'c', '«اللذان» اسم موصول للمثنّى المذكّر، يطابق «الرّجلان»، لا «الذي» الخاصّ بالمفرد ولا «اللتان» للمثنّى المؤنّث.', 3)
