INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('358bd396-0c30-5f5b-aab9-be6acd13a1cb', '12dd8be3-ab92-5c7a-8f09-61d1d3451530', 'قال تلميذٌ: «رأيتُ الفتياتِ الذي نجحْنَ في الامتحان». أين الخطأ؟', '[{"id":"a","text":"لا خطأ في الجملة"},{"id":"b","text":"الصّواب استعمال «اللاتي» بدل «الذي»"},{"id":"c","text":"الصّواب حذف الاسم الموصول من الجملة"},{"id":"d","text":"الصّواب استعمال «اللذان» بدل «الذي»"}]'::jsonb, 'b', '«الفتيات» جمع مؤنّث، فالصّواب استعمال الاسم الموصول «اللاتي» لا «الذي» الخاصّ بالمفرد المذكّر؛ هذا خطأ شائع عند إهمال المطابقة.', 4)
