  ('199781cd-7d49-578d-b5dc-314dbe8249cd', '12dd8be3-ab92-5c7a-8f09-61d1d3451530', '«أخي وأختي ذهبا إلى السّوق» — أيّ ضميرٍ منفصل يمكن أن يحلّ محلّ «أخي وأختي» معًا؟', '[{"id":"a","text":"هما"},{"id":"b","text":"هم"},{"id":"c","text":"هي"},{"id":"d","text":"أنتما"}]'::jsonb, 'a', '«هما» ضمير الغائبَين المنفصل، يصلح للمذكّر والمؤنّث معًا، أمّا «هم» فللجمع و«هي» للمفردة و«أنتما» للمخاطَبَين لا الغائبَين.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
