INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0731c36c-aab6-53e5-884c-c2fc1bd0a761', '99226f6b-742b-54ac-af6e-a76194194f81', '«زرتُ المدينةَ التي وُلِدَ فيها جدّي قديمًا» — عيّن ظرف الزّمان في الجملة:', '[{"id":"a","text":"فيها"},{"id":"b","text":"قديمًا"},{"id":"c","text":"المدينةَ"},{"id":"d","text":"جدّي"}]'::jsonb, 'b', '«قديمًا» ظرف زمان يجيب عن سؤال «متى؟»، أمّا «فيها» فضمير عائد على جملة الصّلة لا ظرف.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('41cb5360-6a9d-510c-9ccc-b36323319bf3', '99226f6b-742b-54ac-af6e-a76194194f81', '«ابنتي وابنُ جارتي ذهبا معًا، وسلّمتُ عليهما» — الضّمير «هما» في «عليهما» يعود على:', '[{"id":"a","text":"ابنتي وحدها"},{"id":"b","text":"ابن جارتي وحده"},{"id":"c","text":"ابنتي وابن جارتي معًا"},{"id":"d","text":"الجارة"}]'::jsonb, 'c', '«هما» ضمير المثنّى الغائب، يعود على اثنين مذكّرًا ومؤنّثًا معًا هنا: ابنتي وابن جارتي.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e82467c4-aa30-59a1-a461-2670eb5d0507', '99226f6b-742b-54ac-af6e-a76194194f81', 'أيّ الجمل التّالية تخطئ في مطابقة اسم الإشارة لما بعده؟', '[{"id":"a","text":"هذا الولدُ مجتهدٌ"},{"id":"b","text":"هذه البنتُ مؤدّبةٌ"},{"id":"c","text":"هؤلاء التّلاميذُ يجتهدون"},{"id":"d","text":"هذا التّلميذاتُ نشيطاتٌ"}]'::jsonb, 'd', 'الصّواب «هؤلاء التّلميذاتُ نشيطاتٌ» لأنّهنّ جمع، فلا يصحّ استعمال «هذا» الخاصّ بالمفرد المذكّر معهنّ.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('17c84a32-355d-5fe4-8a83-341965710059', '99226f6b-742b-54ac-af6e-a76194194f81', 'حلّل تلميذٌ الجملة «الفتاتان اللتان نجحتا كافأهما المدير» فقال: العائد هو «كافأ». أين وجه الخطأ في تحليله؟', '[{"id":"a","text":"الصّواب أنّ العائد هو الألف في «نجحتا» العائدة على «اللتان»"},{"id":"b","text":"لا خطأ، العائد صحيح"},{"id":"c","text":"الصّواب أنّه لا عائد في الجملة"},{"id":"d","text":"الصّواب أنّ العائد هو «المدير»"}]'::jsonb, 'a', 'العائد يكون داخل جملة الصّلة نفسها؛ هنا جملة الصّلة «نجحتا» وعائدها ألف الاثنين العائدة على «اللتان»، أمّا «كافأهما» فخبرٌ خارج جملة الصّلة.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0daf2ac3-8ea1-5c02-9696-684cc1d866f1', '99226f6b-742b-54ac-af6e-a76194194f81', 'أيّ العبارات التّالية عن الضّمير **خاطئة**؟', '[{"id":"a","text":"الضّمير المنفصل يُنطق مستقلًّا بذاته"},{"id":"b","text":"كلّ ضمير متّصل بفعلٍ يقع فاعلًا حتمًا"},{"id":"c","text":"الضّمير المتّصل قد يدلّ على المِلكيّة إذا اتّصل باسم"},{"id":"d","text":"«أنتم» ضمير رفع منفصل لجماعة الذّكور المخاطَبين"}]'::jsonb, 'b', 'العبارة خاطئة لأنّ الضّمير المتّصل بالفعل قد يقع فاعلًا (كتبتُ) أو مفعولًا به (ساعدَني)، فلا يكون فاعلًا حتمًا.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

