INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9be8ac33-5df5-51b7-b4c9-aafe422e883b', '8ad74553-d003-5ea1-b0f1-43dad720f34d', 'الاسمُ الّذي يدلّ على شيءٍ غير معيّن يُسمّى:', '[{"id":"a","text":"نكرة"},{"id":"b","text":"معرفة"},{"id":"c","text":"اسم إشارة"},{"id":"d","text":"ضميرًا"}]'::jsonb, 'a', 'النّكرة تدلّ على شيءٍ شائعٍ غير معيّن بذاته، كـ«رجل» أو «كتاب»، بخلاف المعرفة الّتي تعيّن شيئًا بذاته.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
