INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5424efac-d63b-5965-b155-dc6009421d7e', '8ad74553-d003-5ea1-b0f1-43dad720f34d', 'أيّ الأسماء الآتية معرفة؟', '[{"id":"a","text":"رجلٌ"},{"id":"b","text":"خالدٌ"},{"id":"c","text":"كتابٌ"},{"id":"d","text":"مدينةٌ"}]'::jsonb, 'b', '«خالد» علمٌ يدلّ على شخصٍ معيّن بذاته فهو معرفة، أمّا البقيّة فأسماءٌ نكرة شائعة.', 2)
