  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9a192321-4d65-5284-9e2a-e3c876044ef8', '8ad74553-d003-5ea1-b0f1-43dad720f34d', '«كتابُ خالدٍ» — سبب تعريف «كتاب» هنا هو:', '[{"id":"a","text":"دخول «أل» عليه"},{"id":"b","text":"كونه علمًا"},{"id":"c","text":"إضافته إلى معرفة (خالد)"},{"id":"d","text":"كونه ضميرًا"}]'::jsonb, 'c', '«كتاب» نكرةٌ أُضيفت إلى العلم «خالد» وهو معرفة، فاكتسبت تعريفه؛ فأصبح «كتاب خالد» معرفة بالإضافة.', 3)
ON CONFLICT (id) DO UPDATE SET
