  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3e4da635-557a-5ab1-b46d-0bba1b4a9559', '8ad74553-d003-5ea1-b0f1-43dad720f34d', 'الاسم المُعرَب هو الّذي:', '[{"id":"a","text":"تلزم حركة آخره حالةً واحدة"},{"id":"b","text":"لا يقبل الحركة أصلًا"},{"id":"c","text":"يكون فعلًا دائمًا"},{"id":"d","text":"تتغيّر حركة آخره بتغيّر موقعه"}]'::jsonb, 'd', 'الاسم المُعرَب تتغيّر حركة آخره تبعًا لموقعه من الجملة (رفعًا ونصبًا وجرًّا)، بخلاف المبنيّ الّذي تلزم حركته حالةً واحدة.', 4)
ON CONFLICT (id) DO UPDATE SET
