  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5fbc4101-cb15-5570-a5b1-38067f0d2456', '8ad74553-d003-5ea1-b0f1-43dad720f34d', '«جاء الطّالبُ / رأيتُ الطّالبَ / مررتُ بالطّالبِ» — هذا التّغيّر في حركة «الطّالب» دليلٌ على أنّه:', '[{"id":"a","text":"اسمٌ مبنيّ"},{"id":"b","text":"اسمٌ معرب"},{"id":"c","text":"اسم إشارة"},{"id":"d","text":"ضمير"}]'::jsonb, 'b', 'تغيّر حركة آخر «الطّالب» (ضمّة، فتحة، كسرة) بتغيّر موقعه من الجملة دليلٌ قاطعٌ على أنّه اسمٌ معرب.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

