INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a0166922-c023-5730-8a62-63b1052efdf0', '8c1acff0-d0d4-503f-aa84-e208ab78a1ec', 'أيّ الأسماء التّالية نكرة؟', '[{"id":"a","text":"قلمٌ"},{"id":"b","text":"سعادُ"},{"id":"c","text":"هذا"},{"id":"d","text":"الّذي"}]'::jsonb, 'a', '«قلم» اسمٌ شائعٌ غير معيّن بذاته فهو نكرة، أمّا سعاد فعلمٌ، وهذا اسم إشارة، والّذي اسمٌ موصول — وكلّها معارف.', 1)
