INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('504e599a-9031-52a3-bc1c-2d2171ce89b6', '8c1acff0-d0d4-503f-aa84-e208ab78a1ec', 'أيّ الكلمات الآتية اسم إشارة؟', '[{"id":"a","text":"هذا"},{"id":"b","text":"الكتابُ"},{"id":"c","text":"خالدٌ"},{"id":"d","text":"رجلٌ"}]'::jsonb, 'a', '«هذا» يدلّ على مشارٍ إليه بلفظه فهو اسم إشارة، أمّا الكتاب فمعرَّفٌ بأل، وخالد علم، ورجل نكرة.', 3)
