INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('dcec15b7-1ad6-5d43-bba1-72370a92def8', '8c1acff0-d0d4-503f-aa84-e208ab78a1ec', 'الاسم الموصول من بين هذه الكلمات هو:', '[{"id":"a","text":"هو"},{"id":"b","text":"هذه"},{"id":"c","text":"الّتي"},{"id":"d","text":"متى"}]'::jsonb, 'c', '«الّتي» تدلّ على معيّن بواسطة جملة الصّلة بعدها فهي اسم موصول، أمّا «هو» ضمير، و«هذه» اسم إشارة، و«متى» اسم استفهام.', 4)
