INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('29fd3050-c210-5f8c-ab45-530b18804856', '8c1acff0-d0d4-503f-aa84-e208ab78a1ec', '«القمرُ منيرٌ» — سبب تعريف «القمر» هنا:', '[{"id":"a","text":"كونه علمًا"},{"id":"b","text":"كونه ضميرًا"},{"id":"c","text":"إضافته إلى معرفة"},{"id":"d","text":"دخول «أل» عليه"}]'::jsonb, 'd', '«القمر» نكرةٌ في أصله (قمرٌ)، دخلت عليه «أل» فحوّلته معرفة، وهذا هو التّعريف بأل.', 5)
