INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1311e3e9-31b2-5e76-89e1-e04e2eea33ee', '8c1acff0-d0d4-503f-aa84-e208ab78a1ec', 'أيّ الجمل التّالية تحتوي اسمًا مبنيًّا؟', '[{"id":"a","text":"قرأ الطّالبُ الدّرسَ"},{"id":"b","text":"جاء هذا الرّجلُ"},{"id":"c","text":"نجح المجتهدُ"},{"id":"d","text":"الشّمسُ ساطعةٌ"}]'::jsonb, 'b', '«هذا» اسم إشارة مبنيّ تلزم حركته حالةً واحدة، أمّا بقيّة الأسماء في الجمل الأخرى (الطّالب، الدّرس، المجتهد، الشّمس) معربة.', 6)
