  ('9f72ddc5-d6a8-5bbe-9fa1-e2d2545317f0', '75cba66f-2438-53d4-abe1-7872a242c2ca', 'arabic-7eme', '⚔️ زعيم الفصل ⭐⭐⭐: تمييزُ المعرفة والمُعرَب', 3, 120, 30, 'boss', 'admin', 2)
