INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('50debc13-eba9-5ed5-bbb8-a93dd8898726', '9f72ddc5-d6a8-5bbe-9fa1-e2d2545317f0', '«كتابُ تلميذٍ» — هذا التّركيب:', '[{"id":"a","text":"معرفة لأنّه مضاف"},{"id":"b","text":"نكرة لأنّ المضاف إليه نكرة"},{"id":"c","text":"معرفة لأنّه علم"},{"id":"d","text":"نكرة لدخول «أل» عليه"}]'::jsonb, 'b', 'الإضافة وحدها لا تكفي للتّعريف، بل يجب أن يكون المضاف إليه معرفة؛ و«تلميذ» نكرة فبقي التّركيب نكرة. الخطأ الشّائع اعتبار كلّ مضاف معرفة بمجرّد الإضافة.', 1)
