INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ced5ae01-2ea0-5930-89ca-9202f2314d69', '9f72ddc5-d6a8-5bbe-9fa1-e2d2545317f0', '«مررتُ بأولئك الرّجالِ» — كلمة «أولئك»:', '[{"id":"a","text":"نكرة"},{"id":"b","text":"اسم معرب لأنّه مجرور"},{"id":"c","text":"اسم مبنيّ (اسم إشارة)"},{"id":"d","text":"علم"}]'::jsonb, 'c', 'أسماء الإشارة كلّها مبنيّة ولو وقعت في موضع الجرّ، فحركة آخرها لا تتغيّر بتغيّر الموقع. الخطأ الشّائع ظنّ أنّ دخول حرف الجرّ يجعلها معربة.', 2)
