INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('831b2c0d-7f7e-5811-9a0e-26c145de21b8', '9f72ddc5-d6a8-5bbe-9fa1-e2d2545317f0', '«سلّمتُ على المعلّمِ» — علامة جرّ «المعلّم» هي:', '[{"id":"a","text":"الفتحة"},{"id":"b","text":"الضمّة"},{"id":"c","text":"السّكون"},{"id":"d","text":"الكسرة"}]'::jsonb, 'd', 'الاسم المعرب المفرد يُجرّ بالكسرة، وهي العلامة الأصليّة للجرّ، وقد ظهرت هنا بعد حرف الجرّ «على».', 3)
ON CONFLICT (id) DO UPDATE SET
