  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('690c9a35-8955-5576-a3a5-6ab412f6d08d', '9f72ddc5-d6a8-5bbe-9fa1-e2d2545317f0', '«مَن حضرَ الاجتماعَ؟» — «مَن» هنا مبتدأٌ له محلّ رفعٍ؛ فهل هي معربة أم مبنيّة؟', '[{"id":"a","text":"مبنيّة على السّكون رغم أنّها في محلّ رفعٍ"},{"id":"b","text":"معربة لأنّها تؤدّي وظيفةً نحويّة (مبتدأ)"},{"id":"c","text":"معربة بالضمّة"},{"id":"d","text":"مبنيّة لكنّها لا تؤدّي وظيفةً نحويّة"}]'::jsonb, 'a', 'الخطأ الشّائع الظّنّ أنّ أداء وظيفةٍ نحويّة (كالابتداء) يستلزم الإعراب؛ لكنّ اسم الاستفهام «مَن» مبنيّ دائمًا، وإنّما يكون له محلّ إعرابيّ (هنا الرّفع) دون أن تتغيّر حركته.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('73b45112-8125-5610-819c-6e2f5708a639', '9f72ddc5-d6a8-5bbe-9fa1-e2d2545317f0', 'أيّ العبارات التّالية معرفة بالإضافة إلى معرفة؟', '[{"id":"a","text":"بابُ بيتٍ"},{"id":"b","text":"قلمُ التّلميذِ"},{"id":"c","text":"صوتُ طائرٍ"},{"id":"d","text":"رائحةُ زهرةٍ"}]'::jsonb, 'b', '«قلم» أُضيف إلى «التّلميذ» المعرَّف بـ«أل» (معرفة)، فاكتسب تعريفه؛ أمّا البقيّة فأُضيفت إلى نكرات فبقيت نكرة.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3cc02bbd-852b-5c00-9176-ed94602701cc', '9f72ddc5-d6a8-5bbe-9fa1-e2d2545317f0', '«هذانِ الطّالبانِ مجتهدانِ» — خلافًا لعموم أسماء الإشارة، فإنّ «هذانِ» هنا:', '[{"id":"a","text":"نكرة غير معرفة"},{"id":"b","text":"مبنيّ على الفتح"},{"id":"c","text":"اسمٌ معرب لأنّه مثنًّى"},{"id":"d","text":"لا يدلّ على شيء معيّن"}]'::jsonb, 'c', 'عموم أسماء الإشارة مبنيّة، لكنّ المثنّى منها («هذانِ»/«هاتانِ») يخرج عن هذا الأصل فيُعرب، بخلاف «هذا» و«هذه» وسائر أسماء الإشارة المفردة والجمع.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

