  ('4231274e-15e8-5a96-a8c5-74aaa5919501', '75cba66f-2438-53d4-abe1-7872a242c2ca', 'arabic-7eme', '⭐⭐ تمرين مراجعة (نمط امتحان): النّكرة والمعرفة والمُعرَب والمبنيّ', 2, 70, 15, 'practice', 'admin', 3)
