INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9c8081fe-8b70-5077-b1a9-1b5c659e489a', '4231274e-15e8-5a96-a8c5-74aaa5919501', 'الضّمير نوعٌ من:', '[{"id":"a","text":"النّكرة"},{"id":"b","text":"المعرفة"},{"id":"c","text":"الحرف"},{"id":"d","text":"لا نوع له"}]'::jsonb, 'b', 'الضّمير (أنا، أنتَ، هو...) اسمٌ يدلّ على متكلّمٍ أو مخاطبٍ أو غائبٍ، وهو أحد أنواع المعرفة السّتّة.', 1)
