INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('369efab0-c688-50d2-951d-bc5523eb9983', '4231274e-15e8-5a96-a8c5-74aaa5919501', 'أيّ الأسماء التّالية اسمٌ مبنيّ؟', '[{"id":"a","text":"نحن"},{"id":"b","text":"القلمُ"},{"id":"c","text":"خالدٌ"},{"id":"d","text":"الكتابُ"}]'::jsonb, 'a', '«نحن» ضميرٌ، والضّمائر كلّها مبنيّة تلزم حركة آخرها حالةً واحدة، أمّا البقيّة أسماء معربة.', 2)
