INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a257e06a-f6e5-5b85-a436-b7af95fb5e0a', '4231274e-15e8-5a96-a8c5-74aaa5919501', '«هذه الحديقةُ جميلةٌ» — كلمة «هذه»:', '[{"id":"a","text":"نكرة"},{"id":"b","text":"معرفة، علم"},{"id":"c","text":"معرفة، اسم إشارة"},{"id":"d","text":"معرفة، ضمير"}]'::jsonb, 'c', '«هذه» تدلّ على مشارٍ إليه بلفظه فهي معرفة من نوع اسم الإشارة.', 3)
