INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f1e999eb-6908-5ba3-b91c-457a5de4fc38', '4231274e-15e8-5a96-a8c5-74aaa5919501', '«بيتُ الجارِ قريبٌ» — سبب تعريف «بيت» هنا:', '[{"id":"a","text":"دخول «أل» عليه"},{"id":"b","text":"كونه علمًا"},{"id":"c","text":"كونه اسم إشارة"},{"id":"d","text":"إضافته إلى معرفة (الجار)"}]'::jsonb, 'd', '«بيت» نكرةٌ أُضيفت إلى «الجار» المعرَّف بأل (معرفة)، فاكتسبت تعريفه بالإضافة.', 4)
