INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8012fdbd-05e3-5953-89d6-d8893b8769b6', '4231274e-15e8-5a96-a8c5-74aaa5919501', '«نجحَ التّلميذُ» — علامة رفع «التّلميذ»:', '[{"id":"a","text":"الضّمّة"},{"id":"b","text":"الفتحة"},{"id":"c","text":"الكسرة"},{"id":"d","text":"السّكون"}]'::jsonb, 'a', 'الاسم المعرب المفرد يُرفع بالضمّة، وهي العلامة الأصليّة للرّفع، وقد ظهرت هنا على «التّلميذ» الفاعل.', 5)
