INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a29bf742-ea84-5056-8606-c927c0fa920b', '4231274e-15e8-5a96-a8c5-74aaa5919501', 'أيّ الأسماء التّالية اسمٌ مبنيّ؟', '[{"id":"a","text":"الطّالبُ"},{"id":"b","text":"الّذي"},{"id":"c","text":"البيتُ"},{"id":"d","text":"الحديقةُ"}]'::jsonb, 'b', '«الّذي» اسمٌ موصول، والأسماء الموصولة مبنيّة (عدا مثنّاها)، أمّا البقيّة أسماء معربة معرَّفة بأل.', 6)
