INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('412518af-f85f-56be-a771-b7be78addaef', '75cba66f-2438-53d4-abe1-7872a242c2ca', 'arabic-7eme', '👑 تحدّي النخبة ⭐⭐⭐⭐: النّكرة والمعرفة والمُعرَب والمبنيّ', 4, 300, 60, 'challenge', 'admin', 4)
