INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0003f943-961e-5578-9bf5-9a55c353aa93', '412518af-f85f-56be-a771-b7be78addaef', 'أيّ العبارات التّالية صحيحة؟', '[{"id":"a","text":"كلّ اسم إشارة مبنيّ إلّا مثنّاه"},{"id":"b","text":"كلّ مضاف معرفة"},{"id":"c","text":"الجزم علامة إعرابيّة تخصّ الأسماء"},{"id":"d","text":"«أل» تدخل على المعرفة فتزيدها تعريفًا"}]'::jsonb, 'a', 'أسماء الإشارة مبنيّة عمومًا إلّا مثنّاها الّذي يُعرب. الخطأ الشّائع تعميم التّعريف على كلّ مضاف، والخلط بين الجزم الخاصّ بالفعل والإعراب، وظنّ أنّ «أل» تدخل على المعرفة، والصّواب أنّها تدخل على النّكرة فتعرّفها.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1fbf465a-38a2-537c-8c54-b3b6a162028a', '412518af-f85f-56be-a771-b7be78addaef', 'أيّ الجمل الآتية تحوي اسمًا معربًا؟', '[{"id":"a","text":"سلّمتُ عليه"},{"id":"b","text":"جاء هؤلاء"},{"id":"c","text":"رأيتُ الطّائرةَ"},{"id":"d","text":"حضرَ الّذين نجحوا"}]'::jsonb, 'c', '«الطّائرة» اسمٌ معربٌ تتغيّر حركة آخره بتغيّر موقعه، بخلاف الضّمير «عليه» واسم الإشارة «هؤلاء» والاسم الموصول «الّذين» وهي جميعًا مبنيّة.', 2)
ON CONFLICT (id) DO UPDATE SET
