  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('35a969bc-b9a6-59a0-97e3-18809a81dee5', '412518af-f85f-56be-a771-b7be78addaef', '«سلّمتُ على تلك المعلّمةِ» — عيّن الاسم المبنيّ في هذه الجملة:', '[{"id":"a","text":"المعلّمةِ"},{"id":"b","text":"لا اسم مبنيّ في الجملة"},{"id":"c","text":"سلّمتُ"},{"id":"d","text":"تلك"}]'::jsonb, 'd', '«تلك» اسم إشارة، وأسماء الإشارة من الأسماء المبنيّة الملازمة حالةً واحدة، بخلاف «المعلّمة» وهي اسمٌ معرب.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
