  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('03ad17eb-0170-5765-babd-29d2c49615dc', '412518af-f85f-56be-a771-b7be78addaef', '«زارَ الوفدُ ......» — أيّ تكملةٍ تجعل الاسم معرفة بالإضافة إلى معرفة، لا بأل ولا بالعلميّة؟', '[{"id":"a","text":"المدرسةَ"},{"id":"b","text":"مدرسةَ خالدٍ"},{"id":"c","text":"مدرسةً"},{"id":"d","text":"هذه المدرسةَ"}]'::jsonb, 'b', '«مدرسة» نكرةٌ أُضيفت إلى العلم «خالد» (معرفة) فتعرّفت بالإضافة، دون أل ودون أن تكون هي نفسها علمًا أو اسم إشارة؛ أمّا (أ) تعرّفت بأل، و(د) اسم إشارة، و(ج) بقيت نكرة منصوبة.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('838ec98b-b7aa-5120-86ed-886b99632179', '412518af-f85f-56be-a771-b7be78addaef', 'قال تلميذٌ: «كيفَ تنجحُ؟ — كلمة (كيفَ) معربة لأنّها تسبق فعلًا مضارعًا وتؤثّر في إعرابه». أين الخطأ في هذا الكلام؟', '[{"id":"a","text":"لا خطأ"},{"id":"b","text":"الخطأ أنّ «كيفَ» ليست اسم استفهام"},{"id":"c","text":"الخطأ أنّ الفعل بعدها لا يُعرب أصلًا"},{"id":"d","text":"الخطأ أنّ سبق الفعل لا يجعل الاسم معربًا؛ «كيفَ» كسائر أسماء الاستفهام اسمٌ مبنيّ"}]'::jsonb, 'd', 'جميع أسماء الاستفهام مبنيّة (مَن، ما، متى، أينَ، كيفَ)، والوظيفة النّحويّة أو موقعها من الجملة لا يجعلها معربة.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3113862a-e0f4-58e7-9327-7068a0d50eb0', '412518af-f85f-56be-a771-b7be78addaef', '«سافرَ خالدٌ وسعادُ» — أيّ ممّا يلي صحيحٌ بشأن الاسمين «خالد» و«سعاد»؟', '[{"id":"a","text":"نكرتان لأنّهما غير مقترنين بأل"},{"id":"b","text":"معرفتان لأنّهما علمان، وهما معربان"},{"id":"c","text":"معربتان لكنّهما نكرتان"},{"id":"d","text":"مبنيّتان لأنّهما فاعلان"}]'::jsonb, 'b', 'العلم معرفةٌ سواء اقترن بأل أم لا («خالد»، «سعاد»)، وهما معربان تتغيّر حركة آخرهما بحسب الموقع، لا مبنيّان.', 6)
