INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c212a5fd-2e8f-58c1-840b-f5d0c078c39f', '2079042f-984d-5d68-9ba3-5a0c5bbab0b7', '«أعجبني اجتهادُ سميرةَ» — سبب تعريف «اجتهاد» هنا:', '[{"id":"a","text":"إضافته إلى معرفة (سميرة)"},{"id":"b","text":"دخول «أل» عليه"},{"id":"c","text":"كونه ضميرًا"},{"id":"d","text":"كونه اسم إشارة"}]'::jsonb, 'a', '«اجتهاد» نكرةٌ أُضيفت إلى العلم «سميرة» (معرفة) فتعرّفت بالإضافة.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('14f97d26-d550-5e70-8848-f2d7f17a007c', '2079042f-984d-5d68-9ba3-5a0c5bbab0b7', '«أل» في «الرّجلُ» أداةٌ:', '[{"id":"a","text":"لا تفيد شيئًا"},{"id":"b","text":"تدخل على المعرفة فتزيدها"},{"id":"c","text":"تختصّ بالأفعال"},{"id":"d","text":"تدخل على النّكرة فتحوّلها معرفة"}]'::jsonb, 'd', '«أل» أداة تعريفٍ تدخل على النّكرة («رجلٌ») فتحوّلها معرفة («الرّجلُ»).', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9c37fb88-6451-5846-b4d6-d431040220a5', '2079042f-984d-5d68-9ba3-5a0c5bbab0b7', '«يعمل الفلّاحُ في الحقلِ» — لو غيّرنا موقع «الفلّاح» في الجملة (فاعلًا، ثمّ مفعولًا به، ثمّ مجرورًا)، فإنّ حركة آخره:', '[{"id":"a","text":"تبقى الضّمّة في كلّ الأحوال"},{"id":"b","text":"تتغيّر تبعًا للموقع، لأنّه اسمٌ معرب"},{"id":"c","text":"تتغيّر أحيانًا فقط"},{"id":"d","text":"تصير سكونًا دائمًا"}]'::jsonb, 'b', '«الفلّاح» اسمٌ معربٌ عاديّ، فتتغيّر حركة آخره بتغيّر موقعه: ضمّة في الرّفع (الفلّاحُ)، وفتحة في النّصب (الفلّاحَ)، وكسرة في الجرّ (الفلّاحِ).', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('dad4f066-8e57-5c4f-9346-fec003c3500b', '2079042f-984d-5d68-9ba3-5a0c5bbab0b7', 'أيّ الأسماء التّالية مبنيّ؟', '[{"id":"a","text":"الحديقةُ"},{"id":"b","text":"طبيبٌ"},{"id":"c","text":"هؤلاء"},{"id":"d","text":"القمرُ"}]'::jsonb, 'c', '«هؤلاء» اسم إشارة، وأسماء الإشارة مبنيّة كلّها (ما عدا المثنّى)، أمّا البقيّة أسماء معربة.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('64327dcd-40b1-5b58-880e-cb6c51b58ae2', '2079042f-984d-5d68-9ba3-5a0c5bbab0b7', '«كم كتابًا قرأتَ؟» — «كم» هنا اسم استفهام؛ فهل هي معربة أم مبنيّة؟', '[{"id":"a","text":"مبنيّة، ككلّ أسماء الاستفهام"},{"id":"b","text":"معربة لأنّها تنصب الاسم بعدها"},{"id":"c","text":"معربة لأنّها تفيد السّؤال عن عدد"},{"id":"d","text":"مبنيّة فقط إذا جاءت في أوّل الجملة"}]'::jsonb, 'a', 'أسماء الاستفهام كلّها مبنيّة مهما كانت وظيفتها النّحويّة أو موقعها؛ «كم» الاستفهاميّة مبنيّة على السّكون.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('92472c0f-55ca-55eb-aaa0-54f1cdc5d952', '75cba66f-2438-53d4-abe1-7872a242c2ca', 'arabic-7eme', '👑 تحدّي النخبة ⭐⭐⭐⭐: قمّة النّكرة والمعرفة والمُعرَب والمبنيّ', 4, 300, 60, 'challenge', 'admin', 6)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a6fb42f4-ca0f-5aeb-9256-058f0aba9299', '92472c0f-55ca-55eb-aaa0-54f1cdc5d952', '«دفترُ معلّمٍ» و«دفترُ المعلّمِ» — الوصف الصّحيح لتعريف الكلمتين:', '[{"id":"a","text":"كلتاهما نكرة لأنّ «دفتر» غير مقترن بأل"},{"id":"b","text":"كلتاهما معرفة لأنّهما مضافتان"},{"id":"c","text":"الأولى نكرة (المضاف إليه نكرة) والثّانية معرفة (المضاف إليه معرَّف بأل)"},{"id":"d","text":"الأولى معرفة والثّانية نكرة"}]'::jsonb, 'c', 'يتعرّف المضاف بتعريف المضاف إليه: في «دفترُ معلّمٍ» المضاف إليه نكرة فبقي التّركيب نكرة، وفي «دفترُ المعلّمِ» المضاف إليه معرَّفٌ بأل (معرفة) فتعرّف التّركيب كلّه بالإضافة. الخطأ الشّائع تجاهل حال المضاف إليه أو الحكم بالتّعريف لمجرّد الإضافة.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('384b904c-444f-5bc8-87b7-3f7afd05d79f', '92472c0f-55ca-55eb-aaa0-54f1cdc5d952', 'قال تلميذٌ: «الفتحة في: رأيتُ الطّبيبَ، علامة نصبٍ فرعيّة». هل قوله صحيح؟', '[{"id":"a","text":"صحيح، فكلّ فتحة فرعيّة"},{"id":"b","text":"خطأ، لأنّ «الطّبيب» اسمٌ مبنيّ لا معرب"},{"id":"c","text":"صحيح، لأنّ الاسم جاء بعد فعل متعدٍّ"},{"id":"d","text":"خطأ، فـ«الطّبيب» اسمٌ مفردٌ معربٌ تنصبه الفتحة الأصليّة"}]'::jsonb, 'd', 'الفتحة هنا علامة النّصب الأصليّة لأنّ «الطّبيب» اسمٌ مفردٌ معربٌ عاديّ؛ والعلامات الفرعيّة تخصّ حالاتٍ خاصّة لم تُدرس في هذا الفصل.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9b7e5401-933c-56d3-a57f-e6aad86b8008', '92472c0f-55ca-55eb-aaa0-54f1cdc5d952', '«سلّمتُ على ذلك الرّجلِ» — اسم الإشارة «ذلك» هنا:', '[{"id":"a","text":"معرفة، مبنيّ كسائر أسماء الإشارة غير المثنّاة"},{"id":"b","text":"نكرة"},{"id":"c","text":"معرفة، معرب لأنّه مفرد"},{"id":"d","text":"مبنيّ لكنّه نكرة"}]'::jsonb, 'a', 'أسماء الإشارة معارف مبنيّة عدا مثنّاها، و«ذلك» مفردٌ مذكّرٌ مبنيّ لا معرب.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('56b1ba4e-3ae8-5bf7-8808-d4e4de50338d', '92472c0f-55ca-55eb-aaa0-54f1cdc5d952', 'أيّ الأسماء التّالية، إن أضفنا إليه كلمة «صديق»، يجعل التّركيب معرفة بالإضافة إلى اسمٍ مبنيّ (لا معرب)؟', '[{"id":"a","text":"ـه (كما في «صديقُهُ»)"},{"id":"b","text":"خالدٍ"},{"id":"c","text":"رجلٍ"},{"id":"d","text":"شيءٍ"}]'::jsonb, 'a', 'الضّمير المتّصل «الهاء» اسمٌ مبنيّ وهو معرفة، فتعرّف «صديق» بإضافته إليه؛ أمّا «خالد» معرفة لكنّه معرب، و«رجل» و«شيء» نكرتان.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5c158df7-4cea-5cc1-9112-537eadfcf641', '92472c0f-55ca-55eb-aaa0-54f1cdc5d952', 'أيّ العبارات الأربع التّالية **خاطئة**؟', '[{"id":"a","text":"الضّمائر كلّها أسماء مبنيّة"},{"id":"b","text":"كلّ اسم يقبل الإضافة يصير معرفة حتمًا"},{"id":"c","text":"العلم معرفة سواء اقترن بأل أم لا"},{"id":"d","text":"الاسم الموصول من الأسماء المبنيّة"}]'::jsonb, 'b', 'القاعدة الصّحيحة أنّ الاسم يتعرّف بالإضافة إلى معرفة فقط؛ أمّا إضافته إلى نكرة فيُبقيه نكرة (مثل: كتابُ تلميذٍ). العبارات الثّلاث الأخرى صحيحة تمامًا.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0f5dc669-225a-5e28-a935-16e97026b3cd', '92472c0f-55ca-55eb-aaa0-54f1cdc5d952', 'ما الفرق الجوهريّ بين النّكرة والمعرفة من جهة، وبين المُعرَب والمبنيّ من جهة أخرى؟', '[{"id":"a","text":"تصنيفان متطابقان: كلّ نكرة مبنيّة وكلّ معرفة معربة"},{"id":"b","text":"كلّ مبنيّ نكرة، وكلّ معرب معرفة"},{"id":"c","text":"لا علاقة لزومٍ بينهما: النّكرة/المعرفة تصنيفٌ في المعنى (التّعيين)، والمُعرَب/المبنيّ تصنيفٌ في الحركة الإعرابيّة"},{"id":"d","text":"النّكرة دائمًا معربة، والمعرفة دائمًا مبنيّة"}]'::jsonb, 'c', 'التّصنيفان مستقلّان: «رجل» نكرةٌ معربة، و«خالد» معرفةٌ معربة، و«هذا» معرفةٌ مبنيّة؛ فيمكن أن يجتمع أيٌّ منهما مع أيٍّ من الحركة الإعرابيّة، ولا تلازم بينهما.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

