  ('2ba038d8-1b7c-5cb6-bfcc-ddf0a83873ae', 'ed7989a0-b1f3-5c27-ae93-f4da6a81e635', 'arabic-7eme', 'اختبار فهم الدرس ⭐', 1, 20, 5, 'quiz', 'admin', 0)
