INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e3143be6-9cc0-5bbc-af67-44408457fca2', '2ba038d8-1b7c-5cb6-bfcc-ddf0a83873ae', 'الجملة «وصلَ الصّيادُ» على أيّ شكل من أشكال الجملة الفعليّة؟', '[{"id":"a","text":"فعل + فاعل"},{"id":"b","text":"فعل + فاعل + مفعول به"},{"id":"c","text":"فعل + فاعل + مفعولان"},{"id":"d","text":"مبتدأ + خبر"}]'::jsonb, 'a', '«وصلَ» فعل لازم يكتفي بفاعله «الصّيادُ» دون حاجة إلى مفعول به، فالجملة على شكل فعل + فاعل فقط.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('73aa1168-4826-5955-8756-8e732c3ea6a4', '2ba038d8-1b7c-5cb6-bfcc-ddf0a83873ae', 'حكم الفاعل الإعرابيّ دائمًا هو:', '[{"id":"a","text":"النّصب"},{"id":"b","text":"الجرّ"},{"id":"c","text":"الرّفع"},{"id":"d","text":"يختلف بحسب موقعه في الجملة"}]'::jsonb, 'c', 'الفاعل مرفوعٌ دائمًا مهما كان موقعه في الجملة، وعلامة رفعه الأصليّة الضّمّة.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('53d9a2a8-c8d7-5eb0-ab62-7ebccb4583f0', '2ba038d8-1b7c-5cb6-bfcc-ddf0a83873ae', 'علامة نصب المفعول به الأصليّة هي:', '[{"id":"a","text":"الضّمّة"},{"id":"b","text":"الفتحة"},{"id":"c","text":"الكسرة"},{"id":"d","text":"السّكون"}]'::jsonb, 'b', 'المفعول به منصوبٌ دائمًا، وعلامة نصبه الأصليّة الفتحة، كما في: قطفَ البستانيُّ الورودَ.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b907152a-178c-5d36-810b-294a573a18a3', '2ba038d8-1b7c-5cb6-bfcc-ddf0a83873ae', '«غُسِلَ الثّوبُ» — الثّوبُ في هذه الجملة:', '[{"id":"a","text":"فاعل مرفوع"},{"id":"b","text":"مفعول به منصوب"},{"id":"c","text":"نائب فاعل مرفوع"},{"id":"d","text":"مبتدأ مرفوع"}]'::jsonb, 'c', 'الفعل «غُسِلَ» مبنيّ للمجهول، فحُذف الفاعل وحلّ «الثّوبُ» محلّه نائبًا عنه، فارتفع.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('19bb55d2-5589-54a8-ab6d-ebd12dc9d477', '2ba038d8-1b7c-5cb6-bfcc-ddf0a83873ae', '«نجحتْ آمالُ في الامتحان» — لماذا اتّصلت التّاء بالفعل «نجحتْ»؟', '[{"id":"a","text":"لأنّ الفعل في زمن الماضي فقط"},{"id":"b","text":"لأنّ الفاعل «آمالُ» مؤنّث"},{"id":"c","text":"لأنّ الجملة منفيّة"},{"id":"d","text":"لأنّ الفعل متعدٍّ إلى مفعولين"}]'::jsonb, 'b', 'تتّصل تاء التّأنيث السّاكنة بالفعل الماضي إذا كان فاعله مؤنّثًا، والفاعل هنا اسم العلم المؤنّث «آمالُ».', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

