INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a122c517-7e7a-57b9-b6d5-d84521e2ac17', '0ea77d4e-469a-5c0d-b710-c500ed956564', 'الجملة «زرعَ الفلّاحُ الحقلَ» على أيّ شكل من أشكال الجملة الفعليّة؟', '[{"id":"a","text":"فعل + فاعل"},{"id":"b","text":"فعل + فاعل + مفعول به"},{"id":"c","text":"فعل + فاعل + مفعولان"},{"id":"d","text":"جملة اسميّة"}]'::jsonb, 'b', '«زرعَ» فعل متعدٍّ إلى مفعول واحد هو «الحقلَ»، فشكل الجملة فعل + فاعل + مفعول به.', 1)
