INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('db42eb05-c697-52d1-86ef-d7334463877f', '0ea77d4e-469a-5c0d-b710-c500ed956564', 'في الجملة «اصطادَ الصّيادُ سمكةً» الفاعل هو:', '[{"id":"a","text":"اصطادَ"},{"id":"b","text":"الصّيادُ"},{"id":"c","text":"سمكةً"},{"id":"d","text":"لا فاعل ظاهر في الجملة"}]'::jsonb, 'b', 'الفاعل من قام بالفعل، وهو هنا «الصّيادُ» الذي قام بالاصطياد.', 2)
