INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ab38df71-2b56-5e74-bcb0-1ee74e57c946', '0ea77d4e-469a-5c0d-b710-c500ed956564', '«يكتبُ رسالةً بخطٍّ جميلٍ» — الفاعل في هذه الجملة:', '[{"id":"a","text":"اسم ظاهر"},{"id":"b","text":"ضمير متّصل"},{"id":"c","text":"ضمير مستتر تقديره «هو»"},{"id":"d","text":"لا فاعل في الجملة"}]'::jsonb, 'c', 'لا يوجد اسم ظاهر بعد الفعل، فالفاعل ضمير مستتر تقديره «هو» يعود على شخص معلوم من السّياق.', 3)
