INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('fe739758-8cf7-5902-b8bb-4d575ceb4e4c', '0ea77d4e-469a-5c0d-b710-c500ed956564', 'في «قطفَ البستانيُّ الورودَ» ما إعراب «الورودَ»؟', '[{"id":"a","text":"مفعول به منصوب"},{"id":"b","text":"فاعل مرفوع"},{"id":"c","text":"نائب فاعل مرفوع"},{"id":"d","text":"مضاف إليه مجرور"}]'::jsonb, 'a', '«الورودَ» وقع عليه فعل القطف فهو مفعول به، وحكمه النّصب وعلامته الفتحة.', 5)
