INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('de624408-c608-584e-a991-df99059c2af9', '0ea77d4e-469a-5c0d-b710-c500ed956564', '«بِيعَ الكتابُ في السّوق» — الكتابُ في هذه الجملة:', '[{"id":"a","text":"فاعل مرفوع"},{"id":"b","text":"مفعول به منصوب"},{"id":"c","text":"نائب فاعل مرفوع"},{"id":"d","text":"مبتدأ مرفوع"}]'::jsonb, 'c', 'الفعل «بِيعَ» مبنيّ للمجهول (حُذف الفاعل)، فحلّ «الكتابُ» محلّه نائب فاعل، فارتفع.', 6)
