INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('cff1ecb3-6d33-5ad3-9640-13ccf9939692', '25371201-749b-57a7-893c-f8d909d5af3a', '«فتحَ الحارسُ البابَ» — حوّل الفعل إلى المبنيّ للمجهول:', '[{"id":"a","text":"فَتُحَ البابُ"},{"id":"b","text":"فُتِحَ البابُ"},{"id":"c","text":"يُفتَحُ البابُ"},{"id":"d","text":"فُتِحَ الحارسُ"}]'::jsonb, 'b', 'نبني الماضي على صيغة فُعِلَ: فتحَ ← فُتِحَ، ونحذف الفاعل «الحارسُ»، فيحلّ المفعول به «البابُ» محلّه ويرتفع نائب فاعل.', 1)
