INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('fde82b55-493f-5689-a2a1-ff9226db95dd', '25371201-749b-57a7-893c-f8d909d5af3a', '«فُتِحَ البابُ» — إعراب «البابُ»:', '[{"id":"a","text":"فاعل مرفوع"},{"id":"b","text":"مضاف إليه مجرور"},{"id":"c","text":"مفعول به منصوب"},{"id":"d","text":"نائب فاعل مرفوع"}]'::jsonb, 'd', 'بعد حذف الفاعل «الحارسُ»، حلّ المفعول به السّابق محلّه فأصبح نائب فاعل مرفوعًا لا مفعولًا به.', 2)
