INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4e90744c-45ae-5861-bbb3-de5017c2c676', '25371201-749b-57a7-893c-f8d909d5af3a', '«رجعتْ هالةُ من المدرسة مسرعةً» — سبب اتّصال التّاء بالفعل «رجعتْ»:', '[{"id":"a","text":"الفعل مبنيّ للمجهول"},{"id":"b","text":"الفعل متعدٍّ إلى مفعولين"},{"id":"c","text":"الفاعل «هالةُ» مؤنّث"},{"id":"d","text":"الفعل في زمن المضارع"}]'::jsonb, 'c', 'تتّصل تاء التّأنيث السّاكنة بالفعل الماضي حين يكون فاعله مؤنّثًا، وهو هنا اسم العلم المؤنّث «هالةُ».', 3)
