INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('eed10cfd-3794-551e-a5fc-0cfe73595cb7', '25371201-749b-57a7-893c-f8d909d5af3a', '«علّمَ الأستاذُ التّلميذَ القراءةَ» — عدد المفاعيل المنصوبة في هذه الجملة:', '[{"id":"a","text":"مفعولان"},{"id":"b","text":"مفعول واحد"},{"id":"c","text":"لا مفعول به"},{"id":"d","text":"ثلاثة مفاعيل"}]'::jsonb, 'a', '«علّمَ» متعدٍّ إلى مفعولين: «التّلميذَ» و«القراءةَ»، وكلاهما منصوب وعلامة نصبهما الفتحة.', 4)
