INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9d2ea632-8a8d-59fd-959a-bbc5c3b79e31', '25371201-749b-57a7-893c-f8d909d5af3a', '«وثِقَ المديرُ بالموظّفِ» — الاسم «الموظّفِ» في هذه الجملة:', '[{"id":"a","text":"مفعول به منصوب"},{"id":"b","text":"نائب فاعل مرفوع"},{"id":"c","text":"فاعل مرفوع"},{"id":"d","text":"اسم مجرور بحرف الجرّ"}]'::jsonb, 'd', '«وثِقَ» فعل لازم تعدّى بحرف الجرّ «الباء»، فـ«الموظّفِ» اسم مجرور لا مفعول به؛ والمتعدّي الحقّ ينصب مفعوله بلا واسطة.', 5)
