INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c4ba9fd6-f93e-5a88-ae2d-e9b52d4a83db', '20a60f02-7969-52ee-8830-12751a6f990d', 'أراد تلميذ إعراب الجملة «حضرتْ آمالُ الحفلَ» فقال: «آمالُ: فاعل مرفوع، والحفلَ: نائب فاعل منصوب». أين الخطأ في كلامه؟', '[{"id":"a","text":"لا خطأ، الإعراب صحيح كلّه"},{"id":"b","text":"الخطأ أنّ «آمالُ» ليست فاعلًا"},{"id":"c","text":"الخطأ أنّ «الحفلَ» مفعول به منصوب لا نائب فاعل"},{"id":"d","text":"الخطأ أنّ الفعل مبنيّ للمجهول"}]'::jsonb, 'c', 'الجملة مبنيّة للمعلوم (الفاعل «آمالُ» مذكور)، فـ«الحفلَ» مفعول به منصوب؛ ولا وجود لنائب فاعل إلّا في الجملة المبنيّة للمجهول التي يُحذف فيها الفاعل. الخطأ الشّائع تسمية أيّ منصوب بعد الفاعل «نائب فاعل».', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f90751bd-9567-5ce0-b0bf-767a0e5f5b43', '20a60f02-7969-52ee-8830-12751a6f990d', '«قُطِفَتِ الوردةُ من الحديقةِ» — لو أردنا ذكر الفاعل الأصليّ (البستانيّ)، فأيّ إعادة صياغة صحيحة؟', '[{"id":"a","text":"قَطَفَ البستانيُّ الوردةَ"},{"id":"b","text":"قَطَفَتِ الوردةُ البستانيَّ"},{"id":"c","text":"قُطِفَ البستانيُّ الوردةَ"},{"id":"d","text":"الوردةُ قَطَفَتْ البستانيَّ"}]'::jsonb, 'a', 'نعيد الفاعل «البستانيُّ» ونبني الفعل للمعلوم، فيرتفع الفاعل وتُنصب «الوردةَ» مفعولًا به: قَطَفَ البستانيُّ الوردةَ.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('48874f50-ec94-569b-a653-cbd9b1d2e641', '20a60f02-7969-52ee-8830-12751a6f990d', '«اشترى التّاجرُ حاتمٌ بضاعةً» ثمّ حُذِف الفاعل، فقيل: «اشتُريَتْ بضاعةً». ما الخلل في هذه الصّياغة؟', '[{"id":"a","text":"لا خلل، الصّياغة صحيحة"},{"id":"b","text":"«بضاعةً» بقيت منصوبة، والصّواب رفعها لأنّها نائب فاعل"},{"id":"c","text":"الفعل يجب أن يبقى للمعلوم"},{"id":"d","text":"التّاء الزّائدة خطأ إملائيّ فقط"}]'::jsonb, 'b', 'عند البناء للمجهول يرتفع نائب الفاعل، فالصّواب: اشتُريَتِ البضاعةُ (بالضّمّة لا الفتحة)؛ نسيان تغيير حركة النّائب من النّصب إلى الرّفع خطأ شائع.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ce2163fc-7870-586b-86a7-509dedae629e', '20a60f02-7969-52ee-8830-12751a6f990d', 'أيّ العبارات التّالية عن نائب الفاعل صحيحة؟', '[{"id":"a","text":"نائب الفاعل يكون دائمًا ضميرًا لا اسمًا ظاهرًا"},{"id":"b","text":"نائب الفاعل منصوبٌ كالمفعول به"},{"id":"c","text":"نائب الفاعل يحلّ محلّ الفاعل المحذوف ويُرفع"},{"id":"d","text":"نائب الفاعل لا يوجد إلّا في الجمل الاسميّة"}]'::jsonb, 'c', 'نائب الفاعل اسمٌ (ظاهرًا كان أو ضميرًا) يحلّ محلّ الفاعل المحذوف في الجملة المبنيّة للمجهول، وحكمه الرّفع لا النّصب، ولا وجود له إلّا في الجملة الفعليّة.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('af0e2c14-cfb6-5abb-b4b2-480ca8fe0658', '20a60f02-7969-52ee-8830-12751a6f990d', '«منعَ الحكمُ اللاعبَ المشاركةَ» بُنِيَ للمجهول فصار «مُنِعَ اللاعبُ المشاركةَ». ما إعراب «اللاعبُ» و«المشاركةَ» بعد التّحويل؟', '[{"id":"a","text":"كلاهما نائب فاعل مرفوع"},{"id":"b","text":"اللاعبُ نائب فاعل مرفوع، والمشاركةَ مفعول به منصوب بقي على حاله"},{"id":"c","text":"كلاهما مفعول به منصوب"},{"id":"d","text":"اللاعبُ فاعل، والمشاركةَ نائب فاعل"}]'::jsonb, 'b', 'يحلّ المفعول الأوّل «اللاعبُ» محلّ الفاعل المحذوف فيصبح نائب فاعل مرفوعًا، بينما يبقى المفعول الثّاني «المشاركةَ» منصوبًا كما كان.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

