  ('d8e2f002-5e6c-5590-b85f-d31ce59715b1', 'ed7989a0-b1f3-5c27-ae93-f4da6a81e635', 'arabic-7eme', '📝 تدريب ⭐⭐⭐ (مراجعة شاملة): الفاعل ونائب الفاعل والمفعول به', 3, 120, 30, 'boss', 'admin', 5)
