INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('605ad8f6-d69d-51a6-9f90-06d4a7535fbd', 'd8e2f002-5e6c-5590-b85f-d31ce59715b1', '«جلسَ الجدّ في الحديقةِ يستريحُ» — شكل هذه الجملة:', '[{"id":"a","text":"فعل + فاعل"},{"id":"b","text":"فعل + فاعل + مفعول به"},{"id":"c","text":"فعل + فاعل + مفعولان"},{"id":"d","text":"جملة اسميّة"}]'::jsonb, 'a', '«جلسَ» فعل لازم يكتفي بفاعله «الجدّ»، فلا مفعول به، والجملة فعل + فاعل فقط.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9b83c4ae-acb0-5062-8013-bafbf3244f88', 'd8e2f002-5e6c-5590-b85f-d31ce59715b1', 'في «بنى النّجّارُ كرسيًّا» ما نوع الفاعل؟', '[{"id":"a","text":"ضمير مستتر"},{"id":"b","text":"ضمير متّصل"},{"id":"c","text":"اسم ظاهر"},{"id":"d","text":"مفعول به"}]'::jsonb, 'c', '«النّجّارُ» اسم ظاهر صريح دلّ على من قام بالفعل، فهو الفاعل.', 2)
ON CONFLICT (id) DO UPDATE SET
