  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('793a8a85-bb18-51ff-8137-01937c050d46', 'd8e2f002-5e6c-5590-b85f-d31ce59715b1', '«كسا الأبُ ابنَه معطفًا» — إعراب «معطفًا»:', '[{"id":"a","text":"فاعل مرفوع"},{"id":"b","text":"نائب فاعل مرفوع"},{"id":"c","text":"مضاف إليه مجرور"},{"id":"d","text":"مفعول به ثانٍ منصوب"}]'::jsonb, 'd', '«كسا» متعدٍّ إلى مفعولين، و«معطفًا» هو المفعول الثّاني، منصوب وعلامته الفتحة.', 3)
