  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d558e554-8540-5fad-812a-d133497e01e2', 'd8e2f002-5e6c-5590-b85f-d31ce59715b1', '«حُصِدَ القمحُ في الصّيفِ» — إعراب «القمحُ»:', '[{"id":"a","text":"مفعول به منصوب"},{"id":"b","text":"فاعل مرفوع"},{"id":"c","text":"نائب فاعل مرفوع"},{"id":"d","text":"اسم مجرور"}]'::jsonb, 'c', 'الفعل «حُصِدَ» مبنيّ للمجهول، فحلّ «القمحُ» محلّ الفاعل المحذوف نائبًا عنه، فارتفع.', 4)
