INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8d4b312d-6b3d-5e8f-9d6e-d03ca1461bf3', 'd8e2f002-5e6c-5590-b85f-d31ce59715b1', '«خرجتْ سعادُ من البيتِ باكرًا» — هذا الفعل لازمٌ. هل يمكن بناؤه للمجهول؟', '[{"id":"a","text":"نعم، لأنّه متعدٍّ"},{"id":"b","text":"لا، لأنّه فعل لازم لا مفعول به له يقوم مقام الفاعل"},{"id":"c","text":"نعم، لأنّ الفاعل مؤنّث"},{"id":"d","text":"لا، لأنّ الفعل ماضٍ"}]'::jsonb, 'b', 'لا يُبنى للمجهول إلّا الفعل المتعدّي الذي له مفعول به يحلّ محلّ الفاعل المحذوف؛ والفعل اللازم لا نائب فاعل له.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2d361da0-0e68-5fc1-9794-32071a1eee2a', 'd8e2f002-5e6c-5590-b85f-d31ce59715b1', 'أيّ العبارات التّالية عن الفاعل ونائب الفاعل صحيحة؟', '[{"id":"a","text":"كلاهما مرفوعٌ، لكنّ نائب الفاعل يحلّ محلّ فاعل محذوف"},{"id":"b","text":"الفاعل منصوبٌ ونائب الفاعل مرفوعٌ"},{"id":"c","text":"نائب الفاعل يوجد مع الفاعل معًا في الجملة نفسها"},{"id":"d","text":"الفاعل لا يكون إلّا اسمًا ظاهرًا"}]'::jsonb, 'a', 'الفاعل ونائب الفاعل كلاهما مرفوعٌ، لكنّ نائب الفاعل يظهر فقط بعد حذف الفاعل ليقوم مقامه، ولا يجتمعان في الجملة نفسها.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

