INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d54d5990-ef94-561e-b984-8a0fe8d21664', 'c05cc5b0-96ed-5887-b1e5-6b47c7a19101', '«أهدى الجدّ حفيدتَه كتابًا» — إعراب «حفيدتَه»:', '[{"id":"a","text":"فاعل مرفوع"},{"id":"b","text":"مضاف إليه مجرور"},{"id":"c","text":"مفعول به أوّل منصوب"},{"id":"d","text":"نائب فاعل مرفوع"}]'::jsonb, 'c', '«أهدى» متعدٍّ إلى مفعولين، و«حفيدتَه» هو المفعول الأوّل منصوب، و«كتابًا» المفعول الثّاني.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
