INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f1995d3e-5825-5edc-aecc-873a3bdc4512', 'c05cc5b0-96ed-5887-b1e5-6b47c7a19101', 'حُوِّلت جملة السّؤال السّابق إلى المبنيّ للمجهول. أيّ صياغة صحيحة؟', '[{"id":"a","text":"أُهدِيَ الجدُّ حفيدتَه كتابًا"},{"id":"b","text":"أُهدِيَتْ حفيدةُ الجدِّ كتابًا"},{"id":"c","text":"أَهدَتْ حفيدةُ الجدِّ كتابًا"},{"id":"d","text":"أُهدِيَتْ حفيدةُ الجدِّ الكتابَ"}]'::jsonb, 'b', 'يُحذف الفاعل «الجدّ»، فيحلّ المفعول الأوّل «حفيدةُ الجدِّ» محلّه ويرتفع نائب فاعل، ويبقى المفعول الثّاني «كتابًا» منصوبًا؛ ولاحظ اتّصال تاء التّأنيث لأنّ نائب الفاعل مؤنّث.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4b5d1481-b89a-512e-8bab-120d8e86196c', 'c05cc5b0-96ed-5887-b1e5-6b47c7a19101', '«يُصنَعُ الخبزُ في الفرن كلّ يومٍ» — نوع نائب الفاعل في هذه الجملة:', '[{"id":"a","text":"ضمير متّصل"},{"id":"b","text":"ضمير مستتر"},{"id":"c","text":"اسم ظاهر مؤنّث"},{"id":"d","text":"اسم ظاهر مذكّر"}]'::jsonb, 'd', '«الخبزُ» اسم ظاهر مذكّر حلّ محلّ الفاعل المحذوف، فهو نائب فاعل مرفوع.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
