INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('aebe4552-8c43-5daa-a972-44a01fcfd649', 'c05cc5b0-96ed-5887-b1e5-6b47c7a19101', 'قال تلميذ: «في جملة (سُئِلَ الطّالبُ سؤالًا)، الطّالبُ مفعول به وسؤالًا نائب فاعل». صوّب هذا الخطأ.', '[{"id":"a","text":"لا خطأ في كلامه"},{"id":"b","text":"الصّواب أنّ كليهما نائب فاعل"},{"id":"c","text":"الصّواب: الطّالبُ نائب فاعل مرفوع، وسؤالًا مفعول به ثانٍ بقي منصوبًا"},{"id":"d","text":"الصّواب أنّ كليهما مفعول به"}]'::jsonb, 'c', 'عند بناء المتعدّي إلى مفعولين للمجهول، يرتفع المفعول الأوّل نائب فاعل («الطّالبُ»)، ويبقى الثّاني منصوبًا («سؤالًا»)؛ عكس التّلميذ الحكمين خطأً.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('777670e7-4491-5a1a-bdbf-c4746d94c10a', 'c05cc5b0-96ed-5887-b1e5-6b47c7a19101', 'أيّ العبارات التّالية عن المفعول به صحيحة؟', '[{"id":"a","text":"المفعول به مرفوعٌ دائمًا"},{"id":"b","text":"الاسم المجرور بحرف جرّ يُعدّ مفعولًا به"},{"id":"c","text":"المفعول به لا يوجد إلّا في الجملة الاسميّة"},{"id":"d","text":"المفعول به قد يتعدّد إلى مفعولين مع بعض الأفعال"}]'::jsonb, 'd', 'بعض الأفعال كمنحَ وأعطى وكسا تنصب مفعولين معًا؛ والمفعول به منصوبٌ لا مرفوعٌ، والمجرور بحرف الجرّ ليس مفعولًا به، ولا وجود له إلّا في الجملة الفعليّة.', 5)
ON CONFLICT (id) DO UPDATE SET
