INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('74e3e896-63d3-5ee1-a932-61df56e8ec61', 'c05cc5b0-96ed-5887-b1e5-6b47c7a19101', '«وهبتْ الجدّةُ حفيدَها ساعةً» — أيّ وصفٍ يجمع كلّ ما هو صحيح في هذه الجملة؟', '[{"id":"a","text":"الفاعل «الجدّةُ» مؤنّث فاتّصلت به التّاء، والفعل متعدٍّ إلى مفعولين هما «حفيدَها» و«ساعةً»"},{"id":"b","text":"الفاعل «الجدّةُ» مذكّر، والفعل لازم"},{"id":"c","text":"الفعل متعدٍّ إلى مفعول واحد فقط"},{"id":"d","text":"«ساعةً» فاعل ثانٍ للجملة"}]'::jsonb, 'a', 'الفاعل «الجدّةُ» مؤنّث فاتّصلت تاء التّأنيث بالفعل «وهبتْ»، والفعل متعدٍّ إلى مفعولين منصوبين: «حفيدَها» و«ساعةً»؛ فتجتمع في هذا المثال ثلاث ملاحظات معًا.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

