INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('eaf89618-9290-5e1f-b0f8-1b31a43bb517', '245d2c96-dfb9-513b-bd7b-37c4e49b2c0a', 'ما ركنا الجملة الاسميّة غير المسبوقة بناسخ؟', '[{"id":"a","text":"الفعل والفاعل"},{"id":"b","text":"المبتدأ والخبر"},{"id":"c","text":"المبتدأ والفعل"},{"id":"d","text":"الفاعل والمفعول به"}]'::jsonb, 'b', 'الجملة الاسميّة البسيطة تتكوّن من مبتدأ وخبر، وكلاهما مرفوع إذا لم تسبقهما ناسخ.', 1)
