INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9077e782-8778-518c-889c-b196434de708', '245d2c96-dfb9-513b-bd7b-37c4e49b2c0a', '«الطّائرُ يُغرّدُ» — ما نوع الخبر في هذه الجملة؟', '[{"id":"a","text":"خبر مفرد"},{"id":"b","text":"خبر شبه جملة"},{"id":"c","text":"خبر جملة فعليّة"},{"id":"d","text":"خبر جملة اسميّة"}]'::jsonb, 'c', '«يُغرّدُ» فعل وفاعل مستتر، فهو جملة فعليّة وقعت في محلّ رفع خبر للمبتدأ «الطّائرُ».', 2)
