  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1e988c65-bb36-5783-bfab-6c8eaf550e54', '245d2c96-dfb9-513b-bd7b-37c4e49b2c0a', '«كانَ الدّرسُ سهلًا» — ما عمل «كانَ» في هذه الجملة؟', '[{"id":"a","text":"ترفع المبتدأ وتنصب الخبر"},{"id":"b","text":"تنصب المبتدأ وترفع الخبر"},{"id":"c","text":"ترفع المبتدأ والخبر معًا"},{"id":"d","text":"تنصب المبتدأ والخبر معًا"}]'::jsonb, 'a', '«كانَ» فعل ناسخ يرفع المبتدأ ويسمّيه اسمها، وينصب الخبر ويسمّيه خبرها، فـ«الدّرسُ» اسمها مرفوع و«سهلًا» خبرها منصوب.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b68c1045-26c7-567b-8701-d8c831d5ee26', '245d2c96-dfb9-513b-bd7b-37c4e49b2c0a', '«كادَ» و«أوشكَ» من أفعال المقاربة، وهما يدلّان على:', '[{"id":"a","text":"البدء الفعليّ في الحدث"},{"id":"b","text":"التّشبيه"},{"id":"c","text":"الاستدراك"},{"id":"d","text":"قرب وقوع الحدث"}]'::jsonb, 'd', 'أفعال المقاربة مثل كاد وأوشك تدلّ على قرب وقوع الحدث، بخلاف أفعال الشّروع (شرعَ، أخذَ، بدأَ) الّتي تدلّ على البدء الفعليّ فيه.', 4)
ON CONFLICT (id) DO UPDATE SET
