  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a926ac01-f1b3-5d42-822e-c95c375bba7c', '245d2c96-dfb9-513b-bd7b-37c4e49b2c0a', '«إنّ وأخواتها» حروف ناسخة تعمل بأن:', '[{"id":"a","text":"ترفع الاسم وتنصب الخبر"},{"id":"b","text":"تنصب الاسم وترفع الخبر"},{"id":"c","text":"تنصب الاسم والخبر معًا"},{"id":"d","text":"ترفع الاسم والخبر معًا"}]'::jsonb, 'b', 'إنّ وأخواتها حروف ناسخة تنصب المبتدأ فتسمّيه اسمها، وترفع الخبر فتسمّيه خبرها، وهذا عكس عمل كان وأخواتها تمامًا.', 5)
