INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9b858cda-b130-5aac-bc82-93b6afade038', 'a2b53b75-4fc7-5c86-89b6-649506498a03', 'في «الحديقةُ جميلةٌ»، ما إعراب «الحديقةُ»؟', '[{"id":"a","text":"خبر مرفوع"},{"id":"b","text":"مبتدأ مرفوع"},{"id":"c","text":"فاعل مرفوع"},{"id":"d","text":"اسم كان مرفوع"}]'::jsonb, 'b', '«الحديقةُ» اسمٌ تحدّثنا عنه في أوّل الجملة، فهو مبتدأ مرفوع وعلامة رفعه الضمّة، و«جميلةٌ» خبره.', 1)
