INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('214054c5-b388-5906-ad8b-043719481d37', 'eb33d56b-1547-511b-aec9-018ababc68cb', '«ليسَ الشّتاءُ حارًّا» — لماذا لا يُعدّ «ليسَ» فعلًا يتصرّف كسائر أخوات «كان»؟', '[{"id":"a","text":"لأنّه حرف لا فعل"},{"id":"b","text":"لأنّه فعل جامد لا يأتي إلا بصيغة الماضي"},{"id":"c","text":"لأنّه لا يعمل إلا في المضارع"},{"id":"d","text":"لأنّه ينصب الاسم ويرفع الخبر"}]'::jsonb, 'b', '«ليسَ» فعل ماضٍ ناسخ جامد لا يتصرّف، فلا مضارع له ولا أمر، بخلاف كان وأصبح وصار الّتي تتصرّف في الأزمنة الثّلاثة.', 3)
