INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('59327e85-6510-50c1-bbee-9494051d3fc6', '277b9aec-8131-541f-80a3-60a905cbfc3a', 'arabic-7eme', '⭐⭐ تمرين مراجعة (نمط امتحان): الجملة الاسميّة والنّواسخ', 2, 70, 15, 'practice', 'admin', 3)
