INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('744594d7-9aae-58d9-a7a5-3af9838ce336', '59327e85-6510-50c1-bbee-9494051d3fc6', '«الحديقةُ واسعةٌ» — ما نوع الخبر في هذه الجملة؟', '[{"id":"a","text":"خبر جملة فعليّة"},{"id":"b","text":"خبر مفرد"},{"id":"c","text":"خبر جملة اسميّة"},{"id":"d","text":"خبر شبه جملة"}]'::jsonb, 'b', '«واسعةٌ» كلمة مفردة (ليست جملة ولا شبه جملة) وقعت خبرًا للمبتدأ «الحديقةُ»، فهو خبر مفرد.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5701277e-f855-5529-ae7e-a1fbc1a7e7b6', '59327e85-6510-50c1-bbee-9494051d3fc6', '«الكتابُ صفحاتُهُ ملوّنةٌ» — ما نوع الخبر في هذه الجملة؟', '[{"id":"a","text":"خبر مفرد"},{"id":"b","text":"خبر شبه جملة"},{"id":"c","text":"خبر جملة اسميّة"},{"id":"d","text":"خبر جملة فعليّة"}]'::jsonb, 'c', '«صفحاتُهُ ملوّنةٌ» جملة اسميّة (مبتدأ وخبر) وقعت في محلّ رفع خبر للمبتدأ الأوّل «الكتابُ».', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d4f4741b-7b0e-500e-ba9d-dc709b4cb1b7', '59327e85-6510-50c1-bbee-9494051d3fc6', '«أمسى الفلّاحُ متعبًا» — ما إعراب «الفلّاحُ»؟', '[{"id":"a","text":"خبر أمسى منصوب"},{"id":"b","text":"فاعل مرفوع"},{"id":"c","text":"مبتدأ منصوب"},{"id":"d","text":"اسم أمسى مرفوع"}]'::jsonb, 'd', '«أمسى» من أخوات كان، ترفع المبتدأ فتسمّيه اسمها، فـ«الفلّاحُ» اسم أمسى مرفوع وعلامة رفعه الضمّة.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('bdcd0d77-0c69-5c9d-9742-624502e6e3c2', '59327e85-6510-50c1-bbee-9494051d3fc6', '«كادَ المطرُ ينزلُ» — ما محلّ جملة «ينزلُ» من الإعراب؟', '[{"id":"a","text":"في محلّ رفع اسم كاد"},{"id":"b","text":"لا محلّ لها من الإعراب"},{"id":"c","text":"في محلّ نصب خبر كاد"},{"id":"d","text":"في محلّ رفع خبر كاد"}]'::jsonb, 'c', 'خبر أفعال المقاربة جملة فعليّة في محلّ نصب، فجملة «ينزلُ» في محلّ نصب خبر «كادَ».', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0688308d-2872-54e3-a145-ca2819b529dd', '59327e85-6510-50c1-bbee-9494051d3fc6', '«إنَّ الرّياضةَ مفيدةٌ» — ما إعراب «الرّياضةَ»؟', '[{"id":"a","text":"اسم إنّ منصوب"},{"id":"b","text":"خبر إنّ مرفوع"},{"id":"c","text":"مبتدأ مرفوع"},{"id":"d","text":"فاعل مرفوع"}]'::jsonb, 'a', '«إنّ» حرف ناسخ ينصب المبتدأ فيسمّيه اسمها، فـ«الرّياضةَ» اسم إنّ منصوب وعلامة نصبه الفتحة.', 5)
ON CONFLICT (id) DO UPDATE SET
