  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('097bf049-a65c-5d02-b4de-99ae2f9741d9', '59327e85-6510-50c1-bbee-9494051d3fc6', '«لعلَّ» من الحروف النّاسخة، وتفيد معنى:', '[{"id":"a","text":"التّمنّي"},{"id":"b","text":"التّرجّي"},{"id":"c","text":"التّشبيه"},{"id":"d","text":"الاستدراك"}]'::jsonb, 'b', '«لعلَّ» تفيد التّرجّي، أي توقّع أمر ممكن الحدوث ويُرجى وقوعه، بخلاف «ليتَ» الّتي تفيد التّمنّي في أمر بعيد أو مستحيل.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('a9bde986-c107-5523-9fba-1b3be7b7b0b8', '277b9aec-8131-541f-80a3-60a905cbfc3a', 'arabic-7eme', '👑 تحدّي النخبة ⭐⭐⭐⭐: الجملة الاسميّة والنّواسخ', 4, 300, 60, 'challenge', 'admin', 4)
