INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('68b74555-75dc-56ef-9801-11cd3f0d3c8e', 'a9bde986-c107-5523-9fba-1b3be7b7b0b8', '«الجوُّ باردٌ» جملة اسميّة بسيطة. إذا أدخلنا عليها «أصبحَ» فصارت «أصبحَ الجوُّ باردًا»، فماذا تغيّر في إعراب «باردًا»؟', '[{"id":"a","text":"صار خبرًا منصوبًا بعد أن كان مرفوعًا"},{"id":"b","text":"بقي خبرًا مرفوعًا كما كان"},{"id":"c","text":"صار اسمًا مرفوعًا"},{"id":"d","text":"صار فاعلًا منصوبًا"}]'::jsonb, 'a', 'قبل دخول الناسخ، «باردٌ» خبر مرفوع للمبتدأ «الجوُّ». وبعد دخول «أصبحَ» (فعل ناسخ) ينصب الخبر، فصار «باردًا» خبر أصبح منصوبًا بالفتحة، بينما ظلّ «الجوُّ» مرفوعًا (اسم أصبح).', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3fcdad0c-036d-5444-8cf3-d514eb0a03f3', 'a9bde986-c107-5523-9fba-1b3be7b7b0b8', 'في «إنَّ الطّقسَ جميلٌ»، إذا حذفنا «إنَّ» فعادت الجملة إلى أصلها، فما إعراب «الطّقسَ» بعد الحذف؟', '[{"id":"a","text":"يبقى منصوبًا كما كان اسمَ إنّ"},{"id":"b","text":"يصير مبتدأ مرفوعًا بعد أن كان منصوبًا"},{"id":"c","text":"يصير خبرًا مرفوعًا"},{"id":"d","text":"يصير فاعلًا مرفوعًا"}]'::jsonb, 'b', '«إنّ» حرف ناسخ ينصب المبتدأ فيسمّيه اسمها. بحذفها تعود الجملة إلى أصلها الاسميّ البسيط، فيرتفع «الطّقسُ» مبتدأً بعد أن كان منصوبًا اسمًا لإنّ. الخطأ الشّائع الظنّ بأنّه يبقى منصوبًا.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('79463836-49d6-562b-b1bb-3190441693f8', 'a9bde986-c107-5523-9fba-1b3be7b7b0b8', 'أيّ العبارات التّالية صحيحة؟', '[{"id":"a","text":"صارَ حرف ناسخ ينصب الاسم ويرفع الخبر"},{"id":"b","text":"لكنَّ فعل ناسخ يرفع الاسم وينصب الخبر"},{"id":"c","text":"كادَ فعل ناسخ يرفع اسمه وينصب خبره، وخبره غالبًا جملة فعليّة"},{"id":"d","text":"لعلَّ فعل ناسخ يفيد التّرجّي"}]'::jsonb, 'c', '«كادَ» من أفعال المقاربة، وهو فعل ناسخ يرفع اسمه وينصب خبره الّذي يكون غالبًا جملة فعليّة مضارعة تدلّ على الحدث المقارَب وقوعه. أمّا «صارَ» ففعل يرفع اسمه لا ينصبه، و«لكنَّ» و«لعلَّ» حرفان ناسخان لا فعلان.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ba049487-717c-5104-9adb-637b1bc2fefd', 'a9bde986-c107-5523-9fba-1b3be7b7b0b8', '«المدرسةُ ساحتُها واسعةٌ» جملة اسميّة خبرها جملة اسميّة. إذا أدخلنا عليها «كانت» فصارت «كانتِ المدرسةُ ساحتُها واسعةً»، فما نوع خبر «كانتِ» هنا وما إعرابه؟', '[{"id":"a","text":"خبر مفرد منصوب"},{"id":"b","text":"جملة اسميّة في محلّ رفع خبر"},{"id":"c","text":"شبه جملة في محلّ نصب"},{"id":"d","text":"جملة اسميّة في محلّ نصب خبر كانت"}]'::jsonb, 'd', 'خبر «كانتِ» هنا جملة اسميّة كاملة («ساحتُها واسعةً») في محلّ نصب، بعد أن كانت في محلّ رفع خبرًا للمبتدأ قبل دخول الناسخ. الجملة الاسميّة تقع خبرًا للنواسخ الفعليّة في محلّ نصب، تمامًا كما تقع في محلّ رفع خبرًا للمبتدأ في الجملة البسيطة.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('941803b3-dbd9-5a1b-80bb-c2c8d3470fda', 'a9bde986-c107-5523-9fba-1b3be7b7b0b8', 'أيّ الأفعال التّالية يختلف عن البقيّة لأنّ خبره غالبًا اسم مفرد أو جملة اسميّة، لا جملة فعليّة مضارعة كأخواته في هذه القائمة؟', '[{"id":"a","text":"أصبحَ"},{"id":"b","text":"كادَ"},{"id":"c","text":"شرعَ"},{"id":"d","text":"بدأَ"}]'::jsonb, 'a', '«كادَ» و«شرعَ» و«بدأَ» من أفعال المقاربة والشّروع، وخبرها غالبًا جملة فعليّة مضارعة تدلّ على الحدث نفسه (كادَ ينزلُ، شرعَ يكتبُ). أمّا «أصبحَ» من أخوات «كان»، فخبرها غالبًا اسم مفرد أو جملة اسميّة، لا جملة فعليّة مضارعة ملازمة.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('93857dff-da4f-5f86-9a6b-5436cc50bc19', 'a9bde986-c107-5523-9fba-1b3be7b7b0b8', 'أريد توكيد الجملة «الفريقُ يفوزُ» بإدخال «إنَّ» عليها، فصارت «إنَّ الفريقَ يفوزُ». ما إعراب «الفريقَ» وما محلّ جملة «يفوزُ»؟', '[{"id":"a","text":"الفريقَ خبر إنّ منصوب، وجملة يفوزُ اسمها"},{"id":"b","text":"الفريقَ اسم إنّ منصوب، وجملة يفوزُ في محلّ رفع خبر إنّ"},{"id":"c","text":"الفريقَ اسم إنّ مرفوع، وجملة يفوزُ في محلّ نصب خبر"},{"id":"d","text":"الفريقَ فاعل، وجملة يفوزُ لا محلّ لها"}]'::jsonb, 'b', '«إنّ» تنصب الاسم وترفع الخبر، فـ«الفريقَ» اسم إنّ منصوب بالفتحة، وجملة «يفوزُ» (فعليّة) وقعت خبرًا لإنّ فهي في محلّ رفع خبر إنّ، تمامًا كما تقع الجملة الفعليّة خبرًا للمبتدأ في الجملة البسيطة.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

