  ('42c6bc10-0ab0-5eb9-ba1c-640fb6705f0e', '277b9aec-8131-541f-80a3-60a905cbfc3a', 'arabic-7eme', '📝 تدريب ⭐⭐⭐ (مراجعة شاملة): الجملة الاسميّة والنّواسخ', 3, 120, 30, 'boss', 'admin', 5)
