INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('521f3277-faec-5085-b83a-0280ab0a0378', '42c6bc10-0ab0-5eb9-ba1c-640fb6705f0e', '«الطّائرُ فوقَ الشّجرةِ» — ما نوع الخبر في هذه الجملة؟', '[{"id":"a","text":"خبر مفرد"},{"id":"b","text":"خبر جملة فعليّة"},{"id":"c","text":"خبر جملة اسميّة"},{"id":"d","text":"خبر شبه جملة (ظرف)"}]'::jsonb, 'd', '«فوقَ الشّجرةِ» ظرف مكان (شبه جملة) وقع خبرًا للمبتدأ «الطّائرُ»، فهو في محلّ رفع خبر.', 1)
