INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9a132c0a-69bc-5691-8773-3abbefba919d', '42c6bc10-0ab0-5eb9-ba1c-640fb6705f0e', '«باتَ الحارسُ ساهرًا» — اسم «باتَ» وخبرها هما على التّرتيب:', '[{"id":"a","text":"ساهرًا / الحارسُ"},{"id":"b","text":"الحارسُ / باتَ"},{"id":"c","text":"الحارسُ / ساهرًا"},{"id":"d","text":"باتَ / ساهرًا"}]'::jsonb, 'c', '«باتَ» فعل ناسخ يرفع المبتدأ اسمًا له، فـ«الحارسُ» اسمها، وينصب الخبر، فـ«ساهرًا» خبرها.', 2)
