INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('314cb11f-a703-5783-8f05-71150b87ef18', '42c6bc10-0ab0-5eb9-ba1c-640fb6705f0e', '«أوشكتِ الحصّةُ تنتهي» — ما الفرق بين «أوشكَ» و«شرعَ» من حيث المعنى؟', '[{"id":"a","text":"لا فرق بينهما، كلاهما يفيد الشّروع"},{"id":"b","text":"«أوشكَ» يفيد البدء في الحدث، و«شرعَ» يفيد قربه"},{"id":"c","text":"كلاهما لا يعمل عمل النّواسخ"},{"id":"d","text":"«أوشكَ» يفيد قرب وقوع الحدث، و«شرعَ» يفيد البدء فيه"}]'::jsonb, 'd', '«أوشكَ» من أفعال المقاربة (تدلّ على قرب وقوع الحدث)، بينما «شرعَ» من أفعال الشّروع (تدلّ على البدء الفعليّ في الحدث).', 3)
