  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f0c60afe-3425-50d0-82fd-801917459ea3', '42c6bc10-0ab0-5eb9-ba1c-640fb6705f0e', '«إنَّ الصّدقَ فضيلةٌ» — لو حذفنا «إنَّ» من الجملة، فما إعراب «الصّدقُ» و«فضيلةٌ»؟', '[{"id":"a","text":"الصّدقُ مبتدأ مرفوع، فضيلةٌ خبر مرفوع"},{"id":"b","text":"الصّدقُ اسم إنّ محذوف، فضيلةٌ خبرها"},{"id":"c","text":"الصّدقُ فاعل، فضيلةٌ مفعول به"},{"id":"d","text":"الصّدقُ خبر مقدّم، فضيلةٌ مبتدأ مؤخّر"}]'::jsonb, 'a', 'بحذف الحرف الناسخ تعود الجملة إلى أصلها الاسميّ البسيط: «الصّدقُ فضيلةٌ»، فـ«الصّدقُ» مبتدأ مرفوع و«فضيلةٌ» خبر مرفوع، وهذا يُبيّن أنّ عمل «إنّ» نصب الاسم ورفع الخبر لا العكس.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f9768a88-7d13-5b2c-b946-11f79d02157b', '42c6bc10-0ab0-5eb9-ba1c-640fb6705f0e', '«ليتَ العطلةَ طويلةٌ» — ما الفرق بين «ليتَ» في هذه الجملة و«لعلَّ» من حيث المعنى؟', '[{"id":"a","text":"كلاهما يفيدان التّوكيد بالمعنى نفسه"},{"id":"b","text":"«ليتَ» للتمنّي في أمر قد يتعذّر وقوعه، و«لعلَّ» للترجّي في أمر ممكن ويُرجى"},{"id":"c","text":"«ليتَ» للترجّي و«لعلَّ» للتمنّي"},{"id":"d","text":"«ليتَ» تنصب الخبر وترفع الاسم عكس «لعلَّ»"}]'::jsonb, 'b', '«ليتَ» تفيد التّمنّي في أمر محبوب قد يستحيل وقوعه (كطول العطلة)، أمّا «لعلَّ» فتفيد التّرجّي في أمر ممكن الحدوث فعلًا. وكلاهما ينصب الاسم ويرفع الخبر مثل بقيّة أخوات إنّ.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('31544531-cb26-51dd-9805-ef2ae23c927b', '42c6bc10-0ab0-5eb9-ba1c-640fb6705f0e', '«صارتِ المدينةُ جميلةً» — ما نوع الناسخ في هذه الجملة، وما أثره في الإعراب؟', '[{"id":"a","text":"حرف ناسخ ينصب الاسم ويرفع الخبر"},{"id":"b","text":"لا ناسخ في الجملة"},{"id":"c","text":"فعل ناسخ يرفع الاسم وينصب الخبر"},{"id":"d","text":"فعل ناسخ ينصب الاسم والخبر معًا"}]'::jsonb, 'c', '«صارَ» فعل ناسخ من أخوات «كان» يدلّ على التّحوّل، يرفع المبتدأ اسمًا له («المدينةُ») وينصب الخبر خبرًا له («جميلةً»).', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('2304f28b-7417-5301-9413-3e2760b1c542', '277b9aec-8131-541f-80a3-60a905cbfc3a', 'arabic-7eme', '👑 تحدّي النخبة ⭐⭐⭐⭐: النّواسخ في السّياق', 4, 300, 60, 'challenge', 'admin', 6)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9af8b91d-d5bf-5025-8b32-52e546a7e258', '2304f28b-7417-5301-9413-3e2760b1c542', 'وردت جملة على الشّكل: مبتدأ سابق منصوب، ثمّ خبر لاحق مرفوع، بعد أن دخل عليها ناسخ. أيّ نوع من النّواسخ دخل عليها؟', '[{"id":"a","text":"فعل ناسخ من أخوات كان"},{"id":"b","text":"حرف ناسخ من أخوات إنّ"},{"id":"c","text":"فعل مقاربة"},{"id":"d","text":"لا ناسخ البتّة"}]'::jsonb, 'b', 'الحرف الناسخ (إنّ وأخواتها) هو الّذي ينصب الاسم (السّابق) ويرفع الخبر (اللاحق)، بعكس الفعل الناسخ (كان وأخواتها) الّذي يرفع الاسم وينصب الخبر.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('56544308-e1d6-52d4-a2fa-2b669de15e10', '2304f28b-7417-5301-9413-3e2760b1c542', 'أعرب تلميذ جملة «كادَ القطارُ يصلُ» فقال: «كادَ: فعل ناسخ، القطارُ: خبر كاد مرفوع، يصلُ: جملة فعليّة في محلّ نصب اسم كاد». أين وجه الخطأ في إعرابه؟', '[{"id":"a","text":"لا خطأ، الإعراب صحيح تمامًا"},{"id":"b","text":"الخطأ أنّ «كادَ» ليست فعلًا ناسخًا"},{"id":"c","text":"الخطأ أنّ «القطارُ» اسم كاد لا خبرها، و«يصلُ» خبرها لا اسمها"},{"id":"d","text":"الخطأ أنّ «يصلُ» لا محلّ لها من الإعراب"}]'::jsonb, 'c', '«كادَ» فعل ناسخ يرفع اسمه وينصب خبره: «القطارُ» اسم كاد مرفوع (لا خبرها)، وجملة «يصلُ» خبر كاد في محلّ نصب (لا اسمها). الخطأ الشّائع قلب الاسم والخبر عند وجود جملة فعليّة بعد الفعل الناسخ مباشرةً.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a1d66480-b83a-5063-91bc-cee83ff64bb3', '2304f28b-7417-5301-9413-3e2760b1c542', '«كانَ الطّائرُ فوقَ الشّجرةِ» — ما نوع خبر «كانَ» هنا؟', '[{"id":"a","text":"خبر مفرد منصوب"},{"id":"b","text":"جملة فعليّة في محلّ نصب"},{"id":"c","text":"جملة اسميّة في محلّ نصب"},{"id":"d","text":"شبه جملة (ظرف) في محلّ نصب"}]'::jsonb, 'd', '«فوقَ الشّجرةِ» ظرف مكان (شبه جملة) وقع خبرًا لـ«كانَ»، فهو في محلّ نصب خبر كان، تمامًا كما يقع شبه الجملة خبرًا للمبتدأ في الجملة البسيطة.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9fe61834-3f7c-593d-9d3d-a1a080d5b4c2', '2304f28b-7417-5301-9413-3e2760b1c542', 'متى نستعمل «أنَّ» المفتوحة الهمزة بدل «إنَّ» المكسورة؟', '[{"id":"a","text":"بعد فعل مثل عرفتُ أو سمعتُ، لا في أوّل الكلام"},{"id":"b","text":"في أوّل الكلام دائمًا"},{"id":"c","text":"بعد حرف العطف فقط"},{"id":"d","text":"لا فرق بينهما في الاستعمال"}]'::jsonb, 'a', '«أنَّ» المفتوحة الهمزة تقع بعد فعل مثل عرفتُ أو سمعتُ أو علمتُ، ولا تُستعمل في أوّل الكلام، بخلاف «إنَّ» المكسورة الّتي تفتتح بها الجملة.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('fd5df263-b8df-5dbf-a0fc-b6fdcadee9d1', '2304f28b-7417-5301-9413-3e2760b1c542', '«الطّريقُ طويلٌ، لكنَّ المنظرَ جميلٌ» — ما اسم «لكنَّ» وخبرها في الجملة الثّانية؟', '[{"id":"a","text":"اسمها «جميلٌ» مرفوع، خبرها «المنظرَ» منصوب"},{"id":"b","text":"اسمها «المنظرَ» مرفوع، خبرها «جميلٌ» منصوب"},{"id":"c","text":"اسمها «المنظرَ» منصوب، خبرها «جميلٌ» مرفوع"},{"id":"d","text":"لا اسم لها ولا خبر لأنّها حرف عطف هنا"}]'::jsonb, 'c', '«لكنَّ» هنا حرف استدراك ناسخ (مشدّدة) يعمل عمل «إنّ»: ينصب اسمه ويرفع خبره. فـ«المنظرَ» اسمها منصوب بالفتحة، و«جميلٌ» خبرها مرفوع بالضمّة.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ffaa365a-92d4-5788-ab8f-e69f92eb87f9', '2304f28b-7417-5301-9413-3e2760b1c542', '«بدأتِ الأمطارُ تهطلُ، فأصبحتِ الأرضُ خضراءَ» — وردَ ناسخان مختلفا الوظيفة في هذه الجملة، فما الفرق الجوهريّ بين خبريهما رغم أنّ كليهما يرفعان اسمهما وينصبان خبرهما؟', '[{"id":"a","text":"لا فرق بينهما إطلاقًا في الخبر"},{"id":"b","text":"خبر «بدأتِ» جملة فعليّة تدلّ على الحدث الّذي شرعت فيه الأمطارُ، وخبر «أصبحتِ» اسم مفرد يصف حال الأرض بعد التّحوّل"},{"id":"c","text":"خبر «بدأتِ» اسم مفرد، وخبر «أصبحتِ» جملة فعليّة"},{"id":"d","text":"كلاهما ينصب الاسم ويرفع الخبر"}]'::jsonb, 'b', '«بدأتِ» من أفعال الشّروع، وخبرها هنا جملة فعليّة «تهطلُ» تدلّ على الحدث الّذي شرعت فيه «الأمطارُ». أمّا «أصبحتِ» فمن أخوات «كان»، وخبرها هنا اسم مفرد «خضراءَ» يصف الحال الجديدة لـ«الأرضُ» بعد التّحوّل. كلاهما فعل ناسخ يرفع اسمه وينصب خبره، لكن طبيعة الخبر تختلف بحسب المعنى.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('4022593c-0c76-5a30-8f9b-37369d3c0082', 'cc77fed9-0607-5526-9ace-690120b87b8b', 'arabic-7eme', 'اختبار فهم الدرس ⭐', 1, 20, 5, 'quiz', 'admin', 0)
