INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2dba55c2-e1fb-5ec1-8e87-24a80435ae59', '4022593c-0c76-5a30-8f9b-37369d3c0082', 'المفعول المطلق اسمٌ منصوبٌ يكون:', '[{"id":"a","text":"مصدرًا من لفظ الفعل الذي قبله"},{"id":"b","text":"اسمَ ذاتٍ يقع عليه الفعل"},{"id":"c","text":"ظرفًا يدلّ على الزّمان"},{"id":"d","text":"مصدرًا قلبيًّا يبيّن السّبب"}]'::jsonb, 'a', 'المفعول المطلق مصدر منصوب يُذكر بعد فعله من لفظه (من نفس مادّته)، ليؤكّد الفعل أو يبيّن نوعه أو عدده.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('16f5a1a1-650c-5899-9be4-c7121d15890d', '4022593c-0c76-5a30-8f9b-37369d3c0082', '«نجحَ التّلميذُ نجاحًا» — «نجاحًا» في هذه الجملة:', '[{"id":"a","text":"مفعول به"},{"id":"b","text":"مفعول مطلق"},{"id":"c","text":"ظرف زمان"},{"id":"d","text":"مفعول لأجله"}]'::jsonb, 'b', '«نجاحًا» مصدر من لفظ الفعل «نجحَ» يؤكّده، فهو مفعول مطلق منصوب.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('21007b8e-4d44-5983-b773-69dc1b58460e', '4022593c-0c76-5a30-8f9b-37369d3c0082', '«تكلّم الخطيبُ كلامَ الحكماءِ» — المفعول المطلق «كلامَ الحكماءِ» من نوع:', '[{"id":"a","text":"مبيّن للعدد"},{"id":"b","text":"مؤكّد للفعل"},{"id":"c","text":"مبيّن للنّوع"},{"id":"d","text":"مفعول به"}]'::jsonb, 'c', '«كلامَ الحكماءِ» مصدر مضاف يبيّن نوع الكلام (كلام يشبه كلام الحكماء)، فهو مفعول مطلق مبيّن للنّوع، وليس مؤكّدًا (ذاك يأتي مجرّدًا بلا إضافة) ولا مبيّنًا للعدد (ذاك يفيد التّكرار).', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2a4d6243-9528-50b4-a21d-72e736138c0d', '4022593c-0c76-5a30-8f9b-37369d3c0082', '«سافرَ عمّي صباحًا» — «صباحًا» في الجملة:', '[{"id":"a","text":"مفعول مطلق"},{"id":"b","text":"مفعول به"},{"id":"c","text":"مفعول لأجله"},{"id":"d","text":"مفعول فيه (ظرف زمان)"}]'::jsonb, 'd', '«صباحًا» يدلّ على وقت وقوع الفعل (سافرَ في الصّباح)، فهو مفعول فيه (ظرف زمان) منصوب.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c96515cb-7710-598a-93e9-b3d2ac31ba28', '4022593c-0c76-5a30-8f9b-37369d3c0082', 'من شروط المفعول لأجله أن يكون مصدره:', '[{"id":"a","text":"قلبيًّا يدلّ على معنًى نفسيّ"},{"id":"b","text":"اسم ذاتٍ محسوسًا"},{"id":"c","text":"مثنّى دائمًا"},{"id":"d","text":"مقترنًا بحرف جرّ"}]'::jsonb, 'a', 'يُشترط في المفعول لأجله أن يكون مصدرًا قلبيًّا (يدلّ على شعور أو معنى نفسيّ كالخوف والفرح)، لا اسم ذاتٍ محسوسًا، وأن يتّحد مع فعله في الزّمن والفاعل، ولا يُذكر بحرف جرّ وإلّا صار مجرورًا.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

