INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0bcfbe8b-ce95-5c92-b210-a219ff598dfc', '13348114-e14c-5a35-ba5a-2f7021ffd08c', 'المفعول المطلق مصدرٌ منصوبٌ يُذكر بعد فعله:', '[{"id":"a","text":"من لفظه (من نفس مادّته)"},{"id":"b","text":"من غير لفظه"},{"id":"c","text":"مجرورًا دائمًا"},{"id":"d","text":"بلا علاقة بالفعل"}]'::jsonb, 'a', 'المفعول المطلق مصدر منصوب من نفس مادّة الفعل (من لفظه)، يُذكر بعده ليؤكّده أو يبيّن نوعه أو عدده.', 1)
