INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('68f889db-e154-5f07-aede-54b74c1504ff', '13348114-e14c-5a35-ba5a-2f7021ffd08c', 'أيّ الجمل التّالية تحتوي على مفعول مطلق؟', '[{"id":"a","text":"لعبَ الولدُ كرةَ القدمِ"},{"id":"b","text":"لعبَ الولدُ لعبًا"},{"id":"c","text":"لعبَ الولدُ صباحًا"},{"id":"d","text":"لعبَ الولدُ خوفًا من العقابِ"}]'::jsonb, 'b', '«لعبًا» مصدر من لفظ الفعل «لعبَ» يؤكّده، فهو مفعول مطلق. أمّا «كرةَ القدمِ» فمفعول به، و«صباحًا» ظرف زمان، و«خوفًا» مفعول لأجله.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('662fb7bd-a6e0-528a-8861-00ed01d6b3d2', '13348114-e14c-5a35-ba5a-2f7021ffd08c', '«نامَ القطُّ تحتَ الطّاولةِ» — «تحتَ الطّاولةِ» في الجملة:', '[{"id":"a","text":"ظرف زمان"},{"id":"b","text":"ظرف مكان"},{"id":"c","text":"مفعول به"},{"id":"d","text":"مفعول لأجله"}]'::jsonb, 'b', '«تحتَ الطّاولةِ» يدلّ على مكان وقوع الفعل (نامَ في مكانٍ تحت الطّاولة)، فهو مفعول فيه (ظرف مكان) منصوب.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d6125bd6-50bd-5615-b0e8-90db54693e27', '13348114-e14c-5a35-ba5a-2f7021ffd08c', '«هربَ القطُّ خوفًا من الكلبِ» — «خوفًا» في الجملة:', '[{"id":"a","text":"مفعول به"},{"id":"b","text":"ظرف مكان"},{"id":"c","text":"مفعول مطلق"},{"id":"d","text":"مفعول لأجله"}]'::jsonb, 'd', '«خوفًا» مصدر قلبيّ يبيّن سبب الهروب (لماذا هرب؟ خوفًا)، فهو مفعول لأجله منصوب.', 4)
