INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5ea97383-f444-51bc-a8b1-884555223b44', '13348114-e14c-5a35-ba5a-2f7021ffd08c', '«ضحكَ الأطفالُ ضحكًا» — نوع المفعول المطلق «ضحكًا»:', '[{"id":"a","text":"مؤكّد للفعل"},{"id":"b","text":"مبيّن للنّوع"},{"id":"c","text":"مبيّن للعدد"},{"id":"d","text":"مفعول به"}]'::jsonb, 'a', '«ضحكًا» مصدر مجرّد بلا إضافة ولا تثنية، يؤكّد وقوع فعل الضّحك فحسب، فهو مفعول مطلق مؤكّد للفعل.', 5)
