  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a4415577-3095-50ab-a6c3-ca5a79b0a25c', '13348114-e14c-5a35-ba5a-2f7021ffd08c', '«سأزورُك غدًا» — «غدًا» في الجملة:', '[{"id":"a","text":"مفعول به"},{"id":"b","text":"مفعول لأجله"},{"id":"c","text":"ظرف زمان"},{"id":"d","text":"مفعول مطلق"}]'::jsonb, 'c', '«غدًا» يدلّ على وقت الزّيارة (سأزورُك في الغد)، فهو مفعول فيه (ظرف زمان) منصوب.', 6)
