INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('1f6c2d11-e397-592e-b457-7dc65abcda18', 'cc77fed9-0607-5526-9ace-690120b87b8b', 'arabic-7eme', '⚔️ زعيم الفصل ⭐⭐⭐: المفعول المطلق والمفعول فيه والمفعول لأجله', 3, 120, 30, 'boss', 'admin', 2)
