  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5b08dc4d-bfa1-589f-bd29-823975cdc1f3', '1f6c2d11-e397-592e-b457-7dc65abcda18', '«ركضَ الحصانُ ركضَ الرّيحِ» — نوع المفعول المطلق «ركضَ الرّيحِ»:', '[{"id":"a","text":"مبيّن للنّوع"},{"id":"b","text":"مؤكّد للفعل"},{"id":"c","text":"مبيّن للعدد"},{"id":"d","text":"مفعول لأجله"}]'::jsonb, 'a', '«ركضَ الرّيحِ» مصدر مضاف يبيّن نوع الرّكض وصفته (ركضٌ سريع كالرّيح)، فهو مفعول مطلق مبيّن للنّوع؛ ليس مؤكّدًا (ذاك يُذكر مجرّدًا دون إضافة) ولا مبيّنًا للعدد (ذاك يفيد التّكرار).', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('331cf3ec-31db-5453-bd98-25c164f8d438', '1f6c2d11-e397-592e-b457-7dc65abcda18', '«سلّمَ الضّيفُ سلامَينِ» — نوع المفعول المطلق «سلامَينِ»:', '[{"id":"a","text":"مبيّن للنّوع"},{"id":"b","text":"مبيّن للعدد"},{"id":"c","text":"مؤكّد للفعل"},{"id":"d","text":"مفعول به"}]'::jsonb, 'b', '«سلامَينِ» مصدر جاء مثنّى يبيّن عدد مرّات وقوع الفعل (سلّمَ مرّتين)، فهو مفعول مطلق مبيّن للعدد.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('467367e9-e8eb-598b-88a3-b742d01398f8', '1f6c2d11-e397-592e-b457-7dc65abcda18', '«ذاكرَ التّلميذُ للنّجاحِ» — كلمة «للنّجاحِ» في هذه الجملة:', '[{"id":"a","text":"مفعول لأجله منصوب"},{"id":"b","text":"مفعول مطلق"},{"id":"c","text":"اسم مجرور باللّام، لا مفعول لأجله"},{"id":"d","text":"ظرف زمان"}]'::jsonb, 'c', 'لمّا اقترن المصدر «النّجاح» بحرف الجرّ اللّام صار اسمًا مجرورًا لا مفعولًا لأجله منصوبًا؛ فالمفعول لأجله يُشترط فيه أن يُذكر بلا حرف جرّ ليُنصب: لو قلنا «ذاكرَ التّلميذُ رغبةً في النّجاحِ» لكانت «رغبةً» هي المفعول لأجله المنصوب.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2076c7b2-c7c1-54d0-9f68-c7a0b47ed50d', '1f6c2d11-e397-592e-b457-7dc65abcda18', '«أدّى اللّاعبُ أداءَ المحترفينَ» — أيّ إعرابٍ صحيح لـ«أداءَ المحترفينَ»؟', '[{"id":"a","text":"مفعول به منصوب"},{"id":"b","text":"مفعول مطلق مبيّن للعدد"},{"id":"c","text":"ظرف مكان منصوب"},{"id":"d","text":"مفعول مطلق مبيّن للنّوع منصوب وهو مضاف"}]'::jsonb, 'd', '«أداءَ» مصدر من لفظ الفعل «أدّى» أُضيف إلى «المحترفينَ» ليبيّن نوع الأداء (أداء يشبه أداء المحترفين)، فهو مفعول مطلق مبيّن للنّوع منصوب بالفتحة، وهو مضاف والمحترفين مضاف إليه مجرور.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('19194e52-e16b-5638-bc9a-bcf912e47f3d', '1f6c2d11-e397-592e-b457-7dc65abcda18', '«ذاكرَ التّلميذُ مذاكرةً طويلةً» — هل «مذاكرةً» مفعول لأجله؟', '[{"id":"a","text":"لا، لأنّها مصدر لكنّها ليست قلبيّةً (ليست شعورًا نفسيًّا)"},{"id":"b","text":"نعم، لأنّها مصدر قلبيّ يدلّ على السّبب"},{"id":"c","text":"نعم، لأنّها اسم ذاتٍ يقع عليه الفعل"},{"id":"d","text":"لا، لأنّها ظرف زمان لا مصدر"}]'::jsonb, 'a', '«مذاكرةً» مصدر من لفظ الفعل «ذاكرَ»، فهي في الحقيقة مفعول مطلق لا مفعول لأجله؛ لأنّ المفعول لأجله يُشترط فيه أن يكون مصدرًا قلبيًّا يدلّ على شعور أو معنًى نفسيّ (كالخوف والفرح والرّغبة)، والمذاكرة نشاطٌ لا شعورٌ.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('48451845-ee58-5f09-ba93-d8564187b4c5', '1f6c2d11-e397-592e-b457-7dc65abcda18', 'في الجملة «حيّا التّلميذُ معلّمَه تحيّةً حارّةً احترامًا له صباحَ الاثنينِ» — ما نوع «تحيّةً حارّةً»؟', '[{"id":"a","text":"مفعول به"},{"id":"b","text":"مفعول مطلق مبيّن للنّوع"},{"id":"c","text":"مفعول لأجله"},{"id":"d","text":"ظرف زمان"}]'::jsonb, 'b', '«تحيّةً» مصدر من لفظ الفعل «حيّا» موصوف بـ«حارّةً» يبيّن نوع التّحيّة، فهو مفعول مطلق مبيّن للنّوع؛ أمّا «احترامًا» في الجملة نفسها فمفعول لأجله يبيّن السّبب، و«صباحَ الاثنينِ» ظرف زمان يبيّن الوقت.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

