INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('816865cd-091b-57d1-ab0e-9bf1e11cc015', 'd22f46ff-f25c-5c07-9ab0-d1204f1ac95d', '«اجتمعَ الأصدقاءُ مساءَ الخميسِ» — «مساءَ الخميسِ» في الجملة:', '[{"id":"a","text":"مفعول به"},{"id":"b","text":"ظرف مكان"},{"id":"c","text":"مفعول فيه (ظرف زمان)"},{"id":"d","text":"مفعول لأجله"}]'::jsonb, 'c', '«مساءَ الخميسِ» يدلّ على وقت وقوع الفعل (اجتمعوا في مساء الخميس)، فهو مفعول فيه (ظرف زمان) منصوب، وهو مضاف.', 2)
