INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('348d83b9-6279-5f7a-9375-067827e6a9e7', 'd22f46ff-f25c-5c07-9ab0-d1204f1ac95d', '«جلسَ الطّلابُ أمامَ السّبّورةِ» — «أمامَ السّبّورةِ» في الجملة:', '[{"id":"a","text":"ظرف زمان"},{"id":"b","text":"مفعول مطلق"},{"id":"c","text":"مفعول به"},{"id":"d","text":"ظرف مكان"}]'::jsonb, 'd', '«أمامَ السّبّورةِ» يدلّ على مكان الجلوس، فهو مفعول فيه (ظرف مكان) منصوب.', 3)
