INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2b6710ff-3347-5b59-9804-1cd4706dbf2d', 'd22f46ff-f25c-5c07-9ab0-d1204f1ac95d', '«بكى الطّفلُ حزنًا على لعبتِه الضّائعةِ» — «حزنًا» في الجملة:', '[{"id":"a","text":"مفعول به"},{"id":"b","text":"مفعول لأجله"},{"id":"c","text":"مفعول مطلق"},{"id":"d","text":"ظرف زمان"}]'::jsonb, 'b', '«حزنًا» مصدر قلبيّ يبيّن سبب البكاء (لماذا بكى؟ حزنًا على لعبته)، فهو مفعول لأجله منصوب.', 4)
