INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('73242651-52ce-5bb4-932f-72ceab84e357', 'd22f46ff-f25c-5c07-9ab0-d1204f1ac95d', '«انتصرَ الفريقُ انتصارًا كبيرًا» — نوع المفعول المطلق «انتصارًا»:', '[{"id":"a","text":"مبيّن للنّوع"},{"id":"b","text":"مبيّن للعدد"},{"id":"c","text":"مفعول لأجله"},{"id":"d","text":"مؤكّد للفعل"}]'::jsonb, 'd', '«انتصارًا» مصدر من لفظ الفعل «انتصرَ»، غير مضاف ولا مثنّى (وصفه بـ«كبيرًا» لا يغيّر نوعه)، فهو مفعول مطلق مؤكّد للفعل.', 5)
