INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e09548b7-1865-551e-90ae-8f9621e95783', 'd22f46ff-f25c-5c07-9ab0-d1204f1ac95d', '«وقفَ الحارسُ يسارَ البوّابةِ» — «يسارَ البوّابةِ» في الجملة:', '[{"id":"a","text":"ظرف مكان مضاف"},{"id":"b","text":"ظرف زمان"},{"id":"c","text":"مفعول مطلق"},{"id":"d","text":"مفعول لأجله"}]'::jsonb, 'a', '«يسارَ» اسم منصوب على الظّرفيّة يدلّ على مكان الوقوف، وهو مضاف و«البوّابةِ» مضاف إليه مجرور، فهو ظرف مكان (مفعول فيه).', 6)
