INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0058194d-61a5-5792-b70e-236efafd75fe', 'cc6720aa-b2c7-5125-a9e3-99e6115898f0', '«أنصتَ التّلاميذُ إنصاتَ المستمعينَ احترامًا لمعلّمِهم عصرَ الثّلاثاءِ» — ما نوع كلٍّ من (إنصاتَ المستمعينَ)، (احترامًا)، (عصرَ الثّلاثاءِ) على التّرتيب؟', '[{"id":"a","text":"مفعول مطلق مبيّن للنّوع — مفعول لأجله — ظرف زمان"},{"id":"b","text":"مفعول لأجله — مفعول مطلق مبيّن للنّوع — ظرف مكان"},{"id":"c","text":"ظرف زمان — مفعول مطلق مبيّن للعدد — مفعول لأجله"},{"id":"d","text":"مفعول مطلق مبيّن للعدد — ظرف زمان — مفعول لأجله"}]'::jsonb, 'a', '«إنصاتَ المستمعينَ» مصدر مضاف يبيّن نوع الإنصات، فهو مفعول مطلق مبيّن للنّوع؛ «احترامًا» مصدر قلبيّ يبيّن سبب الإنصات فهو مفعول لأجله؛ «عصرَ الثّلاثاءِ» يبيّن وقت الفعل فهو ظرف زمان. الجملة الواحدة قد تجمع بين المنصوبات الثّلاثة معًا.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5014c251-e8d7-515b-ae50-686600063a6e', 'cc6720aa-b2c7-5125-a9e3-99e6115898f0', 'أردتَ أن تصوغ مفعولًا مطلقًا «مؤكّدًا للفعل» من الفعل «شكَرَ»، فأيّ الصّياغات صحيحة؟', '[{"id":"a","text":"شكَرَ الرّجلُ شكرَ العارفينَ"},{"id":"b","text":"شكَرَ الرّجلُ شكرتَينِ"},{"id":"c","text":"شكَرَ الرّجلُ مساءً"},{"id":"d","text":"شكَرَ الرّجلُ شكرًا"}]'::jsonb, 'd', 'المؤكّد للفعل مصدرٌ مجرّدٌ (بلا إضافة ولا تثنية) يُذكر بعد فعله من لفظه لرفع الشّكّ عن وقوعه: «شكرًا». أمّا (أ) فمبيّن للنّوع (مضاف)، و(ب) مبيّن للعدد (مثنّى)، و(ج) ظرف زمان لا مفعول مطلق.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('610da305-c5c6-5ec6-b1b4-3e9919d8e9f6', 'cc6720aa-b2c7-5125-a9e3-99e6115898f0', 'أردتَ أن تصوغ مفعولًا مطلقًا «مبيّنًا للعدد» من الفعل «طرقَ»، فأيّ الجمل التّالية تحقّق ذلك؟', '[{"id":"a","text":"طرقَ الزّائرُ البابَ"},{"id":"b","text":"طرقَ الزّائرُ الحديدةَ"},{"id":"c","text":"طرقَ الزّائرُ البابَ طرقتَينِ"},{"id":"d","text":"طرقَ الزّائرُ صباحًا"}]'::jsonb, 'c', '«طرقتَينِ» مصدر جاء مثنّى يفيد تكرار الفعل مرّتين، فهو مفعول مطلق مبيّن للعدد. الجملة (أ) لا مفعول مطلق فيها («البابَ» مفعول به)، و(ب) «الحديدةَ» مفعول به أيضًا، و(د) «صباحًا» ظرف زمان لا مفعول مطلق.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('84fb30f9-140c-5a19-8f8d-6da087f3c088', 'cc6720aa-b2c7-5125-a9e3-99e6115898f0', '«سافرَ الشّابُّ طلبًا للرّزقِ» — لو حُذفت «للرّزقِ» وقلنا «سافرَ الشّابُّ طلبَ الرّزقِ» (بلا لام، مضافًا)، فماذا يتغيّر في إعراب «طلبَ»؟', '[{"id":"a","text":"يبقى الإعراب نفسه، مفعولًا لأجله منصوبًا مضافًا"},{"id":"b","text":"يصبح مفعولًا مطلقًا لأنّه أُضيف"},{"id":"c","text":"يصبح ظرف زمان"},{"id":"d","text":"يصبح فعلًا"}]'::jsonb, 'a', '«طلبَ» مصدرٌ قلبيٌّ (الطّلب رغبة نفسيّة) يبيّن سبب السّفر ومتّحد مع فعله في الزّمن والفاعل، فيبقى مفعولًا لأجله منصوبًا سواء أضيف إلى «الرّزقِ» أم لا؛ فالإضافة لا تُخرجه عن كونه مفعولًا لأجله، والعبرة بشروطه الثّلاثة لا بصيغته.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('38add226-f08e-5f58-8102-0aa294990747', 'cc6720aa-b2c7-5125-a9e3-99e6115898f0', 'أيّ العبارات التّالية صحيحة؟', '[{"id":"a","text":"كلّ مصدرٍ منصوبٍ بعد فعله هو مفعول مطلق، مهما كان معناه"},{"id":"b","text":"ظرف الزّمان والمكان يُنصبان لأنّ فيهما معنى حرف الجرّ «في»"},{"id":"c","text":"المفعول لأجله يبقى منصوبًا ولو اقترن بلام الجرّ"},{"id":"d","text":"المفعول المطلق المبيّن للعدد لا يأتي إلّا مفردًا"}]'::jsonb, 'b', 'ظرف الزّمان والمكان يُنصبان على تقدير معنى «في» (سافرَ صباحًا = سافرَ في الصّباح)، وهذا أساس نصبهما. أمّا (أ) فخطأ لأنّ المصدر لا يكون مفعولًا مطلقًا إلّا من لفظ الفعل نفسه؛ و(ج) خطأ لأنّ اقترانه باللّام يجعله مجرورًا لا منصوبًا؛ و(د) خطأ لأنّه يأتي غالبًا مثنّى كمرّتين.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4cb95ca1-2092-55af-8e23-0a8c4a0630ad', 'cc6720aa-b2c7-5125-a9e3-99e6115898f0', 'في وصفٍ لرحلة: «سرنا سيرًا حثيثًا صباحًا باكرًا، ثمّ توقّفنا قليلًا شرقَ الوادي، رغبةً في الاستراحةِ» — ما إعراب «شرقَ الوادي»؟', '[{"id":"a","text":"مفعول مطلق مبيّن للنّوع"},{"id":"b","text":"ظرف زمان منصوب"},{"id":"c","text":"مفعول لأجله"},{"id":"d","text":"ظرف مكان منصوب وهو مضاف"}]'::jsonb, 'd', '«شرقَ» اسم مكان منصوب على الظّرفيّة (توقّفنا في شرق الوادي)، وهو مضاف و«الوادي» مضاف إليه مجرور؛ أمّا «سيرًا حثيثًا» في الجملة نفسها فمفعول مطلق مبيّن للنّوع، و«صباحًا باكرًا» ظرف زمان، و«رغبةً» مفعول لأجله.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('7c828c9b-1d61-53de-ad10-b4c718af9140', 'cc77fed9-0607-5526-9ace-690120b87b8b', 'arabic-7eme', '📝 تدريب ⭐⭐⭐ (مراجعة شاملة): المفعول المطلق والمفعول فيه والمفعول لأجله', 3, 120, 30, 'boss', 'admin', 5)
ON CONFLICT (id) DO UPDATE SET
