  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ec0925ed-fb16-589c-9cef-48f5ecf3fd30', '7c828c9b-1d61-53de-ad10-b4c718af9140', '«قدّرَ الجمهورُ الحكمَ تقديرًا» — «تقديرًا» في الجملة:', '[{"id":"a","text":"مفعول به"},{"id":"b","text":"مفعول مطلق"},{"id":"c","text":"ظرف زمان"},{"id":"d","text":"مفعول لأجله"}]'::jsonb, 'b', '«تقديرًا» مصدر من لفظ الفعل «قدّرَ» يؤكّده، فهو مفعول مطلق منصوب.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3d1000f1-f84a-51ea-aa9d-b6225a84dcc3', '7c828c9b-1d61-53de-ad10-b4c718af9140', '«صفّقَ الجمهورُ تصفيقتَينِ» — نوع المفعول المطلق «تصفيقتَينِ»:', '[{"id":"a","text":"مبيّن للنّوع"},{"id":"b","text":"مؤكّد للفعل"},{"id":"c","text":"مبيّن للعدد"},{"id":"d","text":"مفعول به"}]'::jsonb, 'c', '«تصفيقتَينِ» مصدر جاء مثنّى يبيّن أنّ التّصفيق وقع مرّتين، فهو مفعول مطلق مبيّن للعدد.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('893ba0cc-1129-5b04-8890-2d760a73eca2', '7c828c9b-1d61-53de-ad10-b4c718af9140', '«قابلتُ صديقي بعدَ الظّهرِ» — «بعدَ الظّهرِ» في الجملة:', '[{"id":"a","text":"ظرف مكان"},{"id":"b","text":"مفعول مطلق"},{"id":"c","text":"مفعول لأجله"},{"id":"d","text":"ظرف زمان"}]'::jsonb, 'd', '«بعدَ الظّهرِ» يدلّ على وقت المقابلة، فهو مفعول فيه (ظرف زمان) منصوب.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2063ed3e-2726-5786-b63c-06ed6ef7a51c', '7c828c9b-1d61-53de-ad10-b4c718af9140', '«جلسَ الحكمُ وسطَ الملعبِ» — «وسطَ الملعبِ» في الجملة:', '[{"id":"a","text":"ظرف زمان"},{"id":"b","text":"ظرف مكان"},{"id":"c","text":"مفعول لأجله"},{"id":"d","text":"مفعول مطلق"}]'::jsonb, 'b', '«وسطَ الملعبِ» يدلّ على مكان الجلوس، فهو مفعول فيه (ظرف مكان) منصوب، وهو مضاف.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
