INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9295a4e2-b512-5e1a-8c10-f80bc814a088', '7c828c9b-1d61-53de-ad10-b4c718af9140', '«صرخَ الرّاكبُ فزعًا من الحادثِ» — «فزعًا» في الجملة:', '[{"id":"a","text":"مفعول مطلق"},{"id":"b","text":"ظرف زمان"},{"id":"c","text":"مفعول لأجله"},{"id":"d","text":"مفعول به"}]'::jsonb, 'c', '«فزعًا» مصدر قلبيّ يبيّن سبب الصّراخ (لماذا صرخ؟ فزعًا من الحادث)، فهو مفعول لأجله منصوب.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('de08cb27-15e4-5005-b70e-c370e00bce8a', '7c828c9b-1d61-53de-ad10-b4c718af9140', '«تبرّعَ الرّجلُ رحمةً بالفقراءِ» — هل «رحمةً» تحقّق شروط المفعول لأجله الثّلاثة؟', '[{"id":"a","text":"نعم، فهي مصدر قلبيّ (شعور رحمة)، ومتّحدة مع فعل التّبرّع في الزّمن والفاعل"},{"id":"b","text":"لا، لأنّها ليست مصدرًا بل اسم ذاتٍ"},{"id":"c","text":"لا، لأنّ فاعل الرّحمة يختلف عن فاعل التّبرّع"},{"id":"d","text":"نعم، لكنّها منصوبة على أنّها مفعول مطلق لا لأجله"}]'::jsonb, 'a', '«رحمةً» مصدرٌ (من رحِمَ)، وهي قلبيّة تدلّ على شعور نفسيّ، وفاعل الشّعور بالرّحمة هو نفسه فاعل التّبرّع (الرّجل)، والزّمن واحد؛ فقد استوفت الشّروط الثّلاثة فهي مفعول لأجله منصوب صحيح.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

