  ('1f1955cc-8d7b-5d18-88ed-08136d14c5ba', 'cc77fed9-0607-5526-9ace-690120b87b8b', 'arabic-7eme', '👑 تحدّي القمّة ⭐⭐⭐⭐: ذروة المفعول المطلق والمفعول فيه والمفعول لأجله', 4, 300, 60, 'challenge', 'admin', 6)
