INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c7ab70bf-cbd0-5ebb-9d9f-3cf61bdd67dc', '1f1955cc-8d7b-5d18-88ed-08136d14c5ba', '«استقبلَ الوفدُ استقبالَ الملوكِ ابتهاجًا بالنّصرِ عصرَ الجمعةِ» — ما نوع كلٍّ من (استقبالَ الملوكِ)، (ابتهاجًا)، (عصرَ الجمعةِ) على التّرتيب؟', '[{"id":"a","text":"مفعول مطلق مبيّن للنّوع — مفعول لأجله — ظرف زمان"},{"id":"b","text":"مفعول لأجله — مفعول مطلق مبيّن للنّوع — ظرف مكان"},{"id":"c","text":"ظرف زمان — مفعول مطلق مبيّن للعدد — مفعول لأجله"},{"id":"d","text":"مفعول مطلق مبيّن للعدد — ظرف زمان — مفعول لأجله"}]'::jsonb, 'a', '«استقبالَ الملوكِ» مصدر مضاف يبيّن نوع الاستقبال فهو مفعول مطلق مبيّن للنّوع؛ «ابتهاجًا» مصدر قلبيّ يبيّن سبب الاستقبال فهو مفعول لأجله؛ «عصرَ الجمعةِ» يبيّن وقت الفعل فهو ظرف زمان. التّرتيب الصّحيح إذن: نوع، لأجله، زمان.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9966102a-12cd-5837-b4f5-f3574f7d8691', '1f1955cc-8d7b-5d18-88ed-08136d14c5ba', 'أردتَ أن تصوغ مفعولًا مطلقًا «مؤكّدًا للفعل» من الفعل «شكَرَ»، فأيّ الصّياغات صحيحة؟', '[{"id":"a","text":"شكَرَ الرّجلُ شكرَ العارفينَ"},{"id":"b","text":"شكَرَ الرّجلُ شكرتَينِ"},{"id":"c","text":"شكَرَ الرّجلُ مساءً"},{"id":"d","text":"شكَرَ الرّجلُ شكرًا"}]'::jsonb, 'd', 'المؤكّد للفعل مصدرٌ مجرّدٌ (بلا إضافة ولا تثنية) يُذكر بعد فعله من لفظه لرفع الشّكّ عن وقوعه: «شكرًا». أمّا (أ) فمبيّن للنّوع (مضاف)، و(ب) مبيّن للعدد (مثنّى)، و(ج) ظرف زمان لا مفعول مطلق.', 2)
