  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4918ae5c-42e3-56eb-8d5f-c647863570a2', '1f1955cc-8d7b-5d18-88ed-08136d14c5ba', 'قال تلميذٌ: «في جملة (خرجَ الفلّاحُ خارجَ القريةِ)، (خارجَ القريةِ) مفعولٌ لأجله لأنّه يجيب عن سؤال أين؟». صوّب الخطأ في هذا الحكم.', '[{"id":"a","text":"لا خطأ في الحكم"},{"id":"b","text":"الخطأ أنّها ظرف مكان لا مفعول لأجله؛ فالمفعول لأجله يجيب عن «لماذا؟» لا «أين؟»"},{"id":"c","text":"الخطأ في الاسم: الصّواب «داخل» لا «خارج»"},{"id":"d","text":"الخطأ أنّها مفعول مطلق لا ظرف مكان"}]'::jsonb, 'b', '«خارجَ القريةِ» يدلّ على مكان وقوع الفعل (خرجَ في خارج القرية)، فهو ظرف مكان منصوب. الخطأ الشّائع الخلط بين السّؤال الذي يحدّد كلّ متمّم: ظرف المكان يجيب عن «أين؟»، والمفعول لأجله يجيب عن «لماذا؟» ويكون مصدرًا قلبيًّا، وهو غير متحقّق هنا أصلًا لأنّ «خارجَ» ليست مصدرًا.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('77b02573-5478-562c-ada7-366e74b263c8', '1f1955cc-8d7b-5d18-88ed-08136d14c5ba', '«نزلَ الغوّاصُ نزولَ الخبراءِ داخلَ الكهفِ بحثًا عن اللّؤلؤِ» — لو حذفنا «نزولَ الخبراءِ» من الجملة، ماذا يبقى صحيحًا؟', '[{"id":"a","text":"تبقى الجملة بلا أيّ منصوبٍ من المتمّمات الثّلاثة"},{"id":"b","text":"يتحوّل «داخلَ الكهفِ» إلى مفعول مطلق"},{"id":"c","text":"يبقى في الجملة ظرف مكان «داخلَ الكهفِ» ومفعول لأجله «بحثًا»"},{"id":"d","text":"يصبح «بحثًا» ظرف زمان"}]'::jsonb, 'c', 'حذف المفعول المطلق «نزولَ الخبراءِ» لا يؤثّر في باقي عناصر الجملة: يبقى «داخلَ الكهفِ» ظرف مكان منصوبًا، و«بحثًا عن اللّؤلؤِ» مفعولًا لأجله منصوبًا، فكلّ منصوب مستقلّ بشروطه عن الآخر.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7dd195ac-beba-5c90-97e7-2f1db8b6fa09', '1f1955cc-8d7b-5d18-88ed-08136d14c5ba', 'أيّ العبارات التّالية **خاطئة**؟', '[{"id":"a","text":"كلّ اسمٍ منصوبٍ يجيب عن «لماذا؟» هو بالضّرورة مفعول لأجله ولو لم يكن مصدرًا قلبيًّا"},{"id":"b","text":"المفعول المطلق المؤكّد للفعل يُذكر مجرّدًا بلا إضافة ولا تثنية غالبًا"},{"id":"c","text":"ظرف الزّمان والمكان يتضمّنان معنى حرف الجرّ «في»"},{"id":"d","text":"المفعول لأجله يُشترط فيه اتّحاد الزّمن والفاعل مع عامله"}]'::jsonb, 'a', 'العبارة الخاطئة هي الإجابة عن «لماذا؟» وحدها لا تكفي؛ يُشترط في المفعول لأجله أن يكون مصدرًا وأن يكون قلبيًّا معًا، فقد يُذكر سبب الفعل بأسلوبٍ آخر دون أن يكون مفعولًا لأجله منصوبًا. أمّا العبارات الأخرى فصحيحة.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('43518188-2378-5f28-a31e-eee45f8f418e', '1f1955cc-8d7b-5d18-88ed-08136d14c5ba', 'في وصفٍ لرحلة مدرسيّة: «ركبَ التّلاميذُ الحافلةَ فجرًا، ثمّ ساروا سيرَ المستكشفينَ داخلَ الغابةِ حبًّا في الاستطلاعِ، وعادوا مساءً» — عيّن العنصر الذي **لا يصحّ** عدّه من المتمّمات الثّلاثة (مطلق/فيه/لأجله) بل هو مفعول به:', '[{"id":"a","text":"سيرَ المستكشفينَ"},{"id":"b","text":"داخلَ الغابةِ"},{"id":"c","text":"حبًّا"},{"id":"d","text":"الحافلةَ"}]'::jsonb, 'd', '«الحافلةَ» اسم ذاتٍ وقع عليه فعل الرّكوب مباشرةً، فهو مفعول به لا من المتمّمات الثّلاثة. أمّا «سيرَ المستكشفينَ» فمفعول مطلق مبيّن للنّوع، و«داخلَ الغابةِ» ظرف مكان، و«حبًّا» مفعول لأجله (مصدر قلبيّ يبيّن سبب السّير في الغابة).', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

