  ('83332b07-7ea4-5c34-bb32-e80643c05913', '15b5dfde-cb65-5136-bf1e-4c545316a4aa', 'arabic-7eme', 'اختبار فهم الدرس ⭐', 1, 20, 5, 'quiz', 'admin', 0)
