INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a81c0e68-e3ae-5077-a1b8-85b2c56ad592', '83332b07-7ea4-5c34-bb32-e80643c05913', 'الحال اسم نكرة منصوب يصف:', '[{"id":"a","text":"هيئة صاحبه عند وقوع الفعل"},{"id":"b","text":"نوع صاحبه الثّابت"},{"id":"c","text":"عدد أشياء مبهمة"},{"id":"d","text":"زمن وقوع الفعل فقط"}]'::jsonb, 'a', 'الحال اسم نكرة منصوب يبيّن هيئة صاحبه ساعة وقوع الفعل، ويجيب عن سؤال «كيف؟»، وهي مختلفة عن الزّمن والعدد.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('55ce617a-c185-5912-a768-6891d3c99dc6', '83332b07-7ea4-5c34-bb32-e80643c05913', '«جاء الطّالبُ مسرعًا» — صاحب الحال في هذه الجملة هو:', '[{"id":"a","text":"مسرعًا"},{"id":"b","text":"الطّالبُ"},{"id":"c","text":"جاء"},{"id":"d","text":"الفعل والحال معًا"}]'::jsonb, 'b', 'صاحب الحال هو الاسم الموصوف بالهيئة، وهنا «الطّالبُ» معرفة بأل، والحال «مسرعًا» تصف هيئته ساعة المجيء.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3cc39834-d9a0-5bd7-9d8e-0b890010c878', '83332b07-7ea4-5c34-bb32-e80643c05913', '«دخل الأستاذُ وكتابُه بيدِه» — نوع الحال في هذه الجملة:', '[{"id":"a","text":"حال مفردة"},{"id":"b","text":"حال جملة فعليّة"},{"id":"c","text":"حال جملة اسميّة"},{"id":"d","text":"لا توجد حال في الجملة"}]'::jsonb, 'c', '«وكتابُه بيدِه» جملة اسميّة (مبتدأ وخبر) مسبوقة بواو الحال، وهي في محلّ نصب حال تصف هيئة الأستاذ.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7da80704-0d14-5c04-ac83-1bd8790e00b0', '83332b07-7ea4-5c34-bb32-e80643c05913', 'التّمييز اسم نكرة منصوب وظيفته:', '[{"id":"a","text":"وصف صاحبه الثّابت"},{"id":"b","text":"بيان هيئة صاحبه عند وقوع الفعل"},{"id":"c","text":"ربط جملتين ببعضهما"},{"id":"d","text":"رفع إبهامٍ في كلام سابق"}]'::jsonb, 'd', 'التّمييز يرفع غموضًا (إبهامًا) في كلامٍ سابق فيوضّح المقصود منه بدقّة، بخلاف الحال الّتي تصف الهيئة.', 4)
ON CONFLICT (id) DO UPDATE SET
