  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c9815b3e-1709-5b19-9c19-9cb923ad83ea', '83332b07-7ea4-5c34-bb32-e80643c05913', '«ازداد الطّالبُ نشاطًا» — «نشاطًا» في هذه الجملة:', '[{"id":"a","text":"تمييز نسبة"},{"id":"b","text":"حال مفردة"},{"id":"c","text":"تمييز ذات"},{"id":"d","text":"نعت"}]'::jsonb, 'a', 'الجملة «ازداد الطّالبُ» تامّة لكنّها مبهمة، و«نشاطًا» يرفع إبهام النّسبة، فهو تمييز نسبة لا تمييز ذات ولا حال.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
