INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8f1ea599-6688-5c76-8d7a-b8d25f71a1ba', 'b51d1742-9397-592d-8555-b93cc9f92e91', 'أيّ الجمل التّالية تحتوي حالًا؟', '[{"id":"a","text":"جاء الطّالبُ مسرعًا"},{"id":"b","text":"جاء رجلٌ مسرعٌ"},{"id":"c","text":"هذا كتابٌ مفيدٌ"},{"id":"d","text":"الحديقةُ جميلةٌ"}]'::jsonb, 'a', '«مسرعًا» في الجملة الأولى نكرة منصوبة تصف هيئة «الطّالبُ» المعرفة عند المجيء، فهي حال؛ أمّا البقيّة فلا حال فيها.', 1)
