INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d06df521-1692-5020-bd4b-91535c281f5f', 'b51d1742-9397-592d-8555-b93cc9f92e91', '«رجع الجنديُّ منتصرًا» — الحال في هذه الجملة هي:', '[{"id":"a","text":"رجع"},{"id":"b","text":"الجنديُّ"},{"id":"c","text":"منتصرًا"},{"id":"d","text":"لا توجد حال"}]'::jsonb, 'c', '«منتصرًا» نكرة منصوبة تصف هيئة «الجنديّ» ساعة الرّجوع، فهي الحال، وصاحبها «الجنديّ».', 2)
