INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ee9e6d1c-23ee-5bf0-b232-ec54972fb51d', '56fa4a49-0298-55ad-a628-68f5beba9154', '«حسُن الولدُ خُلقًا» — نوع «خُلقًا»:', '[{"id":"a","text":"تمييز ذات"},{"id":"b","text":"حال جملة"},{"id":"c","text":"نعت"},{"id":"d","text":"تمييز نسبة"}]'::jsonb, 'd', 'الجملة «حسُن الولدُ» تامّة، ولا يسبق «خُلقًا» اسمُ مقدارٍ، فالإبهام في نسبة الحُسن لا في اسمٍ مفرد، فهو تمييز نسبة.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8a155b13-ac81-5bec-aa60-b2b1b69abc5b', '56fa4a49-0298-55ad-a628-68f5beba9154', '«جاء رجلٌ مسرعٌ» و«جاء الرّجلُ مسرعًا» — أيّ الجملتين تحتوي حالًا؟', '[{"id":"a","text":"الأولى، لأنّ رجلٌ نكرة"},{"id":"b","text":"الثّانية، لأنّ الرّجلَ معرفة ومسرعًا منصوبة"},{"id":"c","text":"كلتاهما تحتويان حالًا"},{"id":"d","text":"لا حال في أيٍّ منهما"}]'::jsonb, 'b', 'في الجملة الثّانية «الرّجلَ» معرفة و«مسرعًا» منصوبة تصف هيئته، فهي حال. أمّا الأولى ففيها نعتٌ مرفوع يطابق «رجلٌ» النّكرة. الخطأ الشّائع الخلط بين الجملتين لتشابه لفظ الوصف.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('83883dbe-d45e-5684-8e8d-eaef6bb33688', '56fa4a49-0298-55ad-a628-68f5beba9154', 'ما إعراب «خبزًا» في «باع الخبّازُ كيلوغرامًا خبزًا»؟', '[{"id":"a","text":"تمييز مرفوع"},{"id":"b","text":"حال منصوبة"},{"id":"c","text":"تمييز منصوب وعلامة نصبه الفتحة الظّاهرة"},{"id":"d","text":"مفعول به ثانٍ"}]'::jsonb, 'c', '«خبزًا» تمييز ذات يوضّح «كيلوغرامًا»، وهو منصوب وعلامة نصبه الفتحة الظّاهرة. الخطأ الشّائع رفعه على أنّه فاعل أو خبر، والتّمييز منصوب أبدًا.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9a958f65-ecf5-5e1b-9c86-88408aab6e74', '56fa4a49-0298-55ad-a628-68f5beba9154', 'كتب تلميذ الجملة «جاء الطّالبُ مسرعٌ» بضمّ آخر الحال. أين وجه الخطأ؟', '[{"id":"a","text":"لا خطأ في الجملة"},{"id":"b","text":"الخطأ في الفعل «جاء» لا في «مسرعٌ»"},{"id":"c","text":"الصّواب رفع «مسرعٌ» دائمًا"},{"id":"d","text":"الصّواب نصب الحال «مسرعًا» لأنّها منصوبة أبدًا"}]'::jsonb, 'd', 'الحال منصوبة دائمًا مهما رُفع صاحبها، فالصّواب «مسرعًا» لا «مسرعٌ». الخطأ الشّائع رفع الحال على توهّم مطابقتها لصاحبها في الإعراب كالنّعت.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

