INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5c7bfe0f-1965-546d-8600-9b24bd811f2a', 'f1ed80be-cf62-54ff-bc6c-f7701e4e4ad3', 'الحال تجيب عن أيّ سؤال؟', '[{"id":"a","text":"متى؟"},{"id":"b","text":"كيف؟"},{"id":"c","text":"لماذا؟"},{"id":"d","text":"أين؟"}]'::jsonb, 'b', 'الحال تصف هيئة صاحبها عند وقوع الفعل، فهي تجيب عن سؤال «كيف؟».', 1)
