INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('68d7ccb6-9a85-5fb2-8f64-f30585dcf6e2', 'f1ed80be-cf62-54ff-bc6c-f7701e4e4ad3', 'التّمييز يرفع:', '[{"id":"a","text":"زمن الفعل"},{"id":"b","text":"عدد الجمل"},{"id":"c","text":"إبهامًا في كلامٍ سابق"},{"id":"d","text":"محلّ الجملة الإعرابيّ"}]'::jsonb, 'c', 'وظيفة التّمييز رفع الإبهام (الغموض) عن كلامٍ سابق ليوضّح المقصود منه بدقّة.', 2)
