INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('84bcf800-171a-57fb-972a-ef49f8e499a0', 'f1ed80be-cf62-54ff-bc6c-f7701e4e4ad3', '«وقف الحارسُ صامتًا» — نوع الحال هنا:', '[{"id":"a","text":"حال جملة اسميّة"},{"id":"b","text":"تمييز"},{"id":"c","text":"حال جملة فعليّة"},{"id":"d","text":"حال مفردة"}]'::jsonb, 'd', '«صامتًا» كلمة واحدة مشتقّة تصف هيئة الحارس أثناء الوقوف، فهي حال مفردة.', 3)
