INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b357ccfd-8aa2-50bc-8496-ab7e9903748a', 'f1ed80be-cf62-54ff-bc6c-f7701e4e4ad3', '«خرج الطّفلُ ودموعُه تسيل» — نوع الحال هنا:', '[{"id":"a","text":"حال جملة اسميّة"},{"id":"b","text":"حال مفردة"},{"id":"c","text":"تمييز ذات"},{"id":"d","text":"حال جملة فعليّة"}]'::jsonb, 'a', '«ودموعُه تسيل» جملة اسميّة (مبتدأ وخبر جملة فعليّة) مسبوقة بواو الحال، وهي في محلّ نصب حال.', 4)
