INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f7527344-f19c-5170-adf3-a1d3d1455947', 'f1ed80be-cf62-54ff-bc6c-f7701e4e4ad3', '«باع التّاجرُ مترًا قماشًا» — نوع التّمييز في «قماشًا»:', '[{"id":"a","text":"تمييز نسبة"},{"id":"b","text":"حال مفردة"},{"id":"c","text":"تمييز ذات"},{"id":"d","text":"نعت"}]'::jsonb, 'c', 'سبق «قماشًا» اسمُ مقدارٍ صريح هو «مترًا»، فهو تمييز ذات يوضّح من أيّ شيء هذا المتر.', 5)
