INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('65a1800d-0a34-53c0-ada0-6416ff902860', 'f1ed80be-cf62-54ff-bc6c-f7701e4e4ad3', 'ما علامة نصب الحال المفردة والتّمييز غالبًا؟', '[{"id":"a","text":"الضّمّة الظّاهرة"},{"id":"b","text":"الفتحة الظّاهرة"},{"id":"c","text":"الكسرة الظّاهرة"},{"id":"d","text":"السّكون"}]'::jsonb, 'b', 'الحال المفردة والتّمييز اسمان منصوبان، وعلامة نصبهما غالبًا الفتحة الظّاهرة.', 6)
