  ('58d6ff41-a7a7-5cad-b7e9-cd6ab9b28c97', '15b5dfde-cb65-5136-bf1e-4c545316a4aa', 'arabic-7eme', '👑 تحدّي النخبة ⭐⭐⭐⭐: إتقان الحال والتّمييز', 4, 300, 60, 'challenge', 'admin', 4)
