INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('fed793bd-5b6c-5a4d-ba5c-ab2e98369967', '58d6ff41-a7a7-5cad-b7e9-cd6ab9b28c97', '«هذه المدينةُ أكثر المدن ازدحامًا» — نوع «ازدحامًا» ودوره:', '[{"id":"a","text":"تمييز نسبة يرفع إبهام النّسبة بعد اسم تفضيل"},{"id":"b","text":"تمييز ذات بعد اسم مقدار"},{"id":"c","text":"حال مفردة تصف المدينة"},{"id":"d","text":"نعت لكلمة المدن"}]'::jsonb, 'a', '«أكثر المدن» جملة تامّة تفيد تفضيلًا مبهمًا (أكثر في أيّ جانب؟)، و«ازدحامًا» تمييز نسبة يرفع هذا الإبهام.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
