  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b72c3154-7f37-59a7-a498-dc359e82d6ee', '58d6ff41-a7a7-5cad-b7e9-cd6ab9b28c97', '«وصل الضّيفُ وابتسامتُه على شفتيه» — حدّد الحال في هذه الجملة:', '[{"id":"a","text":"وصل"},{"id":"b","text":"الضّيفُ"},{"id":"c","text":"وابتسامتُه على شفتيه"},{"id":"d","text":"شفتيه"}]'::jsonb, 'c', '«وابتسامتُه على شفتيه» جملة اسميّة مسبوقة بواو الحال، وهي في محلّ نصب حال تصف هيئة الضّيف ساعة الوصول.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
