INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('01ba57a9-494d-5607-aea3-beb38a575dde', '58d6ff41-a7a7-5cad-b7e9-cd6ab9b28c97', '«رأيتُ الفلاّحَ عائدًا من الحقلِ» — صاحب الحال ونوعها:', '[{"id":"a","text":"صاحبها «رأيتُ»، وهي حال جملة"},{"id":"b","text":"صاحبها «الفلاّحَ»، وهي حال مفردة"},{"id":"c","text":"صاحبها «الحقلِ»، وهي تمييز"},{"id":"d","text":"لا حال في الجملة لأنّ صاحبها منصوب"}]'::jsonb, 'b', '«عائدًا» حال مفردة تصف هيئة «الفلاّحَ» (مفعول به معرفة)، فصاحب الحال قد يكون فاعلًا أو مفعولًا به ما دام معرفة.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9fb69acd-f0d0-5070-8f83-7171a3468e76', '58d6ff41-a7a7-5cad-b7e9-cd6ab9b28c97', 'أضاف تلميذ «صفاءً» إلى «طاب الجوّ» فقال «طاب الجوّ صفاءً». لماذا «صفاءً» منصوبة لا مرفوعة؟', '[{"id":"a","text":"لأنّها فاعل ثانٍ للفعل طاب"},{"id":"b","text":"لأنّها خبر لجملة اسميّة محذوفة"},{"id":"c","text":"لأنّها تمييز نسبة يرفع إبهام النّسبة، والتّمييز منصوب أبدًا"},{"id":"d","text":"لأنّها حال تصف الجوّ"}]'::jsonb, 'c', '«طاب الجوّ» جملة تامّة مبهمة (طاب في أيّ جانب؟)، و«صفاءً» تمييز نسبة يرفع هذا الإبهام، والتّمييز منصوب دائمًا لا مرفوعًا.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e83c9afe-184d-521a-bd3b-db09246345a8', '58d6ff41-a7a7-5cad-b7e9-cd6ab9b28c97', 'أعرب تلميذ «ماءً» في «فاض النّهرُ ماءً» فاعلًا ثانيًا. أين الخطأ؟', '[{"id":"a","text":"لا خطأ، فهو فاعل ثانٍ فعلًا"},{"id":"b","text":"الصّواب أنّه تمييز نسبة منصوب يرفع إبهام الفيضان"},{"id":"c","text":"الصّواب أنّه حال جملة فعليّة"},{"id":"d","text":"الصّواب أنّه مفعول به للفعل فاض"}]'::jsonb, 'b', 'الفعل لا يأخذ فاعلين، و«ماءً» منصوبة لا مرفوعة، فهي تمييز نسبة يوضّح في أيّ جانب فاض النّهر، لا فاعل ولا مفعول به.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('14418950-8f8b-51be-8d9f-67f862125539', '58d6ff41-a7a7-5cad-b7e9-cd6ab9b28c97', '«عاد الصّيّادُ يحمل سمكةً» — ما محلّ جملة «يحمل سمكةً» الإعرابيّ؟', '[{"id":"a","text":"في محلّ رفع خبر"},{"id":"b","text":"لا محلّ لها من الإعراب"},{"id":"c","text":"في محلّ نصب مفعول به"},{"id":"d","text":"في محلّ نصب حال"}]'::jsonb, 'd', '«يحمل سمكةً» جملة فعليّة تصف هيئة الصّيّاد ساعة العودة، فهي في محلّ نصب حال، مثل «يبتسمُ» في الأمثلة السّابقة.', 6)
ON CONFLICT (id) DO UPDATE SET
