INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('90d2f07f-8ae7-5a03-abf2-d4d43bdf0c31', 'cc4cf6d6-8909-5a53-9486-953e554b6844', 'أيّ الجمل التّالية حالها جملة اسميّة؟', '[{"id":"a","text":"رجع الجنديُّ يبتسمُ"},{"id":"b","text":"جاء الطّالبُ مسرعًا"},{"id":"c","text":"دخل المعلّمُ وكتابُه بيدِه"},{"id":"d","text":"اشترى الفلاّحُ قنطارًا قمحًا"}]'::jsonb, 'c', '«وكتابُه بيدِه» جملة اسميّة مسبوقة بواو الحال، في محلّ نصب حال؛ الجملتان الأولى والثّانية حالهما فعليّة ومفردة، والرّابعة فيها تمييز لا حال.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('37fc96f2-a15a-5168-8a90-01713f76861d', 'cc4cf6d6-8909-5a53-9486-953e554b6844', 'أراد تلميذ إعراب «رطلًا» في «اشترتِ الأمّ رطلًا عسلًا» فقال «حال منصوبة». ما الصّواب؟', '[{"id":"a","text":"الصّواب أنّه اسم مقدارٍ (مفعول به) يُتبع بتمييز ذات يوضّحه"},{"id":"b","text":"لا خطأ، فهو حال فعلًا"},{"id":"c","text":"الصّواب أنّه فاعل للفعل اشترت"},{"id":"d","text":"الصّواب أنّه مفعول به ثانٍ"}]'::jsonb, 'a', '«رطلًا» اسم مقدارٍ يحتاج تمييزًا يوضّحه (عسلًا)، وليس هو نفسه حالًا؛ صاحب الحال يجب أن يكون معرفة، و«رطلًا» نكرة لا تصف هيئة فاعل. الخطأ الشّائع الخلط بين اسم المقدار وبين الحال.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('16f1bce3-8100-528a-9195-4c7c5b908616', 'cc4cf6d6-8909-5a53-9486-953e554b6844', 'أيّ العبارات التّالية صحيحة في التّفريق بين الحال والتّمييز؟', '[{"id":"a","text":"كلاهما مرفوعان دائمًا"},{"id":"b","text":"الحال تصف الهيئة والتّمييز يرفع الإبهام، وكلاهما منصوب"},{"id":"c","text":"الحال تُرفع والتّمييز يُنصب"},{"id":"d","text":"لا فرق بينهما"}]'::jsonb, 'b', 'الحال تبيّن هيئة صاحبها عند وقوع الفعل، والتّمييز يرفع الإبهام عن ذاتٍ أو نسبة، وكلاهما اسم نكرة منصوب.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0778c192-281a-59e3-98cd-71abde3eaf82', 'cc4cf6d6-8909-5a53-9486-953e554b6844', '«اشترى الحدّادُ لترًا حليبًا» — حدّد نوع التّمييز في «حليبًا» وعلّته:', '[{"id":"a","text":"تمييز نسبة، لأنّ الجملة تامّة"},{"id":"b","text":"حال مفردة، لأنّه يصف الحدّاد"},{"id":"c","text":"تمييز ذات، لأنّه يوضّح مقدارًا صريحًا سبقه (لترًا)"},{"id":"d","text":"مفعول به ثانٍ للفعل اشترى"}]'::jsonb, 'c', 'سبق «حليبًا» اسمُ مقدارٍ صريح هو «لترًا»، فهو تمييز ذات يوضّح من أيّ شيء هذا اللتر، لا حال ولا مفعول به.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('cdaff8c1-9ff4-575c-a211-591e647d89ec', '15b5dfde-cb65-5136-bf1e-4c545316a4aa', 'arabic-7eme', '👑 تحدّي النخبة ⭐⭐⭐⭐: قمّة الحال والتّمييز', 4, 300, 60, 'challenge', 'admin', 6)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1bff3402-3716-59f4-b816-9b21b98a8423', 'cdaff8c1-9ff4-575c-a211-591e647d89ec', '«عاد الفلاّحُ مسرورًا بعد أن باع قنطارًا قمحًا» — ما المنصوبان اللّذان هما حال وتمييز في هذه الجملة؟', '[{"id":"a","text":"منصوبان: «مسرورًا» حال و«قمحًا» تمييز"},{"id":"b","text":"منصوب واحد فقط: «مسرورًا» حال"},{"id":"c","text":"منصوبان: «مسرورًا» تمييز و«قمحًا» حال"},{"id":"d","text":"ثلاثة منصوبات: مسرورًا وقنطارًا وقمحًا كلّها حال"}]'::jsonb, 'a', '«مسرورًا» نكرة منصوبة تصف هيئة الفلاّح فهي حال، و«قمحًا» تمييز ذات يوضّح «قنطارًا» المقدار المذكور؛ أمّا «قنطارًا» نفسه فمفعول به لا حال ولا تمييز.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2f7d3148-af87-597d-a836-302b851baa59', 'cdaff8c1-9ff4-575c-a211-591e647d89ec', '«فلانٌ أطيب النّاس قلبًا» — نوع «قلبًا» ولماذا:', '[{"id":"a","text":"حال مفردة تصف فلانًا"},{"id":"b","text":"تمييز ذات لأنّه يسبقه اسم مقدار"},{"id":"c","text":"تمييز نسبة يرفع إبهام التّفضيل «أطيب النّاس» في أيّ جانب"},{"id":"d","text":"نعت لكلمة النّاس"}]'::jsonb, 'c', '«أطيب النّاس» جملة تفضيل تامّة مبهمة (أطيب في أيّ جانب؟)، و«قلبًا» تمييز نسبة يرفع هذا الإبهام، مثل «ازدحامًا» في «أكثر المدن ازدحامًا».', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d555d8d4-0f28-5328-8d8f-fd346c423b5f', 'cdaff8c1-9ff4-575c-a211-591e647d89ec', '«قطف البستانيّ كيلوغرامًا تفّاحًا» — لو كتب تلميذ «تفّاحٌ» بالرّفع، فما وجه الخطأ بالضّبط؟', '[{"id":"a","text":"لا خطأ، فتفّاحٌ فاعل ثانٍ"},{"id":"b","text":"الخطأ أنّه تمييز ذات، والتّمييز منصوب أبدًا لا مرفوعًا"},{"id":"c","text":"الخطأ أنّه حال، والحال تُرفع لا تُنصب"},{"id":"d","text":"الصّواب فعلًا رفعه لأنّه يتبع كيلوغرامًا في الإعراب"}]'::jsonb, 'b', '«تفّاحًا» تمييز ذات يوضّح «كيلوغرامًا»، والتّمييز اسم منصوب دائمًا. الخطأ الشّائع رفعه توهّمًا بأنّه يتبع المقدار الذي قبله في الإعراب، بينما هو منصوب مستقلّ.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('815741a4-ddac-537a-9af3-e6cf60c899ad', 'cdaff8c1-9ff4-575c-a211-591e647d89ec', 'أيّ العبارات التّالية عن الحال والتّمييز صحيحة؟', '[{"id":"a","text":"صاحب الحال نكرة دائمًا كالحال نفسها"},{"id":"b","text":"التّمييز يكون معرفة إذا جاء بعد عددٍ"},{"id":"c","text":"حال الجملة لا محلّ لها من الإعراب"},{"id":"d","text":"تمييز النّسبة يرفع إبهام جملةٍ تامّة لا اسمٍ مفرد"}]'::jsonb, 'd', 'تمييز النّسبة يرفع إبهامًا يخصّ الجملة كلّها بعد جملة تامّة، مثل «ازداد الطّالبُ نشاطًا». أمّا صاحب الحال فمعرفة غالبًا لا نكرة، والتّمييز نكرة دائمًا لا معرفة، وحال الجملة في محلّ نصب حال لا بلا محلّ.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b6d2ef48-aa5e-5f84-b665-d32c855ed8d4', 'cdaff8c1-9ff4-575c-a211-591e647d89ec', 'حلّ تلميذ إعراب «اشترى التّاجرُ مترًا حريرًا» كالآتي: مترًا: تمييز ذات منصوب. حريرًا: مفعول به منصوب. أين الخطأ في هذا الحلّ؟', '[{"id":"a","text":"لا خطأ، الحلّ صحيح بالكامل"},{"id":"b","text":"عكسَ الإعرابين: الصّواب أنّ «مترًا» مفعول به، و«حريرًا» تمييز ذات يوضّحه"},{"id":"c","text":"الخطأ في الفعل، فهو لازم لا متعدٍّ"},{"id":"d","text":"الصّواب رفع «حريرًا» لا نصبه"}]'::jsonb, 'b', '«مترًا» هو المقدار المشترى فهو مفعول به، والتّمييز يأتي بعد اسم المقدار ليوضّحه، فـ«حريرًا» هو التّمييز الذي يرفع إبهام «مترًا» (متر من أيّ شيء؟). الخطأ الشّائع عكس التّرتيب بين المقدار وموضّحه.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('585a6e37-c7f8-52ef-87f0-330daa01c070', 'cdaff8c1-9ff4-575c-a211-591e647d89ec', '«ما أجملَ الرّبيعَ منظرًا!» — نوع «منظرًا» في أسلوب التّعجّب هذا:', '[{"id":"a","text":"حال مفردة تصف الرّبيع"},{"id":"b","text":"تمييز ذات لأنّه يسبقه اسم مقدار"},{"id":"c","text":"تمييز نسبة يرفع إبهام أسلوب التّعجّب (أجمل في أيّ جانب؟)"},{"id":"d","text":"مفعول به للفعل أجملَ"}]'::jsonb, 'c', 'أسلوب التّعجّب «ما أفعلَ» جملة تامّة مبهمة (ما أجملَ الرّبيعَ في أيّ جانب؟)، و«منظرًا» تمييز نسبة يرفع هذا الإبهام، تمامًا كما في «أكثر المدن ازدحامًا».', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('d3d6c892-83ef-521e-8279-340d2aa1272b', '05d26175-5623-57c5-8a0e-035c3714e72c', 'arabic-7eme', 'اختبار فهم الدرس ⭐', 1, 20, 5, 'quiz', 'admin', 0)
