INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('919887c7-d463-5b6f-b5f6-8344d520f87d', 'd3d6c892-83ef-521e-8279-340d2aa1272b', '«حضر التلاميذُ إلاّ تلميذًا» — ما هو المستثنى في هذه الجملة؟', '[{"id":"a","text":"التلاميذُ"},{"id":"b","text":"حضر"},{"id":"c","text":"إلاّ"},{"id":"d","text":"تلميذًا"}]'::jsonb, 'd', 'المستثنى هو الاسم المذكور بعد أداة الاستثناء «إلاّ»، وهنا «تلميذًا» هو الاسم المُخرَج من حكم «التلاميذُ».', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ea391c1a-267f-5afb-bc7c-54fcd4dc13de', 'd3d6c892-83ef-521e-8279-340d2aa1272b', 'في الاستثناء التّامّ المثبت، يكون المستثنى بعد «إلاّ»:', '[{"id":"a","text":"مرفوعًا دائمًا"},{"id":"b","text":"منصوبًا وجوبًا"},{"id":"c","text":"مجرورًا دائمًا"},{"id":"d","text":"يُعرب حسب موقعه"}]'::jsonb, 'b', 'إذا كان المستثنى منه مذكورًا والكلام مثبتًا (غير منفيّ)، وجب نصب المستثنى بعد «إلاّ».', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('68c38770-4374-5a81-9b70-b8b9950ec6fe', 'd3d6c892-83ef-521e-8279-340d2aa1272b', '«ما حضر التلاميذُ إلاّ تلميذٌ» — لماذا رُفع «تلميذٌ» في هذه الجملة؟', '[{"id":"a","text":"لأنّه بدل من «التلاميذ» المرفوع، والاستثناء تامّ منفيّ يجيز الوجهين"},{"id":"b","text":"لأنّه فاعل مستقلّ"},{"id":"c","text":"لأنّ كلّ مستثنى يُرفع في الجملة المنفيّة"},{"id":"d","text":"لأنّه مبتدأ مؤخّر"}]'::jsonb, 'a', 'الاستثناء هنا تامّ (المستثنى منه «التلاميذ» مذكور) ومنفيّ (بـ«ما»)، فيجوز في المستثنى النّصب أو الإتباع (البدل) لإعراب المستثنى منه، وهنا اختير البدل المرفوع.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('72657817-5937-5044-9274-a7231311bec6', 'd3d6c892-83ef-521e-8279-340d2aa1272b', '«ما حضر إلاّ تلميذٌ» — ما نوع هذا الاستثناء وإعراب «تلميذٌ»؟', '[{"id":"a","text":"تامّ مثبت، والمستثنى منصوب وجوبًا"},{"id":"b","text":"تامّ منفيّ، والمستثنى منصوب أو بدل"},{"id":"c","text":"ناقص منفيّ، والمستثنى منصوب دائمًا"},{"id":"d","text":"ناقص منفيّ (حصر)، و«تلميذٌ» فاعل مرفوع لأنّه يُعرب حسب موقعه"}]'::jsonb, 'd', 'المستثنى منه محذوف والكلام منفيّ، فهذا أسلوب الحصر، ويُعرب المستثنى حسب موقعه في الجملة كأنّ «إلاّ» غير موجودة؛ والتّقدير «ما حضر تلميذٌ»، فـ«تلميذٌ» فاعل مرفوع.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f1baf43a-34a0-5020-9a33-4a6a75fab531', 'd3d6c892-83ef-521e-8279-340d2aa1272b', '«حضر التلاميذُ غيرَ تلميذٍ» — ما إعراب «تلميذٍ»؟', '[{"id":"a","text":"مستثنى منصوب"},{"id":"b","text":"فاعل مرفوع"},{"id":"c","text":"مضاف إليه مجرور"},{"id":"d","text":"مفعول به منصوب"}]'::jsonb, 'c', 'الاسم الواقع بعد «غير» أو «سوى» يكون دائمًا مضافًا إليه مجرورًا، بينما «غيرَ» نفسها هي الّتي تأخذ إعراب المستثنى.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

