INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4e9c19d4-0e9f-5a4d-bee4-6a7a8195bdfe', '8102688c-777b-59dd-8967-76deb6b68f32', 'أركان أسلوب الاستثناء الثّلاثة هي:', '[{"id":"a","text":"الحال وصاحب الحال والفعل"},{"id":"b","text":"المبتدأ والخبر والفعل"},{"id":"c","text":"المستثنى منه وأداة الاستثناء والمستثنى"},{"id":"d","text":"الفعل والفاعل والمفعول به"}]'::jsonb, 'c', 'يتكوّن أسلوب الاستثناء من ثلاثة أركان: المستثنى منه (الاسم العامّ)، وأداة الاستثناء (مثل إلاّ)، والمستثنى (الاسم المُخرَج).', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('98b00bee-9e5a-5ae0-a5bb-62b97e2d0520', '8102688c-777b-59dd-8967-76deb6b68f32', '«نجحَ التلاميذُ إلاّ تلميذًا» — المستثنى منه في هذه الجملة هو:', '[{"id":"a","text":"نجحَ"},{"id":"b","text":"إلاّ"},{"id":"c","text":"تلميذًا"},{"id":"d","text":"التلاميذُ"}]'::jsonb, 'd', 'المستثنى منه هو الاسم العامّ الّذي أُخرج منه المستثنى، وهنا «التلاميذُ» هو الاسم العامّ.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('151a96b3-a4d1-5fc7-a50d-49e5b99da590', '8102688c-777b-59dd-8967-76deb6b68f32', '«باعَ التّاجرُ البضائعَ إلاّ قطعةً» — أداة الاستثناء في هذه الجملة هي:', '[{"id":"a","text":"إلاّ"},{"id":"b","text":"البضائعَ"},{"id":"c","text":"قطعةً"},{"id":"d","text":"التّاجرُ"}]'::jsonb, 'a', '«إلاّ» هي الأداة الّتي تربط المستثنى منه بالمستثنى، وهي أشهر أدوات الاستثناء.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('be748f90-4ae2-5d5e-b9f8-1291df43ec01', '8102688c-777b-59dd-8967-76deb6b68f32', '«حضر التلاميذُ إلاّ تلميذًا» — لماذا نُصب «تلميذًا»؟', '[{"id":"a","text":"لأنّه فاعل"},{"id":"b","text":"لأنّ الاستثناء تامّ ومثبت، فالمستثنى منصوب وجوبًا"},{"id":"c","text":"لأنّه مضاف إليه"},{"id":"d","text":"لأنّ الجملة منفيّة"}]'::jsonb, 'b', 'المستثنى منه (التلاميذُ) مذكور والكلام مثبت (لا نفي فيه)، فهذا استثناء تامّ مثبت يوجب نصب المستثنى.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f98efa00-aa07-5a21-ab72-e0b7bd13dd22', '8102688c-777b-59dd-8967-76deb6b68f32', '«أكلتُ الفواكهَ إلاّ حبّةً» — ما إعراب «حبّةً»؟', '[{"id":"a","text":"فاعل مرفوع"},{"id":"b","text":"مضاف إليه مجرور"},{"id":"c","text":"مستثنى منصوب وعلامة نصبه الفتحة الظّاهرة"},{"id":"d","text":"مفعول به لفعل محذوف"}]'::jsonb, 'c', 'الاستثناء هنا تامّ مثبت (الفواكهَ مذكورة، والجملة غير منفيّة)، فوجب نصب المستثنى «حبّةً» وعلامة نصبه الفتحة الظّاهرة.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7d00e882-f796-5f22-8bc4-402518632b93', '8102688c-777b-59dd-8967-76deb6b68f32', '«زارَ الأصدقاءُ الحديقةَ إلاّ صديقًا» — ما نوع هذا الاستثناء؟', '[{"id":"a","text":"ناقص منفيّ (حصر)"},{"id":"b","text":"تامّ منفيّ"},{"id":"c","text":"استثناء بغير"},{"id":"d","text":"تامّ مثبت"}]'::jsonb, 'd', 'المستثنى منه «الأصدقاءُ» مذكور، والجملة مثبتة (لا أداة نفي)، فهو استثناء تامّ مثبت يوجب نصب المستثنى.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('67463fb7-a44a-51c9-944f-9f72bdfc168f', '05d26175-5623-57c5-8a0e-035c3714e72c', 'arabic-7eme', '⚔️ زعيم الفصل ⭐⭐⭐: الاستثناء والحصر', 3, 120, 30, 'boss', 'admin', 2)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ab848e26-0067-5d5f-add7-2473c4bf7f08', '67463fb7-a44a-51c9-944f-9f72bdfc168f', '«لم يفزْ اللاعبونَ إلاّ لاعبًا» و«لم يفزِ اللاعبونَ إلاّ لاعبٌ» — ما الصّحيح في هذا الاستثناء؟', '[{"id":"a","text":"الجملتان صحيحتان، لأنّ الاستثناء تامّ منفيّ يجيز النّصب أو البدل"},{"id":"b","text":"النّصب واجب دائمًا لأنّ إلاّ تعمل النّصب"},{"id":"c","text":"الجملة الثّانية خطأ لأنّ الفاعل لا يتكرّر"},{"id":"d","text":"الرّفع واجب دائمًا في الاستثناء المنفيّ"}]'::jsonb, 'a', 'المستثنى منه «اللاعبونَ» مذكور والكلام منفيّ (لم)، فهذا استثناء تامّ منفيّ يجيز في المستثنى وجهين: النّصب على الاستثناء، أو البدل المرفوع تبعًا لإعراب «اللاعبونَ». الخطأ الشّائع اعتقاد أنّ النّصب واجب كما في المثبت.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c97673f9-bb29-597e-b8f2-e0b256103567', '67463fb7-a44a-51c9-944f-9f72bdfc168f', '«ما زارَ الضّيوفُ المتحفَ إلاّ ضيفٌ» — ما إعراب «ضيفٌ» هنا؟', '[{"id":"a","text":"مفعول به منصوب"},{"id":"b","text":"بدل مرفوع من «الضّيوف»، لأنّ الاستثناء تامّ منفيّ"},{"id":"c","text":"مستثنى منصوب وجوبًا"},{"id":"d","text":"فاعل جديد للفعل زار"}]'::jsonb, 'b', 'الاستثناء تامّ (المستثنى منه «الضّيوفُ» مذكور) ومنفيّ (ما)، فيجوز إتباع المستثنى لإعراب المستثنى منه بدلًا، وهنا رُفع تبعًا لرفع «الضّيوفُ» فاعلًا، لا تبعًا لـ«المتحفَ» المفعول به الأقرب لفظًا.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('48876615-db75-5b71-b01a-2025ff26fb56', '67463fb7-a44a-51c9-944f-9f72bdfc168f', '«ما مررتُ إلاّ بصديقٍ» — ما إعراب «صديقٍ»؟', '[{"id":"a","text":"مستثنى منصوب"},{"id":"b","text":"فاعل مرفوع"},{"id":"c","text":"اسم مجرور بحرف الجرّ الباء، متعلّق بالفعل «مررتُ»"},{"id":"d","text":"مضاف إليه مجرور"}]'::jsonb, 'c', 'هذا استثناء ناقص منفيّ (حصر): المستثنى منه محذوف، فيُعرب المستثنى حسب موقعه كأنّ «إلاّ» غير موجودة، والتّقدير «ما مررتُ بصديقٍ»، فـ«صديقٍ» اسم مجرور بحرف الجرّ.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('418669ed-04bc-5e83-89c4-796e40c58b6d', '67463fb7-a44a-51c9-944f-9f72bdfc168f', '«ما رأيتُ في الحديقةِ إلاّ زهرةً» — لماذا نُصبت «زهرةً» رغم أنّ الاستثناء منفيّ؟', '[{"id":"a","text":"لأنّ النّصب واجب في كلّ استثناء منفيّ"},{"id":"b","text":"لأنّها بدل من الحديقة"},{"id":"c","text":"لأنّها مضاف إليه"},{"id":"d","text":"لأنّه استثناء ناقص منفيّ (حصر)، وموقع «زهرةً» في الجملة مفعول به، فأُعربت منصوبة تبعًا لموقعها لا بحكم النّصب على الاستثناء"}]'::jsonb, 'd', 'المستثنى منه محذوف، فهذا حصر، ويُعرب المستثنى حسب موقعه؛ والتّقدير «ما رأيتُ زهرةً»، فـ«زهرةً» مفعول به منصوب، لا لأنّ النّصب واجب في كلّ استثناء منفيّ. الخطأ الشّائع تعميم النّصب على كلّ حصر.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a22dcc75-4c85-58ac-a935-bf36a33228de', '67463fb7-a44a-51c9-944f-9f72bdfc168f', 'أعرب تلميذ «تلميذٍ» في «ما حضر غيرُ تلميذٍ» مستثنى منصوبًا، و«غيرُ» حرف استثناء. أين الخطأ؟', '[{"id":"a","text":"الصّواب أنّ «غيرُ» اسم يُعرب فاعلًا مرفوعًا هنا (حصر)، و«تلميذٍ» مضاف إليه مجرور لا مستثنى"},{"id":"b","text":"لا خطأ في الإعراب"},{"id":"c","text":"الصّواب نصب «غيرَ» دائمًا"},{"id":"d","text":"الصّواب جرّ «غيرُ» بالإضافة"}]'::jsonb, 'a', '«غير» اسم لا حرف، ويُعرب حسب حالة الاستثناء؛ وهنا الاستثناء ناقص منفيّ (حصر) فتُعرب «غيرُ» حسب موقعها: فاعل مرفوع (التّقدير: ما حضر تلميذٌ)، و«تلميذٍ» بعدها دائمًا مضاف إليه مجرور، لا مستثنى.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('753010f2-af58-5757-b0a3-9a9e9c9af92b', '67463fb7-a44a-51c9-944f-9f72bdfc168f', '«لن يرسبَ التلاميذُ إلاّ تلميذًا» و«لن يرسبَ التلاميذُ إلاّ تلميذٌ» — صنّف هذا الاستثناء وبيّن سبب جواز الوجهين:', '[{"id":"a","text":"تامّ مثبت، والوجهان جائزان لأنّ الفعل مضارع"},{"id":"b","text":"ناقص منفيّ، فيُعرب حسب موقعه فقط"},{"id":"c","text":"استثناء بغير لا بإلاّ"},{"id":"d","text":"تامّ منفيّ (بلن)، فيجوز نصب المستثنى على الاستثناء أو رفعه بدلًا من «التلاميذُ»"}]'::jsonb, 'd', '«لن» أداة نفي، والمستثنى منه «التلاميذُ» مذكور، فالاستثناء تامّ منفيّ، ويجوز فيه الوجهان: النّصب على الاستثناء، أو البدل المرفوع تبعًا لإعراب «التلاميذُ» فاعلًا.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

