  ('f2631fd4-f56b-5afe-a718-643fc15a4810', '05d26175-5623-57c5-8a0e-035c3714e72c', 'arabic-7eme', '⭐⭐ تمرين مراجعة (نمط امتحان): الاستثناء والحصر', 2, 70, 15, 'practice', 'admin', 3)
