INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('63f76244-acae-5fff-a875-fca11c1ea911', 'f2631fd4-f56b-5afe-a718-643fc15a4810', 'الاستثناء الّذي يكون فيه المستثنى منه مذكورًا والكلام غير منفيّ يُسمّى:', '[{"id":"a","text":"ناقصًا منفيًّا (حصرًا)"},{"id":"b","text":"تامًّا مثبتًا"},{"id":"c","text":"تامًّا منفيًّا"},{"id":"d","text":"ناقصًا مثبتًا"}]'::jsonb, 'b', 'إذا ذُكر المستثنى منه وكان الكلام مثبتًا (بلا نفي)، سُمّي الاستثناء تامًّا مثبتًا، ويكون المستثنى فيه منصوبًا وجوبًا.', 1)
ON CONFLICT (id) DO UPDATE SET
