  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3db0bdd2-efd6-5260-bc4d-d4a44fb18751', 'f2631fd4-f56b-5afe-a718-643fc15a4810', 'في أسلوب الحصر (الاستثناء النّاقص المنفيّ)، يُعرب المستثنى:', '[{"id":"a","text":"منصوبًا دائمًا"},{"id":"b","text":"مرفوعًا دائمًا"},{"id":"c","text":"حسب موقعه في الجملة، كأنّ أداة الاستثناء غير موجودة"},{"id":"d","text":"مجرورًا بالإضافة دائمًا"}]'::jsonb, 'c', 'في الحصر يُحذف المستثنى منه، فيُعرب المستثنى حسب موقعه الحقيقيّ في الجملة، لا بإعراب ثابت.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('04d3787a-4309-59e3-9c28-d2559a1df39b', 'f2631fd4-f56b-5afe-a718-643fc15a4810', '«حضرتِ الطّالباتُ الحفلَ إلاّ طالبةً» — ما إعراب «طالبةً»؟', '[{"id":"a","text":"مستثنى منصوب وجوبًا"},{"id":"b","text":"بدل مرفوع"},{"id":"c","text":"فاعل مرفوع"},{"id":"d","text":"مضاف إليه مجرور"}]'::jsonb, 'a', 'المستثنى منه «الطّالباتُ» مذكور والكلام مثبت، فهذا استثناء تامّ مثبت يوجب نصب المستثنى.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
