INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a9fe8a13-f7fa-5c13-a78e-b3aea94c04cc', 'f2631fd4-f56b-5afe-a718-643fc15a4810', '«لا يذاكرُ إلاّ المجتهدُ» — ما نوع الاستثناء وإعراب «المجتهدُ»؟', '[{"id":"a","text":"تامّ مثبت، مستثنى منصوب"},{"id":"b","text":"تامّ منفيّ، بدل مرفوع"},{"id":"c","text":"استثناء بغير"},{"id":"d","text":"ناقص منفيّ (حصر)، فاعل مرفوع، والتّقدير «لا يذاكر المجتهدُ»"}]'::jsonb, 'd', 'المستثنى منه محذوف والكلام منفيّ بـ«لا»، فهذا حصر؛ والتّقدير «لا يذاكر المجتهدُ»، فـ«المجتهدُ» فاعل مرفوع.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
