  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f51c503c-60de-5933-9b35-e301eb17a2ab', 'f2631fd4-f56b-5afe-a718-643fc15a4810', '«ما حضر التلاميذُ غيرَ تلميذٍ» — ما إعراب «غيرَ»؟', '[{"id":"a","text":"مستثنى منصوب (أحد الوجهين الجائزين في الاستثناء التّامّ المنفيّ)"},{"id":"b","text":"فاعل مرفوع دائمًا"},{"id":"c","text":"مضاف إليه مجرور"},{"id":"d","text":"حرف جرّ"}]'::jsonb, 'a', 'الاستثناء تامّ منفيّ (المستثنى منه «التلاميذُ» مذكور والكلام منفيّ)، فيجوز في «غيرَ» النّصب على الاستثناء أو الرّفع بدلًا من «التلاميذُ»؛ وهنا اختير النّصب.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a8295b20-6237-54dc-aab5-60dabbbc390d', 'f2631fd4-f56b-5afe-a718-643fc15a4810', '«قرأتُ الكتبَ سوى كتابٍ» — ما إعراب «كتابٍ»؟', '[{"id":"a","text":"مستثنى منصوب"},{"id":"b","text":"فاعل مرفوع"},{"id":"c","text":"مضاف إليه مجرور"},{"id":"d","text":"مفعول به منصوب"}]'::jsonb, 'c', 'الاسم الواقع بعد «سوى»، مثل الواقع بعد «غير»، يكون دائمًا مضافًا إليه مجرورًا.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

