  ('9a1ddb5e-9665-5959-9f53-9ba78af7e3eb', '05d26175-5623-57c5-8a0e-035c3714e72c', 'arabic-7eme', '👑 تحدّي النخبة ⭐⭐⭐⭐: إتقان الاستثناء والحصر', 4, 300, 60, 'challenge', 'admin', 4)
