INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('61914bb2-cfae-5e61-9947-198a604bb4d7', '9a1ddb5e-9665-5959-9f53-9ba78af7e3eb', '«لم تطبخِ الأمُّ إلاّ وجبةً واحدةً» — ما إعراب «وجبةً»؟', '[{"id":"a","text":"فاعل مرفوع"},{"id":"b","text":"اسم مجرور"},{"id":"c","text":"مفعول به منصوب، والتّقدير «لم تطبخِ الأمُّ وجبةً واحدةً» (حصر)"},{"id":"d","text":"مستثنى منصوب وجوبًا (تامّ مثبت)"}]'::jsonb, 'c', 'المستثنى منه محذوف والكلام منفيّ، فهذا حصر؛ والتّقدير «لم تطبخِ الأمُّ وجبةً واحدةً»، فـ«وجبةً» مفعول به منصوب.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6a32f49c-b561-5d73-ae8a-174f9a79ea1f', '9a1ddb5e-9665-5959-9f53-9ba78af7e3eb', '«ما اشتريتُ من السّوقِ إلاّ تفّاحًا» — ما إعراب «تفّاحًا»؟', '[{"id":"a","text":"مستثنى منصوب وجوبًا (تامّ مثبت)"},{"id":"b","text":"اسم مجرور"},{"id":"c","text":"فاعل مرفوع"},{"id":"d","text":"مفعول به منصوب، والتّقدير «ما اشتريتُ تفّاحًا» (حصر)"}]'::jsonb, 'd', 'المستثنى منه محذوف والكلام منفيّ، فهذا حصر؛ والتّقدير «ما اشتريتُ تفّاحًا»، فـ«تفّاحًا» مفعول به منصوب لموقعه في الجملة.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c4afe4f3-6779-58e1-82e6-fbd5516c72d8', '9a1ddb5e-9665-5959-9f53-9ba78af7e3eb', 'أعرب تلميذ «النّجاحِ» في «ما تحدّثَ الخطيبُ إلاّ عن النّجاحِ» مستثنى مجرورًا. أين الخطأ في هذا الإعراب؟', '[{"id":"a","text":"لا خطأ في هذا الإعراب"},{"id":"b","text":"الصّواب أنّ «عن» حرف جرّ متعلّق بالفعل، و«النّجاحِ» اسم مجرور بها لا مستثنى، لأنّ هذا حصر يُعرب فيه الاسم حسب موقعه"},{"id":"c","text":"الصّواب رفع «النّجاحِ» فاعلًا"},{"id":"d","text":"الصّواب نصب «النّجاحِ» مفعولًا به"}]'::jsonb, 'b', 'هذا استثناء ناقص منفيّ (حصر)، فلا وجود لإعراب «مستثنى» مستقلّ؛ التّقدير «ما تحدّثَ الخطيبُ عن النّجاحِ»، فـ«عن» حرف جرّ و«النّجاحِ» اسم مجرور بها متعلّق بالفعل. الخطأ الشّائع تسمية كلّ اسم بعد «إلاّ» مستثنى حتّى في الحصر.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('58aa79e3-cd91-5056-9227-e46ccfec4d05', '9a1ddb5e-9665-5959-9f53-9ba78af7e3eb', 'أيّ العبارات التّالية عن الاستثناء التّامّ المنفيّ صحيحة؟', '[{"id":"a","text":"المستثنى منصوب وجوبًا فيه، كالتّامّ المثبت تمامًا"},{"id":"b","text":"المستثنى منه محذوف فيه دائمًا"},{"id":"c","text":"يجوز في المستثنى النّصب على الاستثناء أو البدل تبعًا لإعراب المستثنى منه"},{"id":"d","text":"لا يُستعمل فيه فعل منفيّ بل حرف نفي فقط"}]'::jsonb, 'c', 'التّامّ المنفيّ يتميّز بجواز الوجهين: النّصب على الاستثناء، أو الإتباع (البدل) لإعراب المستثنى منه؛ خلافًا للتّامّ المثبت الّذي يوجب النّصب فقط، وخلافًا للنّاقص المنفيّ الّذي يُحذف فيه المستثنى منه.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2e2fa697-89f8-5108-8ba9-db17d30b66de', '9a1ddb5e-9665-5959-9f53-9ba78af7e3eb', '«لم يحضرِ الطّلاّبُ الاجتماعَ إلاّ طالبًا» و«لم يحضرِ الطّلاّبُ الاجتماعَ إلاّ طالبٌ» — لماذا يصحّ الوجهان معًا؟', '[{"id":"a","text":"لأنّ الاستثناء تامّ (المستثنى منه «الطّلاّبُ» مذكور) ومنفيّ («لم»)، فيجوز نصب المستثنى أو رفعه بدلًا من «الطّلاّبُ» الفاعل"},{"id":"b","text":"لأنّ الفعل «يحضر» يقبل فاعلين"},{"id":"c","text":"لأنّ «الاجتماعَ» هي المستثنى منه لا «الطّلاّبُ»"},{"id":"d","text":"لأنّ الجملة حصر فيُعرب المستثنى حسب موقعه فقط"}]'::jsonb, 'a', 'المستثنى منه هو «الطّلاّبُ» (الفاعل المذكور)، لا «الاجتماعَ» (المفعول به الأقرب لفظًا)، والجملة منفيّة بـ«لم»، فالاستثناء تامّ منفيّ يجيز الوجهين: نصب «طالبًا» على الاستثناء، أو رفع «طالبٌ» بدلًا من «الطّلاّبُ».', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('05dc631c-38a4-5b85-9f00-3b0bb0a3d120', '9a1ddb5e-9665-5959-9f53-9ba78af7e3eb', 'وازِن بين الجملتين: «حضر التلاميذُ غيرَ تلميذٍ» و«ما حضر غيرُ تلميذٍ» — ما نوع كلّ استثناء وإعراب «غير» فيهما؟', '[{"id":"a","text":"الأولى تامّ مثبت (غيرَ منصوبة وجوبًا)، والثّانية ناقص منفيّ / حصر (غيرُ فاعل مرفوع)"},{"id":"b","text":"كلتاهما تامّ مثبت، وغير منصوبة فيهما"},{"id":"c","text":"الأولى حصر، والثّانية تامّ مثبت"},{"id":"d","text":"غيرُ وغيرَ لهما الإعراب نفسه في الجملتين"}]'::jsonb, 'a', 'في الجملة الأولى المستثنى منه «التلاميذُ» مذكور والكلام مثبت، فـ«غيرَ» منصوبة وجوبًا (تامّ مثبت). في الثّانية المستثنى منه محذوف والكلام منفيّ، فهو حصر، وتُعرب «غيرُ» حسب موقعها: فاعل مرفوع (التّقدير: ما حضر تلميذٌ)، و«تلميذٍ» في الحالتين مضاف إليه مجرور.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('87d9ff3c-f2dd-5197-a4fb-f93c8aa0e453', '05d26175-5623-57c5-8a0e-035c3714e72c', 'arabic-7eme', '📝 تدريب ⭐⭐⭐: مراجعة شاملة للاستثناء والحصر', 3, 120, 30, 'boss', 'admin', 5)
