INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5170eb0c-d6e7-587c-b115-022aed11ea92', '87d9ff3c-f2dd-5197-a4fb-f93c8aa0e453', '«سافرَ الرّكّابُ إلاّ راكبًا» — ما نوع الاستثناء وإعراب «راكبًا»؟', '[{"id":"a","text":"تامّ مثبت، مستثنى منصوب وجوبًا"},{"id":"b","text":"تامّ منفيّ، بدل مرفوع"},{"id":"c","text":"ناقص منفيّ، فاعل مرفوع"},{"id":"d","text":"استثناء بغير، مضاف إليه"}]'::jsonb, 'a', 'المستثنى منه «الرّكّابُ» مذكور والكلام مثبت، فهو استثناء تامّ مثبت يوجب نصب «راكبًا».', 1)
