INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('cdab2298-d89b-5855-9401-9c4e6355f115', '87d9ff3c-f2dd-5197-a4fb-f93c8aa0e453', '«ما سلّمتُ إلاّ على المعلّمِ» — ما إعراب «المعلّمِ»؟', '[{"id":"a","text":"مستثنى منصوب"},{"id":"b","text":"فاعل مرفوع"},{"id":"c","text":"اسم مجرور بحرف الجرّ «على»، والتّقدير «ما سلّمتُ على المعلّمِ»"},{"id":"d","text":"مضاف إليه مجرور"}]'::jsonb, 'c', 'استثناء ناقص منفيّ (حصر): المستثنى منه محذوف، فيُعرب الاسم حسب موقعه؛ والتّقدير «ما سلّمتُ على المعلّمِ»، فـ«المعلّمِ» اسم مجرور بحرف الجرّ متعلّق بالفعل.', 2)
