  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f374fca3-f1ee-513a-8836-167f3849ba2b', '87d9ff3c-f2dd-5197-a4fb-f93c8aa0e453', '«لم يفزْ في السّباقِ إلاّ العدّاءُ الأوّلُ» — ما إعراب «العدّاءُ»؟', '[{"id":"a","text":"مستثنى منصوب"},{"id":"b","text":"بدل مرفوع من فاعل مذكور"},{"id":"c","text":"مضاف إليه مجرور"},{"id":"d","text":"فاعل مرفوع، والتّقدير «لم يفز في السّباق العدّاءُ الأوّلُ» (حصر)"}]'::jsonb, 'd', 'المستثنى منه محذوف، فهذا حصر؛ والتّقدير «لم يفز في السّباق العدّاءُ الأوّلُ»، فـ«العدّاءُ» فاعل مرفوع.', 3)
