INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a6b45247-c2ae-5b6c-ae15-2d0800d0e7d5', '87d9ff3c-f2dd-5197-a4fb-f93c8aa0e453', '«ما أكلَ الأولادُ الحلوى إلاّ ولدًا» و«ما أكلَ الأولادُ الحلوى إلاّ ولدٌ» — ما إعراب «ولدٌ» في الصّيغة الثّانية ولماذا؟', '[{"id":"a","text":"مستثنى منصوب وجوبًا، لأنّ الكلام منفيّ"},{"id":"b","text":"مفعول به ثانٍ"},{"id":"c","text":"مضاف إليه مجرور"},{"id":"d","text":"بدل مرفوع من «الأولادُ»، لأنّ الاستثناء تامّ منفيّ يجيز الوجهين"}]'::jsonb, 'd', 'المستثنى منه «الأولادُ» مذكور (الفاعل)، لا «الحلوى» (المفعول به الأقرب لفظًا)، والكلام منفيّ (ما)، فالاستثناء تامّ منفيّ يجيز نصب المستثنى أو رفعه بدلًا من «الأولادُ».', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('59a08058-d952-5cfd-8d3b-7c65ced2186e', '87d9ff3c-f2dd-5197-a4fb-f93c8aa0e453', '«أثمرتِ الأشجارُ إلاّ شجرةً» — صحّح الإعراب الخاطئ التّالي: «شجرةً: بدل مرفوع من الأشجار».', '[{"id":"a","text":"الصّواب أنّ «شجرةً» مستثنى منصوب وجوبًا، لأنّ الكلام مثبت لا منفيّ، فلا مجال للبدل"},{"id":"b","text":"لا خطأ، الإعراب صحيح"},{"id":"c","text":"الصّواب رفعها فاعلًا"},{"id":"d","text":"الصّواب جرّها مضافًا إليه"}]'::jsonb, 'a', 'البدل لا يجوز إلّا في الاستثناء التّامّ المنفيّ. هنا الكلام مثبت (لا أداة نفي)، فالاستثناء تامّ مثبت يوجب نصب «شجرةً» فقط. الخطأ الشّائع تطبيق قاعدة البدل دون التّحقّق من وجود أداة النّفي فعلًا.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f0ad908a-8b44-5733-a36b-61571b76e547', '87d9ff3c-f2dd-5197-a4fb-f93c8aa0e453', '«ما قرأتُ إلاّ كتابًا واحدًا» — ما نوع هذا الاستثناء وإعراب «كتابًا»؟', '[{"id":"a","text":"تامّ منفيّ، بدل منصوب"},{"id":"b","text":"ناقص منفيّ (حصر)، مفعول به منصوب، والتّقدير «ما قرأتُ كتابًا واحدًا»"},{"id":"c","text":"تامّ مثبت، مستثنى منصوب"},{"id":"d","text":"استثناء بغير"}]'::jsonb, 'b', 'المستثنى منه محذوف والكلام منفيّ، فهذا حصر؛ والتّقدير «ما قرأتُ كتابًا واحدًا»، فـ«كتابًا» مفعول به منصوب لموقعه في الجملة لا لأنّ النّصب واجب في كلّ استثناء.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

