  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('dc4b87f0-7f2b-57fe-98c6-c10e3cc36c6a', 'c4a3418f-c053-57d6-814f-718366f20af4', '«باعَ التّاجرُ البضائعَ كلَّها سوى قطعةٍ واحدةٍ» — ما نوع هذا الاستثناء وإعراب «قطعةٍ»؟', '[{"id":"a","text":"تامّ مثبت (المستثنى منه مذكور، الكلام غير منفيّ)، و«قطعةٍ» مضاف إليه مجرور بعد «سوى» المنصوبة وجوبًا"},{"id":"b","text":"ناقص منفيّ، فاعل مرفوع"},{"id":"c","text":"تامّ منفيّ، بدل مجرور"},{"id":"d","text":"استثناء بإلاّ لا بسوى"}]'::jsonb, 'a', 'المستثنى منه «البضائعَ» مذكور والكلام مثبت، فـ«سوى» منصوبة وجوبًا مثل «غير»، و«قطعةٍ» بعدها مضاف إليه مجرور دائمًا.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f2cb36c6-8750-505e-9265-bff5133e6e15', 'c4a3418f-c053-57d6-814f-718366f20af4', 'أيّ العبارات التّالية عن أنواع الاستثناء الثّلاثة صحيحة تمامًا؟', '[{"id":"a","text":"التّامّ المثبت يجيز النّصب أو البدل، والتّامّ المنفيّ يوجب النّصب"},{"id":"b","text":"التّامّ المثبت يوجب النّصب، والتّامّ المنفيّ يجيز النّصب أو البدل، والنّاقص المنفيّ يُعرب حسب الموقع"},{"id":"c","text":"الأنواع الثّلاثة توجب نصب المستثنى دائمًا"},{"id":"d","text":"النّاقص المنفيّ يوجب رفع المستثنى دائمًا لأنّه فاعل غالبًا"}]'::jsonb, 'b', 'الضّبط الدّقيق للأحكام الثّلاثة: تامّ مثبت = نصب واجب؛ تامّ منفيّ = نصب أو بدل جوازًا؛ ناقص منفيّ (حصر) = إعراب حسب الموقع الحقيقيّ في الجملة، وقد يكون فاعلًا أو مفعولًا به أو مجرورًا لا فاعلًا فقط.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('32b4390a-e02f-58aa-90bd-8ad37c6a5ee4', 'c4a3418f-c053-57d6-814f-718366f20af4', '«ما فاز في المسابقةِ إلاّ فريقٌ واحدٌ، وما كافأ المدرّبُ إلاّ هذا الفريقَ» — بيّن نوع الاستثناء في كلّ جملة وإعراب المستثنى:', '[{"id":"a","text":"الجملتان تامّتان منفيّتان، والمستثنيان بدلان مرفوعان"},{"id":"b","text":"كلاهما مستثنى منصوب وجوبًا لأنّ الكلام منفيّ في الحالتين"},{"id":"c","text":"الجملتان ناقصتان منفيّتان (حصر): «فريقٌ» فاعل مرفوع، و«هذا الفريقَ» مفعول به منصوب، كلّ حسب موقعه"},{"id":"d","text":"الأولى ناقصة والثّانية تامّة مثبتة"}]'::jsonb, 'c', 'في الجملتين المستثنى منه محذوف والكلام منفيّ، فكلتاهما حصر؛ يُعرب المستثنى حسب موقعه: «فريقٌ» فاعل مرفوع (التّقدير: ما فاز فريقٌ واحدٌ)، و«هذا الفريقَ» مفعول به منصوب (التّقدير: ما كافأ المدرّبُ هذا الفريقَ).', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ac73710d-3650-59d8-acd3-01322b6e9cd6', 'c4a3418f-c053-57d6-814f-718366f20af4', 'حوّل الجملة «حضر التلاميذُ إلاّ تلميذًا» إلى استثناء ناقص منفيّ (حصر) بأقلّ تغيير ممكن، ثمّ حدّد إعراب المستثنى الجديد:', '[{"id":"a","text":"«التلاميذُ حضروا إلاّ تلميذًا» — تلميذًا: مستثنى منصوب"},{"id":"b","text":"«حضر إلاّ تلميذًا» بلا تغيير في النّصب"},{"id":"c","text":"«ما حضر التلاميذُ إلاّ تلميذًا» فقط بإضافة «ما»"},{"id":"d","text":"«ما حضر إلاّ تلميذٌ» — تلميذٌ: فاعل مرفوع"}]'::jsonb, 'd', 'يتحوّل الاستثناء التّامّ المثبت إلى حصر بحذف المستثنى منه «التلاميذُ» وإضافة أداة نفي: «ما حضر إلاّ تلميذٌ»، فيُعرب المستثنى «تلميذٌ» حسب موقعه الحقيقيّ (فاعل مرفوع)، بخلاف النّصب الواجب في الصّيغة الأصليّة.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5a47c372-33e1-53d9-b0c0-0d5b0a689650', 'c4a3418f-c053-57d6-814f-718366f20af4', 'وجدَ تلميذٌ في نصّ الفرض الجملة «لا يفهمُ هذا الدّرسَ غيرُ التّلميذِ المجتهدِ» فأعرب «غيرُ» «مستثنى منصوبًا وجوبًا». صحّح خطأه بدقّة:', '[{"id":"a","text":"لا خطأ، فغير مستثنى منصوب دائمًا"},{"id":"b","text":"الصّواب أنّ هذا استثناء ناقص منفيّ (حصر)؛ فـ«غيرُ» تُعرب فاعلًا مرفوعًا (التّقدير: لا يفهم هذا الدّرسَ التّلميذُ المجتهدُ)، و«التّلميذِ» مضاف إليه مجرور"},{"id":"c","text":"الصّواب جرّ «غيرُ» بالإضافة"},{"id":"d","text":"الصّواب أنّ «غيرُ» حرف جرّ هنا"}]'::jsonb, 'b', 'المستثنى منه محذوف والكلام منفيّ بـ«لا»، فهو حصر لا تامّ مثبت؛ فـ«غيرُ» اسم يُعرب حسب موقعه: فاعل مرفوع، لا مستثنى منصوب. الخطأ الشّائع نصب «غير» تلقائيًّا في كلّ جملة استثناء دون التّحقّق من نوع الاستثناء.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d9baa7cf-d0c7-5201-a95a-10792d6e6bae', 'c4a3418f-c053-57d6-814f-718366f20af4', 'أيّ الجمل التّالية توضّح حالة استثناء تامّ منفيّ يجوز فيها الوجهان (النّصب والبدل) معًا؟', '[{"id":"a","text":"ما حضر إلاّ تلميذٌ"},{"id":"b","text":"حضر التلاميذُ إلاّ تلميذًا"},{"id":"c","text":"ما نجحَ التلاميذُ إلاّ تلميذًا / ما نجحَ التلاميذُ إلاّ تلميذٌ"},{"id":"d","text":"ما حضر غيرُ تلميذٍ"}]'::jsonb, 'c', 'في الخيار (c) المستثنى منه «التلاميذُ» مذكور والكلام منفيّ، فهذا تامّ منفيّ يجيز الوجهين معًا. أمّا (a) و(d) فحصر (المستثنى منه محذوف)، و(b) تامّ مثبت يوجب النّصب فقط.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('fa38d4ba-1104-5f52-aeb4-64d014fc285b', '223a261b-74e5-5171-9204-246ac41410cc', 'arabic-7eme', 'اختبار فهم الدرس ⭐', 1, 20, 5, 'quiz', 'admin', 0)
