INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('92eb0465-478a-5df3-8cbe-3544529ce092', 'fa38d4ba-1104-5f52-aeb4-64d014fc285b', 'الجملة المركّبة هي الّتي تحتوي على:', '[{"id":"a","text":"نواة إسناديّة واحدة فقط"},{"id":"b","text":"أكثر من نواة إسناديّة واحدة"},{"id":"c","text":"متمّمات كثيرة بلا نواة"},{"id":"d","text":"فعلًا متعدّيًا فقط"}]'::jsonb, 'b', 'الجملة المركّبة تحتوي على أكثر من نواة إسناديّة واحدة (إسنادان تامّان أو أكثر)، بخلاف البسيطة ذات النّواة الواحدة.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2f69d3a7-b758-56b4-9822-45c459c256d4', 'fa38d4ba-1104-5f52-aeb4-64d014fc285b', '«سطعتِ الشّمسُ وابتهجَ الأطفالُ» — هذه الجملة:', '[{"id":"a","text":"بسيطة، لأنّ الواو تربط بين كلمتين فقط"},{"id":"b","text":"بسيطة، لأنّ الفاعل واحد في الجملتين"},{"id":"c","text":"مركّبة، فيها نواتان: سطعتِ الشّمسُ وابتهجَ الأطفالُ"},{"id":"d","text":"مركّبة، فيها ثلاث نوى"}]'::jsonb, 'c', 'فيها إسنادان تامّان: (سطعتِ الشّمسُ) و(ابتهجَ الأطفالُ)، معطوفان بالواو، فهي جملة مركّبة بنواتين لا ثلاث.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('90d0f155-1162-5999-9a6e-5b69f32cab9a', 'fa38d4ba-1104-5f52-aeb4-64d014fc285b', 'أيّ حروف العطف التّالية يفيد التّرتيب مع مهلةٍ وتراخٍ عند ربط نواتين؟', '[{"id":"a","text":"الواو"},{"id":"b","text":"الفاء"},{"id":"c","text":"ثمّ"},{"id":"d","text":"التّتابع دون أداة"}]'::jsonb, 'c', '«ثمّ» يفيد التّرتيب مع مهلةٍ وتراخٍ بين النّواتين، بخلاف الواو (جمعٌ مطلق) والفاء (تعقيبٌ سريع).', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f9d0e166-900b-5e86-a79e-f228cb673610', 'fa38d4ba-1104-5f52-aeb4-64d014fc285b', '«فرحَ سميرٌ وأخوه بالنّجاح» — هذه الجملة:', '[{"id":"a","text":"بسيطة، فيها نواة واحدة وفاعل مركّب بالعطف"},{"id":"b","text":"بسيطة، لأنّها بلا متمّمات"},{"id":"c","text":"مركّبة، فيها نواتان بالعطف"},{"id":"d","text":"مركّبة، فيها ثلاث نوى"}]'::jsonb, 'a', 'الفعل «فرحَ» واحد، وفاعله مركّبٌ بالعطف (سميرٌ وأخوه)، فالنّواة واحدة فقط، والجملة بسيطة رغم الواو.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0eacda57-f78a-5c1b-b450-d53671bdb4f2', 'fa38d4ba-1104-5f52-aeb4-64d014fc285b', '«أغلقَ البائعُ متجرَه، أطفأَ الأنوارَ» — نوع الارتباط بين نواتَي هذه الجملة:', '[{"id":"a","text":"عطف بالواو"},{"id":"b","text":"عطف بالفاء"},{"id":"c","text":"عطف بثمّ"},{"id":"d","text":"تتابع دون أداة"}]'::jsonb, 'd', 'النّواتان (أغلقَ البائعُ متجرَه) و(أطفأَ الأنوارَ) متجاورتان دون أيّ حرف عطف، مفصولتان بفاصلةٍ فقط، فارتباطهما بالتّتابع دون أداة.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

