INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a48575ed-0033-59c9-b92b-814ded2d9953', '5c4e8f99-ef47-59af-a95f-8820d565abd6', '«حصدَ الفلاّحُ القمحَ في الحقلِ» — هذه الجملة:', '[{"id":"a","text":"بسيطة، فيها نواة واحدة"},{"id":"b","text":"مركّبة، فيها نواتان"},{"id":"c","text":"مركّبة، فيها ثلاث نوى"},{"id":"d","text":"لا نواة فيها"}]'::jsonb, 'a', 'النّواة الوحيدة هي (حصدَ الفلاّحُ)، والباقي متمّمات (القمحَ، في الحقلِ)، فالجملة بسيطة.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
