INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('31b72f75-ed52-53b6-91de-231b95828dc5', '5c4e8f99-ef47-59af-a95f-8820d565abd6', '«لعبَ الأطفالُ وضحكوا» — عدد نوى هذه الجملة:', '[{"id":"a","text":"نواة واحدة"},{"id":"b","text":"لا نواة فيها"},{"id":"c","text":"نواتان"},{"id":"d","text":"ثلاث نوى"}]'::jsonb, 'c', 'فيها إسنادان: (لعبَ الأطفالُ) و(ضحكوا)، فهما نواتان، والجملة مركّبة.', 2)
ON CONFLICT (id) DO UPDATE SET
