  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a4464e9f-6bb0-5d28-85ec-791cf51c4226', '5c4e8f99-ef47-59af-a95f-8820d565abd6', '«دخلَ المعلّمُ فوقفَ التّلاميذُ» — نوع الارتباط بين النّواتين:', '[{"id":"a","text":"عطف بالواو"},{"id":"b","text":"عطف بالفاء"},{"id":"c","text":"عطف بثمّ"},{"id":"d","text":"تتابع دون أداة"}]'::jsonb, 'b', 'الفاء هنا تفيد التّرتيب مع تعقيبٍ سريع بين (دخلَ المعلّمُ) و(وقفَ التّلاميذُ).', 3)
ON CONFLICT (id) DO UPDATE SET
