INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9dee2e97-f54a-59eb-8f60-53cc44d8e91e', '5c4e8f99-ef47-59af-a95f-8820d565abd6', '«غسلَ الولدُ يديه ثمّ أكلَ» — نوع الارتباط بين النّواتين:', '[{"id":"a","text":"عطف بالواو"},{"id":"b","text":"عطف بالفاء"},{"id":"c","text":"تتابع دون أداة"},{"id":"d","text":"عطف بثمّ"}]'::jsonb, 'd', '«ثمّ» يفيد التّرتيب مع مهلةٍ بين (غسلَ الولدُ يديه) و(أكلَ).', 4)
