INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ddf3a540-c5f7-5fbe-8fb7-473ccecd233d', '5c4e8f99-ef47-59af-a95f-8820d565abd6', '«سقطَ المطرُ، ابتلّتِ الأرضُ» — نوع الارتباط بين النّواتين:', '[{"id":"a","text":"تتابع دون أداة"},{"id":"b","text":"عطف بالواو"},{"id":"c","text":"عطف بالفاء"},{"id":"d","text":"عطف بثمّ"}]'::jsonb, 'a', 'لا يوجد حرف عطف بين النّواتين، بل فاصلة تفصل بين (سقطَ المطرُ) و(ابتلّتِ الأرضُ)، فالارتباط تتابعٌ دون أداة.', 5)
