  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('75f0ab1d-5d60-5635-b790-4c6b5efef17d', '5c4e8f99-ef47-59af-a95f-8820d565abd6', '«اشترى الأبُ كتابًا ودفترًا» — هذه الجملة:', '[{"id":"a","text":"مركّبة، فيها نواتان بالعطف"},{"id":"b","text":"مركّبة، فيها تتابع دون أداة"},{"id":"c","text":"بسيطة، فيها نواة واحدة ومفعول به مركّب بالعطف"},{"id":"d","text":"بسيطة، بلا معطوفات"}]'::jsonb, 'c', 'الفعل «اشترى» واحد وفاعله واحد (الأبُ)، والعطف هنا بين مفعولين (كتابًا ودفترًا) لا بين نواتين، فالنّواة واحدة والجملة بسيطة.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('9ae907f2-6a3c-50a5-b065-98370534d52f', '223a261b-74e5-5171-9204-246ac41410cc', 'arabic-7eme', '⚔️ زعيم الفصل ⭐⭐⭐: الجملة المركّبة', 3, 120, 30, 'boss', 'admin', 2)
