INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ec8241ab-719f-5cd4-ba17-b8fec242526a', '9ae907f2-6a3c-50a5-b065-98370534d52f', '«زارَ الأستاذُ وتلميذُه معرضَ الكتابِ» — هذه الجملة:', '[{"id":"a","text":"بسيطة، فيها نواة واحدة وفاعل مركّب بالعطف"},{"id":"b","text":"مركّبة، فيها نواتان بالعطف"},{"id":"c","text":"مركّبة، فيها تتابع دون أداة"},{"id":"d","text":"مركّبة، فيها ثلاث نوى"}]'::jsonb, 'a', 'الفعل «زارَ» واحد، وفاعله مركّب بالعطف (الأستاذُ وتلميذُه)، فالنّواة واحدة، والجملة بسيطة رغم الواو.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('91e58767-e621-54d2-9ff9-5603113bf61e', '9ae907f2-6a3c-50a5-b065-98370534d52f', '«زارَ الأستاذُ المعرضَ وصوّرَ اللّوحاتِ» — عدد نوى هذه الجملة:', '[{"id":"a","text":"نواة واحدة"},{"id":"b","text":"نواتان"},{"id":"c","text":"ثلاث نوى"},{"id":"d","text":"لا نواة فيها"}]'::jsonb, 'b', 'فيها فعلان (زارَ وصوّرَ)، لكلٍّ منهما فاعله: «الأستاذُ» ظاهرًا في الأولى، وضميرٌ مستترٌ يعود عليه في الثّانية، فهما نواتان، والجملة مركّبة.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('793794b1-2084-5a61-9516-04bfa848d547', '9ae907f2-6a3c-50a5-b065-98370534d52f', '«وصلَ القطارُ إلى المحطّةِ، هرعَ المسافرونَ لاستقبالِ ذويهم» — نوع الارتباط بين النّواتين:', '[{"id":"a","text":"عطف بالواو"},{"id":"b","text":"عطف بالفاء"},{"id":"c","text":"عطف بثمّ"},{"id":"d","text":"تتابع دون أداة"}]'::jsonb, 'd', 'لا حرف عطف بين (وصلَ القطارُ إلى المحطّةِ) و(هرعَ المسافرونَ لاستقبالِ ذويهم)، بل فاصلة، فالارتباط تتابعٌ دون أداة.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f0188cb3-1c48-5630-8835-444abb67cfe7', '9ae907f2-6a3c-50a5-b065-98370534d52f', 'حلّل تلميذٌ جملة «فرحَ الصّيّادُ وباعَ سمكَه» فقال: النّواة واحدة لأنّ الفاعل مستترٌ في «باعَ» يعود على الصّيّادِ، فلا فاعلَ ظاهرًا ثانيًا. أين الخطأ في هذا التّحليل؟', '[{"id":"a","text":"لا خطأ، التّحليل صحيح"},{"id":"b","text":"الخطأ أنّ «باعَ» فعلٌ له مسندٌ إليه خاصّ به ولو مستترًا، فهما نواتان لا نواة واحدة"},{"id":"c","text":"الخطأ أنّ الجملة اسميّة لا فعليّة"},{"id":"d","text":"الخطأ أنّ «سمكَه» هو النّواة الثّانية"}]'::jsonb, 'b', 'كلّ فعلٍ تامٍّ له مسندٌ إليه، ظاهرًا كان أو مستترًا؛ «باعَ» فعلٌ ثانٍ فاعله ضميرٌ مستترٌ يعود على الصّيّادِ، فهو نواةٌ ثانية مستقلّة، والجملة مركّبة بنواتين. الخطأ الشّائع تجاهل الفاعل المستتر عند عدّ النّوى.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('76e42983-7871-505a-8d66-3ef9e66792b6', '9ae907f2-6a3c-50a5-b065-98370534d52f', '«دخلَ الضّيفُ مبتسمًا، وكانَ الاستقبالُ حارًّا» — حدّد نوى هذه الجملة ووظيفة «مبتسمًا» و«حارًّا»:', '[{"id":"a","text":"نواتان: الأولى فيها حال (مبتسمًا)، والثّانية اسميّة منسوخة فيها خبر كان (حارًّا)"},{"id":"b","text":"نواة واحدة، و«مبتسمًا» و«حارًّا» متمّمان فقط"},{"id":"c","text":"نواتان، و«مبتسمًا» تمييز، و«حارًّا» حال"},{"id":"d","text":"ثلاث نوى، لأنّ «مبتسمًا» نواة مستقلّة"}]'::jsonb, 'a', 'النّواة الأولى فعليّة (دخلَ الضّيفُ) وفيها حالٌ (مبتسمًا) يصف هيئته، والنّواة الثّانية اسميّة منسوخة بـ«كان» (كانَ الاستقبالُ حارًّا) وفيها خبر النّاسخ (حارًّا)، والنّواتان متتابعتان بالواو.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('24f51836-9af6-570a-96ff-7b34237e815e', '9ae907f2-6a3c-50a5-b065-98370534d52f', 'أيّ العبارات التّالية صحيحة في عدّ نوى الجملة المركّبة؟', '[{"id":"a","text":"كلّ حرف عطفٍ في الجملة يصنع نواةً جديدة بالضّرورة"},{"id":"b","text":"الفاعل أو المبتدأ المستتر لا يُحسب في عدّ النّوى"},{"id":"c","text":"عطف الجمل التّامّة، لا المفردات، هو ما يزيد عدد النّوى"},{"id":"d","text":"الجملة المركّبة لا يمكن أن ترتبط نواتاها إلّا بحرف عطف"}]'::jsonb, 'c', 'العبرة في عدّ النّوى بعدد الإسنادات التّامّة؛ فعطف كلمتين داخل نواةٍ واحدة (مفردات) لا يزيد العدد، بخلاف عطف جملتين تامّتين. أمّا الفاعل المستتر فيُحسب، وقد ترتبط النّواتان بالتّتابع دون أداة لا بحرف عطف فقط.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

