INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8b0ad857-c52e-5f29-91c7-35b190267d1d', 'fdab09ea-7cc3-5280-9028-a2c3d94a1906', 'متى تكون الجملة مركّبة؟', '[{"id":"a","text":"عندما تحتوي على متمّم واحد فقط"},{"id":"b","text":"عندما تحتوي على أكثر من نواة إسناديّة"},{"id":"c","text":"عندما يكون فعلها متعدّيًا"},{"id":"d","text":"عندما تبدأ بحرف عطف"}]'::jsonb, 'b', 'تكون الجملة مركّبة متى احتوت على أكثر من نواة إسناديّة واحدة، بصرف النّظر عن نوع الفعل أو أوّل كلمةٍ فيها.', 1)
