INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('524ec2a6-897b-5607-a22f-db31008986a0', 'fdab09ea-7cc3-5280-9028-a2c3d94a1906', 'أيّ حروف العطف التّالية يفيد الجمعَ المطلق بلا ترتيب بين النّواتين؟', '[{"id":"a","text":"ثمّ"},{"id":"b","text":"الفاء"},{"id":"c","text":"الواو"},{"id":"d","text":"حرف الجرّ"}]'::jsonb, 'c', 'الواو تفيد الجمع المطلق بلا ترتيب بين النّواتين، بخلاف الفاء (تعقيب) وثمّ (تراخٍ)؛ وحرف الجرّ ليس أداة ربطٍ بين الجمل أصلًا.', 2)
