INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('39bdf85a-0b74-5cb5-bf5a-ba2fc119eb8e', 'fdab09ea-7cc3-5280-9028-a2c3d94a1906', '«فتحَ البائعُ متجرَه فأقبلَ الزّبائنُ» — نوع الارتباط بين النّواتين:', '[{"id":"a","text":"عطف بالفاء"},{"id":"b","text":"عطف بالواو"},{"id":"c","text":"عطف بثمّ"},{"id":"d","text":"تتابع دون أداة"}]'::jsonb, 'a', 'الفاء تفيد ترتيبًا مع تعقيبٍ سريع بين (فتحَ البائعُ متجرَه) و(أقبلَ الزّبائنُ).', 3)
