INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('10308936-876b-5f31-8f34-f45b569ace9e', 'fdab09ea-7cc3-5280-9028-a2c3d94a1906', '«نجحَ التّلميذُ ورسبَ زميلُه» — عدد نوى هذه الجملة:', '[{"id":"a","text":"نواة واحدة"},{"id":"b","text":"ثلاث نوى"},{"id":"c","text":"لا نواة فيها"},{"id":"d","text":"نواتان"}]'::jsonb, 'd', 'فيها فعلان، كلٌّ له فاعله الخاصّ: (نجحَ التّلميذُ) و(رسبَ زميلُه)، فهما نواتان، والجملة مركّبة.', 4)
