INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('78bc4cb3-36cf-5ced-b905-cd51166e8977', 'fdab09ea-7cc3-5280-9028-a2c3d94a1906', '«اجتهدَ خالدٌ وزميلاه» — هذه الجملة:', '[{"id":"a","text":"بسيطة، فيها نواة واحدة وفاعل مركّب بالعطف"},{"id":"b","text":"مركّبة، فيها نواتان بالعطف"},{"id":"c","text":"مركّبة، فيها تتابع دون أداة"},{"id":"d","text":"مركّبة، فيها ثلاث نوى"}]'::jsonb, 'a', 'الفعل «اجتهدَ» واحد وفاعله مركّب بالعطف (خالدٌ وزميلاه)، فالنّواة واحدة، والجملة بسيطة رغم الواو.', 5)
