INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0ede363f-b76d-56fa-964a-c02caef7d6da', 'fdab09ea-7cc3-5280-9028-a2c3d94a1906', '«غادرَ الرّكّابُ المحطّةَ، أقفلتِ البوّابةُ» — نوع الارتباط بين النّواتين:', '[{"id":"a","text":"عطف بالواو"},{"id":"b","text":"عطف بالفاء"},{"id":"c","text":"تتابع دون أداة"},{"id":"d","text":"عطف بثمّ"}]'::jsonb, 'c', 'لا حرف عطف بين (غادرَ الرّكّابُ المحطّةَ) و(أقفلتِ البوّابةُ)، بل فاصلة، فالارتباط تتابعٌ دون أداة.', 6)
