INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0873f0a5-91eb-5d65-9354-74c393b12949', '7df0b7f9-9904-5748-8e6c-ba5873ba6ab9', '«دخلَ الحرفيّ ورشتَه فأشعلَ الفرنَ» — نوع الارتباط بين نواتَي هذه الجملة:', '[{"id":"a","text":"عطف بالواو"},{"id":"b","text":"عطف بالفاء"},{"id":"c","text":"عطف بثمّ"},{"id":"d","text":"تتابع دون أداة"}]'::jsonb, 'b', 'الفاء تصل بين نواتين تامّتين (دخلَ الحرفيّ ورشتَه) و(أشعلَ الفرنَ) بترتيبٍ مع تعقيبٍ سريع: أشعلَ الفرنَ فور دخوله.', 1)
