INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('84b69559-4a19-5453-89ad-eb739d25a50d', '7df0b7f9-9904-5748-8e6c-ba5873ba6ab9', '«زارَ التّلاميذُ متحفَ قرطاجَ وتأمّلَ القطعَ الأثريّةَ» — عدد نوى هذه الجملة:', '[{"id":"a","text":"نواة واحدة؛ الفاعل واحدٌ بالمرجع في الفعلين"},{"id":"b","text":"نواة واحدة؛ الفعل الثّاني بلا فاعلٍ"},{"id":"c","text":"نواتان؛ الفعل الأوّل فقط له فاعلٌ حقيقيّ"},{"id":"d","text":"نواتان؛ لكلّ فعلٍ مسندٌ إليه خاصّ به ولو كان الضّمير المستتر يعود على المرجع نفسه"}]'::jsonb, 'd', '«زارَ» فعلٌ فاعله ظاهرٌ (التّلاميذُ)، و«تأمّلَ» فعلٌ ثانٍ له فاعله الخاصّ: ضميرٌ مستترٌ تقديره «هم» يعود على التّلاميذ؛ فكلّ إسنادٍ تامٍّ نواةٌ مستقلّة، ولو اتّحد المرجع، فالجملة مركّبة بنواتين. الخطأ الشّائع: الظّنّ أنّ اتّحاد الفاعل في الفعلين يُنقص العدد إلى نواةٍ واحدة.', 2)
