  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1f7bcb49-2e57-5ab8-b9f8-23d0b22688cb', '7df0b7f9-9904-5748-8e6c-ba5873ba6ab9', 'حلّل تلميذٌ جملة «سقى البستانيُّ الشّجرَ، ثمّ قطفَ الرّمّانَ» فقال: النّواة واحدة، لأنّ «ثمّ» أداة عطفٍ تربط بين مفعولين لا بين جملتين. أين الخطأ في هذا التّحليل؟', '[{"id":"a","text":"الخطأ أنّ «ثمّ» تربط هنا بين نواتين تامّتين (سقى البستانيُّ الشّجرَ) و(قطفَ الرّمّانَ)، فالجملة مركّبة بنواتين لا نواة واحدة"},{"id":"b","text":"لا خطأ، التّحليل صحيح"},{"id":"c","text":"الخطأ أنّ الجملة اسميّة لا فعليّة"},{"id":"d","text":"الخطأ أنّ «الرّمّانَ» هو النّواة الثّانية"}]'::jsonb, 'a', '✓ «ثمّ» وصلت بين إسنادَين تامّين، لا بين كلمتين داخل نواةٍ واحدة: (سقى البستانيُّ الشّجرَ) نواةٌ أولى، و(قطفَ الرّمّانَ) نواةٌ ثانية فاعلها ضميرٌ مستترٌ يعود على البستانيّ. الخطأ الشّائع: الخلط بين عطف الجمل التّامّة وعطف المفردات داخل النّواة الواحدة.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b88462d3-385a-571f-aaef-a200f7dbcdb6', '7df0b7f9-9904-5748-8e6c-ba5873ba6ab9', '«فتحَ الحدّادُ دكّانَه، وأشعلَ النّارَ، ثمّ طرقَ الحديدَ» — كم نواة في هذا النّصّ؟', '[{"id":"a","text":"نواة واحدة"},{"id":"b","text":"نواتان"},{"id":"c","text":"ثلاث نوى"},{"id":"d","text":"أربع نوى"}]'::jsonb, 'c', 'ثلاث نوى: (فتحَ الحدّادُ دكّانَه) بفاعلٍ ظاهر، و(أشعلَ النّارَ) بفاعلٍ مستترٍ يعود على الحدّاد، و(طرقَ الحديدَ) بفاعلٍ مستترٍ كذلك؛ الأولى والثّانية مرتبطتان بالواو، والثّانية والثّالثة بثمّ. الخطأ الشّائع: عدُّ «الحديد» أو «النّار» نواةً رابعة لأنّهما اسمان ظاهران، رغم أنّهما مجرّد مفعولين به، لا مسندَين إليهما.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5cec9142-955f-5938-88a0-dfa9e6924ed1', '7df0b7f9-9904-5748-8e6c-ba5873ba6ab9', '«قطفَ الفلّاحُ الزّيتونَ والتّينَ، وباعَهما في السّوقِ» — كم نواة في هذه الجملة، ولماذا؟', '[{"id":"a","text":"نواتان؛ عطف «الزّيتونَ والتّينَ» عطف مفردات لا يزيد العدد، وعطف «باعَهما» بالواو نواةٌ ثانية"},{"id":"b","text":"ثلاث نوى؛ كلّ معطوفٍ يُعدّ نواةً مستقلّة"},{"id":"c","text":"نواة واحدة؛ لا عبرة بحرف العطف في هذه الجملة أصلًا"},{"id":"d","text":"أربع نوى؛ لكلّ اسمٍ ظاهرٍ في الجملة نواته الخاصّة"}]'::jsonb, 'a', '«قطفَ الفلّاحُ الزّيتونَ والتّينَ» نواةٌ واحدة، فالعطف فيها بين مفعولَين (الزّيتونَ والتّينَ) لا بين إسنادَين، فلا يزيد العدد؛ ثمّ عُطفت عليها نواةٌ ثانية تامّة بالواو (باعَهما)، فالمجموع نواتان. الخطأ الشّائع: عدّ كلّ اسمٍ معطوفٍ نواةً، دون التّمييز بين عطف المفردات وعطف الجمل التّامّة.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c6ca789b-5c5d-5170-9e32-217209ca28e3', '7df0b7f9-9904-5748-8e6c-ba5873ba6ab9', 'أيّ العبارات التّالية صحيحة في الجملة المركّبة؟', '[{"id":"a","text":"الفاء تفيد جمعًا مطلقًا بلا ترتيبٍ بين النّواتين"},{"id":"b","text":"قد ترتبط نواتا الجملة المركّبة بفاصلةٍ دون أيّ حرف عطف"},{"id":"c","text":"عطف مفعولين داخل نواةٍ واحدة يزيد عدد النّوى"},{"id":"d","text":"لا يمكن أن تكون إحدى نواتَي الجملة المركّبة جملةً اسميّة"}]'::jsonb, 'b', 'التّتابع دون أداة رابطٌ صحيحٌ بين نواتين تامّتين، يُفصل بينهما بفاصلةٍ أو وقفةٍ في النّطق. أمّا الباقي فخطأ: الفاء تفيد التّرتيبَ مع التّعقيب لا الجمع المطلق (ذاك للواو)، وعطف المفعولين لا يزيد عدد النّوى، والنّواة الاسميّة قد تكون إحدى نواتَي المركّبة كما رأيتَ في الدّرس (كانَ الدّرسُ ممتعًا).', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('c6a11d40-5940-5ee5-88ae-8927ffa5298c', '223a261b-74e5-5171-9204-246ac41410cc', 'arabic-7eme', '📝 تدريب ⭐⭐⭐: مراجعة شاملة للجملة المركّبة', 3, 120, 30, 'boss', 'admin', 5)
ON CONFLICT (id) DO UPDATE SET
