  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('24d71809-86db-593b-98fe-2f102ca029c5', 'c6a11d40-5940-5ee5-88ae-8927ffa5298c', '«شربَ الجدُّ كأسَ الشّاي» — هذه الجملة:', '[{"id":"a","text":"بسيطة، فيها نواة واحدة"},{"id":"b","text":"مركّبة، فيها نواتان"},{"id":"c","text":"مركّبة، فيها ثلاث نوى"},{"id":"d","text":"لا نواة فيها"}]'::jsonb, 'a', 'النّواة الوحيدة هي (شربَ الجدُّ)، و«كأسَ الشّاي» متمّمٌ (مفعول به)، فالجملة بسيطة.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e8bdbdd1-1a43-5e95-897e-7a75cdb40722', 'c6a11d40-5940-5ee5-88ae-8927ffa5298c', '«دخلَ الضّيوفُ فرحّبَ بهم المضيفُ» — نوع الارتباط بين النّواتين:', '[{"id":"a","text":"عطف بالواو"},{"id":"b","text":"عطف بالفاء"},{"id":"c","text":"عطف بثمّ"},{"id":"d","text":"تتابع دون أداة"}]'::jsonb, 'b', 'الفاء تفيد ترتيبًا مع تعقيبٍ سريع بين (دخلَ الضّيوفُ) و(رحّبَ بهم المضيفُ).', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1f004e4b-1d69-51c0-8e19-2a6ee479a94d', 'c6a11d40-5940-5ee5-88ae-8927ffa5298c', '«أعدّتِ الأمُّ الكسكسي والسّلطةَ» — هذه الجملة:', '[{"id":"a","text":"مركّبة، فيها نواتان بالعطف"},{"id":"b","text":"مركّبة، فيها تتابع دون أداة"},{"id":"c","text":"بسيطة، فيها نواة واحدة ومفعول به مركّب بالعطف"},{"id":"d","text":"بسيطة، بلا معطوفات"}]'::jsonb, 'c', 'الفعل «أعدّتِ» واحدٌ وفاعله واحد (الأمُّ)، والعطف هنا بين مفعولَين (الكسكسي والسّلطةَ) لا بين نواتين، فالنّواة واحدة والجملة بسيطة.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('33161312-4777-54ba-ac2c-887f1417eb7c', 'c6a11d40-5940-5ee5-88ae-8927ffa5298c', '«أنهى النّجّارُ العملَ، أغلقَ الورشةَ» — نوع الارتباط بين النّواتين:', '[{"id":"a","text":"عطف بالواو"},{"id":"b","text":"عطف بالفاء"},{"id":"c","text":"عطف بثمّ"},{"id":"d","text":"تتابع دون أداة"}]'::jsonb, 'd', 'لا حرف عطف بين (أنهى النّجّارُ العملَ) و(أغلقَ الورشةَ)، بل فاصلة، فالارتباط تتابعٌ دون أداة.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3a84e1cc-5f23-5644-a34b-79f4234a501f', 'c6a11d40-5940-5ee5-88ae-8927ffa5298c', '«دخلَ الفريقُ الملعبَ مسرعًا، وكانَ التّشجيعُ حماسيًّا» — حدّد نوى هذه الجملة ووظيفة «مسرعًا» و«حماسيًّا»:', '[{"id":"a","text":"نواة واحدة، و«مسرعًا» و«حماسيًّا» متمّمان فقط"},{"id":"b","text":"نواتان: الأولى فيها حال (مسرعًا)، والثّانية اسميّة منسوخة فيها خبر كان (حماسيًّا)"},{"id":"c","text":"نواتان، و«مسرعًا» تمييز، و«حماسيًّا» حال"},{"id":"d","text":"ثلاث نوى، لأنّ «مسرعًا» نواة مستقلّة"}]'::jsonb, 'b', 'النّواة الأولى فعليّة (دخلَ الفريقُ الملعبَ) وفيها حالٌ (مسرعًا) يصف هيئة دخوله، والنّواة الثّانية اسميّة منسوخة بـ«كان» (كانَ التّشجيعُ حماسيًّا) وفيها خبر النّاسخ (حماسيًّا)، والنّواتان متتابعتان بالواو.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a6ee93b8-8857-5e22-90d8-cc1689c450d3', 'c6a11d40-5940-5ee5-88ae-8927ffa5298c', 'حلّل تلميذٌ جملة «فرحَ الحرفيّ وباعَ لوحتَه» فقال: النّواة واحدة، لأنّ الفاعل في «باعَ» مستترٌ فلا يُحسب. أين الخطأ في هذا التّحليل؟', '[{"id":"a","text":"لا خطأ، التّحليل صحيح"},{"id":"b","text":"الخطأ أنّ الجملة اسميّة لا فعليّة"},{"id":"c","text":"الخطأ أنّ «لوحتَه» هي النّواة الثّانية"},{"id":"d","text":"الخطأ أنّ «باعَ» فعلٌ له مسندٌ إليه خاصّ به ولو مستترًا، فهما نواتان لا نواة واحدة"}]'::jsonb, 'd', 'كلّ فعلٍ تامٍّ له مسندٌ إليه، ظاهرًا كان أو مستترًا؛ «باعَ» فعلٌ ثانٍ فاعله ضميرٌ مستترٌ يعود على الحرفيّ، فهو نواةٌ ثانية مستقلّة، والجملة مركّبة بنواتين. الخطأ الشّائع تجاهل الفاعل المستتر عند عدّ النّوى.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('4b5b2929-078a-500e-8008-d7b6133d9e49', '223a261b-74e5-5171-9204-246ac41410cc', 'arabic-7eme', '👑 تحدّي النخبة ⭐⭐⭐⭐: خاتمة الباب الأوّل', 4, 300, 60, 'challenge', 'admin', 6)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b574ce69-3d30-5fea-94e0-d565d2971127', '4b5b2929-078a-500e-8008-d7b6133d9e49', '«وصلَ الفريقُ متأخّرًا، فبدأَ الحكمُ المباراةَ فورًا» — حدّد نوع الارتباط بين النّواتين ووظيفة «متأخّرًا»:', '[{"id":"a","text":"عطف بالواو؛ متأخّرًا مفعول مطلق"},{"id":"b","text":"عطف بالفاء؛ متأخّرًا حال"},{"id":"c","text":"تتابع دون أداة؛ متأخّرًا تمييز"},{"id":"d","text":"عطف بثمّ؛ متأخّرًا مفعول به"}]'::jsonb, 'b', 'الفاء تصل بين (وصلَ الفريقُ متأخّرًا) و(بدأَ الحكمُ المباراةَ) بترتيبٍ مع تعقيب، و«متأخّرًا» حالٌ منصوبةٌ تصف هيئة الفريق حين وصوله، ضمن النّواة الأولى.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1d81ea22-4e89-5818-b770-55ae778578f6', '4b5b2929-078a-500e-8008-d7b6133d9e49', '«كانَ الجوُّ باردًا، فلبسَ الأطفالُ معاطفَهم» — ما وظيفة «باردًا» في النّواة الأولى، وما نوع الارتباط بين النّواتين؟', '[{"id":"a","text":"حال؛ تتابع دون أداة"},{"id":"b","text":"تمييز؛ عطف بالواو"},{"id":"c","text":"مفعول به؛ عطف بثمّ"},{"id":"d","text":"خبر النّاسخ «كان»؛ عطف بالفاء"}]'::jsonb, 'd', 'النّواة الأولى اسميّة منسوخة بـ«كان» (كانَ الجوُّ باردًا)، و«باردًا» خبر النّاسخ منصوبٌ؛ والنّواتان مرتبطتان بالفاء (فلبسَ الأطفالُ معاطفَهم) بترتيبٍ مع تعقيب.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('518c95d9-83f8-5ef1-bcf4-8c17bf637c82', '4b5b2929-078a-500e-8008-d7b6133d9e49', '«أنهى الطّالبُ واجباتِه، ثمّ نامَ مطمئنًّا، وكانَ حلمُه جميلًا» — كم نواة في هذا النّصّ، وما وظيفة «مطمئنًّا»؟', '[{"id":"a","text":"نواتان؛ حال"},{"id":"b","text":"ثلاث نوى؛ تمييز"},{"id":"c","text":"ثلاث نوى؛ حال"},{"id":"d","text":"أربع نوى؛ مفعول به"}]'::jsonb, 'c', 'ثلاث نوى: (أنهى الطّالبُ واجباتِه)، (نامَ) بفاعلٍ مستترٍ يعود على الطّالب، و(كانَ حلمُه جميلًا) اسميّة منسوخة؛ و«مطمئنًّا» حالٌ منصوبةٌ تصف هيئة الطّالب حين نومه، ضمن النّواة الثّانية.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('87c6e170-64bc-5e69-86d6-731a3bb2657d', '4b5b2929-078a-500e-8008-d7b6133d9e49', 'حلّل تلميذٌ جملة «دخلَ الطّبيبُ العيادةَ، وكانَ حديثُه هادئًا» فقال: النّواة الثّانية فيها حالٌ «هادئًا» يصف حديثَ الطّبيبِ. أين الخطأ في هذا التّحليل؟', '[{"id":"a","text":"لا خطأ، التّحليل صحيح"},{"id":"b","text":"الخطأ أنّ النّواة الثّانية فعليّة لا اسميّة"},{"id":"c","text":"الخطأ أنّ العدد نواةٌ واحدة لا نواتان"},{"id":"d","text":"الخطأ أنّ «هادئًا» خبر النّاسخ «كان» لا حال، لأنّه في نواةٍ اسميّةٍ منسوخة"}]'::jsonb, 'd', '✓ النّواة الثّانية (كانَ حديثُه هادئًا) اسميّة منسوخة بـ«كان»، فمنصوبُها «هادئًا» خبر النّاسخ لا حال؛ الحال يتعلّق بهيئة فاعلٍ في جملةٍ فعليّة، لا بخبرٍ منسوخٍ في جملةٍ اسميّة. الخطأ الشّائع: تسمية كلّ منصوبٍ وصفيٍّ حالًا دون النّظر إلى نوع النّواة الّتي وردَ فيها.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('89ecfedb-eaf3-5b5d-9645-a1d4ba5fcdbb', '4b5b2929-078a-500e-8008-d7b6133d9e49', '«امتلأَ الملعبُ جماهيرًا، وارتفعَ الهتافُ عاليًا» — حدّد وظيفتَي «جماهيرًا» و«عاليًا» على التّرتيب:', '[{"id":"a","text":"حال، تمييز"},{"id":"b","text":"مفعول به، حال"},{"id":"c","text":"تمييز، مفعول به"},{"id":"d","text":"تمييز، حال"}]'::jsonb, 'd', '«جماهيرًا» تمييزٌ يزيل غموض الامتلاء (امتلأ بماذا؟)، ضمن النّواة الأولى (امتلأَ الملعبُ جماهيرًا)؛ و«عاليًا» حالٌ تصف هيئة الهتاف حين ارتفاعه، ضمن النّواة الثّانية (ارتفعَ الهتافُ عاليًا). والنّواتان معطوفتان بالواو.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('88ecd959-ce09-5ced-96c4-d06c2d14c0cd', '4b5b2929-078a-500e-8008-d7b6133d9e49', 'أيّ العبارات التّالية تلخّص الباب الأوّل تلخيصًا صحيحًا؟', '[{"id":"a","text":"خبر النّاسخ لا يظهر إلّا في الجملة البسيطة"},{"id":"b","text":"المفعول به ركنٌ في الجملة الاسميّة فقط"},{"id":"c","text":"الحال والتّمييز كلاهما منصوبان قد يردان في أيّ نواةٍ من الجملة المركّبة"},{"id":"d","text":"عدد النّوى لا علاقة له بعدد الوظائف النّحويّة الممكنة داخل الجملة"}]'::jsonb, 'c', 'الصّحيح: كلّ وظائف الباب (النّواة، المتمّمات، الفاعل، المفعول به، خبر النّاسخ، الحال، التّمييز) قد تظهر داخل كلّ نواةٍ على حدةٍ من الجملة المركّبة، ولكلّ نواةٍ إعرابها الخاصّ. أمّا الباقي فخطأ: خبر النّاسخ يظهر في أيّ نواةٍ اسميّةٍ منسوخة ولو كانت ضمن مركّبة، والمفعول به ركن الجملة الفعليّة لا الاسميّة، وكثرة النّوى تزيد فرص ورود الوظائف النّحويّة لأنّ لكلّ نواةٍ متمّماتها الخاصّة.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('aad2786f-edc9-5086-a3d6-be62b09951ba', 'a41b519f-7893-5c73-aef9-a03c5db1edcc', 'arabic-7eme', 'اختبار فهم الدرس ⭐', 1, 20, 5, 'quiz', 'admin', 0)
