INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('db7fec78-c11c-5525-a408-4e518a512838', 'aad2786f-edc9-5086-a3d6-be62b09951ba', 'الصّوت اللّغويّ هو:', '[{"id":"a","text":"أصغر وحدة نطقية يستعملها جهاز النّطق في تركيب الكلمة"},{"id":"b","text":"أطول وحدة نطقية تتكوّن من عدّة مقاطع"},{"id":"c","text":"الحرف المكتوب فقط دون نطقه"},{"id":"d","text":"الجملة الكاملة المفيدة"}]'::jsonb, 'a', 'الصّوت اللّغويّ أصغر وحدة نطقية ينطقها جهاز النّطق، ولا معنى له بمفرده، لكنّه يدخل في تركيب الكلمات.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a894f354-ecb2-5d0e-a6c8-ccb2532ad322', 'aad2786f-edc9-5086-a3d6-be62b09951ba', 'الصّائت في الأصوات اللّغويّة هو:', '[{"id":"a","text":"صوتٌ يُعترض معه مجرى الهواء في جهاز النّطق"},{"id":"b","text":"صوتٌ ينطلق معه الهواء بلا عائق، كالحركات وحروف المدّ"},{"id":"c","text":"الحرف المضعّف بالشّدّة"},{"id":"d","text":"علامة الإعراب الظّاهرة على آخر الكلمة"}]'::jsonb, 'b', 'الصّائت صوتٌ ينطلق معه الهواء بلا عائق، وتمثّله الحركات القصيرة (الفتحة والضّمّة والكسرة) وحروف المدّ الطّويلة (ا، و، ي).', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e6551cf8-8971-5ae8-8fa2-26771ff054f4', 'aad2786f-edc9-5086-a3d6-be62b09951ba', 'يتألّف المقطع الصّوتيّ في أبسط صوره من:', '[{"id":"a","text":"صائت وحده"},{"id":"b","text":"صامتين متتاليين بلا صائت"},{"id":"c","text":"صامت يليه صائت"},{"id":"d","text":"صائت يليه صامت ساكن فقط"}]'::jsonb, 'c', 'المقطع الصّوتيّ يتألّف في أبسط صوره من صامتٍ يليه صائت، ولا يمكن أن يبدأ مقطعٌ في العربيّة بصائتٍ وحده.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6112eab0-6627-5f53-a013-68f784642d64', 'aad2786f-edc9-5086-a3d6-be62b09951ba', 'جذر كلمة «مدرسة» هو:', '[{"id":"a","text":"م د ر"},{"id":"b","text":"م د ر س"},{"id":"c","text":"د ر س ة"},{"id":"d","text":"د ر س"}]'::jsonb, 'd', 'جذر «مدرسة» هو (د ر س) بعد حذف الميم والألف والتّاء المربوطة، وهي زوائد أضيفت إلى الجذر الثّلاثيّ.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('44d8381d-1464-59ae-8810-885cb96b5e43', 'aad2786f-edc9-5086-a3d6-be62b09951ba', 'الكلمات «كاتب، مكتوب، كتاب، مكتب» مشتقّةٌ كلّها من جذرٍ واحد لأنّ:', '[{"id":"a","text":"الحروف الأصليّة (ك ت ب) ثابتة فيها، والمعنى العامّ للكتابة مشترك بينها"},{"id":"b","text":"لكلٍّ منها معنًى مستقلٌّ لا علاقة بينها"},{"id":"c","text":"أوزانها الصّرفيّة متطابقة تمامًا"},{"id":"d","text":"طولها الحرفيّ واحد في كلّ الكلمات"}]'::jsonb, 'a', 'هذه الكلمات مشتقّة من جذرٍ واحد ثابت هو (ك ت ب)، وهو ما يجعل معناها العامّ (الكتابة) مشتركًا رغم اختلاف وظيفة كلٍّ منها.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

