INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('43e4748c-837b-5cec-8149-36bb56010482', '424b7232-f8d8-5657-ab15-9ad7f43546d8', 'الصّوت الصّامت من صفاته:', '[{"id":"a","text":"يخرج بلا عائقٍ يعترض الهواء"},{"id":"b","text":"يُعترض معه مجرى الهواء في جهاز النّطق"},{"id":"c","text":"لا يُنطق أبدًا"},{"id":"d","text":"هو الجملة الكاملة المفيدة"}]'::jsonb, 'b', 'الصّامت صوتٌ يُعترض معه مجرى الهواء في جهاز النّطق، بخلاف الصّائت الّذي ينطلق معه الهواء بلا عائق.', 1)
