INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('620aaf57-f07e-5807-a76b-176eb223ca02', '424b7232-f8d8-5657-ab15-9ad7f43546d8', 'أيّ ممّا يلي صائتٌ طويل (حرف مدّ)؟', '[{"id":"a","text":"الفتحة"},{"id":"b","text":"الباء"},{"id":"c","text":"الألف"},{"id":"d","text":"التّاء"}]'::jsonb, 'c', 'الألف والواو والياء حروف مدّ (صوائت طويلة)، أمّا الفتحة فحركة قصيرة، والباء والتّاء صامتان.', 2)
