INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4a52a0cb-ae7e-5958-ad49-56d71bc01540', '424b7232-f8d8-5657-ab15-9ad7f43546d8', 'المقطع الصّوتيّ لا يمكن أن يبدأ بـ:', '[{"id":"a","text":"صامت"},{"id":"b","text":"صائتٍ وحده"},{"id":"c","text":"صامتٍ متبوعٍ بحركة"},{"id":"d","text":"حرفٍ ساكنٍ في وسط الكلمة"}]'::jsonb, 'b', 'لا يبدأ مقطعٌ في العربيّة بصائتٍ وحده؛ فكلّ مقطع يبدأ وجوبًا بصامتٍ يليه صائت.', 3)
