INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4b88ee3a-8da2-5109-bcec-de7e49a0698b', '424b7232-f8d8-5657-ab15-9ad7f43546d8', 'أيّ الكلمات التّالية **ليست** مشتقّة من جذر (ع ل م)؟', '[{"id":"a","text":"عالمٌ"},{"id":"b","text":"معلّمٌ"},{"id":"c","text":"تعليمٌ"},{"id":"d","text":"عاملٌ"}]'::jsonb, 'd', '«عاملٌ» مشتقّة من جذرٍ آخر هو (ع م ل)، بخلاف «عالم» و«معلّم» و«تعليم» المشتقّة كلّها من الجذر (ع ل م).', 5)
