INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1b109f32-c2ea-58e1-b003-47652cc2913a', 'fc8e264b-6f2d-514b-b6bc-df2c57883742', 'نوع مقطع كلمة «هَلْ»:', '[{"id":"a","text":"قصير لأنّه يتكوّن من صامت وحركة فقط"},{"id":"b","text":"طويل لأنّه صامت + حركة قصيرة + صامت ساكن"},{"id":"c","text":"غير موجود لأنّ الكلمة حرف واحد"},{"id":"d","text":"قصير لأنّه ينتهي بسكون"}]'::jsonb, 'b', '«هَلْ» مقطعٌ واحد طويل: صامت (الهاء) + حركة قصيرة (الفتحة) + صامت ساكن (اللام الساكنة).', 1)
