INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('db05a7fa-7b6b-5201-ad99-6f96d0b0e9ed', 'fc8e264b-6f2d-514b-b6bc-df2c57883742', 'ظنّ تلميذ أنّ جذر «المصنع» أربعة أحرف هي (م ص ن ع). ما الصّواب؟', '[{"id":"a","text":"لا خطأ، هذا صحيح"},{"id":"b","text":"الصّواب أنّ الجذر ثلاثة أحرف (ص ن ع)، والميم زائدة دلّت على اسم المكان"},{"id":"c","text":"الصّواب أنّ الجذر (ص ن ع م)"},{"id":"d","text":"الصّواب أنّ الكلمة لا جذر لها لأنّها اسم مكان"}]'::jsonb, 'b', 'جذر «المصنع» ثلاثة أحرف (ص ن ع)، والميم زائدة تدلّ على اسم المكان الّذي يُصنَع فيه. الخطأ الشّائع عدّ حرف الزّيادة الدّالّ على اسم المكان جزءًا من الجذر.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8e796bb9-0f8d-58e0-9369-b3fc6cf08183', 'fc8e264b-6f2d-514b-b6bc-df2c57883742', '«منظر» و«ناظر» كلاهما مشتقّتان من جذرٍ واحد. ماذا يفيد هذا رغم اختلاف وظيفتيهما؟', '[{"id":"a","text":"أنّهما متضادّتان في المعنى"},{"id":"b","text":"أنّ إحداهما جذرٌ والأخرى كلمة عاديّة لا صلة بينهما"},{"id":"c","text":"أنّهما تشتركان في حروف الجذر (ن ظ ر) وفي أصل المعنى، رغم اختلاف الوظيفة (اسم مكان/مصدر واسم فاعل)"},{"id":"d","text":"أنّ عدد حروفهما متساوٍ فقط دون علاقة أخرى"}]'::jsonb, 'c', '«منظر» (اسم مكان أو مصدر ميميّ) و«ناظر» (اسم فاعل) كلاهما من جذر (ن ظ ر)، فمعناهما العامّ يدور حول النّظر رغم اختلاف وظيفتيهما الصّرفيّة.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('bcd23828-ebd4-523b-87af-45404edc0319', 'fc8e264b-6f2d-514b-b6bc-df2c57883742', 'تقطيع كلمة «خَرَجَ» الصّحيح هو:', '[{"id":"a","text":"خَرْ / جَ (مقطعان: طويل ثمّ قصير)"},{"id":"b","text":"خَ / رَجْ (مقطعان: قصير ثمّ طويل)"},{"id":"c","text":"خَ / رَ / جَ (ثلاثة مقاطع قصيرة)"},{"id":"d","text":"خَرَجَ مقطعٌ واحد فقط"}]'::jsonb, 'c', 'كلّ صامت في «خَرَجَ» متبوعٌ بحركة قصيرة بلا سكون، فتنقسم الكلمة إلى ثلاثة مقاطع قصيرة: خَ / رَ / جَ، تمامًا مثل «دَرَسَ» في الدّرس.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

