INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('31f975ca-fbbf-5d25-a932-4fa0d21a9512', 'b9b85ba2-6c1e-5c7c-a2ab-1cf21981b9ce', 'المقطع الصّوتيّ يتألّف على الأقلّ من:', '[{"id":"a","text":"صامتين متتاليين"},{"id":"b","text":"صامت وصائت"},{"id":"c","text":"صائتين متتاليين"},{"id":"d","text":"كلمة كاملة"}]'::jsonb, 'b', 'المقطع الصّوتيّ يتألّف على الأقلّ من صامتٍ واحد يليه صائت، وهو أبسط تركيبٍ ممكن للمقطع.', 1)
