INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('bd855e2d-0cf2-5dde-87c8-7921ebd58616', 'b9b85ba2-6c1e-5c7c-a2ab-1cf21981b9ce', 'عدد أحرف الجذر في الفعل الثّلاثيّ المجرّد عادةً:', '[{"id":"a","text":"حرفان"},{"id":"b","text":"أربعة أحرف"},{"id":"c","text":"خمسة أحرف"},{"id":"d","text":"ثلاثة أحرف"}]'::jsonb, 'd', 'الفعل الثّلاثيّ المجرّد جذره ثلاثة أحرفٍ أصليّة، وهو الأصل الغالب في جذور الأفعال العربيّة.', 4)
