INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('34216715-b245-595b-9a3a-4e31d37ab901', 'b9b85ba2-6c1e-5c7c-a2ab-1cf21981b9ce', 'الكلمات «جالسٌ، مجلسٌ، جلوسٌ» تشترك في:', '[{"id":"a","text":"الوظيفة الصّرفيّة نفسها فقط"},{"id":"b","text":"عدد الحروف نفسه فقط"},{"id":"c","text":"الجذر (ج ل س) والمعنى العامّ للجلوس، مع اختلاف الوظيفة"},{"id":"d","text":"أنّها ليست مشتقّة من جذرٍ واحد"}]'::jsonb, 'c', 'الكلمات الثّلاث مشتقّة من جذرٍ واحد (ج ل س): جالسٌ اسم فاعل، مجلسٌ اسم مكان، جلوسٌ مصدر، وكلّها تدور حول معنى الجلوس.', 6)
