INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('42d9374f-a0d0-5d38-9cf0-704b145874d1', '02befef7-68cf-5afa-acc9-00a2f42e7905', 'قال تلميذ: جذر «استعمل» خمسة أحرف هي (س ت ع م ل). ما الصّواب؟', '[{"id":"a","text":"لا خطأ، هذا صحيح"},{"id":"b","text":"الصّواب أنّ الجذر أربعة أحرف (ت ع م ل)"},{"id":"c","text":"الصّواب أنّ الجذر ثلاثة أحرف (ع م ل)، والهمزة والسّين والتّاء زوائد"},{"id":"d","text":"الصّواب أنّ الجذر (ع م ل ت)"}]'::jsonb, 'c', 'جذر «استعمل» ثلاثة أحرف (ع م ل)، وما سبقها (الهمزة والسّين والتّاء) زوائد دلّت على معنى الطّلب أو الاتّخاذ. الخطأ الشّائع ضمّ حروف الزّيادة إلى الجذر لأنّها تسبقه مباشرة.', 3)
