INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e0796d74-0ee1-540d-897b-d8294ee7653d', '02befef7-68cf-5afa-acc9-00a2f42e7905', 'أيّ العبارات التّالية صحيحة في العلاقة بين الجذر والكلمات المشتقّة؟', '[{"id":"a","text":"الجذر يتغيّر من كلمةٍ إلى أخرى داخل الأسرة اللّفظيّة الواحدة"},{"id":"b","text":"عدد أحرف الجذر يزداد كلّما طالت الكلمة المشتقّة"},{"id":"c","text":"المقطع الصّوتيّ أصغر من الصّوت اللّغويّ"},{"id":"d","text":"الكلمة المشتقّة قد تحتوي على حروفٍ زائدة لا توجد في الجذر"}]'::jsonb, 'd', 'الكلمة المشتقّة تتألّف من الجذر الثّابت زائدًا حروفًا أو حركات إضافية؛ أمّا الجذر فلا يتغيّر ولا يزداد عدد حروفه، والمقطع أكبر من الصّوت لا أصغر منه.', 4)
