  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('48a9374f-586b-5198-b113-006f56800785', '02befef7-68cf-5afa-acc9-00a2f42e7905', 'تقطيع الفعل «يَفْهَمُ» الصّحيح هو:', '[{"id":"a","text":"يَفْ / هَ / مُ (مقطع طويل مغلق ثمّ مقطعان قصيران)"},{"id":"b","text":"يَ / فَهْ / مُ"},{"id":"c","text":"يَفْهَ / مُ (مقطعان فقط)"},{"id":"d","text":"يَ / فْهَ / مُ"}]'::jsonb, 'a', 'المقطع الأوّل «يَفْ» صامت (الياء) + حركة قصيرة + صامت ساكن (الفاء)، فهو طويل مغلق؛ ثمّ «هَ» و«مُ» مقطعان قصيران، كلٌّ منهما صامت وحركة قصيرة.', 5)
