INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f62c9676-4880-5823-869a-0048828cdb4a', '3abe2557-8958-57a7-8dea-5eb12af28e8b', 'نوع أوّل مقطع في كلمة «غَسَلَ»:', '[{"id":"a","text":"طويل: صامت + صائت طويل"},{"id":"b","text":"طويل مغلق: صامت + حركة + صامت ساكن"},{"id":"c","text":"لا يوجد مقطع أوّل"},{"id":"d","text":"قصير: صامت + حركة قصيرة"}]'::jsonb, 'd', 'المقطع الأوّل «غَ» صامت (الغين) متبوعٌ بحركة قصيرة (الفتحة) فقط، فهو مقطع قصير، مثل «كَ» في «كَتَبَ».', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c58445c8-e438-58a4-b510-9a44cd2cf21d', '3abe2557-8958-57a7-8dea-5eb12af28e8b', 'كلمة «مغسلة» مشتقّة من جذر (غ س ل)، ووظيفتها الصّرفيّة:', '[{"id":"a","text":"اسم فاعل"},{"id":"b","text":"اسم مفعول"},{"id":"c","text":"اسم مكان"},{"id":"d","text":"مصدر"}]'::jsonb, 'c', '«مغسلة» اسم مكان يدلّ على مكان الغسل، مشتقّ من جذر (غ س ل) بزيادة الميم والتّاء المربوطة.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f09d0b66-2b18-5b4b-9fd7-7024bfacc5d3', '3abe2557-8958-57a7-8dea-5eb12af28e8b', 'ظنّ تلميذ أنّ «الدّخول» و«مدخل» ليسا من جذرٍ واحد لاختلاف صورتيهما. ما الصّواب؟', '[{"id":"a","text":"الصّواب أنّهما فعلًا من جذرين مختلفين"},{"id":"b","text":"الصّواب أنّهما مشتقّان من جذرٍ واحد (د خ ل)، واختلاف صورتيهما راجعٌ إلى اختلاف الزّوائد والوظيفة لا الجذر"},{"id":"c","text":"الصّواب أنّ «الدّخول» ليست كلمة مشتقّة أصلًا"},{"id":"d","text":"الصّواب أنّ جذر «مدخل» هو (م د خ ل)"}]'::jsonb, 'b', '«الدّخول» (مصدر) و«مدخل» (اسم مكان) كلاهما من جذرٍ واحد ثابت (د خ ل)؛ اختلاف صورتيهما سببه اختلاف الزّوائد والوظيفة الصّرفيّة، لا اختلاف الجذر. الخطأ الشّائع الحكم باختلاف الجذر لمجرّد اختلاف شكل الكلمة.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('661de8c8-d152-5c36-9650-9a25d6989bb3', '3abe2557-8958-57a7-8dea-5eb12af28e8b', 'الصّوت والمقطع والجذر ثلاث وحداتٍ تُبنى منها الكلمة. أيّ ترتيبٍ صحيحٌ من الأصغر إلى الأكبر؟', '[{"id":"a","text":"الصّوت، ثمّ المقطع، ثمّ الجذر"},{"id":"b","text":"المقطع، ثمّ الصّوت، ثمّ الجذر"},{"id":"c","text":"الجذر، ثمّ الصّوت، ثمّ المقطع"},{"id":"d","text":"المقطع، ثمّ الجذر، ثمّ الصّوت"}]'::jsonb, 'a', 'الصّوت أصغر وحدة (صامت أو صائت واحد)، ثمّ يتركّب منه المقطع (صامت + صائت على الأقلّ)، ثمّ تتألّف من عدّة مقاطع كلمةٌ لها جذرٌ من عدّة أصوات، فالتّرتيب من الأصغر إلى الأكبر: الصّوت ثمّ المقطع ثمّ الجذر.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('beb3b17d-3ed3-55d5-813b-ee27bde9f297', 'a41b519f-7893-5c73-aef9-a03c5db1edcc', 'arabic-7eme', '👑 تحدّي النخبة ⭐⭐⭐⭐: قمّة الجذر والاشتقاق', 4, 300, 60, 'challenge', 'admin', 6)
ON CONFLICT (id) DO UPDATE SET
