  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('33a77236-fb57-59d5-8dd5-2b6bf11a3b7d', 'beb3b17d-3ed3-55d5-813b-ee27bde9f297', 'جذر «المحمول» ووظيفتها الصّرفيّة:', '[{"id":"a","text":"جذرها (ح م ل) ووظيفتها اسم مفعول"},{"id":"b","text":"جذرها (ح م ل) ووظيفتها اسم فاعل"},{"id":"c","text":"جذرها (م ح م ل) ووظيفتها مصدر"},{"id":"d","text":"جذرها (ح م ل) ووظيفتها اسم مكان"}]'::jsonb, 'a', '«المحمول» اسم مفعول يدلّ على ما وقع عليه الحمل، وهو مشتقّ من جذر (ح م ل) بعد حذف أل التّعريف والزّوائد الدّالّة على اسم المفعول.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('642e56cb-2644-5d26-98b4-4bbc4b0722d1', 'beb3b17d-3ed3-55d5-813b-ee27bde9f297', 'جذر «السّاكن» ووظيفتها الصّرفيّة:', '[{"id":"a","text":"جذرها (س ا ك ن) ووظيفتها اسم مفعول"},{"id":"b","text":"جذرها (س ك ن) ووظيفتها اسم فاعل"},{"id":"c","text":"جذرها (س ك ن) ووظيفتها اسم مكان"},{"id":"d","text":"جذرها (س ك) ووظيفتها مصدر"}]'::jsonb, 'b', '«السّاكن» اسم فاعل مباشر من الفعل «سكن»، وجذره (س ك ن) بعد حذف أل التّعريف والألف.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('68ebcdd3-7956-5e17-9475-f885265a23b8', 'beb3b17d-3ed3-55d5-813b-ee27bde9f297', 'تقطيع كلمة «شَكَرَ» الصّحيح هو:', '[{"id":"a","text":"شَكْ / رَ (مقطعان)"},{"id":"b","text":"شَ / كَرْ (مقطعان)"},{"id":"c","text":"شَ / كَ / رَ (ثلاثة مقاطع قصيرة)"},{"id":"d","text":"شَكَرَ مقطعٌ واحد"}]'::jsonb, 'c', 'كلّ صامتٍ في «شَكَرَ» متبوعٌ بحركةٍ قصيرة بلا سكون، فتنقسم الكلمة إلى ثلاثة مقاطع قصيرة: شَ / كَ / رَ، مثل «خَرَجَ» و«دَرَسَ».', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c6d25f2b-8e19-5834-aba9-42e10cbf0967', 'beb3b17d-3ed3-55d5-813b-ee27bde9f297', 'قال تلميذ: جذر «الاجتماع» خمسة أحرف هي (ا ج ت م ع). ما الصّواب؟', '[{"id":"a","text":"لا خطأ، هذا صحيح"},{"id":"b","text":"الصّواب أنّ الجذر أربعة أحرف (ج ت م ع)"},{"id":"c","text":"الصّواب أنّ الكلمة لا جذر لها"},{"id":"d","text":"الصّواب أنّ الجذر ثلاثة أحرف (ج م ع)، والألف والتّاء زائدتان"}]'::jsonb, 'd', 'جذر «الاجتماع» ثلاثة أحرف (ج م ع)، والألف والتّاء زائدتان دلّتا على معنى المشاركة والمطاوعة. الخطأ الشّائع ضمّ حروف الزّيادة السّابقة للجذر إليه لأنّها ملتصقة به مباشرة.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('49e040c4-e581-5fa6-b6eb-061bb8df49e6', 'beb3b17d-3ed3-55d5-813b-ee27bde9f297', 'أيّ الزّوجين التّاليين ينتميان إلى الأسرة اللّفظيّة (الجذر) نفسها؟', '[{"id":"a","text":"دارس - مدرسة (جذراهما د ر س)"},{"id":"b","text":"دارس - درج (د ر س مقابل د ر ج، مختلفان)"},{"id":"c","text":"خارج - درج (خ ر ج مقابل د ر ج، مختلفان)"},{"id":"d","text":"سامع - سمك (س م ع مقابل س م ك، مختلفان)"}]'::jsonb, 'a', '«دارس» و«مدرسة» مشتقّتان من جذرٍ واحد (د ر س). أمّا الأزواج الأخرى فتتشابه في بعض الحروف السّطحيّة لكنّ جذريها مختلفان فعلًا (د ر س ≠ د ر ج، خ ر ج ≠ د ر ج، س م ع ≠ س م ك). الخطأ الشّائع الاعتماد على تشابه الحروف السّطحيّ دون التّحقّق من الجذر الفعليّ.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f257cb53-3975-5b6d-9b7d-45ead559675b', 'beb3b17d-3ed3-55d5-813b-ee27bde9f297', 'كلمة «مُستخرَج» — استخرج جذرها أوّلًا، ثمّ حدّد عدد حروفها الزّائدة عليه:', '[{"id":"a","text":"جذرها (س ت خ ر ج)، وفيها حرفٌ زائد واحد (م)"},{"id":"b","text":"جذرها (خ ر ج)، وفيها ثلاثة أحرف زائدة (م، س، ت)"},{"id":"c","text":"جذرها (خ ر ج)، وفيها حرفٌ زائد واحد فقط (م)"},{"id":"d","text":"جذرها (م س ت خ ر ج) كاملة، فلا زوائد فيها"}]'::jsonb, 'b', 'جذر «مُستخرَج» هو (خ ر ج) ثلاثة أحرف، والكلمة كاملةً ستّة أحرف (م س ت خ ر ج)، فعدد الحروف الزّائدة عليه ثلاثة: الميم والسّين والتّاء.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

