  ('e69f57c1-ee7b-590d-90bb-7465cd11a30f', 'a3db2a72-6dbf-5595-a8ae-bc36e245b207', 'arabic-7eme', 'اختبار فهم الدرس ⭐', 1, 20, 5, 'quiz', 'admin', 0)
