INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('bddc9d69-75f7-5643-9dba-bae6d812ae1c', 'e69f57c1-ee7b-590d-90bb-7465cd11a30f', 'الفعل الثّلاثيّ المجرّد السّالم هو فعل:', '[{"id":"a","text":"من ثلاثة أحرف أصليّة، خالٍ من حرف العلّة والهمزة والتّضعيف"},{"id":"b","text":"من أربعة أحرف أصليّة زيد عليها حرف"},{"id":"c","text":"من ثلاثة أحرف أصليّة أحدها حرف علّة"},{"id":"d","text":"من ثلاثة أحرف أصليّة مضاعف الحرفين الأخيرين"}]'::jsonb, 'a', 'الفعل الثّلاثيّ المجرّد له ثلاثة أحرف أصليّة بلا زيادة، والسّالم منه ما خلا من حرف العلّة والهمزة والتّضعيف، مثل كَتَبَ وفَهِمَ.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('fca8d3d9-c525-511b-98f4-bc5344a9dfa4', 'e69f57c1-ee7b-590d-90bb-7465cd11a30f', 'أيّ الأفعال التّالية ثلاثيّ مجرّد سالم؟', '[{"id":"a","text":"قالَ"},{"id":"b","text":"مَدَّ"},{"id":"c","text":"جَلَسَ"},{"id":"d","text":"أَخَذَ"}]'::jsonb, 'c', '«جَلَسَ» ثلاثيّ سالم لا حرف علّة فيه ولا همزة ولا تضعيف؛ أمّا «قالَ» معتلّ الوسط، و«مَدَّ» مضاعف، و«أَخَذَ» مهموز الفاء.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('dd8d5274-41cd-597b-a8d6-ee37e2b4383e', 'e69f57c1-ee7b-590d-90bb-7465cd11a30f', '«فَهِمَ» مع ضمير «هم» يصبح:', '[{"id":"a","text":"فَهِمَا"},{"id":"b","text":"فَهِمُوا"},{"id":"c","text":"فَهِمْنَ"},{"id":"d","text":"فَهِمْتُم"}]'::jsonb, 'b', 'مع «هم» يتّصل الفعل الماضي بواو الجماعة فيصبح «فَهِمُوا»، وهي علامة جمع الغائبين المذكّرين.', 3)
