INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2f021b53-7b65-58b5-a22b-598f197eef82', 'e69f57c1-ee7b-590d-90bb-7465cd11a30f', 'المضارع المرفوع من «دَرَسَ» مع ضمير «أنتِ» هو:', '[{"id":"a","text":"تَدْرُسُ"},{"id":"b","text":"أَدْرُسُ"},{"id":"c","text":"يَدْرُسُ"},{"id":"d","text":"تَدْرُسِينَ"}]'::jsonb, 'd', 'مع «أنتِ» (المخاطبة المفردة) يتّصل المضارع بياء المخاطبة فيصبح «تَدْرُسِينَ».', 4)
ON CONFLICT (id) DO UPDATE SET
