INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('843361bd-027a-5d37-ab32-f6bcd64825c3', 'e69f57c1-ee7b-590d-90bb-7465cd11a30f', 'وزن الفعل «كَبُرَ» من أوزان الثّلاثيّ المجرّد هو:', '[{"id":"a","text":"فَعَلَ"},{"id":"b","text":"فَعِلَ"},{"id":"c","text":"فَعُلَ"},{"id":"d","text":"أَفْعَلَ"}]'::jsonb, 'c', 'عين الماضي في «كَبُرَ» مضمومة، فوزنه «فَعُلَ»، وهذا الوزن مضارعه دائمًا بالضّمّ: يَكْبُرُ.', 5)
