INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3703acc9-7ea9-5b84-900d-24733f7fec9e', '3fe04af9-dd20-550c-9d24-55ab74ce6f0b', 'أيّ الأفعال التّالية ثلاثيّ مجرّد سالم؟', '[{"id":"a","text":"وَجَدَ"},{"id":"b","text":"رَدَّ"},{"id":"c","text":"شَرِبَ"},{"id":"d","text":"سَأَلَ"}]'::jsonb, 'c', '«شَرِبَ» ثلاثيّ سالم من غير حرف علّة ولا همزة ولا تضعيف؛ أمّا «وَجَدَ» فاؤه واو، و«سَأَلَ» مهموز العين، و«رَدَّ» مضاعف.', 1)
