INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1ac467a8-834e-5c2c-84bd-208e529792c0', '3fe04af9-dd20-550c-9d24-55ab74ce6f0b', 'الفعل «المجرّد» هو الفعل الذي:', '[{"id":"a","text":"أحرفه كلّها أصليّة بلا زيادة"},{"id":"b","text":"زيدت على أحرفه الأصليّة أحرف"},{"id":"c","text":"خالٍ من الحركات"},{"id":"d","text":"لا يتصرّف في الماضي والمضارع"}]'::jsonb, 'a', 'المجرّد فعل أحرفه كلّها أصليّة، بلا حرف زائد، خلافًا للمزيد الذي تُزاد على أصله أحرف، مثل انطلق.', 2)
