INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('30a2861b-d5e5-5a67-9262-f268c281e03e', '3fe04af9-dd20-550c-9d24-55ab74ce6f0b', '«جَلَسَ» مع ضمير «أنا» يصبح:', '[{"id":"a","text":"جَلَسْتَ"},{"id":"b","text":"جَلَسُوا"},{"id":"c","text":"جَلَسْنَا"},{"id":"d","text":"جَلَسْتُ"}]'::jsonb, 'd', 'مع «أنا» تتّصل تاء الفاعل المضمومة فيصبح «جَلَسْتُ»، وهي علامة المتكلّم المفرد.', 4)
