INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f2df0773-8315-5f1f-ae65-d4fc46467f07', '3fe04af9-dd20-550c-9d24-55ab74ce6f0b', 'المضارع المرفوع من «خَرَجَ» مع ضمير «هو» هو:', '[{"id":"a","text":"تَخْرُجُ"},{"id":"b","text":"يَخْرُجُ"},{"id":"c","text":"أَخْرُجُ"},{"id":"d","text":"نَخْرُجُ"}]'::jsonb, 'b', 'مع «هو» يبدأ المضارع بياء المضارعة، فيصبح «يَخْرُجُ».', 5)
