INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f4413329-fbb3-59e3-bc63-cdb2ea593f6e', 'e16e5a83-ad5b-5e43-bf0c-3899ccde226f', 'الفعل الماضي المتّصل بواو الجماعة، مثل «كَتَبُوا»، يُبنى على:', '[{"id":"a","text":"الفتح"},{"id":"b","text":"الضّمّ"},{"id":"c","text":"الكسر"},{"id":"d","text":"السّكون"}]'::jsonb, 'b', 'إذا اتّصلت واو الجماعة بالفعل الماضي بُني على الضّمّ، مثل «كَتَبُوا»، خلافًا لبنائه على الفتح عند عدم الاتّصال أو اتّصاله بتاء التّأنيث أو ألف الاثنين.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('aafd2fbd-0ea3-5279-8541-19d00404d494', 'e16e5a83-ad5b-5e43-bf0c-3899ccde226f', 'الفعل الماضي المتّصل بتاء الفاعل المتحرّكة، مثل «فَهِمْتُ»، يُبنى على:', '[{"id":"a","text":"الفتح"},{"id":"b","text":"الضّمّ"},{"id":"c","text":"الكسر"},{"id":"d","text":"السّكون"}]'::jsonb, 'd', 'تاء الفاعل المتحرّكة (أنا/أنتَ/أنتِ...) تُسكّن آخر الفعل الماضي، مثل «فَهِمْتُ»، كما تفعل نون النّسوة.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
