  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('cb51f0f0-eb56-5757-bea9-95106dc5f153', 'e16e5a83-ad5b-5e43-bf0c-3899ccde226f', 'وزن «حَسُنَ» ومضارعه المرفوع مع «هو» هما على التّرتيب:', '[{"id":"a","text":"فَعُلَ — يَحْسُنُ"},{"id":"b","text":"فَعَلَ — يَحْسُنُ"},{"id":"c","text":"فَعِلَ — يَحْسَنُ"},{"id":"d","text":"فَعُلَ — يَحْسَنُ"}]'::jsonb, 'a', 'عين الماضي في «حَسُنَ» مضمومة، فوزنه «فَعُلَ»، وهذا الوزن مضارعه دائمًا بالضّمّ، فيكون «يَحْسُنُ».', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e443dcfb-bf0e-54f9-95a2-897c7c9a7937', 'e16e5a83-ad5b-5e43-bf0c-3899ccde226f', 'صرّف تلميذ «رَكِبَ» مع «أنتم» فكتب «رَكُبْتُم» بضمّ الكاف بدل كسرها. أين الخطأ؟', '[{"id":"a","text":"لا خطأ، فالصّياغتان صحيحتان"},{"id":"b","text":"الصّواب حذف حرف من الفعل"},{"id":"c","text":"الصّواب تحويل الفعل إلى المضارع"},{"id":"d","text":"الصّواب إبقاء عين الفعل «رَكِبَ» كما هي وتسكين آخره: رَكِبْتُمْ"}]'::jsonb, 'd', 'عند اتّصال تاء الفاعل يُسكَّن آخر حرف في الفعل الماضي فقط، وتبقى حركة عين الفعل الأصليّة كما هي؛ فالصّواب «رَكِبْتُمْ» بإبقاء كسرة العين، لا «رَكُبْتُم» بضمّها.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('20153f6f-c235-5320-b579-c390b7eece42', 'e16e5a83-ad5b-5e43-bf0c-3899ccde226f', 'الفعلان «فَتَحَ» و«جَلَسَ» كلاهما على وزن فَعَلَ، لكنّ مضارعهما يختلف: فَتَحَ ← يَفْتَحُ (فتح)، وجَلَسَ ← يَجْلِسُ (كسر). ما الذي يفسّر هذا الاختلاف رغم اتّحاد الوزن في الماضي؟', '[{"id":"a","text":"حركة عين المضارع في وزن فَعَلَ ثابتة دائمًا"},{"id":"b","text":"يتوقّف الأمر على معنى الفعل لا على صيغته"},{"id":"c","text":"حركة عين المضارع في وزن فَعَلَ غير ثابتة، وتُعرف بالرّجوع إلى المعجم أو الحفظ"},{"id":"d","text":"الاختلاف خطأ، ويجب أن يكون مضارعهما واحدًا"}]'::jsonb, 'c', 'خلافًا لوزن «فَعُلَ» الثّابت الضّمّ في مضارعه، فإنّ حركة عين المضارع في وزن «فَعَلَ» غير ثابتة، فقد تأتي بالفتح أو الكسر أو الضّمّ بحسب الفعل، وتُعرف بالرّجوع إلى المعجم.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c9a3128e-9024-55ff-b18c-5b08af20789c', 'e16e5a83-ad5b-5e43-bf0c-3899ccde226f', '«الطّالبات ـــ يفهمن الدّرس جيّدًا ويكتبن الإجابة بسرعة» — أيّ ضمير يناسب هذا التّصريف؟', '[{"id":"a","text":"هم"},{"id":"b","text":"هنّ"},{"id":"c","text":"أنتنّ"},{"id":"d","text":"نحن"}]'::jsonb, 'b', 'نون النّسوة (يفهمن، يكتبن) تدلّ على جمع الغائبات المؤنّثات، فالضّمير المناسب «هنّ».', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

