INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e65b9c6d-671b-5d9b-9658-7e75212b6d67', '30615558-1787-5afd-952c-c5de967e7691', '«الفلاّحون ـــ الأرض في الصّباح ويزرعونها بعد الظّهر» — أيّ فعل ماضٍ يناسب الفراغ ليتّفق مع الفاعل «الفلاّحون» والفعل «يزرعونها»؟', '[{"id":"a","text":"حَرَثَ"},{"id":"b","text":"حَرَثُوا"},{"id":"c","text":"حَرَثَتْ"},{"id":"d","text":"حَرَثْتُم"}]'::jsonb, 'b', 'الفاعل «الفلاّحون» جمع غائبين مذكّرين، ويتّفق معه في المضارع «يزرعونها» بواو الجماعة، فيلزم الماضي «حَرَثُوا» بواو الجماعة أيضًا للاتّساق.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b9086815-6723-5c41-a36b-3b7bae31e618', '30615558-1787-5afd-952c-c5de967e7691', 'كتب تلميذ: «الطّالباتُ حَفِظْنَ الدّرسَ وفَهِمَتْ معناه». في هذه الجملة خطأ تصريفيّ واحد، ما هو؟', '[{"id":"a","text":"لا خطأ في الجملة"},{"id":"b","text":"الصّواب حَفِظُوا بدل حَفِظْنَ"},{"id":"c","text":"الصّواب فَهِمْنَ بدل فَهِمَتْ"},{"id":"d","text":"الصّواب فَهِمَ بدل فَهِمَتْ"}]'::jsonb, 'c', 'الفاعل «الطّالباتُ» جمع غائبات، ويصحّ معه «حَفِظْنَ» بنون النّسوة، لكنّ الفعل الثّاني «فَهِمَتْ» صيغة مفرد مؤنّث لا تناسب الجمع؛ الصّواب «فَهِمْنَ» بنون النّسوة أيضًا لاتّساق الفاعل نفسه في الجملتين.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('317b15ba-8f2d-5397-bc30-070c9146149a', '30615558-1787-5afd-952c-c5de967e7691', 'الفعلان «عَلِمَ» و«نَزَلَ» يُكتبان أحيانًا دون تشكيل: «علم» و«نزل». كيف نميّز وزنهما (فَعِلَ أم فَعَلَ) عمليًّا عند غياب الحركات؟', '[{"id":"a","text":"باستحالة التّمييز بينهما مطلقًا"},{"id":"b","text":"بعدد أحرف الفعل فقط"},{"id":"c","text":"بموقع الفعل في الجملة فقط"},{"id":"d","text":"بالرّجوع إلى حركة عين الفعل في المعجم أو بمعرفة مضارعه"}]'::jsonb, 'd', 'عند غياب التّشكيل، يُعرف وزن الفعل (فَعَلَ أم فَعِلَ أم فَعُلَ) بالرّجوع إلى حركة عين الماضي في المعجم، أو بمعرفة مضارعه المسموع، لا بعدد الأحرف ولا بموقع الجملة.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('bd9f3b86-7a6f-5c1a-bffd-c007a0cc8f08', '30615558-1787-5afd-952c-c5de967e7691', 'أيّ العبارات التّالية عن أوزان الثّلاثيّ المجرّد السّالم صحيحة؟', '[{"id":"a","text":"كلّ الأفعال على وزن فَعَلَ مضارعها مفتوح العين"},{"id":"b","text":"وزن فَعِلَ مضارعه مضموم العين دائمًا"},{"id":"c","text":"وزن فَعُلَ وحده ثابت حركة عين المضارع (الضّمّ) دائمًا"},{"id":"d","text":"لا علاقة بين وزن الماضي وحركة عين المضارع إطلاقًا"}]'::jsonb, 'c', 'وزن فَعُلَ فريد بثبات ضمّ عين مضارعه (كَبُرَ ← يَكْبُرُ، حَسُنَ ← يَحْسُنُ)، خلافًا لوزنَي فَعَلَ وفَعِلَ اللّذين تتفاوت حركة عين مضارعهما.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('cde2d062-6e40-5313-b330-6691364d7284', '30615558-1787-5afd-952c-c5de967e7691', '«التّلميذاتُ ركِبْنَ الحافلةَ باكرًا» — حدّد معًا: وزنَ «رَكِبَ»، وسببَ بناء «ركِبْنَ» على السّكون.', '[{"id":"a","text":"وزنه فَعُلَ، وبني على السّكون لاتّصاله بواو الجماعة"},{"id":"b","text":"وزنه فَعِلَ، وبني على السّكون لاتّصاله بنون النّسوة"},{"id":"c","text":"وزنه فَعَلَ، وبني على الفتح لعدم اتّصاله بشيء"},{"id":"d","text":"وزنه فَعِلَ، وبني على الضّمّ لاتّصاله بواو الجماعة"}]'::jsonb, 'b', 'عين الماضي في «رَكِبَ» مكسورة فوزنه فَعِلَ، واتّصاله بنون النّسوة (التّلميذاتُ ركِبْنَ) يبني آخره على السّكون، مثل تاء الفاعل تمامًا.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('b394922b-3604-5212-a86f-e023556ed400', 'a3db2a72-6dbf-5595-a8ae-bc36e245b207', 'arabic-7eme', '📝 تدريب ⭐⭐⭐: مراجعة شاملة لتصريف الفعل المجرّد السّالم', 3, 120, 30, 'boss', 'admin', 5)
ON CONFLICT (id) DO UPDATE SET
