  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b82ffa73-e5b6-5b80-b4af-5b4bba12a629', 'b394922b-3604-5212-a86f-e023556ed400', 'أيّ ممّا يلي **ليس** شرطًا لازمًا لكون الفعل ثلاثيًّا سالمًا؟', '[{"id":"a","text":"أن يكون متعدّيًا لمفعول به"},{"id":"b","text":"خلوّه من حرف العلّة"},{"id":"c","text":"خلوّه من الهمزة"},{"id":"d","text":"خلوّه من التّضعيف"}]'::jsonb, 'a', 'شروط السّالم الثّلاثة هي: خلوّه من حرف العلّة والهمزة والتّضعيف؛ أمّا التّعدّي أو اللّزوم فلا علاقة له بالسّلامة، إذ قد يكون الفعل السّالم لازمًا أو متعدّيًا.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ad128f45-eff4-5fc6-9f18-f86a159d4352', 'b394922b-3604-5212-a86f-e023556ed400', 'وزن الفعل «نَصَرَ» ومضارعه:', '[{"id":"a","text":"فَعِلَ — يَنْصَرُ"},{"id":"b","text":"فَعَلَ — يَنْصُرُ"},{"id":"c","text":"فَعُلَ — يَنْصُرُ"},{"id":"d","text":"فَعَلَ — يَنْصِرُ"}]'::jsonb, 'b', 'عين الماضي في «نَصَرَ» مفتوحة فوزنه فَعَلَ، ومضارعه المسموع «يَنْصُرُ» بضمّ العين.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ed3a1b43-7a17-571d-842c-ce3dcb162cfe', 'b394922b-3604-5212-a86f-e023556ed400', '«ضَرَبَ» مع ضمير «أنتما» يصبح:', '[{"id":"a","text":"ضَرَبَا"},{"id":"b","text":"ضَرَبَتَا"},{"id":"c","text":"ضَرَبْتُما"},{"id":"d","text":"ضَرَبُوا"}]'::jsonb, 'c', 'مع «أنتما» (المخاطبَين المثنّى) تتّصل تاء الفاعل بضمير «تُما»، فيصبح «ضَرَبْتُما»، بخلاف «ضَرَبَا» الخاصّة بـ«هما» الغائبين.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('86102391-992d-5671-86a7-0a6fb5393d1f', 'b394922b-3604-5212-a86f-e023556ed400', 'المضارع المرفوع من «فَرِحَ» مع ضمير «أنتنّ» هو:', '[{"id":"a","text":"يَفْرَحْنَ"},{"id":"b","text":"تَفْرَحُونَ"},{"id":"c","text":"تَفْرَحُ"},{"id":"d","text":"تَفْرَحْنَ"}]'::jsonb, 'd', 'مع «أنتنّ» (جمع المخاطبات) يتّصل المضارع بنون النّسوة مسبوقة بتاء المخاطبة، فيصبح «تَفْرَحْنَ».', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e67817cf-b9bd-55cd-b808-9c9a78df0cd9', 'b394922b-3604-5212-a86f-e023556ed400', 'الفعلان «بَعُدَ» و«صَعُبَ»: ما الذي يجمع بينهما صرفيًّا؟', '[{"id":"a","text":"كلاهما على وزن فَعُلَ ومضارعهما ثابت الضّمّ: يَبْعُدُ، يَصْعُبُ"},{"id":"b","text":"كلاهما على وزن فَعَلَ ومضارعهما مفتوح العين"},{"id":"c","text":"كلاهما معتلّ الآخر"},{"id":"d","text":"كلاهما مزيد بحرف واحد"}]'::jsonb, 'a', 'عين الماضي في الفعلين مضمومة (بَعُدَ، صَعُبَ)، فوزنهما فَعُلَ، وهذا الوزن مضارعه ثابت الضّمّ دائمًا: يَبْعُدُ ويَصْعُبُ.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b17958a6-981b-56bb-90eb-94ef522bc963', 'b394922b-3604-5212-a86f-e023556ed400', 'أراد تلميذ تصريف «ذَهَبَ» مع «هنّ» و«نحن»، فكتب: مع هنّ «ذَهَبْنَ»، ومع نحن «ذَهَبْنَا». أين الصّواب والخطأ في هذا التّصريف؟', '[{"id":"a","text":"كلاهما خاطئ، والصّواب ذَهَبُوا وذَهَبْتُم"},{"id":"b","text":"كلاهما صحيح: ذَهَبْنَ لهنّ، وذَهَبْنَا لنحن"},{"id":"c","text":"الصّواب عكس التّصريفين"},{"id":"d","text":"ذَهَبْنَ خاصّة بنحن لا بهنّ"}]'::jsonb, 'b', 'التّصريفان صحيحان: «ذَهَبْنَ» بنون النّسوة الخاصّة بجمع الغائبات (هنّ)، و«ذَهَبْنَا» بنا الفاعلين الخاصّة بالمتكلّمين (نحن)، ولا يجوز الخلط بينهما.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('b1b87758-45e7-5e72-88ed-888e177473c7', 'a3db2a72-6dbf-5595-a8ae-bc36e245b207', 'arabic-7eme', '👑 تحدّي النخبة ⭐⭐⭐⭐: قمّة تصريف الفعل المجرّد السّالم', 4, 300, 60, 'challenge', 'admin', 6)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
