  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('fbc94a05-11e6-593c-abfe-6d511ce4ab88', 'b1b87758-45e7-5e72-88ed-888e177473c7', 'الفعل «حَسُنَ» سالم على وزن فَعُلَ. صرّفه في الماضي والمضارع المرفوع معًا مع ضمير «هم»:', '[{"id":"a","text":"حَسُنُوا — يَحْسَنُونَ"},{"id":"b","text":"حَسِنُوا — يَحْسُنُونَ"},{"id":"c","text":"حَسُنُوا — يَحْسُنُونَ"},{"id":"d","text":"حَسُنَ — يَحْسُنُ"}]'::jsonb, 'c', 'مع «هم» يتّصل الماضي بواو الجماعة: حَسُنُوا، والمضارع يبدأ بياء الجماعة مع واو ونون الرّفع: يَحْسُنُونَ (فَعُلَ ثابت الضّمّ في مضارعه).', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f9f15d13-e73c-5f41-b606-28b8ada683c5', 'b1b87758-45e7-5e72-88ed-888e177473c7', 'أيّ العبارات التّالية عن تصريف الثّلاثيّ المجرّد السّالم خاطئة؟', '[{"id":"a","text":"يُبنى الماضي على الفتح إذا اتّصل بواو الجماعة"},{"id":"b","text":"يُبنى الماضي على الفتح إذا لم يتّصل بشيء أو اتّصل بألف الاثنين"},{"id":"c","text":"تُسكّن نون النّسوة وتاء الفاعل آخر الفعل الماضي"},{"id":"d","text":"وزن فَعُلَ وحده ثابت ضمّ عين المضارع"}]'::jsonb, 'a', 'الفعل الماضي يُبنى على الضّمّ لا الفتح عند اتّصاله بواو الجماعة (كَتَبُوا)؛ العبارات الثّلاث الأخرى صحيحة تمامًا.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('94bad37d-f9a9-53f0-a19c-aa0234718490', 'b1b87758-45e7-5e72-88ed-888e177473c7', 'كتب تلميذ: «العمّالُ حَفَرُوا الأرضَ، والتّلميذةُ فَهِمَتِ الدّرسَ، والفلاّحاتُ حَصَدُوا القمحَ». في أيّ فعل الخطأ التّصريفيّ، ولماذا؟', '[{"id":"a","text":"لا خطأ في الجملة"},{"id":"b","text":"الخطأ في «حَفَرُوا»، والصّواب حَفَرْنَ"},{"id":"c","text":"الخطأ في «فَهِمَتِ»، والصّواب فَهِمُوا"},{"id":"d","text":"الخطأ في «حَصَدُوا»، والصّواب حَصَدْنَ لأنّ الفاعل جمع مؤنّث غائب"}]'::jsonb, 'd', '«الفلاّحاتُ» جمع تكسير لمؤنّث غائب، فيلزمه نون النّسوة لا واو الجماعة: الصّواب «حَصَدْنَ»؛ أمّا «حَفَرُوا» (العمّالُ، جمع مذكّر) و«فَهِمَتِ» (التّلميذةُ، مفرد مؤنّث) فصحيحان.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e7301c47-b408-5331-9b3f-2c000b865881', 'b1b87758-45e7-5e72-88ed-888e177473c7', 'حوّل «سَمِعْنَ» (الفلاّحاتُ سَمِعْنَ النّداءَ) إلى المضارع المرفوع مع إبقاء الفاعل نفسه (جمع المؤنّث الغائب):', '[{"id":"a","text":"تَسْمَعُونَ"},{"id":"b","text":"يَسْمَعْنَ"},{"id":"c","text":"تَسْمَعْنَ"},{"id":"d","text":"يَسْمَعُونَ"}]'::jsonb, 'b', 'جمع الغائبات المؤنّثات «هنّ» يقابله في المضارع صيغة تبدأ بياء المضارعة وتنتهي بنون النّسوة: «يَسْمَعْنَ» (وليس تاء المخاطبة لأنّ الفاعل غائب لا مخاطب).', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ebecff86-5322-5433-8b31-4c0ec64731b3', 'b1b87758-45e7-5e72-88ed-888e177473c7', 'انظر إلى الأفعال: «سَهُلَ، ضَرَبَ، فَهِمَ». أيّ ترتيب صحيح لأوزانها الثّلاثة على التّوالي؟', '[{"id":"a","text":"فَعَلَ — فَعِلَ — فَعُلَ"},{"id":"b","text":"فَعِلَ — فَعُلَ — فَعَلَ"},{"id":"c","text":"فَعُلَ — فَعَلَ — فَعِلَ"},{"id":"d","text":"فَعُلَ — فَعِلَ — فَعَلَ"}]'::jsonb, 'c', '«سَهُلَ» عينه مضمومة (فَعُلَ)، «ضَرَبَ» عينه مفتوحة (فَعَلَ)، «فَهِمَ» عينه مكسورة (فَعِلَ)؛ فالتّرتيب الصّحيح فَعُلَ - فَعَلَ - فَعِلَ.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b1495e1e-5eeb-56f5-85f9-ab6b6a8ac9f7', 'b1b87758-45e7-5e72-88ed-888e177473c7', 'الصّيغة «يَقْرُبْنَ» في المضارع: ما ضميرها المناسب، وما وزن الفعل وصورته في الماضي معه؟', '[{"id":"a","text":"الضّمير أنتنّ، والفعل «قَرُبَ» على وزن فَعَلَ، وماضيه معها «قَرُبْتُنَّ»"},{"id":"b","text":"الضّمير هنّ، والفعل «قَرُبَ» على وزن فَعُلَ، وماضيه معها «قَرُبْنَ»"},{"id":"c","text":"الضّمير هم، والفعل «قَرُبَ» على وزن فَعِلَ، وماضيه معها «قَرُبُوا»"},{"id":"d","text":"الضّمير هنّ، والفعل «قَرِبَ» على وزن فَعِلَ، وماضيه معها «قَرِبْنَ»"}]'::jsonb, 'b', '«يَقْرُبْنَ» صيغة مضارع بياء المضارعة ونون النّسوة، فضميرها «هنّ» (غائبات لا مخاطبات)؛ والفعل «قَرُبَ» عينه مضمومة فوزنه فَعُلَ، وماضيه معها «قَرُبْنَ» بنون النّسوة المسكّنة لآخره.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('efdbfbcc-b9e0-5577-bdcf-3dd3172543ee', '62bf5b1e-1bd3-5f9b-81f7-aa94e6add020', 'arabic-7eme', 'اختبار فهم الدرس ⭐', 1, 20, 5, 'quiz', 'admin', 0)
