INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('bae6d3d3-1390-594c-a5a7-6d2e7096d150', 'efdbfbcc-b9e0-5577-bdcf-3dd3172543ee', 'المصدر اسمٌ يدلّ على:', '[{"id":"a","text":"الحدث نفسه، مجرّدًا من الزّمن"},{"id":"b","text":"من قام بالحدث"},{"id":"c","text":"من وقع عليه الحدث"},{"id":"d","text":"صفة ثابتة لازمة في صاحبها"}]'::jsonb, 'a', 'المصدر يسمّي الحدث وحده دون ارتباطٍ بزمنٍ ماضٍ أو مضارع أو أمر، خلافًا لاسم الفاعل واسم المفعول والصّفة المشبّهة.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f711d10a-cb47-5181-bbf3-b7d3e5bad24d', 'efdbfbcc-b9e0-5577-bdcf-3dd3172543ee', 'اسم الفاعل من الفعل «دَرَسَ» هو:', '[{"id":"a","text":"دُروس"},{"id":"b","text":"مَدْروس"},{"id":"c","text":"دَارِس"},{"id":"d","text":"دَرْس"}]'::jsonb, 'c', 'اسم الفاعل من الثّلاثيّ المجرّد يُصاغ دائمًا على وزن فاعِل، فمن «دَرَسَ» يكون «دَارِس»، أي من قام بالدّراسة.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5c95d5bb-f3cc-5caa-bf3b-8587eaf790ef', 'efdbfbcc-b9e0-5577-bdcf-3dd3172543ee', 'اسم المفعول من الفعل «فَتَحَ» هو:', '[{"id":"a","text":"فَاتِح"},{"id":"b","text":"فُتوح"},{"id":"c","text":"فَتْح"},{"id":"d","text":"مَفْتوح"}]'::jsonb, 'd', 'اسم المفعول من الثّلاثيّ المجرّد يُصاغ دائمًا على وزن مَفْعول، فمن «فَتَحَ» يكون «مَفْتوح»، أي ما وقع عليه الفتح.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('782ff5a9-4ea4-5ecc-881e-0eb4e87f7171', 'efdbfbcc-b9e0-5577-bdcf-3dd3172543ee', 'الصّفة المشبّهة تدلّ على:', '[{"id":"a","text":"حدثٍ وقع في الماضي فقط"},{"id":"b","text":"صفةٍ ثابتة لازمة في صاحبها"},{"id":"c","text":"من وقع عليه الحدث"},{"id":"d","text":"الحدث مجرّدًا من الزّمن"}]'::jsonb, 'b', 'الصّفة المشبّهة، خلافًا لاسم الفاعل، لا تدلّ على حدثٍ عارض بل على صفةٍ ثابتة أو لازمة في صاحبها، مثل العطش والغضب والألوان.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5537af9b-cc57-5321-9a2c-a6d99aa8852f', 'efdbfbcc-b9e0-5577-bdcf-3dd3172543ee', 'الكلمة «عَطْشان» في قولنا «الولدُ عَطْشانُ» هي:', '[{"id":"a","text":"مصدر"},{"id":"b","text":"اسم فاعل"},{"id":"c","text":"اسم مفعول"},{"id":"d","text":"صفة مشبّهة"}]'::jsonb, 'd', '«عَطْشان» على وزن فَعْلان تدلّ على صفةٍ ثابتة لازمة في صاحبها (العطش)، فهي صفة مشبّهة، لا اسم فاعلٍ يدلّ على حدثٍ عارض.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

