INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2d3031aa-b345-5d17-baa7-bd77dda4d22e', 'd0ffe55d-ad48-5ac2-9a80-9a22c66b8ef9', 'اسم الفاعل اسمٌ مشتقّ يدلّ على:', '[{"id":"a","text":"من قام بالحدث"},{"id":"b","text":"الحدث نفسه مجرّدًا من الزّمن"},{"id":"c","text":"من وقع عليه الحدث"},{"id":"d","text":"صفة ثابتة لازمة في صاحبها"}]'::jsonb, 'a', 'اسم الفاعل يدلّ على من قام بالحدث أو اتّصف به، خلافًا للمصدر الذي يسمّي الحدث وحده.', 1)
