INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('155d5bac-a974-56c1-9e5b-19a102011b19', 'd0ffe55d-ad48-5ac2-9a80-9a22c66b8ef9', 'وزن اسم الفاعل من الفعل الثّلاثيّ المجرّد هو:', '[{"id":"a","text":"مَفْعول"},{"id":"b","text":"فَعِيل"},{"id":"c","text":"مِفْعال"},{"id":"d","text":"فاعِل"}]'::jsonb, 'd', 'اسم الفاعل من الثّلاثيّ المجرّد يُصاغ دائمًا على وزنٍ ثابتٍ واحد هو فاعِل، مهما كان وزن الفعل نفسه.', 2)
