INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c1070413-a025-5c6f-b7aa-a7433f1894de', 'd0ffe55d-ad48-5ac2-9a80-9a22c66b8ef9', 'اسم الفاعل من الفعل «لَعِبَ» هو:', '[{"id":"a","text":"لَعِب"},{"id":"b","text":"لاعِب"},{"id":"c","text":"مَلْعوب"},{"id":"d","text":"لُعوب"}]'::jsonb, 'b', 'على وزن فاعِل، اسم الفاعل من «لَعِبَ» هو «لاعِب»، أي من قام باللّعب.', 3)
