INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('89a96365-6a7f-5ce7-80e9-426378794247', 'd0ffe55d-ad48-5ac2-9a80-9a22c66b8ef9', 'أيّ الكلمات التّالية صفة مشبّهة؟', '[{"id":"a","text":"كاتِب"},{"id":"b","text":"كِتابة"},{"id":"c","text":"عَطْشان"},{"id":"d","text":"مَفْتوح"}]'::jsonb, 'c', '«عَطْشان» على وزن فَعْلان تدلّ على صفةٍ ثابتة لازمة في صاحبها (العطش)، فهي صفة مشبّهة؛ أمّا الباقي فاسم فاعل ومصدر واسم مفعول.', 6)
