INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7f8e3b89-2f06-5e3f-a505-5e9ed52b6248', 'ad20fb51-9a4e-50f9-824d-071e1d48f7e1', 'مصدر الفعل «سَبَقَ» هو «سِباق». على أيّ وزنٍ جاء هذا المصدر؟', '[{"id":"a","text":"فِعال"},{"id":"b","text":"فَعْل"},{"id":"c","text":"فُعول"},{"id":"d","text":"فَعيل"}]'::jsonb, 'a', '«سِباق» على وزن فِعال، وهو من أشيع أوزان المصدر السّماعيّة في الثّلاثيّ المجرّد.', 1)
