INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9cd1e3b2-44e7-53fb-97e0-24e37d558cb9', 'ad20fb51-9a4e-50f9-824d-071e1d48f7e1', 'أيّ الأفعال التّالية لا اسم مفعولٍ صحيحٍ له بدلالته المعتادة؟', '[{"id":"a","text":"كَتَبَ"},{"id":"b","text":"فَتَحَ"},{"id":"c","text":"ذَهَبَ"},{"id":"d","text":"حَمَلَ"}]'::jsonb, 'c', '«ذَهَبَ» فعلٌ لازم لا مفعول به له، فلا اسم مفعول له بدلالته المعتادة؛ أمّا الأفعال الثّلاثة الأخرى متعدّية، فلها اسم مفعولٍ سليم.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
