INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8169dbc3-0c02-56e1-bdb8-c21fd1f27b56', 'ad20fb51-9a4e-50f9-824d-071e1d48f7e1', '«الرّجلُ غَضْبانُ منذ الصّباح.» ما نوع الكلمة «غَضْبان» في هذه الجملة، ولماذا؟', '[{"id":"a","text":"اسم فاعل، لأنّها مشتقّة من فعل"},{"id":"b","text":"صفة مشبّهة، لأنّها تدلّ على حالةٍ ثابتة لا حدثًا عارضًا"},{"id":"c","text":"اسم مفعول، لأنّ الغضب وقع على الرّجل"},{"id":"d","text":"مصدر، لأنّها تسمّي حدث الغضب"}]'::jsonb, 'b', '«غَضْبان» على وزن فَعْلان تدلّ على صفةٍ ثابتة لازمة تصف صاحبها وصفًا مستقرًّا، لا على حدثٍ وقع مرّةً وانتهى، فهي صفة مشبّهة لا اسم فاعل.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e56957c8-0098-54d7-9a27-c096310d9dbf', 'ad20fb51-9a4e-50f9-824d-071e1d48f7e1', 'اشتقّ تلميذ من الفعل «طَلَبَ» اسم مفعولٍ فكتب «طالِب». أين الخطأ في اشتقاقه؟', '[{"id":"a","text":"لا خطأ، فـ«طالِب» اسم مفعول صحيح"},{"id":"b","text":"الخطأ أنّ الفعل «طَلَبَ» لازمٌ لا اسم مفعول له"},{"id":"c","text":"الصّواب الاكتفاء بالمصدر «طَلَب» بلا صيغةٍ اسميّة أخرى"},{"id":"d","text":"الخطأ أنّ «طالِب» اسم فاعل على وزن فاعِل، والصّواب اسم المفعول «مَطْلوب» على وزن مَفْعول"}]'::jsonb, 'd', '«طالِب» على وزن فاعِل هو اسم الفاعل من «طَلَبَ» (من قام بالطّلب)، لا اسم المفعول؛ اسم المفعول الصّحيح هو «مَطْلوب» على وزن مَفْعول (ما وقع عليه الطّلب).', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('08cc38d6-b86a-50be-b6b9-66e2be6a3cbb', 'ad20fb51-9a4e-50f9-824d-071e1d48f7e1', 'الفعلان «فَرِحَ» و«فَتَحَ» يختلف وزنهما (فَعِلَ وفَعَلَ)، لكنّ اسم الفاعل منهما (فارِح، فاتِح) يشترك في الوزن نفسه. لماذا؟', '[{"id":"a","text":"لأنّ وزن اسم الفاعل من الثّلاثيّ المجرّد ثابتٌ دائمًا (فاعِل)، بصرف النّظر عن وزن الفعل"},{"id":"b","text":"لأنّ الفعلين متماثلان في المعنى"},{"id":"c","text":"لأنّ اسم الفاعل يتبع وزن المصدر لا وزن الفعل"},{"id":"d","text":"هذا خطأ، فوزن اسمَي الفاعل مختلفٌ فعلًا"}]'::jsonb, 'a', 'خلافًا للمصدر المتعدّد الأوزان، اسم الفاعل من الثّلاثيّ المجرّد يُصاغ دائمًا على وزنٍ ثابتٍ واحد هو فاعِل، مهما اختلف وزن الفعل نفسه (فَعَلَ، فَعِلَ، فَعُلَ).', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('54ffcf29-adba-5f23-951a-4444b50f1829', 'ad20fb51-9a4e-50f9-824d-071e1d48f7e1', 'أيّ العبارات التّالية عن المشتقّات الأربعة صحيحة؟', '[{"id":"a","text":"المصدر يدلّ على من قام بالحدث"},{"id":"b","text":"اسم المفعول يُشتقّ من كلّ فعلٍ لازمٍ ومتعدٍّ على السّواء"},{"id":"c","text":"الصّفة المشبّهة تدلّ على صفةٍ ثابتة لا حدثًا متجدّدًا"},{"id":"d","text":"اسم الفاعل من الثّلاثيّ المجرّد يختلف وزنه باختلاف وزن الفعل"}]'::jsonb, 'c', 'الصّفة المشبّهة وحدها تدلّ على صفةٍ ثابتة لازمة؛ أمّا المصدر فيدلّ على الحدث لا الفاعل، واسم المفعول لا يُشتقّ من اللاّزم، واسم الفاعل وزنه فاعِل ثابت لا يتغيّر.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

