  ('0bca561a-8973-5c05-9a61-431b405d3790', '62bf5b1e-1bd3-5f9b-81f7-aa94e6add020', 'arabic-7eme', '⭐⭐ تمرين مراجعة (نمط امتحان): الاشتقاق من الثّلاثيّ المجرّد', 2, 70, 15, 'practice', 'admin', 3)
