INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('12119d60-ce2d-5986-b9af-581627b1c2de', '0bca561a-8973-5c05-9a61-431b405d3790', 'اسم المفعول اسمٌ مشتقّ يدلّ على:', '[{"id":"a","text":"من قام بالحدث"},{"id":"b","text":"من وقع عليه الحدث"},{"id":"c","text":"الحدث نفسه مجرّدًا من الزّمن"},{"id":"d","text":"صفة ثابتة لازمة في صاحبها"}]'::jsonb, 'b', 'اسم المفعول يدلّ على من وقع عليه الحدث، أي الّذي أصابه فعل الفاعل.', 1)
ON CONFLICT (id) DO UPDATE SET
