INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0507b770-5ff9-5d9f-b1d5-3d4d7574bb65', '0bca561a-8973-5c05-9a61-431b405d3790', 'مصدر الفعل «جَلَسَ» هو «جُلوس»، وهو على وزن:', '[{"id":"a","text":"فَعْل"},{"id":"b","text":"فِعال"},{"id":"c","text":"فُعول"},{"id":"d","text":"فَعيل"}]'::jsonb, 'c', '«جُلوس» على وزن فُعول، وهو من أشيع أوزان مصدر الثّلاثيّ المجرّد.', 2)
ON CONFLICT (id) DO UPDATE SET
