INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7f1d6a42-f9f9-5d2d-b612-48684be6f286', '0bca561a-8973-5c05-9a61-431b405d3790', 'الصّفة المشبّهة من الفعل «حَمِرَ» هي:', '[{"id":"a","text":"حامِر"},{"id":"b","text":"مَحْمور"},{"id":"c","text":"حَمْر"},{"id":"d","text":"أَحْمَر"}]'::jsonb, 'd', 'من أوزان الصّفة المشبّهة الشّائعة وزن أَفْعَل، ومنه «أَحْمَر» من «حَمِرَ»، يدلّ على صفةٍ ثابتة (اللّون).', 3)
