INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0891d237-d95c-55c1-99e4-7b7d553e9d44', '0bca561a-8973-5c05-9a61-431b405d3790', 'اسم الفاعل من الفعل «سَمِعَ» هو:', '[{"id":"a","text":"سامِع"},{"id":"b","text":"مَسْموع"},{"id":"c","text":"سَمْع"},{"id":"d","text":"سَميع"}]'::jsonb, 'a', 'على وزن فاعِل، اسم الفاعل من «سَمِعَ» هو «سامِع»، أي من قام بالسّماع.', 4)
