INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b5b61169-a046-5827-9e48-2ea939f10419', '0bca561a-8973-5c05-9a61-431b405d3790', 'اسم المفعول من الفعل «حَفِظَ» هو:', '[{"id":"a","text":"حافِظ"},{"id":"b","text":"حِفْظ"},{"id":"c","text":"مَحْفوظ"},{"id":"d","text":"حَفيظ"}]'::jsonb, 'c', 'على وزن مَفْعول، اسم المفعول من «حَفِظَ» هو «مَحْفوظ»، أي ما وقع عليه الحفظ.', 5)
ON CONFLICT (id) DO UPDATE SET
