INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ded3061e-77f9-5146-9bfa-98f2dc02e6bb', '0bca561a-8973-5c05-9a61-431b405d3790', 'أيّ الأزواج التّالية (فعل ← مشتقّ) غير صحيحٍ في تصنيفه؟', '[{"id":"a","text":"دَرَسَ ← دارِس (اسم فاعل)"},{"id":"b","text":"سَمِعَ ← مَسْموع (اسم مفعول)"},{"id":"c","text":"عَطِشَ ← عَطْشان (صفة مشبّهة)"},{"id":"d","text":"خَرَجَ ← خُروج (اسم فاعل)"}]'::jsonb, 'd', '«خُروج» على وزن فُعول مصدرٌ يسمّي الحدث، لا اسم فاعل؛ اسم الفاعل من «خَرَجَ» هو «خارِج». الأزواج الثّلاثة الأخرى صحيحة التّصنيف.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('604708f0-64a8-5b17-8e62-100cec0fd8b9', '62bf5b1e-1bd3-5f9b-81f7-aa94e6add020', 'arabic-7eme', '👑 تحدّي النخبة ⭐⭐⭐⭐: إتقان الاشتقاق من الثّلاثيّ المجرّد', 4, 300, 60, 'challenge', 'admin', 4)
