INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('61303536-71db-5866-a57c-9fef03cd6e50', '604708f0-64a8-5b17-8e62-100cec0fd8b9', 'اشتقّ من الفعل «مَنَعَ» اسم الفاعل، ثمّ أنّثه بتاء التّأنيث:', '[{"id":"a","text":"مَمْنوع — مَمْنوعة"},{"id":"b","text":"مانِع — مانِعة"},{"id":"c","text":"مَنْع — مَنْعة"},{"id":"d","text":"مانِع — مَنّاعة"}]'::jsonb, 'b', 'اسم الفاعل من «مَنَعَ» على وزن فاعِل هو «مانِع»، ويؤنَّث بتاء التّأنيث فيصبح «مانِعة».', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('eebda336-a9aa-5122-9fc4-a02b146a19d4', '604708f0-64a8-5b17-8e62-100cec0fd8b9', 'في الجملة «الحارسُ الحَذِرُ حافظٌ على الأمن»، صنّف الكلمتين «الحَذِر» و«حافظ» صرفيًّا:', '[{"id":"a","text":"الحَذِر: اسم فاعل — حافظ: صفة مشبّهة"},{"id":"b","text":"كلاهما اسم فاعل"},{"id":"c","text":"الحَذِر: صفة مشبّهة (وزن فَعِل) — حافظ: اسم فاعل (وزن فاعِل)"},{"id":"d","text":"كلاهما صفة مشبّهة"}]'::jsonb, 'c', '«الحَذِر» من «حَذِرَ» على وزن فَعِل تدلّ على صفةٍ ثابتة لازمة (الحذر)، فهي صفة مشبّهة؛ و«حافظ» من «حَفِظَ» على وزن فاعِل يدلّ على من قام بالحفظ، فهو اسم فاعل.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c1e04ed7-4e92-5a27-9b97-c28f227e2f2f', '604708f0-64a8-5b17-8e62-100cec0fd8b9', 'اسم مفعولٍ على وزن مَفْعول معناه «ما وقع عليه الحفظ». ما الفعل الّذي اشتُقّ منه، وما اسم فاعله؟', '[{"id":"a","text":"الفعل فَهِمَ، واسم فاعله فاهِم"},{"id":"b","text":"الفعل حَمَلَ، واسم فاعله حامِل"},{"id":"c","text":"الفعل حَرَسَ، واسم فاعله حارِس"},{"id":"d","text":"الفعل حَفِظَ، واسم فاعله حافِظ"}]'::jsonb, 'd', 'اسم المفعول «مَحْفوظ» (ما وقع عليه الحفظ) مشتقٌّ من الفعل «حَفِظَ»، واسم فاعله على وزن فاعِل هو «حافِظ».', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e84c515d-300f-58ce-b4e6-bcf824105309', '604708f0-64a8-5b17-8e62-100cec0fd8b9', 'قال تلميذ: «مصدر فَتَحَ هو فاتِح، لأنّه يبدأ بالفاء مثل الفعل». صوّب هذا الخطأ.', '[{"id":"a","text":"الصّواب أنّه لا مصدر لهذا الفعل"},{"id":"b","text":"الصّواب أنّ «فاتِح» اسم فاعل لا مصدر، والمصدر الصّحيح «فَتْح»"},{"id":"c","text":"الصّواب أنّ «فاتِح» مصدر صحيح، والملاحظة غير مهمّة"},{"id":"d","text":"الصّواب أنّ كلّ مصدرٍ يجب أن يبدأ بميم"}]'::jsonb, 'b', '«فاتِح» على وزن فاعِل هو اسم الفاعل من «فَتَحَ» (من قام بالفتح)، لا المصدر؛ المصدر الصّحيح هو «فَتْح» على وزن فَعْل، يسمّي الحدث نفسه.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('83addbb1-c068-5166-9ef1-7bb5f5d69b82', '604708f0-64a8-5b17-8e62-100cec0fd8b9', 'أيّ العبارات التّالية عن اشتقاق الثّلاثيّ المجرّد **خاطئة**؟', '[{"id":"a","text":"وزن اسم الفاعل من الثّلاثيّ المجرّد ثابتٌ دائمًا (فاعِل)"},{"id":"b","text":"وزن اسم المفعول من الثّلاثيّ المجرّد ثابتٌ دائمًا (مَفْعول)"},{"id":"c","text":"وزن مصدر الثّلاثيّ المجرّد ثابتٌ لا يتغيّر مهما اختلف الفعل"},{"id":"d","text":"اسم المفعول يستلزم فعلًا متعدّيًا له مفعول به"}]'::jsonb, 'c', 'خلافًا لاسم الفاعل واسم المفعول، وزن المصدر سماعيٌّ غير ثابت (فَعْل، فِعال، فُعول وغيرها)؛ فالعبارة الخاطئة هي القول بثباته.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('60bbdbd3-0428-5852-b8b1-bf53aa08434b', '604708f0-64a8-5b17-8e62-100cec0fd8b9', 'الفعل «غَسَلَ» متعدٍّ (يتعدّى بنفسه: غَسَلَ الثّوبَ). اختر المجموعة الصّحيحة لثلاثة مشتقّاتٍ منه معًا: مصدره على وزن فَعْل، واسم فاعله، واسم مفعوله.', '[{"id":"a","text":"مصدر: غَسْل — اسم فاعل: غاسِل — اسم مفعول: مَغْسول"},{"id":"b","text":"مصدر: غُسول — اسم فاعل: غاسِل — اسم مفعول: مَغْسول"},{"id":"c","text":"مصدر: غَسْل — اسم فاعل: مَغْسول — اسم مفعول: غاسِل"},{"id":"d","text":"مصدر: غَسيل — اسم فاعل: غاسِل — اسم مفعول: مَغْسول"}]'::jsonb, 'a', 'المصدر على وزن فَعْل من «غَسَلَ» هو «غَسْل»، واسم الفاعل على وزن فاعِل «غاسِل»، واسم المفعول على وزن مَفْعول «مَغْسول»؛ الخيارات الأخرى تخلط الأوزان أو تعكس اسم الفاعل والمفعول.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

