  ('84aad506-8d2a-52a4-b1d1-44513d3e6f99', '62bf5b1e-1bd3-5f9b-81f7-aa94e6add020', 'arabic-7eme', '📝 تدريب ⭐⭐⭐: مراجعة شاملة للاشتقاق من الثّلاثيّ المجرّد', 3, 120, 30, 'boss', 'admin', 5)
