INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0214a1a4-9352-51f7-8cf3-23d0bfc8d2da', '84aad506-8d2a-52a4-b1d1-44513d3e6f99', 'مصدر الفعل «رَكِبَ» هو «رُكوب». على أيّ وزنٍ جاء؟', '[{"id":"a","text":"فَعْل"},{"id":"b","text":"فُعول"},{"id":"c","text":"فِعال"},{"id":"d","text":"فَعيل"}]'::jsonb, 'b', '«رُكوب» على وزن فُعول، وهو من أشيع أوزان مصدر الثّلاثيّ المجرّد.', 1)
