INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b3a68209-718a-59af-9fa4-46c402315d24', '84aad506-8d2a-52a4-b1d1-44513d3e6f99', 'اسم الفاعل من الفعل «طَبَخَ» هو:', '[{"id":"a","text":"طابِخ"},{"id":"b","text":"مَطْبوخ"},{"id":"c","text":"طَبْخ"},{"id":"d","text":"طَبّاخ"}]'::jsonb, 'a', 'على وزن فاعِل، اسم الفاعل من «طَبَخَ» هو «طابِخ»؛ أمّا «طَبّاخ» فصيغة مبالغة (المحترف بالطّبخ)، وزنٌ آخر غير اسم الفاعل المقرّر.', 2)
