INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e8f19841-6838-5527-a21c-2944773001bb', '84aad506-8d2a-52a4-b1d1-44513d3e6f99', 'اسم المفعول من الفعل «طَبَخَ» هو:', '[{"id":"a","text":"طابِخ"},{"id":"b","text":"طَبْخ"},{"id":"c","text":"طَبّاخ"},{"id":"d","text":"مَطْبوخ"}]'::jsonb, 'd', 'على وزن مَفْعول، اسم المفعول من «طَبَخَ» هو «مَطْبوخ»، أي ما وقع عليه الطّبخ.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('02d9af3a-b5cd-555b-af5a-d73189a3b96f', '84aad506-8d2a-52a4-b1d1-44513d3e6f99', 'الفعل «سَقَطَ» لازم. أيّ ممّا يلي **غير ممكنٍ** اشتقاقه منه بدلالته المعتادة؟', '[{"id":"a","text":"اسم المفعول: مَسْقوط"},{"id":"b","text":"المصدر: سُقوط"},{"id":"c","text":"اسم الفاعل: ساقِط"},{"id":"d","text":"الصّفة المشبّهة: ساقِط"}]'::jsonb, 'a', '«سَقَطَ» فعلٌ لازم لا مفعول به له، فلا معنى لاسم مفعولٍ منه بدلالته المعتادة؛ أمّا مصدره واسم فاعله فمشتقّان بلا إشكال.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('47e6826d-10bf-54e4-817a-442e89c17249', '84aad506-8d2a-52a4-b1d1-44513d3e6f99', 'في العبارة «الطّالبُ التَّعِبُ يستريحُ الآن، وواجباتُه مَحْفوظةٌ في الحقيبة»، حدّد نوع «التَّعِب» و«مَحْفوظة» صرفيًّا.', '[{"id":"a","text":"التَّعِب: اسم فاعل — مَحْفوظة: صفة مشبّهة"},{"id":"b","text":"التَّعِب: صفة مشبّهة (وزن فَعِل) — مَحْفوظة: اسم مفعول (وزن مَفْعول)"},{"id":"c","text":"كلاهما اسم مفعول"},{"id":"d","text":"كلاهما صفة مشبّهة"}]'::jsonb, 'b', '«التَّعِب» على وزن فَعِل تدلّ على صفةٍ ثابتة لازمة (التّعب)، فهي صفة مشبّهة؛ و«مَحْفوظة» على وزن مَفْعول (مؤنّثًا) تدلّ على ما وقع عليه الحفظ، فهي اسم مفعول.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e5863f73-0f7c-5f87-994b-c18cb976dd15', '84aad506-8d2a-52a4-b1d1-44513d3e6f99', 'أيّ العبارات التّالية عن أوزان المشتقّات الأربعة من الثّلاثيّ المجرّد صحيحة؟', '[{"id":"a","text":"وزن المصدر ثابتٌ واحدٌ لا يتعدّد"},{"id":"b","text":"الصّفة المشبّهة تُصاغ دائمًا من فعلٍ متعدٍّ"},{"id":"c","text":"اسم المفعول يُشتقّ من اللاّزم والمتعدّي معًا"},{"id":"d","text":"اسم الفاعل واسم المفعول وزناهما ثابتان (فاعِل ومَفْعول)، خلافًا للمصدر السّماعيّ المتعدّد الأوزان"}]'::jsonb, 'd', 'اسم الفاعل (فاعِل) واسم المفعول (مَفْعول) وزناهما ثابتان لكلّ الثّلاثيّ المجرّد؛ أمّا المصدر فسماعيّ متعدّد الأوزان، والصّفة المشبّهة تصاغ من اللاّزم غالبًا، واسم المفعول يستلزم فعلًا متعدّيًا.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('a8ddb541-b32a-5b60-8003-bd4dab9c8a55', '62bf5b1e-1bd3-5f9b-81f7-aa94e6add020', 'arabic-7eme', '👑 تحدّي النخبة ⭐⭐⭐⭐: قمّة الاشتقاق من الثّلاثيّ المجرّد', 4, 300, 60, 'challenge', 'admin', 6)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b53a264d-8eb5-5f30-bdd7-44decd6e380e', 'a8ddb541-b32a-5b60-8003-bd4dab9c8a55', 'اشتقّ من الفعل «قَطَعَ» مصدره على وزن فَعْل أوّلًا، ثمّ استنتج اسم فاعله من الفعل نفسه لا من المصدر.', '[{"id":"a","text":"قِطاع — قاطِع"},{"id":"b","text":"قَطْع — مَقْطوع"},{"id":"c","text":"قَطْع — قاطِع"},{"id":"d","text":"قُطوع — قاطِع"}]'::jsonb, 'c', 'مصدر «قَطَعَ» على وزن فَعْل هو «قَطْع»، واسم فاعله على وزن فاعِل هو «قاطِع» (وليس اسم مفعول مثل «مَقْطوع»).', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c9cfb7e0-2a2b-531b-a1ba-b0a07c186fac', 'a8ddb541-b32a-5b60-8003-bd4dab9c8a55', 'في الجملة «الفلاّحُ الحَذِرُ حارِسٌ على أرضه، وأدواتُه مَحْفوظةٌ في المخزن»، أيّ العبارات التّالية صحيحة في تصنيف «الحَذِر» و«حارِس» و«مَحْفوظة»؟', '[{"id":"a","text":"الثّلاثة اسم فاعل"},{"id":"b","text":"الحَذِر اسم فاعل، حارِس صفة مشبّهة، مَحْفوظة مصدر"},{"id":"c","text":"الثّلاثة صفة مشبّهة"},{"id":"d","text":"الحَذِر صفة مشبّهة، حارِس اسم فاعل، مَحْفوظة اسم مفعول"}]'::jsonb, 'd', '«الحَذِر» (وزن فَعِل) صفةٌ ثابتة لازمة فهي صفة مشبّهة؛ «حارِس» (وزن فاعِل) من قام بالحراسة فهو اسم فاعل؛ «مَحْفوظة» (وزن مَفْعول) ما وقع عليه الحفظ فهي اسم مفعول.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9dcee0c0-cc8c-5f7d-96a0-189282732acc', 'a8ddb541-b32a-5b60-8003-bd4dab9c8a55', 'كلمةٌ على وزن مَفْعول معناها «ما وقع عليه القطع»، وكلمةٌ أخرى على وزن فاعِل من الفعل نفسه. ما الفعل الأصل، وما مصدره على وزن فَعْل؟', '[{"id":"a","text":"الفعل حَرَسَ، ومصدره حَرْس"},{"id":"b","text":"الفعل قَطَعَ، ومصدره قَطْع"},{"id":"c","text":"الفعل زَرَعَ، ومصدره زَرْع"},{"id":"d","text":"الفعل قَطَعَ، ومصدره قِطاع"}]'::jsonb, 'b', '«ما وقع عليه القطع» هو اسم المفعول «مَقْطوع» من الفعل «قَطَعَ»، ومصدره على وزن فَعْل هو «قَطْع»؛ الخيارات الأخرى تُخطئ إمّا الفعل الأصل وإمّا وزن المصدر.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4b263ef5-9829-5e5a-8be3-d2b5b49fe15e', 'a8ddb541-b32a-5b60-8003-bd4dab9c8a55', 'حوّل الجملة «الأمُّ تَحْرُسُ أطفالَها» إلى جملةٍ تستعمل اسم الفاعل من الفعل نفسه بدل الفعل، مع إبقاء المعنى:', '[{"id":"a","text":"الأمُّ مَحْروسةٌ أطفالَها"},{"id":"b","text":"الأمُّ حارِسةٌ أطفالَها"},{"id":"c","text":"الأمُّ حِراسةٌ أطفالَها"},{"id":"d","text":"الأمُّ حَذِرةٌ أطفالَها"}]'::jsonb, 'b', 'اسم الفاعل من «حَرَسَ» على وزن فاعِل هو «حارِس»، ويؤنَّث «حارِسة»؛ فالتّحويل الصّحيح «الأمُّ حارِسةٌ أطفالَها»، محتفظًا بمعنى من قام بالحراسة.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2780f6f6-a2a2-5979-b522-1fb709907fbc', 'a8ddb541-b32a-5b60-8003-bd4dab9c8a55', 'ما الّذي يمنع اشتقاق اسم مفعولٍ ذي معنًى من الفعل «جَلَسَ»، رغم أنّ وزن مَفْعول صالحٌ صرفيًّا لتوليد صيغة «مَجْلوس»؟', '[{"id":"a","text":"لأنّ «جَلَسَ» فعلٌ معتلّ"},{"id":"b","text":"لأنّ وزن مَفْعول خاصٌّ بالأفعال الرّباعيّة فقط"},{"id":"c","text":"لأنّ «جَلَسَ» ليس له مصدر"},{"id":"d","text":"لأنّ «جَلَسَ» فعلٌ لازم لا مفعول به يقع عليه الحدث، فتغيب الدّلالة رغم صحّة الوزن صرفيًّا"}]'::jsonb, 'd', 'الوزن مَفْعول قالبٌ صرفيٌّ عامّ يمكن توليده شكليًّا من أيّ ثلاثيّ، لكنّ اسم المفعول لا يكون ذا معنًى إلاّ من فعلٍ متعدٍّ له مفعول به يقع عليه الحدث؛ و«جَلَسَ» لازم، فتغيب الدّلالة رغم صحّة الوزن.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9d3fe2df-52cc-5029-8316-049ac62dd959', 'a8ddb541-b32a-5b60-8003-bd4dab9c8a55', 'الفعل «سَمِعَ» متعدٍّ، ومصدره «سَمْع» على وزن فَعْل. اختر المجموعة الصّحيحة لاسم فاعله واسم مفعوله معًا:', '[{"id":"a","text":"اسم الفاعل: سامِع — اسم المفعول: مَسْموع"},{"id":"b","text":"اسم الفاعل: سَميع — اسم المفعول: مَسْموع"},{"id":"c","text":"اسم الفاعل: سامِع — اسم المفعول: سَميع"},{"id":"d","text":"اسم الفاعل: مَسْموع — اسم المفعول: سامِع"}]'::jsonb, 'a', 'اسم الفاعل من «سَمِعَ» على وزن فاعِل هو «سامِع»، واسم المفعول على وزن مَفْعول هو «مَسْموع»؛ «سَميع» صيغة مبالغة (كثير السّماع)، ليست اسم الفاعل ولا اسم المفعول القياسيّين.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

