INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('cdd7b98e-af4e-59a1-9964-07a568092390', '1a096533-3331-5635-89dc-4c4ab79a003e', 'أيّ الأفعال التّالية مضاعف؟', '[{"id":"a","text":"فَهِمَ"},{"id":"b","text":"شَدَّ"},{"id":"c","text":"قَرَأَ"},{"id":"d","text":"كَتَبَ"}]'::jsonb, 'b', '«شَدَّ» عينه ولامه (الدّال) من جنس واحد، فهو فعل مضاعف مدغم؛ أمّا فَهِمَ وكَتَبَ فسالمان، وقَرَأَ مهموز اللاّم.', 1)
ON CONFLICT (id) DO UPDATE SET
