INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('aab8276e-6850-54c4-885d-91a058076bb0', '1a096533-3331-5635-89dc-4c4ab79a003e', 'الفعل «أَخَذَ» مهموز الفاء لأنّ:', '[{"id":"a","text":"الهمزة وسط الفعل"},{"id":"b","text":"لا همزة فيه"},{"id":"c","text":"الهمزة أوّل حرف فيه"},{"id":"d","text":"الهمزة آخر حرف فيه"}]'::jsonb, 'c', 'الهمزة هي أوّل حرف أصليّ في «أَخَذَ» (أ-خ-ذ)، فهو مهموز الفاء.', 2)
ON CONFLICT (id) DO UPDATE SET
