INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('eddcbf4d-b3ca-568a-ab82-14e5ebd2d136', '1a096533-3331-5635-89dc-4c4ab79a003e', 'همزة الكلمة «إِذَا» في أوّلها مكتوبة:', '[{"id":"a","text":"على الألف من فوق"},{"id":"b","text":"تحت الألف"},{"id":"c","text":"على واو"},{"id":"d","text":"على ياء"}]'::jsonb, 'b', 'همزة أوّل الكلمة تُكتب دائمًا على الألف، تحتها إذا كانت مكسورة كما في «إِذَا».', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('43aeee3e-f18e-5585-b2c0-d04e08247cd0', '1a096533-3331-5635-89dc-4c4ab79a003e', 'لماذا فُكّ الإدغام في «مَدَدْتُ» بينما بقي في «مَدَّ»؟', '[{"id":"a","text":"لأنّ «مَدَدْتُ» صيغة أمر"},{"id":"b","text":"لأنّ الإدغام ممنوع في اللّغة العربيّة مطلقًا"},{"id":"c","text":"لا فرق بينهما، وكلاهما صحيح"},{"id":"d","text":"لأنّ تاء الفاعل تُسكّن آخر الفعل فيمتنع اجتماع ساكنين فيُفكّ الإدغام"}]'::jsonb, 'd', 'تاء الفاعل تُسكّن آخر الفعل الماضي، فيمتنع بقاء حرفين مدغمين ساكنين، فيُفكّ الإدغام: مَدَدْتُ.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5df7b276-499c-5eef-9a68-1bfbd28e2afc', '1a096533-3331-5635-89dc-4c4ab79a003e', 'همزة «قَرَأَ» المتطرّفة كُتبت على ألف لأنّ:', '[{"id":"a","text":"الحرف الّذي قبلها مفتوح"},{"id":"b","text":"الهمزة نفسها مفتوحة"},{"id":"c","text":"الحرف الّذي قبلها مضموم"},{"id":"d","text":"الحرف الّذي قبلها ساكن"}]'::jsonb, 'a', 'الهمزة المتطرّفة تُكتب حسب حركة ما قبلها فقط، وما قبل همزة «قَرَأَ» مفتوح (الرّاء)، فكُتبت على ألف.', 5)
