INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a7001590-3e63-5d62-abef-309c6eee8804', '17f528e7-816e-540f-9e3a-3e8c365d7dc2', '«حَبَّ» مع ضمير «أنتَ» يصبح:', '[{"id":"a","text":"حَبَبْتَ"},{"id":"b","text":"حَبَّ"},{"id":"c","text":"حَبَّتَ"},{"id":"d","text":"حَبُّوا"}]'::jsonb, 'a', 'مع «أنتَ» تتّصل تاء الفاعل المتحرّكة فتُسكّن آخر الفعل، فيمتنع الإدغام ويجب فكّه: حَبَبْتَ.', 1)
