INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('27971771-99dc-5667-b0c9-831b3ad39c09', '17f528e7-816e-540f-9e3a-3e8c365d7dc2', 'كتب تلميذ «قَرّأ» بدل «قَرَأَ» ظانًّا أنّ الفعل مضاعف. أين خطؤه؟', '[{"id":"a","text":"لا خطأ في كتابته"},{"id":"b","text":"الفعل مضاعف فعلًا فلا خطأ"},{"id":"c","text":"الصّواب أن تُشدّد الرّاء دائمًا"},{"id":"d","text":"الفعل مهموز اللاّم لا مضاعف، والهمزة تُكتب حسب قاعدة الهمزة المتطرّفة لا الإدغام"}]'::jsonb, 'd', '«قَرَأَ» (ق-ر-أ) فعل مهموز اللاّم لا مضاعف؛ لا يوجد فيه حرفان متماثلان يُدغمان، بل همزة أصليّة تُكتب حسب قاعدة الهمزة المتطرّفة (بعد فتح: على ألف): قَرَأَ.', 4)
