INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0e500be2-f09e-5a47-9f05-60087ca3adfe', '584f420e-4c04-55b0-a4e2-49f14f4afbf8', 'أيّ العبارات التّالية عن رسم الهمزة صحيحة؟', '[{"id":"a","text":"الكسرة أضعف الحركات"},{"id":"b","text":"الهمزة المتطرّفة تُكتب حسب حركتها هي لا حركة ما قبلها"},{"id":"c","text":"الضّمّة أقوى من الكسرة دائمًا"},{"id":"d","text":"همزة أوّل الكلمة تُكتب دائمًا على ألف"}]'::jsonb, 'd', 'همزة أوّل الكلمة تُكتب دائمًا على ألف (فوقها أو تحتها)؛ الكسرة هي أقوى الحركات لا أضعفها، والمتطرّفة تتبع ما قبلها لا حركتها هي، والضّمّة أضعف من الكسرة.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('982a27ae-d70a-54ee-b8da-105ac7102912', '584f420e-4c04-55b0-a4e2-49f14f4afbf8', 'حدّد وزن ونوع الفعل «سَأَلَ» أوّلًا، ثمّ استنتج كيف تُرسم همزته:', '[{"id":"a","text":"مهموز العين؛ فتحة وفتحة فالأقوى الفتحة، فتُكتب على ألف"},{"id":"b","text":"مهموز الفاء؛ تُكتب على واو"},{"id":"c","text":"مضاعف؛ لا همزة فيه أصلًا"},{"id":"d","text":"مهموز اللاّم؛ تُكتب على السّطر"}]'::jsonb, 'a', '«سَأَلَ» (س-أ-ل) مهموز العين؛ حركة الهمزة فتحة وحركة ما قبلها (السّين) فتحة أيضًا، فالأقوى الفتحة، فتُكتب الهمزة على ألف: سَأَلَ.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6e4ad8df-02cd-5bee-978d-096492683733', '584f420e-4c04-55b0-a4e2-49f14f4afbf8', 'الفعل «حَقَّ» مضاعف، والفعل «مَلَأَ» مهموز اللاّم. أيّ العبارتين التّاليتين صحيحة معًا؟', '[{"id":"a","text":"مع «أنتِ»: حَقَّتِ (بقي الإدغام)، و«مَلَأَ» همزته فاء الفعل"},{"id":"b","text":"كلا الفعلين مضاعف"},{"id":"c","text":"مع «أنتِ»: حَقَقْتِ (فُكّ الإدغام)، و«مَلَأَ» همزته لام الفعل"},{"id":"d","text":"كلا الفعلين مهموز"}]'::jsonb, 'c', 'مع «أنتِ» تتّصل تاء الفاعل السّاكنة بـ«حَقَّ» فيجب فكّ إدغامه: حَقَقْتِ؛ و«مَلَأَ» (م-ل-أ) همزته آخر حرف أصليّ فهو مهموز اللاّم.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6d6e49d0-11df-5814-a074-148a737bbec1', '584f420e-4c04-55b0-a4e2-49f14f4afbf8', 'الفعلان «وَدَّ» (بمعنى أحبّ) و«وَعَدَ» يتشابهان في أوّل حرف (الواو)، لكنّهما مختلفان صرفيًّا. ما الفرق؟', '[{"id":"a","text":"كلاهما مضاعف"},{"id":"b","text":"كلاهما مهموز"},{"id":"c","text":"«وَدَّ» مضاعف (عينه ولامه من جنس واحد) و«وَعَدَ» سالم"},{"id":"d","text":"«وَدَّ» سالم و«وَعَدَ» مضاعف"}]'::jsonb, 'c', '«وَدَّ» عينه ولامه (الدّال) حرف واحد مكرّر فهو مضاعف، أمّا «وَعَدَ» فأحرفه الثّلاثة (و-ع-د) مختلفة بلا علّة ولا همزة ولا تضعيف فهو سالم؛ تشابه الحرف الأوّل لا يعني تشابه النّوع الصّرفيّ.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('77d3a3b4-45d0-5379-825b-91be32114d7e', '584f420e-4c04-55b0-a4e2-49f14f4afbf8', 'أيّ العبارات التّالية عن المضاعف والمهموز خاطئة؟', '[{"id":"a","text":"المضاعف عينه ولامه من جنس واحد"},{"id":"b","text":"المهموز أحد أحرفه الأصليّة همزة"},{"id":"c","text":"الإدغام يُفكّ مع تاء الفاعل ونون النّسوة"},{"id":"d","text":"كلّ فعل فيه همزة يكون مضاعفًا أيضًا"}]'::jsonb, 'd', 'وجود الهمزة لا يجعل الفعل مضاعفًا؛ المضاعف حالة مستقلّة تقوم على تماثل العين واللاّم، بينما المهموز يقوم على وجود همزة أصليّة، ولا يشترط اجتماعهما.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('a2405d0e-39c4-5c33-9819-1617d4ea891a', '97942395-0db3-57fb-b622-32910cb2f88b', 'arabic-7eme', '📝 تدريب ⭐⭐⭐: مراجعة شاملة للمضاعف والمهموز ورسم الهمزة', 3, 120, 30, 'boss', 'admin', 5)
