  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('79b94ab7-aeb9-59b8-8b96-193caba4d265', 'a2405d0e-39c4-5c33-9819-1617d4ea891a', 'أيّ ممّا يلي شرطٌ لازمٌ لكون الفعل مضاعفًا؟', '[{"id":"a","text":"أن يكون عينه ولامه من جنس واحد"},{"id":"b","text":"أن يحتوي على همزة"},{"id":"c","text":"أن يكون معتلّ الآخر"},{"id":"d","text":"أن يتّصل بتاء الفاعل دائمًا"}]'::jsonb, 'a', 'شرط المضاعف الوحيد هو تماثل العين واللاّم (الحرف الثّاني والثّالث)؛ لا علاقة له بوجود همزة أو حرف علّة أو نوع الضّمير المتّصل به.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4b2b9084-b871-5d25-8bdf-9472e7dd4a97', 'a2405d0e-39c4-5c33-9819-1617d4ea891a', '«حَبَّ» مع ضمير «هنّ» يصبح:', '[{"id":"a","text":"حَبَّتْ"},{"id":"b","text":"حَبُّوا"},{"id":"c","text":"حَبَبْنَ"},{"id":"d","text":"حَبَبْتُنَّ"}]'::jsonb, 'c', 'نون النّسوة (هنّ) تُسكّن آخر الفعل الماضي، فيمتنع الإدغام ويجب فكّه: حَبَبْنَ.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9de5a4fb-ce4f-539e-bfd9-39b4cabcab6d', 'a2405d0e-39c4-5c33-9819-1617d4ea891a', 'الفعلان «بَدَأَ» و«ابْتَدَأَ» كلاهما يحملان همزة في الموضع نفسه من الجذر (ب-د-أ). ما موضعها؟', '[{"id":"a","text":"الفاء"},{"id":"b","text":"العين"},{"id":"c","text":"لا موضع محدّد"},{"id":"d","text":"اللاّم"}]'::jsonb, 'd', 'همزة «بَدَأَ» آخر حرف أصليّ من الجذر (ب-د-أ)، فهي همزة اللاّم (مهموز اللاّم).', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('21afbd5c-a8fd-5298-8abf-7a9847503394', 'a2405d0e-39c4-5c33-9819-1617d4ea891a', 'لماذا يبقى الفعل «مَسَّ» (بمعنى لمس) مدغمًا مع «هو» بينما يُفكّ إدغامه مع «أنتَ»؟', '[{"id":"a","text":"لأنّ «مَسَّ» فعلٌ مختلف في الحالتين"},{"id":"b","text":"لأنّ اتّصاله بـ«هو» لا يُسكّن آخره، بخلاف اتّصاله بتاء الفاعل مع «أنتَ»"},{"id":"c","text":"لأنّ «هو» ضمير مبنيّ و«أنتَ» معرب"},{"id":"d","text":"لا فرق حقيقيّ، والقاعدة اختياريّة"}]'::jsonb, 'b', 'مع «هو» لا يتّصل بالفعل شيء يُسكّن آخره فيبقى مدغمًا (مَسَّ)، ومع «أنتَ» تتّصل تاء الفاعل السّاكنة فيجب فكّ الإدغام (مَسَسْتَ).', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ccd59330-828e-5877-9af6-50a7068e146a', 'a2405d0e-39c4-5c33-9819-1617d4ea891a', 'رتّب الكلمات التّالية حسب موضع الهمزة (فاء ثمّ عين ثمّ لام): سَأَلَ، قَرَأَ، أَخَذَ.', '[{"id":"a","text":"سَأَلَ - أَخَذَ - قَرَأَ"},{"id":"b","text":"أَخَذَ - سَأَلَ - قَرَأَ"},{"id":"c","text":"قَرَأَ - سَأَلَ - أَخَذَ"},{"id":"d","text":"أَخَذَ - قَرَأَ - سَأَلَ"}]'::jsonb, 'b', 'أَخَذَ مهموز الفاء (الهمزة أوّلًا)، سَأَلَ مهموز العين (وسطًا)، قَرَأَ مهموز اللاّم (آخرًا)؛ فالتّرتيب الصّحيح: أَخَذَ - سَأَلَ - قَرَأَ.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('81eb1020-965a-5c6c-86ea-ac3218debbf5', 'a2405d0e-39c4-5c33-9819-1617d4ea891a', 'الكلمات «قارِئ» و«لُؤْلُؤ» و«جُزْء»: ما القاعدة المشتركة الّتي تفسّر رسم همزة كلٍّ منها؟', '[{"id":"a","text":"جميعها همزات أوّل الكلمة"},{"id":"b","text":"جميعها همزات متوسّطة تتبع أقوى الحركتين"},{"id":"c","text":"الهمزة المتطرّفة تتبع حركة الحرف الّذي قبلها: مكسور فياء، مضموم فواو، ساكن فعلى السّطر"},{"id":"d","text":"لا قاعدة موحّدة تجمعها"}]'::jsonb, 'c', 'الهمزات الثّلاث متطرّفة، وتتبع حركة ما قبلها فقط: الرّاء في «قارِئ» مكسورة (ياء)، اللاّم في «لُؤْلُؤ» مضمومة (واو)، والزّاي في «جُزْء» ساكنة (على السّطر).', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

