  ('0b581367-28ea-57f5-82b3-d955ceed0735', '97942395-0db3-57fb-b622-32910cb2f88b', 'arabic-7eme', '👑 تحدّي النخبة ⭐⭐⭐⭐: قمّة المضاعف والمهموز ورسم الهمزة', 4, 300, 60, 'challenge', 'admin', 6)
