INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5a87b2b3-777d-56e9-8e9f-242bd74c72a2', '0b581367-28ea-57f5-82b3-d955ceed0735', 'الفعل «شَذَّ» (بمعنى خرج عن القاعدة): صنّفه، واذكر صورته الصّحيحة مع «نحن»:', '[{"id":"a","text":"مضاعف؛ شَذَذْنا"},{"id":"b","text":"مهموز؛ شَأَذْنا"},{"id":"c","text":"مضاعف؛ شَذَّنا"},{"id":"d","text":"سالم؛ شَذَذْنا"}]'::jsonb, 'a', '«شَذَّ» عينه ولامه (الذّال) من جنس واحد فهو مضاعف؛ ومع «نحن» تتّصل نا الفاعلين السّاكنة، فيجب فكّ الإدغام: شَذَذْنا.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3e5c9af3-3e97-5883-9614-2901c8f002c0', '0b581367-28ea-57f5-82b3-d955ceed0735', 'فعلٌ ماضٍ صورته مع «أنتم» هي «قَرَأْتُم». ما نوعه، وأين موضع همزته؟', '[{"id":"a","text":"مضاعف؛ همزته عينه"},{"id":"b","text":"مهموز؛ همزته لامه (آخر الجذر)"},{"id":"c","text":"مهموز؛ همزته فاؤه"},{"id":"d","text":"سالم؛ لا همزة أصليّة فيه"}]'::jsonb, 'b', 'الفعل «قَرَأَ» (ق-ر-أ) مهموز اللاّم لأنّ همزته آخر حرف أصليّ، وصورته مع «أنتم» «قَرَأْتُم».', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
