  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('86ffe34b-790e-5805-ac7b-2441d0bec482', '0b581367-28ea-57f5-82b3-d955ceed0735', 'في جملة «الطّلاّبُ سَأَلوا المعلّمَ ثمّ ردَّوا على أسئلته»، حدّد نوع الفعلين المسندين إلى «الطّلاّب»:', '[{"id":"a","text":"«سَأَلوا» سالم و«ردَّوا» مهموز"},{"id":"b","text":"كلاهما مضاعف"},{"id":"c","text":"كلاهما مهموز"},{"id":"d","text":"«سَأَلوا» مهموز العين و«ردَّوا» مضاعف"}]'::jsonb, 'd', '«سَأَلوا» من «سَأَلَ» مهموز العين (همزته وسط الجذر س-أ-ل)، و«ردَّوا» من «رَدَّ» مضاعف (عينه ولامه الدّال من جنس واحد).', 3)
