INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('747f249c-45d4-56dc-9524-028d36bc1582', '0b581367-28ea-57f5-82b3-d955ceed0735', 'لاحظ الكلمات: أَخَذَ (صحيحة) — سُؤِلَ (بدل سُئِلَ) — قَرَأَ (صحيحة). في أيّ كلمة خطأ إملائيّ، ولماذا؟', '[{"id":"a","text":"لا خطأ في أيّ كلمة"},{"id":"b","text":"الخطأ في «أَخَذَ»"},{"id":"c","text":"الخطأ في «سُؤِلَ»؛ الصّواب «سُئِلَ» لأنّ الكسرة (حركة الهمزة) أقوى من الضّمّة (ما قبلها) فتُكتب على ياء"},{"id":"d","text":"الخطأ في «قَرَأَ»؛ الصّواب أن تُكتب على واو"}]'::jsonb, 'c', 'في «سُئِلَ» حركة الهمزة كسرة وما قبلها ضمّة؛ الكسرة أقوى الحركات دائمًا فتُكتب الهمزة على ياء: سُئِلَ، لا على واو.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2e77a397-09cf-512f-90ff-72646bb35094', '0b581367-28ea-57f5-82b3-d955ceed0735', 'أيّ العبارات التّالية عن المضاعف والمهموز ورسم الهمزة صحيحة؟', '[{"id":"a","text":"الفعل المضاعف قد يكون مهموزًا في الوقت نفسه دائمًا"},{"id":"b","text":"الهمزة المتوسّطة تُكتب دائمًا على الحرف الموافق لحركتها هي وحدها بصرف النّظر عمّا قبلها"},{"id":"c","text":"الهمزة المتطرّفة تتبع حركة الحرف الّذي قبلها فقط، لا حركتها هي"},{"id":"d","text":"إدغام المضاعف يبقى في كلّ صور تصريفه بلا استثناء"}]'::jsonb, 'c', 'الهمزة المتطرّفة تُكتب حسب حركة ما قبلها فقط بصرف النّظر عن حركتها هي؛ أمّا العبارات الأخرى فخاطئة: المتوسّطة تقارن حركتها بحركة ما قبلها معًا، والإدغام يُفكّ مع بعض الضّمائر، والمضاعف ليس بالضّرورة مهموزًا.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('297f1c20-a730-50d4-8335-8c4a81ccbb9a', '77bf962a-cc7b-5251-abaa-dba374b6de38', 'arabic-7eme', 'اختبار فهم الدرس ⭐', 1, 20, 5, 'quiz', 'admin', 0)
