INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('46d9ce13-afed-5313-b8f5-18b8eb8d62fd', '297f1c20-a730-50d4-8335-8c4a81ccbb9a', 'الفعل المعتلّ هو فعل:', '[{"id":"a","text":"أحد أحرفه الأصليّة الثّلاثة حرف علّة (ا، و، ي)"},{"id":"b","text":"أحرفه الأصليّة أربعة أو أكثر"},{"id":"c","text":"خالٍ من حرف العلّة والهمزة معًا"},{"id":"d","text":"مضاعف الحرفين الثّاني والثّالث"}]'::jsonb, 'a', 'الفعل المعتلّ فعلٌ أحد أحرفه الأصليّة الثّلاثة حرف علّة، وأحرف العلّة ثلاثة: الألف والواو والياء.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6ac54874-d037-50a8-9fbb-6fefb0be7b22', '297f1c20-a730-50d4-8335-8c4a81ccbb9a', 'أيّ الأفعال التّالية مثال (معتلّ الفاء)؟', '[{"id":"a","text":"قالَ"},{"id":"b","text":"وَعَدَ"},{"id":"c","text":"دَعا"},{"id":"d","text":"رَوى"}]'::jsonb, 'b', '«وَعَدَ» جذره و ع د، فاؤه (الحرف الأوّل) حرف علّة، فهو مثال؛ أمّا قالَ فأجوف، ودَعا وروى معتلاّن في مواضع أخرى.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a6a95746-647d-556b-a6e6-34fe85ac7c81', '297f1c20-a730-50d4-8335-8c4a81ccbb9a', 'الفعل «باعَ» يُصنَّف:', '[{"id":"a","text":"مثال، لأنّ فاءه حرف علّة"},{"id":"b","text":"ناقص، لأنّ لامه حرف علّة"},{"id":"c","text":"أجوف، لأنّ عينه (الحرف الثّاني) حرف علّة"},{"id":"d","text":"لفيف، لأنّ فيه حرفَي علّة"}]'::jsonb, 'c', '«باعَ» جذره ب ي ع، عينه (الحرف الثّاني) حرف علّة (أصله بَيَعَ)، فهو أجوف.', 3)
ON CONFLICT (id) DO UPDATE SET
