INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('741616cd-ae06-5be9-bfe4-d77da958d66b', '297f1c20-a730-50d4-8335-8c4a81ccbb9a', 'أيّ الأفعال التّالية لفيف (فيه حرفا علّة معًا)؟', '[{"id":"a","text":"وَعَدَ (فاؤه فقط حرف علّة)"},{"id":"b","text":"وَفى (فاؤه ولامه حرفا علّة)"},{"id":"c","text":"قالَ (عينه فقط حرف علّة)"},{"id":"d","text":"رَمى (لامه فقط حرف علّة)"}]'::jsonb, 'b', '«وَفى» جذره و ف ي: فاؤه (و) ولامه (ي) حرفا علّة، وعينه (ف) صحيح، فهو لفيف؛ أمّا البقيّة ففيها حرف علّة واحد فقط.', 5)
ON CONFLICT (id) DO UPDATE SET
