INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a5cff859-bf43-5277-8a93-2dbbbc1c408e', '59617e23-1095-5e6c-b7cd-f27e797ad706', 'أحرف العلّة الثّلاثة التي يُصنَّف على أساسها الفعل معتلًّا هي:', '[{"id":"a","text":"الباء، التّاء، الثّاء"},{"id":"b","text":"الألف، الواو، الياء"},{"id":"c","text":"الهمزة، الألف، الواو"},{"id":"d","text":"الواو، الياء، النّون"}]'::jsonb, 'b', 'أحرف العلّة ثلاثة لا غير: الألف (ا)، والواو (و)، والياء (ي)؛ ووجود أحدها في الجذر يجعل الفعل معتلًّا.', 1)
