INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('de550a5a-af1b-55a3-8234-115d9874b9c6', '59617e23-1095-5e6c-b7cd-f27e797ad706', 'الفعل «يَسَرَ» يُصنَّف مثالًا لأنّ:', '[{"id":"a","text":"لامه (الحرف الثّالث) حرف علّة"},{"id":"b","text":"عينه (الحرف الثّاني) حرف علّة"},{"id":"c","text":"فاءه (الحرف الأوّل) حرف علّة"},{"id":"d","text":"فيه حرفا علّة معًا"}]'::jsonb, 'c', 'جذر «يَسَرَ» ي س ر، فاؤه (الحرف الأوّل) حرف علّة، وهذا هو تعريف المثال بالضّبط.', 2)
