INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('bdf921a4-75af-53e4-a546-cfa6af79955a', '59617e23-1095-5e6c-b7cd-f27e797ad706', 'الفعل «رَوى»: جذره ر و ي، فاؤه صحيح، وعينه ولامه حرفا علّة متجاوران. أيّ صنفٍ يناسبه؟', '[{"id":"a","text":"مثال"},{"id":"b","text":"لفيف مفروق"},{"id":"c","text":"أجوف"},{"id":"d","text":"لفيف مقرون"}]'::jsonb, 'd', 'حرفا العلّة في «رَوى» (العين والّلام) متجاوران بلا حرفٍ صحيح بينهما، فهو لفيف مقرون.', 5)
