  ('f0f1951b-3ec1-528b-a146-7a3738257dc2', '17f30f44-6f2d-5a55-a3b2-4fe26a011948', 'الفعل «صامَ» (جذره ص و م) يُصنَّف:', '[{"id":"a","text":"مثال"},{"id":"b","text":"أجوف"},{"id":"c","text":"ناقص"},{"id":"d","text":"لفيف مقرون"}]'::jsonb, 'b', 'عين «صامَ» (الحرف الثّاني، الواو) حرف علّة (أصله صَوَمَ)، فهو أجوف.', 1)
