  ('c0e319a6-3616-5f0d-ba70-ec2c88de8768', '17f30f44-6f2d-5a55-a3b2-4fe26a011948', 'الفعل «سَعى» (جذره س ع ي) يُصنَّف:', '[{"id":"a","text":"ناقص"},{"id":"b","text":"أجوف"},{"id":"c","text":"مثال"},{"id":"d","text":"لفيف مفروق"}]'::jsonb, 'a', 'لام «سَعى» (الحرف الثّالث، الياء) حرف علّة، فهو ناقص.', 2)
