INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d5a22db9-87af-54af-a8da-ad210e84ef67', '17f30f44-6f2d-5a55-a3b2-4fe26a011948', 'الفعلان «طَوى» و«وَقى» كلاهما فيه حرفا علّة، لكنّهما يختلفان في الصّنف. ما الفارق بينهما؟', '[{"id":"a","text":"لا فارق، كلاهما لفيف مقرون"},{"id":"b","text":"«طَوى» لفيف مقرون (عين ولام متجاوران)، و«وَقى» لفيف مفروق (فاء ولام يفصل بينهما العين الصّحيح)"},{"id":"c","text":"«طَوى» مثال، و«وَقى» أجوف"},{"id":"d","text":"الفارق في عدد الأحرف الأصليّة فقط"}]'::jsonb, 'b', '«طَوى» (ط و ي): عينه ولامه متجاوران فهو مقرون؛ «وَقى» (و ق ي): فاؤه ولامه معتلاّن ويفصل بينهما القاف الصّحيحة، فهو مفروق.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('925cd62a-e4a1-5720-ae64-9c4f4dbf648a', '17f30f44-6f2d-5a55-a3b2-4fe26a011948', 'صنّف تلميذ الفعل «خافَ» على أنّه ناقص لأنّ آخره يُنطق ممدودًا. أين الخطأ في تصنيفه؟', '[{"id":"a","text":"لا خطأ، فالتّصنيف صحيح"},{"id":"b","text":"الصّواب مثال، لأنّ فاءه حرف علّة"},{"id":"c","text":"الصّواب أجوف، لأنّ حرف العلّة في جذره (خ و ف) هو العين (الحرف الثّاني) لا اللام"},{"id":"d","text":"الصّواب لفيف، لأنّ فيه حرفَي علّة"}]'::jsonb, 'c', 'الخطأ الشّائع الحكم على الصّنف من مظهر الفعل لا من موقع الحرف في جذره؛ جذر «خافَ» خ و ف، حرف العلّة فيه هو العين (الحرف الثّاني)، فهو أجوف لا ناقص.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
