INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('fcf48efc-4d8a-595c-a032-50a76c892113', 'df9bfa0f-d822-5fa1-80ea-4da9a3e4f055', 'الفعل المعتلّ يُصنَّف بحسب:', '[{"id":"a","text":"موقع حرف العلّة من أحرفه الأصليّة الثّلاثة"},{"id":"b","text":"عدد أحرفه الأصليّة"},{"id":"c","text":"زمنه (ماضٍ أم مضارع)"},{"id":"d","text":"لزومه أو تعدّيه"}]'::jsonb, 'a', 'يُصنَّف الفعل المعتلّ بحسب موقع حرف العلّة في جذره: الفاء (مثال)، أو العين (أجوف)، أو اللام (ناقص)، أو موقعين معًا (لفيف).', 1)
