INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f121b481-f93c-5dfb-b2f0-e20fb2121227', 'df9bfa0f-d822-5fa1-80ea-4da9a3e4f055', 'الفعل «شَوى» (جذره ش و ي): عينه ولامه حرفا علّة متجاوران، وفاؤه صحيحة. أيّ صنفٍ يناسبه؟', '[{"id":"a","text":"لفيف مقرون"},{"id":"b","text":"لفيف مفروق"},{"id":"c","text":"ناقص"},{"id":"d","text":"أجوف"}]'::jsonb, 'a', 'حرفا العلّة (العين واللام) متجاوران بلا فاصل، فهو لفيف مقرون.', 5)
