INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1fa65295-6d88-51f3-b4bb-ecc51a4e7eec', 'df9bfa0f-d822-5fa1-80ea-4da9a3e4f055', 'الفعل «وَعى» (جذره و ع ي): فاؤه ولامه حرفا علّة، ويفصل بينهما العين الصّحيح. أيّ صنفٍ يناسبه؟', '[{"id":"a","text":"أجوف"},{"id":"b","text":"لفيف مفروق"},{"id":"c","text":"مثال"},{"id":"d","text":"لفيف مقرون"}]'::jsonb, 'b', 'حرفا العلّة (الفاء واللام) يفصل بينهما حرفٌ صحيح (العين)، فهو لفيف مفروق.', 6)
