INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('358c2c98-e58e-5151-a31b-35e348a4cfd3', 'cb7da75e-3ce9-5b02-957e-25f2aab173af', 'الفعل «عادَ» أصله «عَوَدَ» (من العودة). ما صنفه؟', '[{"id":"a","text":"أجوف، لأنّ عينه (الواو) حرف علّة"},{"id":"b","text":"مثال، لأنّ فاءه حرف علّة"},{"id":"c","text":"ناقص، لأنّ لامه حرف علّة"},{"id":"d","text":"لفيف مقرون"}]'::jsonb, 'a', 'أصل «عادَ» عَوَدَ: عينه (الحرف الثّاني، الواو) حرف علّة، فهو أجوف.', 1)
