INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7ff6ca1d-5906-5e44-b8ca-8ba83a7dc0a9', 'cb7da75e-3ce9-5b02-957e-25f2aab173af', 'أيّ العبارات التّالية عن أصناف الفعل المعتلّ صحيحة؟', '[{"id":"a","text":"الأجوف معتلّ الفاء، والمثال معتلّ العين"},{"id":"b","text":"اللّفيف المقرون فيه حرف علّة واحد فقط"},{"id":"c","text":"النّاقص معتلّ اللام، وحرف علّته يقع آخر الجذر"},{"id":"d","text":"كلّ فعل فيه ألف هو معتلّ الفاء حتمًا"}]'::jsonb, 'c', 'النّاقص معتلّ اللام (الحرف الثّالث والأخير من الجذر)، كما في دَعا ورَمى؛ أمّا العبارات الأخرى فتقلب التّعريفات أو تخطئ في شرط اللّفيف.', 3)
