INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('bacaec6a-5be9-51c0-ab4c-6fe017f6bcac', 'cb7da75e-3ce9-5b02-957e-25f2aab173af', 'صنّف تلميذ الفعل «قَوِيَ» (جذره ق و ي) على أنّه أجوف لوجود واوٍ في وسطه. أين الخطأ في هذا التّصنيف؟', '[{"id":"a","text":"لا خطأ، فالتّصنيف صحيح"},{"id":"b","text":"الصّواب مثال، لأنّ فاءه حرف علّة"},{"id":"c","text":"الصّواب ناقص فقط، لأنّ لامه حرف علّة"},{"id":"d","text":"الصّواب لفيف مقرون، لأنّ عينه (و) ولامه (ي) حرفا علّة متجاوران معًا، لا حرف علّة واحد"}]'::jsonb, 'd', 'الخطأ الشّائع الاكتفاء برصد حرف علّة واحد وإهمال الثّاني؛ في «قَوِيَ» حرفا العلّة (العين والّلام) موجودان معًا ومتجاوران، فوجب تصنيفه لفيفًا مقرونًا لا أجوف فقط.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4cf9b308-43e3-5f42-8db6-2bcffacc6212', 'cb7da75e-3ce9-5b02-957e-25f2aab173af', 'قارن بين «وَلِيَ» (جذره و ل ي) و«وَلَدَ» (جذره و ل د): لماذا يختلف صنفهما رغم بدئهما بالحرف نفسه؟', '[{"id":"a","text":"«وَلِيَ» لفيف مفروق (فاؤه ولامه حرفا علّة يفصل بينهما اللام الصّحيح)، و«وَلَدَ» مثال (فاؤه حرف علّة وحيد)"},{"id":"b","text":"لا فارق، كلاهما مثال"},{"id":"c","text":"«وَلِيَ» أجوف، و«وَلَدَ» ناقص"},{"id":"d","text":"الفارق في عدد أحرف الجذر لا في نوعها"}]'::jsonb, 'a', '«وَلِيَ» فاؤه (و) ولامه (ي) حرفا علّة، فهو لفيف مفروق؛ أمّا «وَلَدَ» فحرف العلّة فيه واحد فقط (الفاء)، فهو مثال، رغم اشتراكهما في الحرف الأوّل.', 5)
