INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('67db8fc5-b458-5a16-af25-027b6bbaa86f', '1cf271cb-f5a3-5079-bd59-9dc5c58e3670', 'أيّ العبارات التّالية عن أصناف الفعل المعتلّ الأربعة صحيحة؟', '[{"id":"a","text":"المثال معتلّ الفاء، والأجوف معتلّ العين، والنّاقص معتلّ اللام، واللّفيف فيه حرفا علّة"},{"id":"b","text":"الأجوف والنّاقص صنفٌ واحد لأنّ كليهما فيه ألف"},{"id":"c","text":"اللّفيف المفروق فيه العين واللام حرفا علّة"},{"id":"d","text":"المثال يكون حرف علّته في وسط الجذر دائمًا"}]'::jsonb, 'a', 'هذا الملخّص الدّقيق للأصناف الأربعة: المثال (فاء)، الأجوف (عين)، النّاقص (لام)، واللّفيف (حرفان معًا، مفروقًا كان أم مقرونًا).', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5049934d-0aba-55f7-ac51-937216225f7f', '1cf271cb-f5a3-5079-bd59-9dc5c58e3670', 'صنّف تلميذ الفعل «وَشى» (جذره و ش ي) على أنّه مثال فقط لأنّ أوّله واو. أين يكمن قصور هذا التّصنيف؟', '[{"id":"a","text":"لا قصور، فالتّصنيف كافٍ وصحيح"},{"id":"b","text":"الصّواب أجوف لا مثال"},{"id":"c","text":"التّصنيف ناقص: لام الفعل (الياء) حرف علّة أيضًا، فيجب تصنيفه لفيفًا مفروقًا لا مثالًا فقط"},{"id":"d","text":"الصّواب ناقص لا مثال"}]'::jsonb, 'c', 'التّلميذ رصد حرف العلّة الأوّل فقط وأغفل الثّاني؛ «وَشى» فاؤه (و) ولامه (ي) حرفا علّة معًا يفصل بينهما الشّين الصّحيحة، فهو لفيف مفروق لا مثال.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

