INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('226b8c11-784a-5f77-a989-cd80752cfc29', '424660f8-0ae2-5222-ab62-dd93de53907a', 'الفعل «نَسِيَ» (جذره ن س ي) يُصنَّف:', '[{"id":"a","text":"ناقص، لأنّ لامه (الياء) حرف علّة"},{"id":"b","text":"مثال"},{"id":"c","text":"أجوف"},{"id":"d","text":"لفيف مفروق"}]'::jsonb, 'a', 'لام «نَسِيَ» (الحرف الثّالث، الياء) حرف علّة وحيد، فهو ناقص.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a845c879-accb-561e-a8f9-0b0a122c5b22', '424660f8-0ae2-5222-ab62-dd93de53907a', 'الفعل «غَوى» (جذره غ و ي): فاؤه (الغين) صحيح، وعينه ولامه حرفا علّة. صنّفه:', '[{"id":"a","text":"لفيف مفروق"},{"id":"b","text":"لفيف مقرون"},{"id":"c","text":"ناقص"},{"id":"d","text":"أجوف"}]'::jsonb, 'b', 'عين «غَوى» ولامه (الواو والياء) متجاوران بلا فاصل، فهو لفيف مقرون.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c10539d5-bdac-59cd-8af7-e6b8429f02dd', '424660f8-0ae2-5222-ab62-dd93de53907a', '«دَعا الفلاّحُ جارَه، فوَعَدَه بالمساعدة، وفَهِمَ حاجتَه، ثمّ رَوى له قصّةً مشابهة.» أيّ فعلٍ من أفعال هذه الجملة مثال؟', '[{"id":"a","text":"دَعا"},{"id":"b","text":"فَهِمَ"},{"id":"c","text":"وَعَدَ"},{"id":"d","text":"رَوى"}]'::jsonb, 'c', '«وَعَدَ» فاؤه (الواو) حرف علّة وحيد، فهو مثال؛ أمّا «دَعا» فناقص، و«فَهِمَ» سالم، و«رَوى» لفيف مقرون.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('dbdbe5c5-fe64-5991-867e-58dc7a762a48', '424660f8-0ae2-5222-ab62-dd93de53907a', 'الفعلان «وَعى» و«وَعَدَ» يبدآن بالحرف نفسه (الواو)، لكنّهما ليسا من الصّنف نفسه. لماذا؟', '[{"id":"a","text":"لا فارق، فكلاهما لفيف"},{"id":"b","text":"«وَعَدَ» لفيف، و«وَعى» مثال"},{"id":"c","text":"كلاهما مثال لأنّهما يبدآن بالواو"},{"id":"d","text":"«وَعى» لفيف مفروق (فاؤه ولامه حرفا علّة)، و«وَعَدَ» مثال (فاؤه فقط حرف علّة)"}]'::jsonb, 'd', 'الحرف الأوّل المشترك لا يكفي للحكم؛ يجب فحص الجذر كاملًا: «وَعى» (و ع ي) فيه حرفا علّة (الفاء واللام)، أمّا «وَعَدَ» (و ع د) ففيه حرف علّة واحد (الفاء) فقط.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c09c1d72-d534-5dde-afaf-ec5c64401803', '424660f8-0ae2-5222-ab62-dd93de53907a', 'صنّف تلميذ ثلاثة أفعال: «قالَ = أجوف»، «رَمى = ناقص»، «رَوى = مثال». تصنيفان صحيحان وواحد خاطئ. أين الخطأ؟', '[{"id":"a","text":"الخطأ في تصنيف «رَوى»، وصوابه لفيف مقرون لا مثال"},{"id":"b","text":"الخطأ في تصنيف «قالَ»، وصوابه ناقص"},{"id":"c","text":"الخطأ في تصنيف «رَمى»، وصوابه أجوف"},{"id":"d","text":"لا خطأ في التّصنيفات الثّلاثة"}]'::jsonb, 'a', '«رَوى» (ر و ي): عينه ولامه (الواو والياء) حرفا علّة متجاوران، فهو لفيف مقرون، لا مثال؛ أمّا «قالَ» (أجوف) و«رَمى» (ناقص) فتصنيفهما صحيح.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e8951672-e779-5647-b8af-a7b25bc70fb7', '424660f8-0ae2-5222-ab62-dd93de53907a', 'أيّ العبارات التّالية عن أصناف الفعل المعتلّ صحيحة حصرًا؟', '[{"id":"a","text":"الأجوف والنّاقص يجتمعان دائمًا في الفعل نفسه"},{"id":"b","text":"قد يجتمع حرفا علّة متجاوران (لفيف مقرون) أو يفصل بينهما حرف صحيح (لفيف مفروق)، بينما يكتفي المثال والأجوف والنّاقص بحرف علّة واحد في موقع محدّد"},{"id":"c","text":"كلّ الأفعال المعتلّة فيها حرفا علّة على الأقل"},{"id":"d","text":"موقع حرف العلّة لا يؤثّر في تصنيف الفعل"}]'::jsonb, 'b', 'هذا هو التّمييز الدّقيق: المثال والأجوف والنّاقص فيها حرف علّة واحد بموقع محدّد (فاء/عين/لام)، أمّا اللّفيف وحده ففيه حرفا علّة، إمّا متجاوران (مقرون) أو مفصولان بحرفٍ صحيح (مفروق).', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

