  ('23288e2b-3808-5cd4-b82a-54a1b81bc1a3', '8bbdfcf3-9192-5cc9-a7ac-ce67acaca7fa', 'arabic-7eme', 'اختبار فهم الدرس ⭐', 1, 20, 5, 'quiz', 'admin', 0)
