INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('219c09d7-ba1d-57f2-9991-d57b532e19fb', '23288e2b-3808-5cd4-b82a-54a1b81bc1a3', 'الفعل الرّباعيّ المجرّد هو فعل:', '[{"id":"a","text":"أحرفه الأصليّة أربعة كلّها أصليّة بلا زيادة"},{"id":"b","text":"أحرفه الأصليّة ثلاثة زيد عليها حرف"},{"id":"c","text":"أحرفه الأصليّة أربعة أحدها زائد"},{"id":"d","text":"أحرفه الأصليّة ثلاثة أحدها حرف علّة"}]'::jsonb, 'a', 'الفعل الرّباعيّ المجرّد أحرفه الأصليّة أربعة كلّها أصليّة، بلا أيّ حرفٍ زائد عليها، على وزن فَعْلَلَ، مثل دَحْرَجَ.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('efd0318d-75c0-5e54-8e3c-6ae2d248145d', '23288e2b-3808-5cd4-b82a-54a1b81bc1a3', 'أيّ الأفعال التّالية رباعيّ مجرّد؟', '[{"id":"a","text":"أَخْرَجَ"},{"id":"b","text":"بَعْثَرَ"},{"id":"c","text":"عَلَّمَ"},{"id":"d","text":"تَعَاوَنَ"}]'::jsonb, 'b', '«بَعْثَرَ» جذره (ب ع ث ر) أربعة أحرفٍ كلّها أصليّة، فهو رباعيّ مجرّد؛ أمّا الأفعال الأخرى فثلاثيّةٌ زيد على أصلها حرفٌ أو أكثر.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
