INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0a95352c-9a94-53e1-9b03-d55a402e1a79', '23288e2b-3808-5cd4-b82a-54a1b81bc1a3', 'عدد الأحرف الزّائدة في وزن «أَفْعَلَ» هو:', '[{"id":"a","text":"حرفان"},{"id":"b","text":"لا زيادة فيه"},{"id":"c","text":"حرف واحد"},{"id":"d","text":"ثلاثة أحرف"}]'::jsonb, 'c', 'زيادة وزن أَفْعَلَ حرفٌ واحدٌ فقط، هو الهمزة في أوّل الفعل، مثل أَكْرَمَ من كَرُمَ.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
