  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('bc970c25-fb03-5fbc-8799-a1cc7eb6b581', '23288e2b-3808-5cd4-b82a-54a1b81bc1a3', 'أيّ الأفعال التّالية مثالٌ على التّعدية بزيادة الهمزة؟', '[{"id":"a","text":"عَلَّمَ"},{"id":"b","text":"تَعَاوَنَ"},{"id":"c","text":"دَحْرَجَ"},{"id":"d","text":"أَخْرَجَ"}]'::jsonb, 'd', '«أَخْرَجَ» فعلٌ متعدٍّ نتج عن زيادة همزةٍ على الفعل اللاّزم «خَرَجَ»؛ أمّا الأفعال الأخرى فليست أمثلةً على التّعدية بالهمزة.', 4)
