INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f6e6a735-54b5-5ae7-9a44-fcf0d7ba9728', '23288e2b-3808-5cd4-b82a-54a1b81bc1a3', 'جذر الفعل «تَعَاوَنَ» وعدد أحرفه الزّائدة هما:', '[{"id":"a","text":"ع و ن — حرفان"},{"id":"b","text":"ت ع ا و ن — لا زيادة فيه"},{"id":"c","text":"ع و ن — حرف واحد"},{"id":"d","text":"ع ا و ن — حرفان"}]'::jsonb, 'a', 'جذر «تَعَاوَنَ» ثلاثيٌّ (ع و ن)، وزيدت عليه التّاء في أوّله والألف بعد الفاء، أي حرفان، على وزن تَفَاعَلَ.', 5)
