INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('61677294-c063-57da-8761-395a76ea19c8', 'e3288318-5500-5c20-a535-2e51c76b17f8', 'الفعل الّذي جميع أحرفه الأربعة أصليّةٌ بلا أيّ زيادة يُسمّى:', '[{"id":"a","text":"ثلاثيًّا مجرّدًا"},{"id":"b","text":"رباعيًّا مجرّدًا"},{"id":"c","text":"ثلاثيًّا مزيدًا"},{"id":"d","text":"رباعيًّا مزيدًا"}]'::jsonb, 'b', 'الفعل الّذي أحرفه الأربعة كلّها أصليّة بلا زيادة يُسمّى رباعيًّا مجرّدًا، مثل زَلْزَلَ.', 1)
