INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4080201e-e703-5a9c-8263-d10fd5111048', 'e3288318-5500-5c20-a535-2e51c76b17f8', 'الفعل «عَلَّمَ» على وزن:', '[{"id":"a","text":"فَعَّلَ"},{"id":"b","text":"أَفْعَلَ"},{"id":"c","text":"تَفَاعَلَ"},{"id":"d","text":"فَعْلَلَ"}]'::jsonb, 'a', '«عَلَّمَ» أصله الثّلاثيّ «عَلِمَ»، ضُوعفت عينه، فهو على وزن فَعَّلَ.', 4)
