INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('219f290a-ce73-5675-a315-049973538647', 'e3288318-5500-5c20-a535-2e51c76b17f8', 'الفعل «تَعَاوَنَ» على وزن:', '[{"id":"a","text":"أَفْعَلَ"},{"id":"b","text":"فَعَّلَ"},{"id":"c","text":"تَفَاعَلَ"},{"id":"d","text":"فَعْلَلَ"}]'::jsonb, 'c', '«تَعَاوَنَ» أصله الثّلاثيّ (ع و ن)، زيدت عليه التّاء في أوّله والألف بعد الفاء، فهو على وزن تَفَاعَلَ.', 6)
