  ('7ebb4c46-409d-586b-94bd-7527d58bd9fd', '8bbdfcf3-9192-5cc9-a7ac-ce67acaca7fa', 'arabic-7eme', '⚔️ زعيم الفصل ⭐⭐⭐: اشتقاق الرّباعيّ المجرّد والمزيد', 3, 120, 30, 'boss', 'admin', 2)
