INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7e605dc2-e507-59d6-81de-29ed51705c7f', '7ebb4c46-409d-586b-94bd-7527d58bd9fd', 'جذر الفعل «بَعْثَرَ» هو:', '[{"id":"a","text":"ب ع ث (ثلاثة أحرف)"},{"id":"b","text":"ع ث ر (ثلاثة أحرف)"},{"id":"c","text":"ب ر (حرفان)"},{"id":"d","text":"ب ع ث ر (أربعة أحرف)"}]'::jsonb, 'd', '«بَعْثَرَ» رباعيّ مجرّد، جذره أربعة أحرفٍ أصليّة كاملة: ب ع ث ر.', 1)
