INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a2cc7343-2c26-5e0d-b959-194db8463ac1', '7ebb4c46-409d-586b-94bd-7527d58bd9fd', 'عدد الأحرف الزّائدة في الفعل «تَعَاوَنَ» هو:', '[{"id":"a","text":"حرفان"},{"id":"b","text":"حرف واحد"},{"id":"c","text":"ثلاثة أحرف"},{"id":"d","text":"لا زيادة فيه"}]'::jsonb, 'a', 'زيادة وزن تَفَاعَلَ حرفان: التّاء في أوّل الفعل، والألف بعد الفاء، كما في تَعَاوَنَ.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3de69e65-90ab-51be-90bf-cdaf11e9dcf7', '7ebb4c46-409d-586b-94bd-7527d58bd9fd', 'فعلٌ من أربعة أحرفَ، لكنّه ليس رباعيًّا مجرّدًا لأنّ أحد أحرفه زائدٌ على أصلٍ ثلاثيّ. أيّ الأفعال التّالية هو؟', '[{"id":"a","text":"دَحْرَجَ"},{"id":"b","text":"أَخْرَجَ"},{"id":"c","text":"بَعْثَرَ"},{"id":"d","text":"زَلْزَلَ"}]'::jsonb, 'b', '«أَخْرَجَ» من أربعة أحرفَ في الظّاهر، لكنّ أصله الثّلاثيّ «خَرَجَ» وزيدت عليه همزةٌ، فهو ثلاثيّ مزيد لا رباعيّ مجرّد؛ أمّا الأفعال الأخرى فرباعيّةٌ مجرّدةٌ حقًّا.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1d1b49f7-c4b3-5d0d-a015-562454d03fbc', '7ebb4c46-409d-586b-94bd-7527d58bd9fd', '«فَرِحَ» فعلٌ لازم. أيّ صيغةٍ منه تجعله متعدّيًا بزيادة الهمزة في أوّله تحديدًا؟', '[{"id":"a","text":"فَرَّحَ"},{"id":"b","text":"تَفَارَحَ"},{"id":"c","text":"أَفْرَحَ"},{"id":"d","text":"فَارَحَ"}]'::jsonb, 'c', 'زيادة الهمزة في أوّل الفعل اللاّزم «فَرِحَ» تعطي «أَفْرَحَ» المتعدّي (أَفْرَحَ الخبرُ الولدَ)؛ أمّا «فَرَّحَ» فتعديةٌ أخرى بالتّضعيف لا بالهمزة، والصّيغتان الأخريان غير مستعملتين.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('07cbff43-e1bd-5a8a-9eeb-f6a15b22cf24', '7ebb4c46-409d-586b-94bd-7527d58bd9fd', 'قال تلميذٌ: «الفعل أَخْرَجَ رباعيّ مجرّد لأنّه من أربعة أحرف». أين الخطأ في هذا الحكم؟', '[{"id":"a","text":"لا خطأ، الحكم صحيح"},{"id":"b","text":"الصّواب أنّه رباعيّ مزيد"},{"id":"c","text":"الصّواب أنّه ثلاثيّ مجرّد لأنّ جذره ثلاثة أحرف"},{"id":"d","text":"الصّواب أنّه ثلاثيّ مزيد لأنّ أصله الثّلاثيّ «خَرَجَ» زيدت عليه الهمزة"}]'::jsonb, 'd', 'عدد أحرف الكلمة وحده لا يحدّد نوع الفعل؛ العبرة بأصالة الأحرف: «أَخْرَجَ» أصله الثّلاثيّ خَرَجَ، زيدت عليه همزةٌ، فهو ثلاثيّ مزيد لا رباعيّ مجرّد.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6cf58604-1bdb-52f7-9480-6a89514c2edd', '7ebb4c46-409d-586b-94bd-7527d58bd9fd', 'ما وزن الفعل «زَلْزَلَ» وعدد أحرفه الأصليّة؟', '[{"id":"a","text":"فَعْلَلَ — أربعة أحرف"},{"id":"b","text":"فَعَّلَ — ثلاثة أحرف"},{"id":"c","text":"أَفْعَلَ — أربعة أحرف"},{"id":"d","text":"تَفَعْلَلَ — خمسة أحرف"}]'::jsonb, 'a', '«زَلْزَلَ» رباعيّ مجرّد على وزن فَعْلَلَ، وأحرفه الأصليّة أربعة: ز ل ز ل.', 6)
