INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e365cc68-f170-5980-871d-ca9966b60743', '080f4190-deeb-5305-a094-8207d7b81686', 'المضارع المرفوع من الفعل الرّباعيّ المجرّد «دَحْرَجَ» مع «هو» هو:', '[{"id":"a","text":"يَدَحْرِجُ"},{"id":"b","text":"يُدَحْرَجُ"},{"id":"c","text":"يُدَحْرِجُ"},{"id":"d","text":"يَتَدَحْرَجُ"}]'::jsonb, 'c', 'مضارع الرّباعيّ المجرّد يبدأ بحرف مضارعةٍ مضمومٍ دائمًا، وعينه ولامه الأولى مكسورتان، فمضارع دَحْرَجَ هو يُدَحْرِجُ.', 2)
