INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('123fef92-ab54-5c17-85b0-b7a00dd01f3a', '080f4190-deeb-5305-a094-8207d7b81686', 'الفعل «قَدَّمَ» على وزن فَعَّلَ. عدد أحرفه الزّائدة هو:', '[{"id":"a","text":"حرفان"},{"id":"b","text":"ثلاثة أحرف"},{"id":"c","text":"لا زيادة فيه"},{"id":"d","text":"حرف واحد"}]'::jsonb, 'd', 'وزن فَعَّلَ زيادته حرفٌ واحد، هو تضعيف عين الفعل، فأصل «قَدَّمَ» ثلاثيٌّ زيدت عليه هذه الزّيادة الواحدة.', 3)
