INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8864b35f-fc71-5826-8b65-d0bd41139586', '080f4190-deeb-5305-a094-8207d7b81686', 'الفعل «دَخَلَ» لازمٌ. أيّ صيغةٍ مزيدةٍ منه تدلّ على التّعدية بزيادة الهمزة؟', '[{"id":"a","text":"أَدْخَلَ"},{"id":"b","text":"دَخَّلَ"},{"id":"c","text":"تَدَاخَلَ"},{"id":"d","text":"ادَّخَلَ"}]'::jsonb, 'a', 'زيادة الهمزة في أوّل «دَخَلَ» اللاّزم تعطي «أَدْخَلَ» المتعدّي (أَدْخَلَ الحارسُ الزّائرَ).', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
