INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('37ef668e-bca3-5d97-8d48-f26a31057e25', '080f4190-deeb-5305-a094-8207d7b81686', 'الماضي من الفعل الرّباعيّ المجرّد «زَلْزَلَ» مع ضمير «هم» هو:', '[{"id":"a","text":"زَلْزَلَا"},{"id":"b","text":"زَلْزَلُوا"},{"id":"c","text":"زَلْزَلَتْ"},{"id":"d","text":"زَلْزَلْنَا"}]'::jsonb, 'b', 'مع «هم» يتّصل الماضي بواو الجماعة كما في الثّلاثيّ، فيصبح «زَلْزَلُوا».', 5)
