INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('42c7df9a-67f3-5582-af87-9313283e02df', '7e260862-b80b-5f45-a12b-fd3777a2469e', 'الفعل «أَحْسَنَ»: حدّد معًا جذره الثّلاثيّ ووزنه وعدد أحرفه الزّائدة.', '[{"id":"a","text":"ح س ن — فَعَّلَ — حرف واحد"},{"id":"b","text":"أ ح س ن — فَعْلَلَ — لا زيادة فيه"},{"id":"c","text":"ح س ن — تَفَاعَلَ — حرفان"},{"id":"d","text":"ح س ن — أَفْعَلَ — حرف واحد"}]'::jsonb, 'd', 'أصل «أَحْسَنَ» الثّلاثيّ «حَسُنَ» (ح س ن)، زيدت عليه همزةٌ واحدةٌ في أوّله، فوزنه أَفْعَلَ.', 1)
