INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e755b5ad-3a07-5588-be95-dadb242005ac', '7e260862-b80b-5f45-a12b-fd3777a2469e', 'قال تلميذٌ: «الفعل تَعَاوَنَ زيدت عليه ثلاثة أحرف: التّاء والألف والواو». أين الخطأ في هذا الحكم؟', '[{"id":"a","text":"الواو أصليّةٌ من الجذر (ع و ن)، لا زائدة؛ فالزّيادة حرفان فقط: التّاء والألف"},{"id":"b","text":"لا خطأ، الزّيادة فعلًا ثلاثة أحرف"},{"id":"c","text":"الخطأ أنّ الزّيادة حرفٌ واحدٌ فقط هو التّاء"},{"id":"d","text":"الخطأ أنّ جذر الفعل رباعيّ لا ثلاثيّ"}]'::jsonb, 'a', 'جذر «تَعَاوَنَ» ثلاثيٌّ (ع و ن)؛ الواو أصليّةٌ من الجذر لا زائدة. الزّيادة الحقيقيّة حرفان فقط: التّاء في أوّل الفعل والألف بعد الفاء.', 2)
ON CONFLICT (id) DO UPDATE SET
