  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('60ddd617-83a3-5989-9b89-697e435afe3a', '7e260862-b80b-5f45-a12b-fd3777a2469e', 'فعلان لازمان: «نَزَلَ» و«جَلَسَ». حُوِّل كلاهما إلى متعدٍّ بزيادة الهمزة في أوّلهما. أيّ صياغةٍ صحيحةٌ للفعلين معًا؟', '[{"id":"a","text":"نَزَّلَ — جَلَّسَ"},{"id":"b","text":"أَنْزَلَ — أَجْلَسَ"},{"id":"c","text":"تَنَازَلَ — تَجَالَسَ"},{"id":"d","text":"نَازَلَ — جَالَسَ"}]'::jsonb, 'b', 'زيادة الهمزة في أوّل كلّ فعلٍ لازمٍ تعطي «أَنْزَلَ» (من نَزَلَ) و«أَجْلَسَ» (من جَلَسَ)، وكلاهما متعدٍّ الآن (أَنْزَلَ الحقيبةَ، أَجْلَسَ الطّفلَ).', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('de4430de-0706-5e6e-82bd-63e1082d6daf', '7e260862-b80b-5f45-a12b-fd3777a2469e', 'أيّ العبارات التّالية عن الرّباعيّ المجرّد والمزيد صحيحةٌ؟', '[{"id":"a","text":"كلّ فعلٍ من أربعة أحرفَ رباعيٌّ مجرّد"},{"id":"b","text":"وزن تَفَاعَلَ زيادته حرفٌ واحدٌ فقط"},{"id":"c","text":"الرّباعيّ المجرّد أحرفه الأربعة كلّها أصليّة، بخلاف الثّلاثيّ المزيد الّذي يضمّ حرفًا زائدًا على أصلٍ ثلاثيّ"},{"id":"d","text":"الفعل المزيد لا يمكن أن يكون متعدّيًا أبدًا"}]'::jsonb, 'c', 'العبارة الصّحيحة الوحيدة: الرّباعيّ المجرّد كلّ أحرفه أصليّة، خلافًا للثّلاثيّ المزيد الّذي يبقى جذره ثلاثيًّا مع حرفٍ زائد؛ أمّا العبارات الأخرى فخاطئة: عدد الأحرف وحده لا يحدّد النّوع، وتَفَاعَلَ زيادته حرفان لا حرفٌ واحد، وكثيرٌ من المزيد يكون متعدّيًا (كالتّعدية بالهمزة).', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('deaa4c4e-a9e7-53ad-88e3-dbdbc8637588', '7e260862-b80b-5f45-a12b-fd3777a2469e', 'صُنِّفت أربعة أفعالٍ حسب عدد أحرفها الأصليّة وأصالتها: وَسْوَسَ، أَكْرَمَ، تَعَاوَنَ، بَعْثَرَ. أيّ فعلين منها رباعيّان مجرّدان؟', '[{"id":"a","text":"أَكْرَمَ وتَعَاوَنَ"},{"id":"b","text":"وَسْوَسَ وأَكْرَمَ"},{"id":"c","text":"تَعَاوَنَ وبَعْثَرَ"},{"id":"d","text":"وَسْوَسَ وبَعْثَرَ"}]'::jsonb, 'd', '«وَسْوَسَ» و«بَعْثَرَ» أحرفهما الأربعة كلّها أصليّة (و س و س / ب ع ث ر)، فهما رباعيّان مجرّدان؛ أمّا «أَكْرَمَ» (أَفْعَلَ) و«تَعَاوَنَ» (تَفَاعَلَ) فثلاثيّان مزيدان.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d17e2a7a-cc3d-55ec-85f0-81fb7875c5a3', '7e260862-b80b-5f45-a12b-fd3777a2469e', 'الفعل اللاّزم «ضَحِكَ» زيدت عليه همزةٌ فصار متعدّيًا. ثمّ صُرِّف هذا الفعل الجديد في الماضي مع ضمير «هم». ما الصّيغة النّهائيّة؟', '[{"id":"a","text":"أَضْحَكُوا"},{"id":"b","text":"ضَحِكُوا"},{"id":"c","text":"ضَحَّكُوا"},{"id":"d","text":"تَضَاحَكُوا"}]'::jsonb, 'a', 'زيادة الهمزة على «ضَحِكَ» تعطي المتعدّي «أَضْحَكَ» (أَضْحَكَ الطّفلَ الأبَ)؛ وبتصريفه مع «هم» يتّصل بواو الجماعة فيصبح «أَضْحَكُوا».', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('ed575078-bdc0-56bf-b005-89d37112ae58', '8bbdfcf3-9192-5cc9-a7ac-ce67acaca7fa', 'arabic-7eme', '📝 تدريب ⭐⭐⭐: مراجعة شاملة لباب الصّرف كاملًا', 3, 120, 30, 'boss', 'admin', 5)
ON CONFLICT (id) DO UPDATE SET
