  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2ccaa71e-3f61-51a0-b534-04366ef8dbcb', 'ed575078-bdc0-56bf-b005-89d37112ae58', 'الجذر في علم الصّرف هو:', '[{"id":"a","text":"كلّ حرفٍ يظهر في الكلمة مهما كان"},{"id":"b","text":"الحروف الأصليّة الثّابتة الّتي يدور حولها معنى الكلمة، مجرّدةً من الزّوائد"},{"id":"c","text":"الحرف الأوّل من الفعل فقط"},{"id":"d","text":"الحركات الّتي تظهر على الفعل"}]'::jsonb, 'b', 'الجذر هو الحروف الأصليّة الثّابتة الّتي يقوم عليها المعنى الأساسيّ للكلمة، مجرّدةً من كلّ حرفٍ زائد.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('558dea27-766b-55c0-bd3f-4b267394e8d0', 'ed575078-bdc0-56bf-b005-89d37112ae58', 'الفعل السّالم -الّذي درسته سابقًا- هو الفعل الخالي من:', '[{"id":"a","text":"الزّيادة فقط"},{"id":"b","text":"الأحرف الأصليّة"},{"id":"c","text":"حرف العلّة والهمزة والتّضعيف"},{"id":"d","text":"الضّمائر"}]'::jsonb, 'c', 'الفعل السّالم أحرفه الأصليّة الثّلاثة كلّها صحيحة، خالية من حرف العلّة والهمزة والتّضعيف.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8249f651-6c99-5b33-a31c-9181edf7d5f0', 'ed575078-bdc0-56bf-b005-89d37112ae58', 'الاشتقاق من الثّلاثيّ المجرّد يولّد من الجذر الواحد، من بين ما يولّد، كلماتٍ مثل:', '[{"id":"a","text":"حروف العطف والجرّ فقط"},{"id":"b","text":"الضّمائر المتّصلة فقط"},{"id":"c","text":"أدوات الاستفهام فقط"},{"id":"d","text":"المصدر واسم الفاعل واسم المفعول"}]'::jsonb, 'd', 'الاشتقاق من الثّلاثيّ المجرّد يولّد من الجذر الواحد كلماتٍ مثل المصدر واسم الفاعل واسم المفعول والصّفة المشبّهة.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('19508254-fae6-50ad-a785-280b4ff51407', 'ed575078-bdc0-56bf-b005-89d37112ae58', 'الفعل المعتلّ يختلف عن الفعل المزيد لأنّ معيار تصنيف كلٍّ منهما مختلف. ما الفرق الصّحيح بينهما؟', '[{"id":"a","text":"المعتلّ ينظر إلى نوع الأحرف الأصليّة (سالمة أم معتلّة)، والمزيد ينظر إلى وجود زيادةٍ على الأصل"},{"id":"b","text":"المعتلّ والمزيد مترادفان تمامًا"},{"id":"c","text":"المعتلّ خاصٌّ بالأسماء والمزيد خاصٌّ بالأفعال"},{"id":"d","text":"لا فرق سوى في عدد الأحرف"}]'::jsonb, 'a', 'المعتلّ يصنَّف بحسب نوع أحرفه الأصليّة (هل فيها حرف علّة أم لا)، بينما المزيد يصنَّف بحسب وجود زيادةٍ من عدمها على الأصل؛ فهما معياران مختلفان قد يجتمعان في فعلٍ واحد.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c7f5bab6-e3b7-5850-9100-d0a183d86110', 'ed575078-bdc0-56bf-b005-89d37112ae58', 'بين الأفعال «كَاتِبٌ» (اسم مشتقّ)، «دَحْرَجَ»، «أَكْرَمَ»، «قَالَ» (معتلّ)، أيّها فعلٌ رباعيّ مجرّد؟', '[{"id":"a","text":"كَاتِبٌ"},{"id":"b","text":"دَحْرَجَ"},{"id":"c","text":"أَكْرَمَ"},{"id":"d","text":"قَالَ"}]'::jsonb, 'b', '«دَحْرَجَ» وحده رباعيّ مجرّد (أربعة أحرفٍ أصليّة)؛ «كَاتِبٌ» اسمٌ مشتقّ من الثّلاثيّ، «أَكْرَمَ» ثلاثيّ مزيد، و«قَالَ» ثلاثيّ معتلّ.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('896f68e9-8058-5cf6-bed3-f8deda483650', 'ed575078-bdc0-56bf-b005-89d37112ae58', 'بعد رحلةٍ كاملةٍ في باب الصّرف، لخّص طالبٌ الفرق بين «زَلْزَلَ» و«أَخْرَجَ» رغم أنّ كليهما من أربعة أحرفَ. أيّ تلخيصٍ صحيح؟', '[{"id":"a","text":"كلاهما رباعيّ مجرّد لأنّ عدد أحرفهما واحد"},{"id":"b","text":"كلاهما ثلاثيّ مزيد"},{"id":"c","text":"«زَلْزَلَ» رباعيّ مجرّد (أحرفه الأربعة أصليّة)، و«أَخْرَجَ» ثلاثيّ مزيد (أصله «خَرَجَ» زيدت عليه همزة)"},{"id":"d","text":"لا فرق بينهما إطلاقًا"}]'::jsonb, 'c', 'العبرة دائمًا بأصالة الأحرف لا بعددها: «زَلْزَلَ» جذره رباعيٌّ كاملٌ (ز ل ز ل)، أمّا «أَخْرَجَ» فجذره ثلاثيّ (خ ر ج) زيدت عليه همزةٌ واحدة، فهو ثلاثيّ مزيد.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('99324a23-cb7c-5c34-b269-ae0e33311d3c', '8bbdfcf3-9192-5cc9-a7ac-ce67acaca7fa', 'arabic-7eme', '👑 تحدّي النخبة ⭐⭐⭐⭐: قمّة باب الصّرف', 4, 300, 60, 'challenge', 'admin', 6)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8e0fe436-2b66-50a4-90b0-06813646ab53', '99324a23-cb7c-5c34-b269-ae0e33311d3c', 'الفعل «طَمْأَنَ» (بمعنى: جعله يشعر بالأمان) من أربعة أحرفَ: ط م أ ن. حدّد نوعه، ثمّ صرّف ماضيه مع «أنتَ».', '[{"id":"a","text":"رباعيّ مجرّد — طَمْأَنْتَ"},{"id":"b","text":"ثلاثيّ مزيد — أَطْمَأَنْتَ"},{"id":"c","text":"رباعيّ مزيد — تَطَمْأَنْتَ"},{"id":"d","text":"ثلاثيّ مجرّد — طَمِنْتَ"}]'::jsonb, 'a', 'أحرف «طَمْأَنَ» الأربعة (ط م أ ن) كلّها أصليّةٌ لا زيادة فيها (الهمزة هنا أصليّةٌ من الجذر، لا زائدة كما في أَخْرَجَ)، فهو رباعيّ مجرّد، وماضيه مع «أنتَ» طَمْأَنْتَ.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ccf49a67-8f33-5229-8ea9-76ad577d9b6f', '99324a23-cb7c-5c34-b269-ae0e33311d3c', 'في الفعلين «طَمْأَنَ» و«أَخْرَجَ» تظهر همزةٌ في كلٍّ منهما، لكنّ حكمها مختلف. ما الفرق؟', '[{"id":"a","text":"همزة «طَمْأَنَ» أصليّةٌ من جذره الرّباعيّ، وهمزة «أَخْرَجَ» زائدةٌ على أصله الثّلاثيّ «خَرَجَ»"},{"id":"b","text":"الهمزتان زائدتان في الفعلين معًا"},{"id":"c","text":"الهمزتان أصليّتان في الفعلين معًا"},{"id":"d","text":"لا فرق البتّة بين الحالتين"}]'::jsonb, 'a', 'همزة «طَمْأَنَ» من صميم جذره الرّباعيّ (ط م أ ن)، فهي أصليّة؛ أمّا همزة «أَخْرَجَ» فزائدةٌ على أصله الثّلاثيّ «خَرَجَ» لغرض التّعدية. تحديد أصالة الحرف لا يكون بموقعه، بل بالرّجوع إلى الفعل الثّلاثيّ الأصل إن وُجد.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3552c3b1-ceaf-5cb9-a67f-bbeb83c3b010', '99324a23-cb7c-5c34-b269-ae0e33311d3c', 'الفعل اللاّزم «جَلَسَ» يصير متعدّيًا بزيادة الهمزة. زد على هذا الفعل الجديد المتعدّي واو الجماعة (فاعله جمع مذكّر غائب) في الماضي. ما الصّيغة النّهائيّة؟', '[{"id":"a","text":"جَلَسُوا"},{"id":"b","text":"أَجْلَسُوا"},{"id":"c","text":"جَلَّسُوا"},{"id":"d","text":"تَجَالَسُوا"}]'::jsonb, 'b', 'زيادة الهمزة تحوّل «جَلَسَ» اللاّزم إلى «أَجْلَسَ» المتعدّي؛ وبإسناده لجمع الغائبين المذكّرين تتّصل واو الجماعة، فتكون الصّيغة النّهائيّة «أَجْلَسُوا» (أَجْلَسُوا الضّيوفَ).', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ed8981b2-f7b6-5532-9859-4970c1782b16', '99324a23-cb7c-5c34-b269-ae0e33311d3c', 'أيّ العبارات التّالية عن باب الصّرف كاملًا صحيحةٌ؟', '[{"id":"a","text":"الجذر يتغيّر بتغيّر الكلمات المشتقّة منه"},{"id":"b","text":"الفعل المعتلّ هو نفسه الفعل المزيد دائمًا"},{"id":"c","text":"الرّباعيّ المجرّد أحرفه الأربعة أصليّة، أمّا الثّلاثيّ المزيد فيبقى جذره ثلاثيًّا رغم زيادة حرفٍ أو أكثر على ظاهره"},{"id":"d","text":"كلّ الأفعال الرّباعيّة الظّاهر متعدّيةٌ حتمًا"}]'::jsonb, 'c', 'العبارة الصّحيحة الوحيدة: الرّباعيّ المجرّد كلّ أحرفه أصليّة، بخلاف الثّلاثيّ المزيد الّذي يحتفظ بجذرٍ ثلاثيٍّ رغم ظهور حرفٍ إضافيّ؛ أمّا الباقي فخطأ: الجذر ثابتٌ لا يتغيّر، والمعتلّ والمزيد معياران مختلفان لا مترادفان، والتّعدية ليست حتميّةً في كلّ رباعيّ.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('979295a5-f2a5-5a4c-b32a-74c13eba3e0f', '99324a23-cb7c-5c34-b269-ae0e33311d3c', 'أربعة أفعالٍ: زَلْزَلَ، أَفْرَحَ، وَسْوَسَ، أَحْسَنَ. صُنِّفها إلى مجموعتين: رباعيّ مجرّد، وثلاثيّ مزيد بالهمزة. أيّ تصنيفٍ صحيح؟', '[{"id":"a","text":"رباعيّ مجرّد: زَلْزَلَ وأَحْسَنَ — ثلاثيّ مزيد: أَفْرَحَ ووَسْوَسَ"},{"id":"b","text":"رباعيّ مجرّد: أَفْرَحَ وأَحْسَنَ — ثلاثيّ مزيد: زَلْزَلَ ووَسْوَسَ"},{"id":"c","text":"الأفعال الأربعة كلّها رباعيّةٌ مجرّدة"},{"id":"d","text":"رباعيّ مجرّد: زَلْزَلَ ووَسْوَسَ — ثلاثيّ مزيد: أَفْرَحَ وأَحْسَنَ"}]'::jsonb, 'd', '«زَلْزَلَ» و«وَسْوَسَ» أحرفهما الأربعة كلّها أصليّة، فهما رباعيّان مجرّدان؛ أمّا «أَفْرَحَ» (من فَرِحَ) و«أَحْسَنَ» (من حَسُنَ) فأصلهما ثلاثيّ زيدت عليه همزةٌ، فهما ثلاثيّان مزيدان.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('84f87ed2-e739-58b8-8a78-dbf24986da6a', '99324a23-cb7c-5c34-b269-ae0e33311d3c', 'الفعل اللاّزم «بَعُدَ»: زد عليه همزةً لتعديته، حدّد وزن الفعل الجديد، ثمّ صرّفه في المضارع المرفوع مع ضمير «هي».', '[{"id":"a","text":"أَفْعَلَ — تُبْعِدُ"},{"id":"b","text":"فَعَّلَ — تُبَعِّدُ"},{"id":"c","text":"فَعْلَلَ — لا زيادة فيه"},{"id":"d","text":"تَفَاعَلَ — تَتَبَاعَدُ"}]'::jsonb, 'a', 'زيادة الهمزة على «بَعُدَ» تعطي «أَبْعَدَ» على وزن أَفْعَلَ (أَبْعَدَ الحارسُ الخطرَ)؛ ومضارعه المرفوع مع «هي» «تُبْعِدُ».', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

